#!/usr/bin/env python3
"""
rsi_levels_metaforge :: REAL-SEARCH RUNTIME CORE (rebuilt)
==========================================================

This core replaces the previous oracle-lookup runtime. Differences are
structural, not cosmetic:

  OLD (removed)                          NEW (this file)
  -------------------------------       -------------------------------------
  Candidates were the oracle             Candidates are bytecode programs for a
  functions themselves, fetched          typed stack VM, synthesized by budgeted
  from TASK_TO_FN by task name.          stochastic search. No task-name lookup
                                         from id to solution exists anywhere.
  "Substrates" were decorative           The searcher state (macro library +
  strings that were never executed.      proposal weights) is executable and is
                                         the only thing search behavior depends
                                         on, so improving it improves search.
  "Self-improvement" was asserted.       Improvements are PROPOSED from the
                                         system's own solved programs, then pass
                                         an empirical META-GATE: A/B against the
                                         incumbent searcher on the unsolved
                                         frontier with equal budget and seeds.
                                         Regressions are rejected and logged.
  No counterfactual existed.             A frozen-searcher arm runs the same
                                         task stream with the same budgets and
                                         seeds. The self-improvement claim is
                                         exactly the measured delta, no more.
  Recursion was a word.                  Macros may contain earlier macros
                                         (bounded depth). Lineage depth >= 2
                                         means an improvement was built on top
                                         of a previous improvement.

Honesty constraints enforced by tests at the bottom of this core:
  * The synthesizer receives ONLY training input/output pairs. Oracles live
    inside sealed gate closures and are never passed to search code.
  * Adoption requires exact behavioral match on all training examples AND a
    pass on the external holdout gate (longer, unseen input lengths).
  * Tasks that search cannot reach stay OPEN and are reported as such.
  * Deterministic: fixed seeds; two runs produce identical adoption logs.
  * No eval/exec anywhere in the runtime core.


UNIFIED GENERAL-DOMAIN DIRECTIVE LAYER (this build):
  Section 11 integrates four measured mechanisms -- S1 PRM (StepScorer +
  prm_beam channel inside run_wave, attempt 3, dual-gated), S2 committee
  debate with adversarial distinguisher + constitutional checks under a
  scarce request_label budget (holdout demoted to AUDIT-ONLY), S3 a learned
  OpSemanticsModel world model (act & observe on the real VM, declared
  finite prior, honest abstention), and S4 meta-learning (oracle-free
  config selection with Goodhart audit; self-minted GD curriculum with
  per-generation audited drift). Run `--mode directive-battery` for the
  measured experiments; the embedded test suite covers every mechanism.

Run:
    python rsi_core.py --mode demo            # adaptive run, full report
    python rsi_core.py --mode counterfactual  # adaptive vs frozen, same budget
    python rsi_core.py --mode test            # honest test suite
"""
from __future__ import annotations

import argparse
import os
import hashlib
import json
import math
import random
from dataclasses import dataclass, field
from typing import Callable, Dict, Iterable, List, Optional, Sequence, Tuple

try:
    import numpy as np  # noqa: F401  (kept for embedded-subsystem parity)
except Exception:  # pragma: no cover
    np = None

# ---------------------------------------------------------------------------
# Deterministic constants.
# ---------------------------------------------------------------------------
SEED = 2026
DATA_SEED = 11
GATE_SEED = 2027
CF_GATE_SEED = 4099
CF_LENGTHS = (6, 9, 14, 22, 30)
CF_TRIALS = 6
CF_VALMAX = 15
WAVES = 8
MINT_PER_WAVE = 2
MAX_GEN_TASKS = 14
TRAIN_LENGTHS = (1, 2, 3, 4, 6)
HOLDOUT_LENGTHS = (5, 8, 13, 21, 34)
PER_LENGTH = 4
GATE_TRIALS = 8

MAX_PROGRAM_LEN = 14          # surface tokens (macros count as 1)
MAX_EXPANDED_LEN = 20_000     # expanded base-op cap; raised after the
                              # self-generated ladder organically outgrew the
                              # original 96 (see CAND_COMPILE_CRASH logging)
MAX_STACK = 32
MAX_LIST_LEN = 256
MAX_MACRO_BODY = 6
MAX_MACROS = 24
MACRO_DEPTH_CAP = 10

RESTARTS_PER_TASK = 6
ITERS_PER_RESTART = 550       # candidate evaluations per restart
METAGATE_MAX_TASKS = 12

# Rule 2 growth bounds for the top core (Phase A). A capacity rung beyond
# these bounds is never proposed; reaching them is reported as
# "growth bound reached", not treated as an error.
CAPACITY_GROWTH_STEP_LEN = 6      # max_program_len grows +6 per adopted rung
CAPACITY_GROWTH_STEP_MACROS = 24  # max_macros grows +24 per adopted rung
CAPACITY_BOUND_PROGRAM_LEN = 56   # max_stack doubles per rung up to its bound
CAPACITY_BOUND_STACK = 128
CAPACITY_BOUND_MACROS = 96


def build_train_inputs(seed: int = DATA_SEED) -> List[List[int]]:
    rng = random.Random(seed)
    out: List[List[int]] = []
    for L in TRAIN_LENGTHS:
        for _ in range(PER_LENGTH):
            out.append([rng.randint(0, 7) for _ in range(L)])
    return out


TRAIN_INPUTS: Tuple[Tuple[int, ...], ...] = tuple(tuple(x) for x in build_train_inputs())

# ---------------------------------------------------------------------------
# Stack VM. Values are int or tuple-of-int. Every op checks types/arity and
# crashes (VMCrash) on violation; crashes are scored 0, never hidden.
# ---------------------------------------------------------------------------
class VMCrash(Exception):
    pass


OP_NAMES: Tuple[str, ...] = (
    "PUSH0", "PUSH1", "PUSH2", "PUSH3",            # 0..3
    "INPUT",                                        # 4
    "DUP", "SWAP", "DROP", "OVER",                  # 5..8
    "ADD", "SUB", "MUL", "DIVI", "MOD",             # 9..13
    "MAX2", "MIN2",                                 # 14..15
    "LEN", "HEAD", "LAST", "IDX",                   # 16..19
    "TAIL", "REVL", "SORTL",                        # 20..22
    "ZADD", "ZSUB", "ZMUL", "ZMAX",                 # 23..26
    "SCAN_MAX", "SCAN_ADD",                         # 27..28
    "RED_ADD", "RED_MAX",                           # 29..30
    "EVENIDX", "ODDIDX",                            # 31..32
    "SELECT",                                       # 33
)
N_BASE_OPS = len(OP_NAMES)
MACRO_ID_BASE = 100
INT_CAP = 10 ** 3000   # bounds runaway growth; self-generated power ladders
                       # legitimately reach astronomically large exact ints


def _need(stack: List[object], n: int) -> None:
    if len(stack) < n:
        raise VMCrash("stack_underflow")


def _pop_int(stack: List[object]) -> int:
    _need(stack, 1)
    v = stack.pop()
    if not isinstance(v, int):
        raise VMCrash("type_expected_int")
    return v


def _pop_list(stack: List[object]) -> Tuple[int, ...]:
    _need(stack, 1)
    v = stack.pop()
    if not isinstance(v, tuple):
        raise VMCrash("type_expected_list")
    return v


# Active VM stack bound. Default is the historical MAX_STACK; executors that
# run under a specific searcher capacity (run_base_program, build_enum_table)
# set it for the duration of one execution and always restore it. A one-slot
# list (not rebinding a global) keeps set/restore local and exception-safe.
_ACTIVE_MAX_STACK: List[int] = [MAX_STACK]


def _push(stack: List[object], v: object) -> None:
    if isinstance(v, int):
        if abs(v) > INT_CAP:
            raise VMCrash("int_overflow")
    elif isinstance(v, tuple):
        if len(v) > MAX_LIST_LEN:
            raise VMCrash("list_overflow")
    else:  # pragma: no cover
        raise VMCrash("bad_value_type")
    if len(stack) >= _ACTIVE_MAX_STACK[0]:
        raise VMCrash("stack_overflow")
    stack.append(v)


def _op_push_const(c):
    def f(stack, inp):
        _push(stack, c)
    return f

def _op_input(stack, inp):
    _push(stack, inp)

def _op_dup(stack, inp):
    _need(stack, 1); _push(stack, stack[-1])

def _op_swap(stack, inp):
    _need(stack, 2); stack[-1], stack[-2] = stack[-2], stack[-1]

def _op_drop(stack, inp):
    _need(stack, 1); stack.pop()

def _op_over(stack, inp):
    _need(stack, 2); _push(stack, stack[-2])

def _bin(fn):
    def f(stack, inp):
        b = _pop_int(stack); a = _pop_int(stack); _push(stack, fn(a, b))
    return f

def _lop(fn):
    def f(stack, inp):
        l = _pop_list(stack); _push(stack, fn(l))
    return f

def _zip2(fn):
    def f(stack, inp):
        b = _pop_list(stack); a = _pop_list(stack)
        n = min(len(a), len(b))
        _push(stack, tuple(fn(a[i], b[i]) for i in range(n)))
    return f

def _op_idx(stack, inp):
    i = _pop_int(stack); l = _pop_list(stack)
    _push(stack, l[i % len(l)] if l else 0)

def _scan_max(l):
    acc = []; cur = None
    for v in l:
        cur = v if cur is None else (cur if cur >= v else v)
        acc.append(cur)
    return tuple(acc)

def _scan_add(l):
    s = 0; acc = []
    for v in l:
        s += v; acc.append(s)
    return tuple(acc)

def _op_select(stack, inp):
    c = _pop_int(stack)
    ev = stack.pop() if stack else None
    tv = stack.pop() if stack else None
    if ev is None or tv is None:
        raise VMCrash("stack_underflow")
    _push(stack, tv if c != 0 else ev)

OP_IMPL = (
    _op_push_const(0), _op_push_const(1), _op_push_const(2), _op_push_const(3),
    _op_input,
    _op_dup, _op_swap, _op_drop, _op_over,
    _bin(lambda a, b: a + b), _bin(lambda a, b: a - b), _bin(lambda a, b: a * b),
    _bin(lambda a, b: 0 if b == 0 else a // b),
    _bin(lambda a, b: 0 if b == 0 else a % b),
    _bin(lambda a, b: a if a >= b else b), _bin(lambda a, b: a if a <= b else b),
    _lop(len), _lop(lambda l: l[0] if l else 0), _lop(lambda l: l[-1] if l else 0),
    _op_idx,
    _lop(lambda l: l[1:]), _lop(lambda l: tuple(reversed(l))),
    _lop(lambda l: tuple(sorted(l))),
    _zip2(lambda a, b: a + b), _zip2(lambda a, b: a - b),
    _zip2(lambda a, b: a * b), _zip2(lambda a, b: a if a >= b else b),
    _lop(_scan_max), _lop(_scan_add),
    _lop(sum), _lop(lambda l: max(l) if l else 0),
    _lop(lambda l: l[0::2]), _lop(lambda l: l[1::2]),
    _op_select,
)
assert len(OP_IMPL) == N_BASE_OPS


# Granted-primitive registries (Section 13). Dormant by default: empty dicts
# make every dispatch below behave exactly as the pre-extension system.
EXT_IMPL: Dict[int, Callable[[List[object], Tuple[int, ...]], None]] = {}
EXT_TYPES: Dict[int, Tuple[Tuple[str, ...], Tuple[str, ...]]] = {}


def step_op(stack: List[object], op: int, inp: Tuple[int, ...]) -> None:
    """Execute ONE base op against a live stack. Single source of truth for VM
    semantics; the table above is that source, this is the safe wrapper."""
    if 0 <= op < N_BASE_OPS:
        OP_IMPL[op](stack, inp)
    elif op in EXT_IMPL:
        EXT_IMPL[op](stack, inp)
    else:
        raise VMCrash(f"unknown_op_{op}")


def run_base_program(expanded: Sequence[int], xs: Sequence[int],
                     max_stack: Optional[int] = None) -> int:
    """Execute a fully expanded base-op program. Returns the single int left on
    the stack; anything else is a crash. Total and deterministic. max_stack
    None keeps the historical MAX_STACK bound; a searcher capacity threads a
    per-execution bound through here."""
    if len(expanded) > MAX_EXPANDED_LEN:
        raise VMCrash("program_too_long")
    stack: List[object] = []
    inp = tuple(int(v) for v in xs)
    prev = _ACTIVE_MAX_STACK[0]
    _ACTIVE_MAX_STACK[0] = MAX_STACK if max_stack is None else max_stack
    try:
        for op in expanded:
            step_op(stack, op, inp)
    finally:
        _ACTIVE_MAX_STACK[0] = prev
    if len(stack) != 1 or not isinstance(stack[0], int):
        raise VMCrash("bad_terminal_state")
    return stack[0]



# ---------------------------------------------------------------------------
# Searcher state: THE SELF. Macro library + proposal weights. This object is
# the only mutable thing search depends on, so modifying it modifies search.
# ---------------------------------------------------------------------------
@dataclass(frozen=True)
class Macro:
    mid: int                       # token id (>= MACRO_ID_BASE)
    body: Tuple[int, ...]          # surface tokens; may contain earlier macros
    depth: int                     # 1 = base ops only; 2 = contains depth-1 macro
    wave_discovered: int
    parent_tasks: Tuple[str, ...]  # opaque task ids it was mined from


@dataclass(frozen=True)
class CapacityConfig:
    """Top-VM/searcher capacity (Phase A). Defaults reproduce the historical
    module constants exactly; a run whose capacity never grows is
    behaviorally identical to the pre-CapacityConfig runtime. Capacity is
    part of SearcherState, so a grown candidate is A/B-compared against the
    incumbent by the unchanged meta_gate and rolls back with the searcher."""
    max_program_len: int = MAX_PROGRAM_LEN
    max_stack: int = MAX_STACK
    max_macros: int = MAX_MACROS


@dataclass
class SearcherState:
    macros: Dict[int, Macro] = field(default_factory=dict)
    weights: Dict[int, float] = field(default_factory=dict)
    version: int = 0
    history: List[str] = field(default_factory=list)
    extended: Dict[int, str] = field(default_factory=dict)
    capacity: CapacityConfig = field(default_factory=CapacityConfig)

    def clone(self) -> "SearcherState":
        s = SearcherState()
        s.macros = dict(self.macros)
        s.weights = dict(self.weights)
        s.version = self.version
        s.history = list(self.history)
        s.extended = dict(self.extended)
        s.capacity = self.capacity
        return s

    def vocab(self) -> List[int]:
        return (list(range(N_BASE_OPS)) + sorted(self.extended)
                + sorted(self.macros))

    def weight(self, tok: int) -> float:
        return self.weights.get(tok, 1.0)

    def digest(self) -> str:
        raw = json.dumps({
            "macros": {m.mid: list(m.body) for m in self.macros.values()},
            "weights": {k: round(v, 6) for k, v in sorted(self.weights.items())},
            "version": self.version,
        }, sort_keys=True).encode()
        return hashlib.sha256(raw).hexdigest()[:16]


def expand_tokens(tokens: Sequence[int], macros: Dict[int, Macro]) -> Tuple[int, ...]:
    """Expand macro tokens to base ops. Depth-bounded; cycle-safe because a
    macro body may only reference strictly smaller macro ids (enforced at
    creation)."""
    out: List[int] = []

    def rec(seq: Sequence[int], depth: int) -> None:
        if depth > MACRO_DEPTH_CAP + 1:
            raise VMCrash("macro_depth_exceeded")
        for t in seq:
            if t < N_BASE_OPS or t in EXT_IMPL:
                out.append(t)
            elif t not in macros:
                raise VMCrash(f"unknown_token_{t}")
            else:
                m = macros.get(t)
                if m is None:
                    raise VMCrash("unknown_macro")
                rec(m.body, depth + 1)
            if len(out) > MAX_EXPANDED_LEN:
                raise VMCrash("program_too_long")

    rec(tokens, 1)
    return tuple(out)


def token_str(tokens: Sequence[int], macros: Dict[int, Macro]) -> str:
    parts = []
    for t in tokens:
        if t < N_BASE_OPS:
            parts.append(OP_NAMES[t])
        else:
            parts.append(f"M{t}")
    return " ".join(parts)


# ---------------------------------------------------------------------------
# Sealed tasks. The synthesizer sees ONLY (task_id, train_pairs). The oracle is
# captured inside the holdout-gate closure and inside the train-output values;
# no code path hands the oracle callable to search.
# ---------------------------------------------------------------------------
@dataclass(frozen=True)
class SealedTask:
    tid: str                                       # opaque id, e.g. "T07"
    family: str                                    # diagnostic metadata; never
                                                   # consulted by search code
    train_pairs: Tuple[Tuple[Tuple[int, ...], int], ...]
    holdout_gate: Callable[[Callable[[List[int]], int]], bool]
    cf_gate: Callable[[Callable[[List[int]], int]], bool]


def _make_gate(oracle, seed: int, lengths, trials: int, valmax: int):
    def gate(fn: Callable[[List[int]], int]) -> bool:
        rng = random.Random(seed)
        for L in lengths:
            for _ in range(trials):
                xs = [rng.randint(0, valmax) for _ in range(L)]
                try:
                    if int(fn(list(xs))) != int(oracle(list(xs))):
                        return False
                except Exception:
                    return False
        return True
    return gate


def seal_task(tid: str, family: str, oracle) -> SealedTask:
    pairs = tuple((xs, int(oracle(list(xs)))) for xs in TRAIN_INPUTS)
    return SealedTask(
        tid=tid, family=family, train_pairs=pairs,
        holdout_gate=_make_gate(oracle, GATE_SEED, HOLDOUT_LENGTHS,
                                GATE_TRIALS, 7),
        cf_gate=_make_gate(oracle, CF_GATE_SEED, CF_LENGTHS,
                           CF_TRIALS, CF_VALMAX))


# --- oracle definitions (used ONLY by seal_task; never imported by search) ---
def _safe_max(xs): return max(xs) if xs else 0
def _second_largest(xs):
    if not xs: return 0
    if len(xs) == 1: return xs[0]
    return sorted(xs)[-2]
def _argmax_index(xs):
    if not xs: return -1
    m = max(xs)
    return next(i for i, x in enumerate(xs) if x == m)
def _first_gt_prev(xs):
    for i in range(1, len(xs)):
        if xs[i] > xs[i - 1]: return i
    return -1
def _longest_inc_run(xs):
    if not xs: return 0
    best = cur = 1
    for i in range(1, len(xs)):
        if xs[i] > xs[i - 1]:
            cur += 1
        else:
            cur = 1
        best = max(best, cur)
    return best


ORACLES: Tuple[Tuple[str, str, Callable[[List[int]], int]], ...] = (
    # -- core / closure tier --
    ("sum", "reduce",                      lambda xs: sum(xs)),
    ("count", "reduce",                    lambda xs: len(xs)),
    ("max", "reduce",                      _safe_max),
    ("2*sum", "scale",                    lambda xs: 2 * sum(xs)),
    ("parity", "conditional",                   lambda xs: len(xs) % 2),
    ("sum_sq", "power",                   lambda xs: sum(x * x for x in xs)),
    ("sum+count", "compose",                lambda xs: sum(xs) + len(xs)),
    ("sum*count", "compose",                lambda xs: sum(xs) * len(xs)),
    ("max_sq", "power",                   lambda xs: _safe_max(xs) ** 2),
    ("count*count", "power",              lambda xs: len(xs) * len(xs)),
    # -- power tier --
    ("sum_x4", "power",                   lambda xs: sum(x ** 4 for x in xs)),
    ("sumx4_sq", "power",                 lambda xs: sum(x ** 4 for x in xs) ** 2),
    ("sum_x8", "power",                   lambda xs: sum(x ** 8 for x in xs)),
    # -- wall tier --
    ("middle", "index",                   lambda xs: xs[len(xs) // 2] if xs else 0),
    ("sum*max", "compose",                  lambda xs: sum(xs) * _safe_max(xs)),
    ("alternating_sum", "position",          lambda xs: sum((1 if i % 2 == 0 else -1) * x for i, x in enumerate(xs))),
    ("prefix_max_sum", "scan",           lambda xs: sum(max(xs[:i + 1]) for i in range(len(xs)))),
    ("second_largest", "order",           _second_largest),
    ("length_conditioned_sum", "conditional",   lambda xs: sum(xs) if len(xs) % 2 == 0 else _safe_max(xs) * len(xs)),
    ("pairwise_product_sum", "pairwise",     lambda xs: sum(xs[i] * xs[i + 1] for i in range(len(xs) - 1))),
    # -- successor tier --
    ("first_quartile", "index",           lambda xs: xs[len(xs) // 4] if xs else 0),
    ("last_quartile", "index",            lambda xs: xs[(3 * len(xs)) // 4] if xs else 0),
    ("sum*second_largest", "compose",       lambda xs: sum(xs) * _second_largest(xs)),
    ("sum*range", "compose",                lambda xs: sum(xs) * (_safe_max(xs) - (min(xs) if xs else 0))),
    ("parity_conditioned_sum", "position",   lambda xs: sum(xs[0::2]) if len(xs) % 2 == 0 else sum(xs[1::2])),
    ("rolling_pair_sum", "pairwise",         lambda xs: max((xs[i] + xs[i + 1] for i in range(len(xs) - 1)), default=0)),
    ("adjacent_difference_energy", "pairwise", lambda xs: sum((xs[i + 1] - xs[i]) ** 2 for i in range(len(xs) - 1))),
    # -- power-tower successor tier (auto-curriculum headroom): same family as
    #    sum_sq/sum_x4/sum_x8, parameter doubled. Base-ISA surface cost 10 and
    #    12 tokens -- beyond the enumeration horizon without nested macros. --
    ("sum_x16", "power",                  lambda xs: sum(x ** 16 for x in xs)),
    ("sum_x32", "power",                  lambda xs: sum(x ** 32 for x in xs)),
    # -- expected-open tier: no comparison/search primitives exist in the ISA,
    #    so these should stay OPEN. Honest walls, reported as unsolved. --
    ("count_above_threshold", "search",    lambda xs: sum(1 for x in xs if x > 3)),
    ("argmax_index", "search",             _argmax_index),
    ("first_greater_than_previous", "search", _first_gt_prev),
    ("longest_increasing_run", "search",   _longest_inc_run),
)

TASK_NAME_BY_TID: Dict[str, str] = {}
TASK_FAMILY_BY_TID: Dict[str, str] = {}


def build_sealed_tasks() -> List[SealedTask]:
    tasks = []
    for i, (name, family, fn) in enumerate(ORACLES):
        tid = f"T{i:02d}"
        TASK_NAME_BY_TID[tid] = name
        TASK_FAMILY_BY_TID[tid] = family
        _register_oracle(tid, fn)
        tasks.append(seal_task(tid, family, fn))
    return tasks


# ---------------------------------------------------------------------------
# SELF-GENERATED CURRICULUM ("headroom synthesis").
# The generator -- part of the improving system -- proposes new wall SPECS
# using only public information (which task ids are solved, public train
# vectors). The MINT FACTORY below -- part of the environment, exactly like
# seal_task -- holds the private oracle registry and assembles sealed tasks
# (dual gates included) from specs. Search code never touches the registry;
# a test enforces this. Composition operators are fixed and generic:
#   sq   : C(xs) = A([x*x for x in xs])      (input-square composition)
#   mulo : C(xs) = A(xs) * B(xs)             (pointwise output product)
# Which walls get minted is the system's choice; that the operator vocabulary
# is designer-fixed is disclosed in reports.
# ---------------------------------------------------------------------------
_ORACLE_REGISTRY: Dict[str, Callable[[List[int]], int]] = {}


def _register_oracle(tid: str, fn: Callable[[List[int]], int]) -> None:
    _ORACLE_REGISTRY[tid] = fn


def _macro_transform(rs: "RunState", mid: int) -> Callable[[List[int]], List[int]]:
    # Lift an installed macro into an input transform: run its expanded body
    # on xs from an empty stack and take the top value, which must be a list.
    # Semantics freeze at mint time (installed macros are immutable).
    exp = expand_tokens(rs.searcher.macros[mid].body, rs.searcher.macros)

    def t(xs: List[int], _exp=exp) -> List[int]:
        s: List[object] = []
        inp = tuple(int(v) for v in xs)
        for b in _exp:
            (OP_IMPL[b] if b < N_BASE_OPS else EXT_IMPL[b])(s, inp)
        if not s or not isinstance(s[-1], tuple):
            raise VMCrash("via_transform_not_list")
        return list(s[-1])
    return t


def _list_producer_mids(rs: "RunState", cap: int = 3) -> List[int]:
    out: List[int] = []
    for mid in sorted(rs.searcher.macros, reverse=True):
        try:
            t = _macro_transform(rs, mid)
            for xs in TRAIN_INPUTS[:4]:
                t(list(xs))
        except VMCrash:
            continue
        out.append(mid)
        if len(out) >= cap:
            break
    return out


def _gen_oracle(spec: Tuple[str, str, str],
                rs: Optional["RunState"] = None) -> Callable[[List[int]], int]:
    op, a, b = spec
    fa = _ORACLE_REGISTRY[a]
    if op == "sq":
        return lambda xs, _fa=fa: _fa([int(v) * int(v) for v in xs])
    if op == "mulo":
        fb = _ORACLE_REGISTRY[b]
        return lambda xs, _fa=fa, _fb=fb: _fa(list(xs)) * _fb(list(xs))
    if op.startswith("via"):
        if rs is None:
            raise ValueError("via_op_requires_runstate")
        t = _macro_transform(rs, int(op[3:]))
        return lambda xs, _fa=fa, _t=t: _fa(_t(list(xs)))
    raise ValueError(f"unknown_gen_op:{spec}")


def mint_task(rs: "RunState", spec: Tuple[str, str, str]) -> SealedTask:
    tid = f"G{len(rs.gen_specs):02d}"
    oracle = _gen_oracle(spec, rs)
    _register_oracle(tid, oracle)
    task = seal_task(tid, "self_gen", oracle)
    rs.gen_specs.append(list(spec))
    rs.gen_names[tid] = f"{spec[0]}({spec[1]}" + (f",{spec[2]})" if spec[2] else ")")
    rs.tasks.append(task)
    return task


def task_label(rs: "RunState", tid: str) -> str:
    return rs.gen_names.get(tid) or TASK_NAME_BY_TID.get(tid, tid)


def propose_mints(rs: "RunState", wave: int) -> List[Tuple[str, str, str]]:
    """System-side generator policy (public info only, deterministic):
    prefer input-square composition of the most recently adopted task --
    the move that extends whatever ladder the system is currently climbing --
    then pointwise products of recent pairs. A spec is admitted only if its
    train vector duplicates no existing task's vector and the task is not
    already adopted-equivalent; whether it is already table-reachable
    ('bridge') or beyond the current horizon ('frontier') is recorded, not
    hidden."""
    if len(rs.gen_specs) >= MAX_GEN_TASKS:
        return []
    existing_vecs = {task_target_vector(t) for t in rs.tasks}
    solved = sorted(rs.adopted_tokens,
                    key=lambda t: (-rs.adopted_wave[t], t))
    cands: List[Tuple[str, str, str]] = []
    for t in solved[:8]:
        cands.append(("sq", t, ""))
    for t in solved[:4]:
        for mid in _list_producer_mids(rs):
            cands.append((f"via{mid}", t, ""))
    for i in range(min(3, len(solved))):
        for j in range(i, min(3, len(solved))):
            cands.append(("mulo", solved[i], solved[j]))
    frontier_pool: List[Tuple[str, str, str]] = []
    bridge_pool: List[Tuple[str, str, str]] = []
    seen_new = set()
    for spec in cands:
        if list(spec) in rs.gen_specs:
            continue
        try:
            vec = tuple(int(_gen_oracle(spec, rs)(list(xs)))
                        for xs in TRAIN_INPUTS)
        except Exception:
            continue
        if vec in existing_vecs or vec in seen_new:
            continue
        seen_new.add(vec)
        # Frontier-first: headroom means beyond the CURRENT horizon, so a
        # candidate the present table already reaches is only a fallback.
        if lookup_solution(rs, vec) is None:
            frontier_pool.append(spec)
        else:
            bridge_pool.append(spec)
    ordered = frontier_pool + bridge_pool
    return ordered[:MINT_PER_WAVE]


def mint_step(rs: "RunState", wave: int) -> None:
    for spec in propose_mints(rs, wave):
        task = mint_task(rs, spec)
        reach = "bridge" if lookup_solution(rs, task_target_vector(task)) \
            else "frontier"
        rs.gen_reach[task.tid] = reach
        rs.events.append(
            f"w{wave} MINT {task.tid} {rs.gen_names[task.tid]} [{reach}]")


# ---------------------------------------------------------------------------
# Synthesis search: seeded (1+1) hill climbing with restarts. The ONLY inputs
# are train pairs and the searcher state. No oracle, no gate, no task name.
# ---------------------------------------------------------------------------
@dataclass
class SynthResult:
    tid: str
    solved: bool
    tokens: Tuple[int, ...]
    expanded_len: int
    evals_used: int
    best_score: float
    channel: str = "exploit"
    drift_evals: int = 0
    exploit_evals: int = 0
    neg_skips: int = 0
    zero_grams: Dict[Tuple[int, ...], int] = field(default_factory=dict)


def _score_tokens(tokens: Sequence[int], macros: Dict[int, Macro],
                  pairs: Sequence[Tuple[Tuple[int, ...], int]],
                  max_stack: Optional[int] = None) -> float:
    """Fraction of train pairs matched; crash on a pair scores that pair 0.
    Early exit: if the first two probe pairs both crash, bail (score 0)."""
    try:
        expanded = expand_tokens(tokens, macros)
    except VMCrash:
        return 0.0
    screen = pairs[:6]
    s_hits = 0
    crashes_head = 0
    for k, (xs, y) in enumerate(screen):
        try:
            if run_base_program(expanded, xs, max_stack=max_stack) == y:
                s_hits += 1
        except VMCrash:
            if k < 2:
                crashes_head += 1
                if crashes_head == 2:
                    return 0.0
    if s_hits < len(screen):
        # coarse but monotone-enough signal for hill-climbing; full evaluation
        # is reserved for screen-perfect candidates.
        return 0.999 * (s_hits / len(pairs))
    hits = s_hits
    for xs, y in pairs[6:]:
        try:
            if run_base_program(expanded, xs, max_stack=max_stack) == y:
                hits += 1
        except VMCrash:
            pass
    return hits / len(pairs)


# Static type/arity model of the ISA: 'i'=int, 'l'=list, '?'=either.
# (pops_rightmost_first, pushes). Exact for every base op; macros derive theirs.
OP_TYPES: Dict[int, Tuple[Tuple[str, ...], Tuple[str, ...]]] = {
    0: ((), ("i",)), 1: ((), ("i",)), 2: ((), ("i",)), 3: ((), ("i",)),
    4: ((), ("l",)),
    5: (("?",), ("?", "?")),          # DUP
    6: (("?", "?"), ("?", "?")),      # SWAP
    7: (("?",), ()),                  # DROP
    8: (("?", "?"), ("?", "?", "?")), # OVER
    9: (("i", "i"), ("i",)), 10: (("i", "i"), ("i",)), 11: (("i", "i"), ("i",)),
    12: (("i", "i"), ("i",)), 13: (("i", "i"), ("i",)),
    14: (("i", "i"), ("i",)), 15: (("i", "i"), ("i",)),
    16: (("l",), ("i",)), 17: (("l",), ("i",)), 18: (("l",), ("i",)),
    19: (("l", "i"), ("i",)),
    20: (("l",), ("l",)), 21: (("l",), ("l",)), 22: (("l",), ("l",)),
    23: (("l", "l"), ("l",)), 24: (("l", "l"), ("l",)),
    25: (("l", "l"), ("l",)), 26: (("l", "l"), ("l",)),
    27: (("l",), ("l",)), 28: (("l",), ("l",)),
    29: (("l",), ("i",)), 30: (("l",), ("i",)),
    31: (("l",), ("l",)), 32: (("l",), ("l",)),
    33: (("?", "?", "i"), ("?",)),    # SELECT
}


def _sim_types(seq: Sequence[int],
               sigs: Dict[int, Tuple[Tuple[str, ...], Tuple[str, ...]]],
               start: Tuple[str, ...] = ()) -> Optional[Tuple[str, ...]]:
    """Abstract interpretation over the type stack. Returns final type stack or
    None if any op cannot type-check. Exact w.r.t. crash-by-arity/type, modulo
    '?' wildcards (DUP/SWAP/OVER/SELECT)."""
    st: List[str] = list(start)
    for t in seq:
        sig = sigs.get(t)
        if sig is None:
            return None
        ins, outs = sig
        if len(st) < len(ins):
            return None
        popped = []
        for need in ins:                      # rightmost-first
            v = st.pop()
            if need != "?" and v != "?" and v != need:
                return None
            popped.append(v)
        if t == 5:                            # DUP: y y
            st.extend([popped[0], popped[0]])
        elif t == 6:                          # SWAP
            st.extend([popped[0], popped[1]])
        elif t == 8:                          # OVER: x y x
            st.extend([popped[1], popped[0], popped[1]])
        elif t == 33:                         # SELECT -> unify then/else
            a, b = popped[2], popped[1]
            st.append(a if a == b else "?")
        else:
            st.extend(outs)
        if len(st) > MAX_STACK:
            return None
    return tuple(st)


def build_type_sigs(macros: Dict[int, Macro]) -> Dict[int, Tuple[Tuple[str, ...], Tuple[str, ...]]]:
    """Derive a (possibly approximate) signature for each macro by simulating
    its body on a generic '?'*k prefix; falls back to depth-only typing ('?')
    when the body is polymorphic. Sound: anything passing here may still crash
    at runtime on values, but arity is exact."""
    sigs = dict(OP_TYPES)
    sigs.update(EXT_TYPES)
    for mid in sorted(macros):
        body = macros[mid].body
        found = None
        for k in range(0, 5):
            res = _sim_types(body, sigs, start=("?",) * k)
            if res is not None:
                found = (("?",) * k, tuple(res[k - len(res):] if len(res) >= k else res))                     if False else (("?",) * k, tuple(res))
                # signature: consumes k wildcards, leaves the full result stack
                # relative to those k slots.
                ins = ("?",) * k
                # outs = result stack minus untouched part is complex; use the
                # simulated whole-stack delta instead:
                found = (ins, tuple(res))
                break
        if found is None:
            sigs[mid] = (("?", "?", "?", "?"), ("?",))
        else:
            ins, full_out = found
            sigs[mid] = (ins, full_out)
    return sigs


def static_plausible(tokens: Sequence[int],
                     sigs: Dict[int, Tuple[Tuple[str, ...], Tuple[str, ...]]]) -> bool:
    res = _sim_types(tokens, sigs)
    return res is not None and len(res) == 1 and res[0] in ("i", "?")


def _sample_token(rng: random.Random, state: SearcherState) -> int:
    vocab = state.vocab()
    weights = [state.weight(t) for t in vocab]
    total = sum(weights)
    r = rng.random() * total
    acc = 0.0
    for t, w in zip(vocab, weights):
        acc += w
        if r <= acc:
            return t
    return vocab[-1]


def _random_tokens(rng: random.Random, state: SearcherState, lo: int = 2,
                   hi: Optional[int] = None) -> List[int]:
    n = rng.randint(lo, state.capacity.max_program_len if hi is None else hi)
    return [_sample_token(rng, state) for _ in range(n)]


def _mutate(rng: random.Random, state: SearcherState, tokens: List[int]) -> List[int]:
    t = list(tokens)
    op = rng.random()
    if op < 0.45 and t:
        t[rng.randrange(len(t))] = _sample_token(rng, state)
    elif op < 0.70 and len(t) < state.capacity.max_program_len:
        t.insert(rng.randrange(len(t) + 1), _sample_token(rng, state))
    elif op < 0.90 and len(t) > 2:
        del t[rng.randrange(len(t))]
    else:
        if len(t) >= 2:
            i, j = rng.randrange(len(t)), rng.randrange(len(t))
            t[i], t[j] = t[j], t[i]
    return t


# ---------------------------------------------------------------------------
# DIRECTED STOCHASTIC DRIFT + NEGATIVE-GRAMMAR FILTERING
#
# Stage-1 analog (directed drift): a fraction of stochastic restarts sample
# tokens from an ANTI-weighted distribution (low-probability regions of the
# learned proposal model, blended with uniform) and use larger edit moves.
# This is the mutation channel that escapes in-distribution local optima.
#
# Orchestrator control law: the controlled variable is DRIFT_RATE (share of
# restarts given to the drift channel == proposal entropy); the controlling
# metric is the per-channel VERIFIED-YIELD PER EVALUATION (adoptions that
# passed BOTH sealed gates, divided by candidate evaluations spent). The rate
# is updated multiplicatively each wave toward the higher-yield channel and
# clipped to [DRIFT_MIN, DRIFT_MAX]. Everything is logged (DRIFT_TUNE events)
# so the control trajectory is itself a measured result.
#
# Stage-2 cost reducer (negative grammar induction, after the user's NGI
# framework): contiguous grams that recur in type-valid but zero-scoring
# candidates and never occur in any adopted program become EVAL-SKIP filters
# in the mutation loop. They never block adoption (enumeration stays
# exhaustive; gates unchanged) and any gram contradicted by a later adoption
# is purged immediately. Effect is budget reallocation, not truth-shaping.
# ---------------------------------------------------------------------------
DRIFT_RATE_INIT = 0.30
DRIFT_MIN, DRIFT_MAX = 0.10, 0.70
DRIFT_ETA = 0.25
NEG_GRAM_PROMOTE_AT = 25
NEG_GRAM_MAX_ACTIVE = 40


def _sample_token_drift(rng: random.Random, state: SearcherState) -> int:
    """Low-probability-region sampling: invert learned weights, blend with
    uniform. The learned model's tail is exactly where unexplored structure
    lives; uniform admixture keeps support full."""
    vocab = state.vocab()
    if rng.random() < 0.5:
        return vocab[rng.randrange(len(vocab))]
    ws = [state.weight(t) for t in vocab]
    mx = max(ws) if ws else 1.0
    inv = [(mx - w) + 0.25 for w in ws]
    total = sum(inv)
    r = rng.random() * total
    acc = 0.0
    for t, w in zip(vocab, inv):
        acc += w
        if r <= acc:
            return t
    return vocab[-1]


def _mutate_drift(rng: random.Random, state: SearcherState,
                  tokens: List[int]) -> List[int]:
    """Larger edit moves for the drift channel: segment rewrite, block insert,
    or plain heavy substitution."""
    t = list(tokens)
    op = rng.random()
    if op < 0.40 and len(t) >= 2:
        i = rng.randrange(len(t))
        j = min(len(t), i + rng.randint(1, 3))
        t[i:j] = [_sample_token_drift(rng, state)
                  for _ in range(rng.randint(1, 3))]
    elif op < 0.70 and len(t) < state.capacity.max_program_len - 1:
        i = rng.randrange(len(t) + 1)
        t[i:i] = [_sample_token_drift(rng, state)
                  for _ in range(rng.randint(1, 2))]
    else:
        for _ in range(rng.randint(2, 3)):
            if t:
                t[rng.randrange(len(t))] = _sample_token_drift(rng, state)
    return t[:state.capacity.max_program_len]


def _grams(tokens: Sequence[int], lo: int = 2, hi: int = 3):
    n = len(tokens)
    for k in range(lo, hi + 1):
        for i in range(n - k + 1):
            yield tuple(tokens[i:i + k])


def _hits_negative(tokens: Sequence[int], active: set) -> bool:
    if not active:
        return False
    return any(g in active for g in _grams(tokens))


# Shared bottom-up enumeration with observational-equivalence pruning.
# Prefix runtime stacks depend only on the train INPUTS (shared by all tasks),
# so one table serves every task: a completed program is a solution for task T
# iff its output vector equals T's training-output vector. Soundness: crashing
# prefixes cannot prefix a total solution (execution is sequential), and two
# prefixes with identical stacks on every train input have identical futures.
# Caps below bound completeness (may miss), never correctness (never wrong);
# every table hit is re-verified by real execution and the external holdout
# gate before adoption.
ENUM_SURFACE_MAX = 6          # surface tokens; macros count as 1 -> adopted
                              # macros extend EXPANDED reach beyond this.
ENUM_CLASS_CAP = 50_000       # admitted equivalence classes per length
ENUM_STACK_DEPTH = 8          # prefix stack-depth bound inside the engine


@dataclass
class EnumTable:
    version: int
    solutions: Dict[Tuple[int, ...], Tuple[int, ...]]   # output vector -> tokens
    extensions: int                                     # work units performed
    classes_per_len: List[int]
    truncated: bool
    frontiers: Optional[List[Dict[Tuple, Tuple[int, ...]]]] = None
    rewrites: List[Tuple[Tuple[int, ...], Tuple[int, ...]]] = field(default_factory=list)


def build_enum_table(state: SearcherState,
                     surface_max: int = ENUM_SURFACE_MAX,
                     class_cap: int = ENUM_CLASS_CAP,
                     keep_frontiers: bool = False,
                     priority_tokens: Optional[Sequence[int]] = None,
                     vocab_override: Optional[Sequence[int]] = None) -> EnumTable:
    """Thin capacity wrapper: the enumeration executes ops under the
    searcher's max_stack (so a grown-capacity candidate is judged by the
    unchanged meta_gate machinery at its own capacity), restored on exit.
    Enumeration budgets (surface_max, class_cap, ENUM_STACK_DEPTH) are
    budgets, not capacity, and stay identical across A/B arms."""
    prev = _ACTIVE_MAX_STACK[0]
    _ACTIVE_MAX_STACK[0] = state.capacity.max_stack
    try:
        return _build_enum_table_inner(state, surface_max, class_cap,
                                       keep_frontiers, priority_tokens,
                                       vocab_override)
    finally:
        _ACTIVE_MAX_STACK[0] = prev


def _build_enum_table_inner(state: SearcherState,
                            surface_max: int = ENUM_SURFACE_MAX,
                            class_cap: int = ENUM_CLASS_CAP,
                            keep_frontiers: bool = False,
                            priority_tokens: Optional[Sequence[int]] = None,
                            vocab_override: Optional[Sequence[int]] = None) -> EnumTable:
    """Abstraction-first order: newest macros enumerate before base ops, and a
    reserved admission lane keeps macro-bearing prefixes alive under the class
    cap. Rationale (measured, wave-0 dissection): without the lane, macro
    branching inflates class counts and the cap evicts exactly the deep
    macro-built states an improvement exists to create -- abstractions must not
    be priced out by their own branching cost. Proposal weights do NOT shape
    enumeration; they only bias the stochastic phase."""
    macros = state.macros
    if vocab_override is not None:
        vocab = list(vocab_override)
    else:
        pri = [t for t in (priority_tokens or []) if t in macros]
        rest = sorted((k for k in macros if k not in set(pri)), reverse=True)
        vocab = pri + rest + list(range(N_BASE_OPS))
    # Token application plan. Pure-producer macros (consume nothing below,
    # values depend only on the input) are evaluated ONCE per train input and
    # cached; applying them becomes an O(pushes) append instead of replaying
    # the full expanded body -- the cost term that otherwise grows with macro
    # depth times bigint width. Non-producers fall back to op replay.
    bodies: Dict[int, Tuple[str, object]] = {}
    for t in vocab:
        if t < N_BASE_OPS or t in EXT_IMPL:
            bodies[t] = ("ops", (t,))
            continue
        try:
            exp = expand_tokens(macros[t].body, macros)
        except VMCrash:
            continue
        cached: List[Tuple[object, ...]] = []
        producer = True
        for xs in TRAIN_INPUTS:
            s: List[object] = []
            try:
                for b in exp:
                    (OP_IMPL[b] if b < N_BASE_OPS else EXT_IMPL[b])(s, xs)
            except VMCrash:
                producer = False
                break
            cached.append(tuple(s))
        bodies[t] = ("cached", tuple(cached)) if producer else ("ops", exp)
    inputs = TRAIN_INPUTS
    empty_sig: Tuple[Tuple[object, ...], ...] = tuple(() for _ in inputs)
    frontier: Dict[Tuple, Tuple[int, ...]] = {empty_sig: ()}
    frontier_has_macro: Dict[Tuple, bool] = {empty_sig: False}
    solutions: Dict[Tuple[int, ...], Tuple[int, ...]] = {}
    ext = 0
    truncated = False
    classes_per_len: List[int] = []
    kept: List[Dict[Tuple, Tuple[int, ...]]] = []
    # Shortcut harvest: shallow-layer states (surface length <= 3) are kept in
    # a side map; any deeper prefix colliding with one is (a) soundly pruned
    # (the shallow twin's subtree already covers it within the horizon) and
    # (b) recorded as a prefix REWRITE RULE long->short. These rules are the
    # 'high-dimensional shortcuts' the enumeration discovers anyway; instead
    # of discarding them, the system reingests them as meta-rules that
    # normalize adopted programs before macro mining. Verification paths
    # never consume rules, so they cannot distort ground truth.
    shallow_map: Dict[Tuple, Tuple[int, ...]] = {}
    rewrites: List[Tuple[Tuple[int, ...], Tuple[int, ...]]] = []
    cap_base = class_cap if not macros else (class_cap * 3) // 5
    for _L in range(1, surface_max + 1):
        nxt: Dict[Tuple, Tuple[int, ...]] = {}
        nxt_has_macro: Dict[Tuple, bool] = {}
        n_base_admitted = 0
        for sig, toks in frontier.items():
            parent_macro = frontier_has_macro[sig]
            for t in vocab:
                plan = bodies.get(t)
                if plan is None:
                    continue
                ext += 1
                kind, payload = plan
                new_stacks = []
                ok = True
                if kind == "cached":
                    for st, pushed in zip(sig, payload):
                        if len(st) + len(pushed) > ENUM_STACK_DEPTH:
                            ok = False
                            break
                        new_stacks.append(st + pushed)
                else:
                    for st, xs in zip(sig, inputs):
                        s = list(st)
                        try:
                            for b in payload:
                                (OP_IMPL[b] if b < N_BASE_OPS else EXT_IMPL[b])(s, xs)
                        except VMCrash:
                            ok = False
                            break
                        if len(s) > ENUM_STACK_DEPTH:
                            ok = False
                            break
                        new_stacks.append(tuple(s))
                if not ok:
                    continue
                nsig = tuple(new_stacks)
                if all(len(s) == 1 and isinstance(s[0], int) for s in nsig):
                    vec = tuple(s[0] for s in nsig)
                    if vec not in solutions:
                        solutions[vec] = toks + (t,)
                if nsig in nxt:
                    continue                       # within-length equivalence
                if _L >= 4:
                    short = shallow_map.get(nsig)
                    if short is not None:
                        if len(rewrites) < 400:
                            rewrites.append((toks + (t,), short))
                        continue                   # sound cross-length prune
                has_macro = parent_macro or t >= MACRO_ID_BASE
                if has_macro:
                    admit = len(nxt) < class_cap
                else:
                    admit = n_base_admitted < cap_base and len(nxt) < class_cap
                if admit:
                    nxt[nsig] = toks + (t,)
                    nxt_has_macro[nsig] = has_macro
                    if not has_macro:
                        n_base_admitted += 1
                else:
                    truncated = True
        classes_per_len.append(len(nxt))
        if _L <= 3:
            shallow_map.update(nxt)
        if keep_frontiers:
            kept.append(nxt)
        frontier = nxt
        frontier_has_macro = nxt_has_macro
        if not frontier:
            break
    return EnumTable(version=state.version, solutions=solutions,
                     extensions=ext, classes_per_len=classes_per_len,
                     truncated=truncated,
                     frontiers=kept if keep_frontiers else None,
                     rewrites=rewrites)


def gated_solution_count(solutions, macros, probes) -> int:
    solved = 0
    for task in probes:
        toks = solutions.get(task_target_vector(task))
        if toks is None:
            continue
        try:
            fn = compile_program(toks, macros)
        except VMCrash:
            continue
        if task.holdout_gate(fn) and task.cf_gate(fn):
            solved += 1
    return solved



def task_target_vector(task: SealedTask) -> Tuple[int, ...]:
    return tuple(y for _, y in task.train_pairs)


def synthesize(task_train_pairs: Sequence[Tuple[Tuple[int, ...], int]],
               tid: str,
               state: SearcherState,
               seed: int,
               restarts: int = RESTARTS_PER_TASK,
               iters: int = ITERS_PER_RESTART,
               seed_pool: Optional[Sequence[Tuple[int, ...]]] = None,
               drift_rate: float = DRIFT_RATE_INIT,
               neg_active: Optional[set] = None) -> SynthResult:
    """Dual-channel budgeted stochastic search. EXPLOIT restarts follow the
    learned proposal weights; DRIFT restarts sample the low-probability region
    with larger edits (the mutation channel). Negative grams skip evaluation
    only -- they cannot block an adoption and never touch enumeration.
    Receives NO oracle and NO gate; exact short-program coverage comes from
    the shared enumeration table consulted by the caller."""
    evals = 0
    d_evals = 0
    e_evals = 0
    skips = 0
    zero_grams: Dict[Tuple[int, ...], int] = {}
    neg = neg_active or set()
    best_tokens: Tuple[int, ...] = ()
    best_score = -1.0
    best_channel = "exploit"
    sigs = build_type_sigs(state.macros)
    pool = [p for p in (seed_pool or []) if p]
    n_drift = max(0, min(restarts, round(restarts * drift_rate)))
    for r in range(restarts):
        is_drift = r < n_drift
        chan = "drift" if is_drift else "exploit"
        rng = random.Random((seed * 1_000_003) ^ (r * 7919) ^ (137 if is_drift else 0))
        if pool and not is_drift and r % 3 == 2:
            cur = _mutate(rng, state, list(rng.choice(pool)))
        elif is_drift:
            if pool and rng.random() < 0.8:
                cur = list(rng.choice(pool))
                for _ in range(rng.randint(2, 4)):
                    cur = _mutate_drift(rng, state, cur)
                if not cur:
                    cur = [_sample_token_drift(rng, state)]
            else:
                cur = [_sample_token_drift(rng, state)
                       for _ in range(rng.randint(3, state.capacity.max_program_len))]
        else:
            cur = _random_tokens(rng, state)
        cur_score = _score_tokens(cur, state.macros, task_train_pairs,
                                  max_stack=state.capacity.max_stack)
        evals += 1
        if is_drift:
            d_evals += 1
        else:
            e_evals += 1
        for it in range(iters):
            cand = (_mutate_drift if is_drift else _mutate)(rng, state, cur)
            if not static_plausible(cand, sigs):
                continue
            if _hits_negative(cand, neg):
                skips += 1
                continue
            s = _score_tokens(cand, state.macros, task_train_pairs,
                              max_stack=state.capacity.max_stack)
            evals += 1
            if is_drift:
                d_evals += 1
            else:
                e_evals += 1
            if s == 0.0:
                for g in _grams(cand):
                    zero_grams[g] = zero_grams.get(g, 0) + 1
            better = s > cur_score or (s == cur_score and len(cand) < len(cur))
            if not better and is_drift and s < cur_score:
                temp = max(0.02, 0.35 * (1.0 - it / max(1, iters)))
                if rng.random() < math.exp((s - cur_score) / temp):
                    better = True              # annealed downhill acceptance
            if better:
                cur, cur_score = cand, s
            if cur_score > best_score or (cur_score == best_score and len(cur) < len(best_tokens or cur) + 1):
                best_tokens, best_score = tuple(cur), cur_score
                best_channel = chan
            if cur_score >= 1.0:
                exp = expand_tokens(cur, state.macros)
                return SynthResult(tid, True, tuple(cur), len(exp), evals, 1.0,
                                   channel=chan, drift_evals=d_evals,
                                   exploit_evals=e_evals, neg_skips=skips,
                                   zero_grams=zero_grams)
    exp_len = 0
    try:
        exp_len = len(expand_tokens(best_tokens, state.macros))
    except VMCrash:
        pass
    return SynthResult(tid, False, best_tokens, exp_len, evals,
                       max(best_score, 0.0), channel=best_channel,
                       drift_evals=d_evals, exploit_evals=e_evals,
                       neg_skips=skips, zero_grams=zero_grams)


def compile_program(tokens: Sequence[int], macros: Dict[int, Macro],
                    max_stack: Optional[int] = None) -> Callable[[List[int]], int]:
    expanded = expand_tokens(tokens, macros)

    def fn(xs: List[int]) -> int:
        return run_base_program(expanded, xs, max_stack=max_stack)

    fn.__rsi_vm_program__ = tuple(expanded)  # marker: this is a synthesized fn
    return fn


# ---------------------------------------------------------------------------
# REWRITE-RULE REINGESTION (meta-rules from enumeration shortcuts).
# A rule (long_prefix -> short_prefix) is train-behavior-preserving for any
# program that STARTS with long_prefix, because prefix execution is
# context-free from the left. Normalization is applied only to mining input:
# surface variants of one idea collapse, n-gram recurrence sharpens, macro
# proposals improve. Rules never touch adoption, gating, or enumeration
# correctness paths.
# ---------------------------------------------------------------------------
REWRITE_RULES_MAX = 120
REWRITE_PASSES = 3


def _rule_holds_small_domain(long_p: Tuple[int, ...],
                             short_p: Tuple[int, ...],
                             macros: Dict[int, "Macro"]) -> bool:
    """Exhaustive check on every input list of length 0..3 over values 0..3
    (85 inputs): both prefixes must execute and leave identical stacks. This
    upgrades train-collision evidence to a small-domain formal proof; rules
    failing it are discarded."""
    try:
        le = expand_tokens(long_p, macros)
        se = expand_tokens(short_p, macros)
    except VMCrash:
        return False
    from itertools import product as _prod
    for n in range(0, 4):
        for vals in _prod(range(4), repeat=n):
            xs = list(vals)
            sa: List[object] = []
            sb: List[object] = []
            try:
                for b in le:
                    (OP_IMPL[b] if b < N_BASE_OPS else EXT_IMPL[b])(sa, xs)
                for b in se:
                    (OP_IMPL[b] if b < N_BASE_OPS else EXT_IMPL[b])(sb, xs)
            except VMCrash:
                return False
            if sa != sb:
                return False
    return True


def absorb_rewrites(rs: "RunState", table: "EnumTable") -> None:
    if not table.rewrites:
        return
    known = {tuple(l) for l, _ in rs.rewrite_rules}
    JUGGLE = {0, 1, 2, 3, 5, 6, 7, 8}      # constants + pure stack shuffling
    cands = []
    for long_p, short_p in table.rewrites:
        lp, sp = tuple(long_p), tuple(short_p)
        if lp in known or len(sp) >= len(lp):
            continue
        if all(t in JUGGLE for t in lp):
            continue                        # zero mining value
        if not _rule_holds_small_domain(lp, sp, rs.searcher.macros):
            continue                        # train-coincidence; not a law
        savings = len(lp) - len(sp)
        rich = sum(1 for t in lp if t >= 16 or t >= MACRO_ID_BASE)
        cands.append((-savings, -rich, lp, sp))
    cands.sort()
    added = 0
    for _, _, lp, sp in cands:
        if len(rs.rewrite_rules) >= REWRITE_RULES_MAX:
            break
        rs.rewrite_rules.append((lp, sp))
        known.add(lp)
        added += 1
    if added:
        rs.rewrite_rules.sort(key=lambda lp: (-len(lp[0]), lp[0]))
        rs.events.append(
            f"REWRITE_ABSORB +{added} rules total={len(rs.rewrite_rules)} "
            f"example={rs.rewrite_rules[0][0]}->{rs.rewrite_rules[0][1]}")


def normalize_prefix(tokens: Tuple[int, ...],
                     rules: List[Tuple[Tuple[int, ...], Tuple[int, ...]]]
                     ) -> Tuple[int, ...]:
    """Longest-rule-first prefix rewriting, bounded passes, deterministic."""
    cur = tuple(tokens)
    for _ in range(REWRITE_PASSES):
        changed = False
        for long_p, short_p in rules:
            lp = len(long_p)
            if len(cur) >= lp and cur[:lp] == long_p:
                cur = short_p + cur[lp:]
                changed = True
                break
        if not changed:
            break
    return cur


# ---------------------------------------------------------------------------
# Improvement proposals: mined from the system's OWN adopted programs.
#   IO1 compress: frequent contiguous n-grams -> macro candidates (nesting OK).
#   IO2 reweight: token statistics of adopted programs -> proposal weights.
# Both land only through the meta-gate below.
# ---------------------------------------------------------------------------
@dataclass
class ImprovementProposal:
    wave: int
    new_macros: List[Macro]
    new_weights: Dict[int, float]
    note: str
    capacity: Optional[CapacityConfig] = None   # Rule 2 growth rider; None
                                                # for ordinary proposals


def mine_macros(adopted: Dict[str, Tuple[int, ...]], state: SearcherState,
                wave: int, top_k: int = 3) -> List[Macro]:
    counts: Dict[Tuple[int, ...], List[str]] = {}
    for tid, toks in adopted.items():
        L = len(toks)
        for n in range(2, min(MAX_MACRO_BODY, L) + 1):
            for i in range(L - n + 1):
                sub = tuple(toks[i:i + n])
                counts.setdefault(sub, []).append(tid)
    existing_bodies = {m.body for m in state.macros.values()}
    scored = []
    for sub, tids in counts.items():
        n_tasks = len(set(tids))
        has_macro = any(t >= MACRO_ID_BASE for t in sub)
        if n_tasks < 2 and not has_macro:
            continue                    # base-op grams must recur across tasks;
                                        # macro-bearing grams (recursive
                                        # composition candidates) may not.
        if sub in existing_bodies:
            continue
        if len(set(sub)) == 1 and not has_macro:
            continue
        try:
            exp = expand_tokens(sub, state.macros)
        except VMCrash:
            continue
        if len(exp) < 3:
            continue                    # cannot cross the horizon: compression
                                        # of a single surface token never turns
                                        # an unreachable program reachable.
        depth = 1 + max((state.macros[t].depth for t in sub if t >= MACRO_ID_BASE), default=0)
        if depth > MACRO_DEPTH_CAP:
            continue
        score = n_tasks * len(exp) + (len(exp) if has_macro else 0)
        scored.append((score, sub, tuple(sorted(set(tids))), depth))
    scored.sort(key=lambda z: (-z[0], z[1]))
    out: List[Macro] = []
    next_id = max(state.macros.keys(), default=MACRO_ID_BASE - 1) + 1
    for score, sub, tids, depth in scored[:top_k]:
        if len(state.macros) + len(out) >= state.capacity.max_macros:
            break
        out.append(Macro(mid=next_id, body=sub, depth=depth,
                         wave_discovered=wave, parent_tasks=tids))
        next_id += 1
    return out


def derive_weights(adopted: Dict[str, Tuple[int, ...]], state: SearcherState,
                   smoothing: float = 1.0) -> Dict[int, float]:
    counts: Dict[int, float] = {}
    for toks in adopted.values():
        for t in toks:
            counts[t] = counts.get(t, 0.0) + 1.0
    vocab = state.vocab()
    total = sum(counts.values()) + smoothing * len(vocab)
    out: Dict[int, float] = {}
    for t in vocab:
        p = (counts.get(t, 0.0) + smoothing) / total
        out[t] = max(0.25, min(6.0, p * len(vocab)))
    return out


def propose_improvement(adopted: Dict[str, Tuple[int, ...]],
                        state: SearcherState, wave: int,
                        rewrite_rules: Optional[List[Tuple[Tuple[int, ...], Tuple[int, ...]]]] = None
                        ) -> Optional[ImprovementProposal]:
    norm_changed = 0
    if rewrite_rules:
        normed = {}
        for tid, toks in adopted.items():
            nt = normalize_prefix(toks, rewrite_rules)
            if nt != toks:
                norm_changed += 1
            normed[tid] = nt
        adopted = normed
    macros = mine_macros(adopted, state, wave)
    if not adopted:
        return None
    weights = derive_weights(adopted, state)
    # give freshly mined macros a real chance to be sampled
    for m in macros:
        weights[m.mid] = 2.5
    if not macros and weights == state.weights:
        return None
    note = (f"wave{wave}: +{len(macros)} macros, reweight over "
            f"{len(weights)} tokens, norm_changed={norm_changed}")
    return ImprovementProposal(wave=wave, new_macros=macros, new_weights=weights, note=note)


# ---------------------------------------------------------------------------
# META-GATE: an improvement is adopted only if the candidate searcher
# empirically beats-or-ties the incumbent on the unsolved frontier under
# IDENTICAL budget and seeds. Regressions are rejected and logged. This is the
# self-modification gate: the system's own output must prove itself before it
# becomes part of the system.
# ---------------------------------------------------------------------------
@dataclass
class MetaGateRecord:
    wave: int
    accepted: bool
    inc_solved: int
    cand_solved: int
    inc_extensions: int
    cand_extensions: int
    probe_tids: Tuple[str, ...]
    note: str


def _apply(incumbent: SearcherState, macros: List[Macro],
           weights: Optional[Dict[int, float]], note: str,
           capacity: Optional[CapacityConfig] = None) -> SearcherState:
    cand = incumbent.clone()
    for m in macros:
        cand.macros[m.mid] = m
    if weights is not None:
        cand.weights = dict(weights)
    if capacity is not None:
        cand.capacity = capacity
    cand.version += 1
    cand.history.append(note)
    return cand


def ensure_worktable(rs: "RunState") -> None:
    """One shared working table per run: base-vocabulary enumeration with
    frontiers kept. Accepted macros never trigger rebuilds; their cones are
    merged into these frontiers, so later cones root on earlier ones and
    nested abstractions arise by construction."""
    if rs.work_table is not None:
        return
    rs.work_table = build_enum_table(rs.searcher,
                                     surface_max=ENUM_SURFACE_MAX,
                                     class_cap=ENUM_CLASS_CAP,
                                     keep_frontiers=True)
    rs.enum_extensions_total += rs.work_table.extensions
    absorb_rewrites(rs, rs.work_table)
    rs.events.append(
        f"WORK_TABLE v{rs.searcher.version} "
        f"solutions={len(rs.work_table.solutions)} "
        f"ext={rs.work_table.extensions} "
        f"classes={rs.work_table.classes_per_len} "
        f"truncated={rs.work_table.truncated}")


def lookup_solution(rs: "RunState", vec: Tuple[int, ...]) -> Optional[Tuple[int, ...]]:
    hit = rs.extra_solutions.get(vec)
    if hit is not None:
        return hit
    return rs.work_table.solutions.get(vec) if rs.work_table else None


# ---------------------------------------------------------------------------
# TCCI: Transferable Counterfactual Compression Index for macro candidates.
# Adapted from the ECT+TCCI core (user framework): a proposed abstraction is
# scored on compression (broad capture / short body), transfer (across task
# FAMILIES, metadata never visible to search), and anti-cheat (input-coupled
# structure, not constant-pushing surface). The pre-score ORDERS single-macro
# judgments; recovery (holdout+cf gated gains) remains the hard acceptance
# criterion and is written back into the report after judgment.
# ---------------------------------------------------------------------------
def _contains_gram(toks: Tuple[int, ...], body: Tuple[int, ...]) -> bool:
    n, m = len(toks), len(body)
    return any(toks[i:i + m] == body for i in range(n - m + 1))


def tcci_pre_score(rs: "RunState", m: Macro) -> Dict[str, float]:
    adopted = rs.adopted_tokens
    try:
        exp = expand_tokens(m.body, {**rs.searcher.macros, m.mid: m})
    except VMCrash:
        return {"compression": 0.0, "transfer": 0.0, "anti_cheat": 0.0,
                "pre_total": 0.0}
    captured = [tid for tid, toks in adopted.items()
                if _contains_gram(toks, m.body)]
    capture_rate = len(captured) / max(1, len(adopted))
    fams = {TASK_FAMILY_BY_TID.get(t, "?") for t in captured}
    all_fams = {TASK_FAMILY_BY_TID.get(t, "?") for t in adopted} or {"?"}
    family_diversity = min(1.0, len(fams) / 5.0)
    length_bonus = 1.0 / (1.0 + math.log1p(len(exp)) / 10.0)
    compression = min(1.0, 0.65 * capture_rate + 0.20 * family_diversity
                      + 0.15 * length_bonus)
    transfer = len(fams) / len(all_fams)
    input_coupled = sum(1 for b in exp if b not in (0, 1, 2, 3))
    anti_cheat = input_coupled / max(1, len(exp))
    pre_total = 0.5 * compression + 0.3 * transfer + 0.2 * anti_cheat
    return {"compression": round(compression, 4),
            "transfer": round(transfer, 4),
            "anti_cheat": round(anti_cheat, 4),
            "pre_total": round(pre_total, 4),
            "captured": sorted(captured)}


def _install(rs: "RunState", mset: List[Macro], weights, note: str,
             table: Optional[EnumTable],
             capacity: Optional[CapacityConfig] = None) -> None:
    rs.searcher = _apply(rs.searcher, mset, weights, note, capacity=capacity)
    if table is None:
        table = build_enum_table(rs.searcher,
                                 surface_max=ENUM_SURFACE_MAX,
                                 class_cap=ENUM_CLASS_CAP,
                                 keep_frontiers=True)
        rs.enum_extensions_total += table.extensions
    rs.work_table = table
    rs.extra_solutions = {}
    absorb_rewrites(rs, table)
    rs.events.append(
        f"SEARCHER_NOW v{rs.searcher.version} macros={sorted(rs.searcher.macros)} "
        f"table_solutions={len(table.solutions)} classes={table.classes_per_len} "
        f"truncated={table.truncated}")


def meta_gate(rs: "RunState", proposal: ImprovementProposal,
              wave: int) -> bool:
    """Self-modification gate, generation-exact.

    Singles are PRE-SCREENED by macro cones (cheap incremental reachability);
    a cone win is decisive because cone solutions are real programs that then
    face holdout. A cone can also MISS deep single-lineage chains -- per-level
    caps times branching evict rank-r parents' children at 38r -- so when no
    single survives, the full bundle gets ONE exact candidate-table test.
    Every acceptance triggers a fresh worktable rebuild with the new
    vocabulary (abstraction-first, macro lane), restoring exact per-generation
    enumeration instead of approximating across generations. Regressions never
    land: acceptance requires >= 1 previously-unsolved task whose new program
    passes the external holdout gate."""
    ensure_worktable(rs)
    probes = rs.unsolved()
    if not probes:
        rs.gate_records.append(
            MetaGateRecord(wave, False, 0, 0, 0, 0, (), "empty_frontier"))
        return False
    tids = tuple(t.tid for t in probes)
    base_solved = sum(
        1 for t in probes if lookup_solution(rs, task_target_vector(t)) is not None)
    any_accept = False

    def record(tag, accept, gained, ext):
        rs.gate_records.append(MetaGateRecord(
            wave=wave, accepted=accept,
            inc_solved=base_solved, cand_solved=base_solved + gained,
            inc_extensions=0, cand_extensions=ext,
            probe_tids=tids, note=f"{proposal.note} [{tag}]"))
        rs.events.append(
            f"w{wave} {'META_ACCEPT' if accept else 'META_REJECT'} "
            f"[{tag}] gained={gained} ext={ext}")

    ranked = sorted(proposal.new_macros,
                    key=lambda m: (-tcci_pre_score(rs, m)["pre_total"], m.mid))
    for m in ranked:
        pre = tcci_pre_score(rs, m)
        pre.update({"wave": wave, "depth": m.depth,
                    "body": token_str(m.body, {**rs.searcher.macros, m.mid: m})})
        rs.tcci_reports[m.mid] = pre

    cand = _apply(rs.searcher, ranked, proposal.new_weights,
                  f"{proposal.note} [bundle]", capacity=proposal.capacity)
    # Macro-closure screen: ladder-regime solutions are macro-dense by
    # construction, so a tiny vocabulary -- every macro plus the base ops the
    # system itself uses most -- finds them in seconds. Full-table fallback
    # preserves completeness when the screen sees nothing.
    base_freq: Dict[int, int] = {}
    for toks in rs.adopted_tokens.values():
        for t in expand_tokens(toks, rs.searcher.macros):
            base_freq[t] = base_freq.get(t, 0) + 1
    top_base = [t for t, _ in sorted(base_freq.items(),
                                     key=lambda kv: (-kv[1], kv[0]))[:rs.screen_topbase]]
    screen_vocab = ([m.mid for m in ranked]
                    + sorted(cand.macros.keys() - {m.mid for m in ranked},
                             reverse=True) + top_base)
    screen = build_enum_table(cand, surface_max=ENUM_SURFACE_MAX,
                              class_cap=rs.screen_cap,
                              vocab_override=screen_vocab)
    rs.gate_extensions_total += screen.extensions
    screen_new = {v: t for v, t in screen.solutions.items()
                  if lookup_solution(rs, v) is None}
    screen_pairs = []
    for task in probes:
        toks = screen_new.get(task_target_vector(task))
        if toks is None:
            continue
        try:
            fn = compile_program(toks, cand.macros,
                                 max_stack=cand.capacity.max_stack)
        except VMCrash as e:
            rs.events.append(f"w{wave} CAND_COMPILE_CRASH {task.tid} {e} toks={toks}")
            continue
        if task.holdout_gate(fn) and task.cf_gate(fn):
            screen_pairs.append((task.tid, toks))
    if screen_pairs:
        rs.cascade_stats["screen_hits"] += 1
        rs.cascade_stats["consecutive_hits"] += 1
        if rs.cascade_stats["consecutive_hits"] >= 2:
            old_tb, old_cap = rs.screen_topbase, rs.screen_cap
            rs.screen_topbase = max(8, rs.screen_topbase - 2)
            rs.screen_cap = max(12_000, rs.screen_cap - 4_000)
            rs.cascade_stats["consecutive_hits"] = 0
            if (old_tb, old_cap) != (rs.screen_topbase, rs.screen_cap):
                rs.events.append(
                    f"w{wave} CASCADE_TUNE narrow topbase {old_tb}->"
                    f"{rs.screen_topbase} cap {old_cap}->{rs.screen_cap}")
        record("macro_closure_screen", True, len(screen_pairs),
               screen.extensions)
        used_ids = {t for _, tk in screen_pairs for t in tk
                    if t >= MACRO_ID_BASE and t in {m.mid for m in ranked}}
        keep = [m for m in ranked if m.mid in used_ids]
        dropped = sorted(m.mid for m in ranked if m.mid not in used_ids)
        for m in ranked:
            rep = rs.tcci_reports[m.mid]
            rep["recovery_gained_tasks"] = sorted(
                tid for tid, tk in screen_pairs if m.mid in tk)
            rep["used_in_gain"] = m.mid in used_ids
            rep["accepted"] = True
            rep["judged_via"] = "macro_closure_screen"
        _install(rs, keep, proposal.new_weights,
                 f"{proposal.note} [screen_install]", table=None,
                 capacity=proposal.capacity)
        rs.events.append(
            f"w{wave} SCREEN_INSTALL dropped_riders={dropped} "
            f"gained={[tid for tid, _ in screen_pairs]}")
        return True
    record("macro_closure_screen", False, 0, screen.extensions)
    rs.cascade_stats["consecutive_hits"] = 0
    tab = build_enum_table(cand, surface_max=ENUM_SURFACE_MAX,
                           class_cap=ENUM_CLASS_CAP, keep_frontiers=True,
                           priority_tokens=[m.mid for m in ranked])
    rs.gate_extensions_total += tab.extensions
    new_sols = {v: t for v, t in tab.solutions.items()
                if lookup_solution(rs, v) is None}
    gained_pairs = []
    for task in probes:
        toks = new_sols.get(task_target_vector(task))
        if toks is None:
            continue
        try:
            fn = compile_program(toks, cand.macros,
                                 max_stack=cand.capacity.max_stack)
        except VMCrash as e:
            rs.events.append(f"w{wave} CAND_COMPILE_CRASH {task.tid} {e} toks={toks}")
            continue
        if task.holdout_gate(fn) and task.cf_gate(fn):
            gained_pairs.append((task.tid, toks))
    gained = len(gained_pairs)
    accept = gained >= 1
    if accept:
        # screen false negative: the filter threshold was too tight; widen.
        rs.cascade_stats["screen_misses"] += 1
        old_tb, old_cap = rs.screen_topbase, rs.screen_cap
        rs.screen_topbase = min(24, rs.screen_topbase + 4)
        rs.screen_cap = min(40_000, rs.screen_cap + 8_000)
        rs.events.append(
            f"w{wave} CASCADE_TUNE widen topbase {old_tb}->{rs.screen_topbase} "
            f"cap {old_cap}->{rs.screen_cap} (screen false negative)")
    else:
        rs.cascade_stats["clean_rejects"] += 1
    record("bundle_table", accept, gained, tab.extensions)
    # usage-based credit assignment: a proposed macro earns credit iff it
    # appears in the token stream of a task it just made reachable.
    used_ids = {t for _, toks in gained_pairs for t in toks if t >= MACRO_ID_BASE}
    for m in ranked:
        rep = rs.tcci_reports[m.mid]
        rep["recovery_gained_tasks"] = sorted(
            tid for tid, toks in gained_pairs if m.mid in toks)
        rep["used_in_gain"] = m.mid in used_ids
        rep["accepted"] = accept
    if accept:
        keep = [m for m in ranked if m.mid in used_ids]
        dropped = sorted(m.mid for m in ranked if m.mid not in used_ids)
        final = _apply(rs.searcher, keep, proposal.new_weights,
                       f"{proposal.note} [installed_used_only]",
                       capacity=proposal.capacity)
        ok_ids = set(final.macros)
        tab.solutions = {v: t for v, t in tab.solutions.items()
                         if all(tok < MACRO_ID_BASE or tok in ok_ids
                                for tok in t)}
        rs.searcher = final
        rs.work_table = tab
        rs.extra_solutions = {}
        any_accept = True
        rs.events.append(
            f"SEARCHER_NOW v{final.version} macros={sorted(final.macros)} "
            f"dropped_riders={dropped} gained={[tid for tid, _ in gained_pairs]} "
            f"classes={tab.classes_per_len} truncated={tab.truncated}")
    return any_accept


# ---------------------------------------------------------------------------
# Rule 2 for the top core (Phase A): stagnation-triggered, gate-approved
# capacity growth. Trigger = the run's existing no-fresh-material condition
# (zero adoptions this wave AND no newly minted unreachable frontier task)
# while designer tasks remain OPEN. The grown-capacity candidate rides an
# ordinary ImprovementProposal through the UNCHANGED meta_gate; capacity is
# adopted only when the gate finds >= 1 newly gated previously-unsolved task
# at identical enumeration budgets. Every attempt is appended to
# rs.growth_log with its trigger values, old -> new capacity, and the range
# of gate records the attempt produced. A capacity change without an
# accepted growth_log entry is a bug (audited by test).
# ---------------------------------------------------------------------------
def next_capacity_rung(cap: CapacityConfig) -> Optional[CapacityConfig]:
    """Deterministic growth ladder; None when the bounds are reached."""
    nxt = CapacityConfig(
        max_program_len=min(cap.max_program_len + CAPACITY_GROWTH_STEP_LEN,
                            CAPACITY_BOUND_PROGRAM_LEN),
        max_stack=min(cap.max_stack * 2, CAPACITY_BOUND_STACK),
        max_macros=min(cap.max_macros + CAPACITY_GROWTH_STEP_MACROS,
                       CAPACITY_BOUND_MACROS))
    return None if nxt == cap else nxt


def attempt_capacity_growth(rs: "RunState", wave: int) -> bool:
    old = rs.searcher.capacity
    open_designer = sorted(t.tid for t in rs.unsolved()
                           if t.tid.startswith("T"))
    if not open_designer:
        return False                     # no designer wall: nothing to cross
    grown = next_capacity_rung(old)
    if grown is None:
        rs.events.append(
            f"w{wave} GROWTH_BOUND_REACHED len={old.max_program_len} "
            f"stack={old.max_stack} macros={old.max_macros}")
        return False
    tmp = rs.searcher.clone()
    tmp.capacity = grown
    macros = mine_macros(rs.adopted_tokens, tmp, wave)
    weights = None
    if rs.adopted_tokens:
        weights = derive_weights(rs.adopted_tokens, rs.searcher)
        for m in macros:
            weights[m.mid] = 2.5
    note = (f"wave{wave}: capacity_growth "
            f"len{old.max_program_len}->{grown.max_program_len} "
            f"stack{old.max_stack}->{grown.max_stack} "
            f"macros{old.max_macros}->{grown.max_macros} "
            f"+{len(macros)} macros")
    proposal = ImprovementProposal(wave=wave, new_macros=macros,
                                   new_weights=weights, note=note,
                                   capacity=grown)
    pdig = hashlib.sha256(json.dumps({
        "m": [list(m.body) for m in macros],
        "w": ({k: round(v, 6) for k, v in sorted(weights.items())}
              if weights else None),
        "cap": [grown.max_program_len, grown.max_stack, grown.max_macros],
    }, sort_keys=True).encode()).hexdigest()[:16]
    if pdig in rs.rejected_digests:
        rs.events.append(f"w{wave} SKIP_DUPLICATE_GROWTH {pdig}")
        return False
    n_rec = len(rs.gate_records)
    ok = meta_gate(rs, proposal, wave)
    if not ok:
        rs.rejected_digests.append(pdig)
    rs.growth_log.append({
        "wave": wave,
        "trigger": {"fresh_adopt": 0, "fresh_frontier": False,
                    "open_designer": open_designer},
        "old": {"max_program_len": old.max_program_len,
                "max_stack": old.max_stack,
                "max_macros": old.max_macros},
        "new": {"max_program_len": grown.max_program_len,
                "max_stack": grown.max_stack,
                "max_macros": grown.max_macros},
        "accepted": bool(ok),
        "gate_records": [n_rec, len(rs.gate_records)],
        "proposal_digest": pdig,
    })
    rs.events.append(
        f"w{wave} {'GROWTH_ADOPT' if ok else 'GROWTH_REJECT'} "
        f"len{old.max_program_len}->{grown.max_program_len} "
        f"stack{old.max_stack}->{grown.max_stack} "
        f"macros{old.max_macros}->{grown.max_macros} "
        f"open={','.join(open_designer)}")
    return bool(ok)


# ---------------------------------------------------------------------------
# Wave loop. `adaptive=True` runs the full self-improvement cycle;
# `adaptive=False` is the frozen counterfactual arm: same tasks, same budgets,
# same seeds, but the searcher never changes.
# ---------------------------------------------------------------------------
@dataclass
class RunState:
    adaptive: bool
    searcher: SearcherState = field(default_factory=SearcherState)
    tasks: List[SealedTask] = field(default_factory=list)
    adopted_tokens: Dict[str, Tuple[int, ...]] = field(default_factory=dict)
    adopted_fns: Dict[str, Callable[[List[int]], int]] = field(default_factory=dict)
    adopted_wave: Dict[str, int] = field(default_factory=dict)
    adopted_searcher_version: Dict[str, int] = field(default_factory=dict)
    evals_total: int = 0
    evals_to_solve: Dict[str, int] = field(default_factory=dict)
    gate_records: List[MetaGateRecord] = field(default_factory=list)
    rejected_digests: List[str] = field(default_factory=list)
    events: List[str] = field(default_factory=list)
    best_scores: Dict[str, float] = field(default_factory=dict)
    work_table: Optional[EnumTable] = None
    tcci_reports: Dict[int, Dict[str, object]] = field(default_factory=dict)
    gen_specs: List[List[str]] = field(default_factory=list)
    gen_names: Dict[str, str] = field(default_factory=dict)
    gen_reach: Dict[str, str] = field(default_factory=dict)
    drift_rate: float = DRIFT_RATE_INIT
    channel_stats: Dict[str, Dict[str, int]] = field(default_factory=lambda: {
        "drift": {"evals": 0, "adoptions": 0},
        "exploit": {"evals": 0, "adoptions": 0}})
    neg_gram_counts: Dict[Tuple[int, ...], int] = field(default_factory=dict)
    neg_active: set = field(default_factory=set)
    neg_skips: int = 0
    rewrite_rules: List[Tuple[Tuple[int, ...], Tuple[int, ...]]] = field(default_factory=list)
    screen_topbase: int = 12
    screen_cap: int = 20_000
    cascade_stats: Dict[str, int] = field(default_factory=lambda: {
        "screen_hits": 0, "screen_misses": 0, "clean_rejects": 0,
        "consecutive_hits": 0})
    residues: List[Dict[str, object]] = field(default_factory=dict if False else list)
    extra_solutions: Dict[Tuple[int, ...], Tuple[int, ...]] = field(default_factory=dict)
    enum_extensions_total: int = 0
    gate_extensions_total: int = 0
    prm: Optional[object] = None        # S1 StepScorer (adaptive arm only)
    wm: Optional[object] = None         # S3 OpSemanticsModel (adaptive only)
    prm_prefix_runs: int = 0
    wm_acts: int = 0
    growth_log: List[Dict[str, object]] = field(default_factory=list)

    def unsolved(self) -> List[SealedTask]:
        return [t for t in self.tasks if t.tid not in self.adopted_tokens]


def run_wave(rs: RunState, wave: int) -> None:
    pool = list(rs.adopted_tokens.values())
    own_near = [tuple(r["tokens"]) for r in rs.residues
                if r.get("tid") and r.get("tokens")
                and r.get("best", 0.0) >= 0.5]
    ensure_worktable(rs)
    fail_density: Dict[str, int] = {}
    for r in rs.residues:
        fail_density[r["family"]] = fail_density.get(r["family"], 0) + 1
    order = sorted(rs.unsolved(),
                   key=lambda t: (-fail_density.get(t.family, 0), t.tid))
    if fail_density:
        rs.events.append(f"w{wave} SCHEDULER pressure={fail_density}")
    for task in order:
        seed = SEED + wave * 10_007 + int(task.tid[1:]) * 211 + ord(task.tid[0]) * 37
        candidates: List[SynthResult] = []
        hit = lookup_solution(rs, task_target_vector(task))
        if hit is not None:
            candidates.append(SynthResult(task.tid, True, hit,
                              len(expand_tokens(hit, rs.searcher.macros)), 0, 1.0))
        adopted_now = False
        for attempt in range(2):
            if not candidates:
                boost = 2 if fail_density.get(task.family, 0) >= max(
                    fail_density.values(), default=0) and fail_density else 0
                task_pool = ([tuple(r["tokens"]) for r in rs.residues
                              if r.get("tid") == task.tid and r.get("tokens")
                              and r.get("best", 0.0) >= 0.5] * 3) + pool
                candidates.append(synthesize(task.train_pairs, task.tid,
                                             rs.searcher, seed=seed,
                                             seed_pool=task_pool,
                                             restarts=RESTARTS_PER_TASK + boost,
                                             drift_rate=rs.drift_rate,
                                             neg_active=rs.neg_active))
            res = candidates.pop(0)
            rs.best_scores[task.tid] = max(rs.best_scores.get(task.tid, 0.0),
                                           res.best_score)
            rs.evals_total += res.evals_used
            rs.channel_stats["drift"]["evals"] += res.drift_evals
            rs.channel_stats["exploit"]["evals"] += res.exploit_evals
            rs.neg_skips += res.neg_skips
            for g, c in res.zero_grams.items():
                rs.neg_gram_counts[g] = rs.neg_gram_counts.get(g, 0) + c
            if not res.solved:
                rs.residues.append({
                    "wave": wave, "tid": task.tid,
                    "family": TASK_FAMILY_BY_TID.get(task.tid, "?"),
                    "best": round(res.best_score, 4),
                    "tokens": list(res.tokens),
                    "evals": res.evals_used})
                rs.events.append(
                    f"w{wave} OPEN {task.tid} best={res.best_score:.2f} "
                    f"evals={res.evals_used}")
                break
            fn = compile_program(res.tokens, rs.searcher.macros,
                                 max_stack=rs.searcher.capacity.max_stack)
            if any(fn(list(xs)) != y for xs, y in task.train_pairs):
                rs.events.append(f"w{wave} TRAIN_REVERIFY_FAIL {task.tid}")
                continue
            if not task.holdout_gate(fn):
                rs.events.append(
                    f"w{wave} GATE_FAIL {task.tid} "
                    f"tokens=[{token_str(res.tokens, rs.searcher.macros)}]")
                continue
            if not task.cf_gate(fn):
                rs.events.append(
                    f"w{wave} CF_GATE_CATCH {task.tid} "
                    f"tokens=[{token_str(res.tokens, rs.searcher.macros)}]")
                continue
            adopted_now = True
            if res.evals_used > 0:
                rs.channel_stats[res.channel]["adoptions"] += 1
                rs.events.append(
                    f"w{wave} CHANNEL_ADOPT {task.tid} via={res.channel}")
            break
        if (not adopted_now and rs.adaptive and rs.prm is not None
                and getattr(rs.prm, "seen", 0) >= PRM_MIN_UPDATES):
            # S1 channel: PRM-guided beam, gated by the SAME dual sealed
            # gates as every other channel. Frozen arm never runs this.
            res2, pruns = prm_beam_synthesize(
                task.train_pairs, task.tid, rs.searcher, rs.prm,
                seed=seed ^ 0x5151, wm=rs.wm)
            rs.evals_total += res2.evals_used
            rs.prm_prefix_runs += pruns
            rs.channel_stats.setdefault("prm", {"evals": 0, "adoptions": 0})
            rs.channel_stats["prm"]["evals"] += res2.evals_used
            if res2.solved:
                fn2 = compile_program(res2.tokens, rs.searcher.macros,
                                      max_stack=rs.searcher.capacity.max_stack)
                if (all(fn2(list(xs)) == y for xs, y in task.train_pairs)
                        and task.holdout_gate(fn2) and task.cf_gate(fn2)):
                    res, fn, adopted_now = res2, fn2, True
                    rs.best_scores[task.tid] = 1.0
                    rs.channel_stats["prm"]["adoptions"] += 1
                    rs.events.append(
                        f"w{wave} CHANNEL_ADOPT {task.tid} via=prm")
        if not adopted_now:
            continue
        rs.adopted_tokens[task.tid] = res.tokens
        rs.adopted_fns[task.tid] = fn
        rs.adopted_wave[task.tid] = wave
        rs.adopted_searcher_version[task.tid] = rs.searcher.version
        rs.evals_to_solve[task.tid] = res.evals_used
        rs.events.append(
            f"w{wave} ADOPT {task.tid} len={len(res.tokens)}/exp{res.expanded_len} "
            f"evals={res.evals_used} sv={rs.searcher.version} "
            f"[{token_str(res.tokens, rs.searcher.macros)}]")
    # S1/S3 maintenance (adaptive arm only): lazily bootstrap the world
    # model by acting on the real VM, then train the PRM on this wave's
    # self-verified episodes (+) and strongest failed residues (-).
    if rs.adaptive:
        if rs.wm is None:
            rs.wm = OpSemanticsModel()
            rs.wm_acts += rs.wm.bootstrap(seed=SEED)
            rs.events.append(f"w{wave} WM_BOOTSTRAP acts={rs.wm.acts}")
        if rs.prm is None:
            rs.prm = StepScorer()
        rs.channel_stats.setdefault("prm", {"evals": 0, "adoptions": 0})
        task_by_tid = {t.tid: t for t in rs.tasks}
        for tid in sorted(rs.adopted_tokens):
            if rs.adopted_wave.get(tid) != wave:
                continue
            rs.prm_prefix_runs += rs.prm.train_episode(
                rs.adopted_tokens[tid], rs.searcher.macros,
                task_by_tid[tid].train_pairs, +1, wm=rs.wm)
        negs = sorted((r for r in rs.residues
                       if r.get("wave") == wave and r.get("tokens")),
                      key=lambda r: -r.get("best", 0.0))[:2]
        for r in negs:
            t = task_by_tid.get(r.get("tid"))
            if t is None or not r.get("tokens"):
                continue
            rs.prm_prefix_runs += rs.prm.train_episode(
                tuple(r["tokens"]), rs.searcher.macros, t.train_pairs, -1,
                wm=rs.wm)
        rs.events.append(
            f"w{wave} PRM_STATE updates={rs.prm.updates} "
            f"digest={rs.prm.digest()} prefix_runs={rs.prm_prefix_runs}")


def _orchestrate_drift_and_ngi(rs: RunState, wave: int) -> None:
    d = rs.channel_stats["drift"]
    e = rs.channel_stats["exploit"]
    yd = (d["adoptions"] + 1) / (d["evals"] + 200)
    ye = (e["adoptions"] + 1) / (e["evals"] + 200)
    old = rs.drift_rate
    factor = (1 + DRIFT_ETA) if yd > ye else (1 - DRIFT_ETA) if ye > yd else 1.0
    rs.drift_rate = min(DRIFT_MAX, max(DRIFT_MIN, rs.drift_rate * factor))
    rs.events.append(
        f"w{wave} DRIFT_TUNE rate {old:.3f}->{rs.drift_rate:.3f} "
        f"yield(d/e)={yd:.5f}/{ye:.5f} "
        f"evals(d/e)={d['evals']}/{e['evals']} "
        f"adopts(d/e)={d['adoptions']}/{e['adoptions']} neg_skips={rs.neg_skips}"
        + (f" prm(evals={rs.channel_stats['prm']['evals']},"
           f"adopts={rs.channel_stats['prm']['adoptions']})"
           if "prm" in rs.channel_stats else ""))
    adopted_streams = list(rs.adopted_tokens.values())

    def in_adopted(g: Tuple[int, ...]) -> bool:
        return any(any(gg == g for gg in _grams(toks, len(g), len(g)))
                   for toks in adopted_streams)

    purged = [g for g in rs.neg_active if in_adopted(g)]
    for g in purged:
        rs.neg_active.discard(g)
    promoted = 0
    for g, c in sorted(rs.neg_gram_counts.items(),
                       key=lambda kv: (-kv[1], kv[0])):
        if len(rs.neg_active) >= NEG_GRAM_MAX_ACTIVE:
            break
        if c >= NEG_GRAM_PROMOTE_AT and g not in rs.neg_active \
                and not in_adopted(g):
            rs.neg_active.add(g)
            promoted += 1
    if promoted or purged:
        rs.events.append(
            f"w{wave} NGI promoted={promoted} purged={len(purged)} "
            f"active={len(rs.neg_active)}")


def run_system(adaptive: bool = True, waves: int = WAVES,
               rs: Optional[RunState] = None, wave_start: int = 0) -> RunState:
    if rs is None:
        rs = RunState(adaptive=adaptive)
        rs.tasks = build_sealed_tasks()
    for w in range(wave_start, waves):
        n_before = len(rs.adopted_tokens)
        run_wave(rs, w)
        _orchestrate_drift_and_ngi(rs, w)
        fresh_adopt = len(rs.adopted_tokens) - n_before
        n_tasks_before = len(rs.tasks)
        mint_step(rs, w)
        fresh_frontier = any(
            lookup_solution(rs, task_target_vector(t)) is None
            for t in rs.tasks[n_tasks_before:])
        if not adaptive:
            continue
        if w == WAVES - 1:
            rs.events.append(f"w{w} GATE_SKIPPED_FINAL_WAVE")
            continue
        if fresh_adopt == 0 and not fresh_frontier:
            rs.events.append(f"w{w} GATE_SKIPPED_NO_FRESH_MATERIAL")
            attempt_capacity_growth(rs, w)   # Rule 2: stagnation -> gated growth
            continue
        proposal = propose_improvement(rs.adopted_tokens, rs.searcher, w,
                                       rewrite_rules=rs.rewrite_rules)
        if proposal is None:
            rs.events.append(f"w{w} NO_PROPOSAL")
            continue
        pdig = hashlib.sha256(json.dumps({
            "m": [list(m.body) for m in proposal.new_macros],
            "w": {k: round(v, 6) for k, v in sorted(proposal.new_weights.items())},
        }, sort_keys=True).encode()).hexdigest()[:16]
        if pdig in rs.rejected_digests:
            rs.events.append(f"w{w} SKIP_DUPLICATE_PROPOSAL {pdig}")
            continue
        ok = meta_gate(rs, proposal, w)
        if not ok:
            rs.rejected_digests.append(pdig)
    return rs


# ---------------------------------------------------------------------------
# Recursion evidence: macro lineage depth, and which adopted programs use
# macros that themselves contain macros.
# ---------------------------------------------------------------------------
def lineage_report(rs: RunState) -> Dict[str, object]:
    macros = rs.searcher.macros
    max_depth = max((m.depth for m in macros.values()), default=0)
    used_by: Dict[int, List[str]] = {m: [] for m in macros}
    for tid, toks in rs.adopted_tokens.items():
        for t in toks:
            if t in used_by and tid not in used_by[t]:
                used_by[t].append(tid)
    deep_used = sorted(
        (m.mid for m in macros.values() if m.depth >= 2 and used_by.get(m.mid)),
    )
    solved_with_macros = sorted(
        tid for tid, toks in rs.adopted_tokens.items()
        if any(t >= MACRO_ID_BASE for t in toks))
    return {
        "n_macros": len(macros),
        "max_macro_depth": max_depth,
        "depth2plus_macros_used_in_solutions": deep_used,
        "solutions_using_macros": solved_with_macros,
        "macro_table": {
            m.mid: {
                "body": token_str(m.body, macros),
                "depth": m.depth,
                "wave": m.wave_discovered,
                "from_tasks": list(m.parent_tasks),
                "used_in": used_by.get(m.mid, []),
            } for m in sorted(macros.values(), key=lambda z: z.mid)
        },
    }


def counterfactual_report(adaptive: RunState, frozen: RunState) -> Dict[str, object]:
    a_set = {t for t in adaptive.adopted_tokens if t.startswith("T")}
    f_set = {t for t in frozen.adopted_tokens if t.startswith("T")}
    both = sorted(a_set & f_set)
    speedup = {}
    for tid in both:
        ea, ef = adaptive.evals_to_solve[tid], frozen.evals_to_solve[tid]
        speedup[tid] = {"adaptive_evals": ea, "frozen_evals": ef,
                        "ratio": round(ef / ea, 3) if ea else None}
    return {
        "adaptive_solved": len(a_set),
        "frozen_solved": len(f_set),
        "solved_only_by_adaptive": sorted(a_set - f_set),
        "solved_only_by_frozen": sorted(f_set - a_set),
        "adaptive_total_evals": adaptive.evals_total,
        "frozen_total_evals": frozen.evals_total,
        "adaptive_enum_extensions": adaptive.enum_extensions_total,
        "frozen_enum_extensions": frozen.enum_extensions_total,
        "adaptive_gate_extensions": adaptive.gate_extensions_total,
        "frozen_gate_extensions": frozen.gate_extensions_total,
        "per_task_evals_on_common": speedup,
        "delta_solved": len(a_set) - len(f_set),
    }


def adoption_log_digest(rs: RunState) -> str:
    raw = json.dumps({tid: list(t) for tid, t in sorted(rs.adopted_tokens.items())},
                     sort_keys=True).encode()
    return hashlib.sha256(raw).hexdigest()[:16]


# ---------------------------------------------------------------------------
# Checkpoint serialization: lets adaptive/frozen arms run in separate
# processes within a fixed wall-clock box; the counterfactual report is then
# computed from saved summaries. Determinism makes the split exact.
# ---------------------------------------------------------------------------
def runstate_summary(rs: RunState) -> Dict[str, object]:
    return {
        "adaptive": rs.adaptive,
        "adopted_tokens": {t: list(v) for t, v in rs.adopted_tokens.items()},
        "adopted_wave": dict(rs.adopted_wave),
        "adopted_searcher_version": dict(rs.adopted_searcher_version),
        "evals_to_solve": dict(rs.evals_to_solve),
        "evals_total": rs.evals_total,
        "enum_extensions_total": rs.enum_extensions_total,
        "gate_extensions_total": rs.gate_extensions_total,
        "searcher": {
            "version": rs.searcher.version,
            "macros": {str(m.mid): {"body": list(m.body), "depth": m.depth,
                                     "wave": m.wave_discovered,
                                     "parents": list(m.parent_tasks)}
                        for m in rs.searcher.macros.values()},
            "weights": {str(k): v for k, v in rs.searcher.weights.items()},
            "capacity": {
                "max_program_len": rs.searcher.capacity.max_program_len,
                "max_stack": rs.searcher.capacity.max_stack,
                "max_macros": rs.searcher.capacity.max_macros,
            },
        },
        "growth_log": [dict(g) for g in rs.growth_log],
        "gate_records": [
            {"wave": r.wave, "accepted": r.accepted,
             "inc_solved": r.inc_solved, "cand_solved": r.cand_solved,
             "inc_extensions": r.inc_extensions,
             "cand_extensions": r.cand_extensions, "note": r.note}
            for r in rs.gate_records],
        "events": list(rs.events),
        "tcci": {str(k): v for k, v in getattr(rs, "tcci_reports", {}).items()},
        "residues": list(rs.residues),
        "gen_specs": [list(s) for s in rs.gen_specs],
        "gen_names": dict(rs.gen_names),
        "gen_reach": dict(rs.gen_reach),
        "drift_rate": rs.drift_rate,
        "channel_stats": rs.channel_stats,
        "neg_active": [list(g) for g in sorted(rs.neg_active)],
        "neg_skips": rs.neg_skips,
        "rewrite_rules": [[list(l), list(s)] for l, s in rs.rewrite_rules],
        "screen_topbase": rs.screen_topbase,
        "screen_cap": rs.screen_cap,
        "cascade_stats": dict(rs.cascade_stats),
        "rejected_digests": list(rs.rejected_digests),
        "best_scores": dict(rs.best_scores),
        "adoption_digest": adoption_log_digest(rs),
        "wm_acts": rs.wm_acts,
        "prm_prefix_runs": rs.prm_prefix_runs,
        "prm_state": ({"n_feats": rs.prm.n_feats,
                       "w": [float(v) for v in rs.prm.w],
                       "wsum": [float(v) for v in rs.prm.wsum],
                       "updates": rs.prm.updates, "seen": rs.prm.seen}
                      if rs.prm is not None else None),
    }


def restore_runstate(summary: Dict[str, object]) -> RunState:
    rs = RunState(adaptive=bool(summary["adaptive"]))
    rs.tasks = build_sealed_tasks()
    s = SearcherState()
    s.version = int(summary["searcher"]["version"])
    for mid_s, m in summary["searcher"]["macros"].items():
        mid = int(mid_s)
        s.macros[mid] = Macro(mid=mid, body=tuple(m["body"]),
                              depth=int(m["depth"]),
                              wave_discovered=int(m["wave"]),
                              parent_tasks=tuple(m["parents"]))
    s.weights = {int(k): float(v)
                 for k, v in summary["searcher"]["weights"].items()}
    cap = summary["searcher"].get("capacity")
    if cap:
        s.capacity = CapacityConfig(
            max_program_len=int(cap["max_program_len"]),
            max_stack=int(cap["max_stack"]),
            max_macros=int(cap["max_macros"]))
    rs.searcher = s
    rs.growth_log = [dict(g) for g in summary.get("growth_log", [])]
    rs.adopted_tokens = {t: tuple(v)
                         for t, v in summary["adopted_tokens"].items()}
    rs.adopted_wave = {t: int(v) for t, v in summary["adopted_wave"].items()}
    rs.adopted_searcher_version = {
        t: int(v) for t, v in summary["adopted_searcher_version"].items()}
    rs.evals_to_solve = {t: int(v)
                         for t, v in summary["evals_to_solve"].items()}
    rs.evals_total = int(summary["evals_total"])
    rs.enum_extensions_total = int(summary["enum_extensions_total"])
    rs.gate_extensions_total = int(summary["gate_extensions_total"])
    rs.events = list(summary["events"])
    rs.residues = list(summary.get("residues", []))
    for spec in summary.get("gen_specs", []):
        mint_task(rs, tuple(spec))
    rs.gen_reach = dict(summary.get("gen_reach", {}))
    if not rs.gen_reach:
        import re as _re
        for ev in rs.events:
            m = _re.match(r"w\d+ MINT (G\d+) .* \[(bridge|frontier)\]$", ev)
            if m:
                rs.gen_reach[m.group(1)] = m.group(2)
    rs.drift_rate = float(summary.get("drift_rate", DRIFT_RATE_INIT))
    cs = summary.get("channel_stats")
    if cs:
        rs.channel_stats = {k: dict(v) for k, v in cs.items()}
    rs.neg_active = {tuple(g) for g in summary.get("neg_active", [])}
    rs.neg_skips = int(summary.get("neg_skips", 0))
    rs.rewrite_rules = [(tuple(l), tuple(s))
                        for l, s in summary.get("rewrite_rules", [])]
    rs.screen_topbase = int(summary.get("screen_topbase", 12))
    rs.screen_cap = int(summary.get("screen_cap", 20_000))
    cs2 = summary.get("cascade_stats")
    if cs2:
        rs.cascade_stats = {k: int(v) for k, v in cs2.items()}
    rs.rejected_digests = list(summary.get("rejected_digests", []))
    rs.best_scores = {k: float(v)
                      for k, v in summary.get("best_scores", {}).items()}
    rs.tcci_reports = {int(k): v
                       for k, v in summary.get("tcci", {}).items()}
    rs.wm_acts = int(summary.get("wm_acts", 0))
    rs.prm_prefix_runs = int(summary.get("prm_prefix_runs", 0))
    ps = summary.get("prm_state")
    if ps:
        sc = StepScorer(int(ps.get("n_feats", PRM_N_FEATS)))
        sc.w = [float(v) for v in ps["w"]]
        sc.wsum = [float(v) for v in ps["wsum"]]
        sc.updates = int(ps["updates"])
        sc.seen = int(ps["seen"])
        rs.prm = sc
    for tid, toks in rs.adopted_tokens.items():
        rs.adopted_fns[tid] = compile_program(toks, s.macros)
    return rs


def save_runstate(rs: RunState, path: str) -> None:
    import pathlib
    pathlib.Path(path).write_text(
        json.dumps(runstate_summary(rs), sort_keys=True), encoding="utf-8")


def load_summary(path: str) -> Dict[str, object]:
    import pathlib
    return json.loads(pathlib.Path(path).read_text(encoding="utf-8"))


def counterfactual_report_from(a: Dict[str, object],
                               f: Dict[str, object]) -> Dict[str, object]:
    a_set = set(a["adopted_tokens"]); f_set = set(f["adopted_tokens"])
    # G-tids are arm-local namespaces (each arm mints its own specs), so
    # cross-arm set algebra is only meaningful on external T-tasks; the
    # self-generated side is compared via the frontier discriminator fields.
    a_ext = {t for t in a_set if t.startswith("T")}
    f_ext = {t for t in f_set if t.startswith("T")}
    both = sorted(a_ext & f_ext)
    speed = {}
    for tid in both:
        ea = a["evals_to_solve"].get(tid); ef = f["evals_to_solve"].get(tid)
        if ea is not None and ef is not None:
            speed[tid] = {"adaptive_evals": ea, "frozen_evals": ef}
    return {
        "adaptive_solved": len(a_set), "frozen_solved": len(f_set),
        "delta_solved": len(a_set) - len(f_set),
        "delta_external": len(a_ext) - len(f_ext),
        "solved_only_by_adaptive": sorted(a_ext - f_ext),
        "solved_only_by_frozen": sorted(f_ext - a_ext),
        "adaptive_total_evals": a["evals_total"],
        "frozen_total_evals": f["evals_total"],
        "adaptive_enum_extensions": a["enum_extensions_total"],
        "frozen_enum_extensions": f["enum_extensions_total"],
        "adaptive_gate_extensions": a["gate_extensions_total"],
        "frozen_gate_extensions": f["gate_extensions_total"],
        "per_task_evals_on_common": speed,
        "adaptive_external_solved": sum(1 for t in a_set if t.startswith("T")),
        "frozen_external_solved": sum(1 for t in f_set if t.startswith("T")),
        "adaptive_gen_minted": len(a.get("gen_specs", [])),
        "frozen_gen_minted": len(f.get("gen_specs", [])),
        "adaptive_frontier_gen_solved": sorted(
            t for t in a_set if t.startswith("G")
            and a.get("gen_reach", {}).get(t) == "frontier"),
        "frozen_frontier_gen_solved": sorted(
            t for t in f_set if t.startswith("G")
            and f.get("gen_reach", {}).get(t) == "frontier"),
        "adaptive_gen_solved": sorted(
            (t, a.get("gen_names", {}).get(t, t)) for t in a_set
            if t.startswith("G")),
        "frozen_gen_solved": sorted(
            (t, f.get("gen_names", {}).get(t, t)) for t in f_set
            if t.startswith("G")),
    }


# ---------------------------------------------------------------------------
# Demo / CLI for the standalone core (the monolith adds archive modes).
# ---------------------------------------------------------------------------
_ADAPTIVE: Optional[RunState] = None
_FROZEN: Optional[RunState] = None


def _load_or_run(path: str, adaptive: bool) -> RunState:
    import os
    if os.path.exists(path):
        try:
            return restore_runstate(load_summary(path))
        except Exception:
            pass
    return run_system(adaptive=adaptive)


def build_adaptive() -> RunState:
    global _ADAPTIVE
    if _ADAPTIVE is None:
        _ADAPTIVE = _load_or_run("adaptive.json", True)
    return _ADAPTIVE


def build_frozen() -> RunState:
    global _FROZEN
    if _FROZEN is None:
        _FROZEN = _load_or_run("frozen.json", False)
    return _FROZEN


def demo() -> None:
    rs = build_adaptive()
    print("=" * 88)
    print("RSI METAFORGE (real-search core) -- adaptive run")
    print("=" * 88)
    name = lambda tid: task_label(rs, tid)
    print(f"tasks={len(rs.tasks)} solved={len(rs.adopted_tokens)} "
          f"open={len(rs.unsolved())} total_evals={rs.evals_total}")
    print("\nSOLVED (tid name wave searcher_version surface_tokens):")
    for tid in sorted(rs.adopted_tokens):
        toks = rs.adopted_tokens[tid]
        print(f"  {tid} {name(tid):28s} w{rs.adopted_wave[tid]} "
              f"sv{rs.adopted_searcher_version[tid]} "
              f"[{token_str(toks, rs.searcher.macros)}]")
    print("\nOPEN (honest unsolved walls):")
    for t in rs.unsolved():
        print(f"  {t.tid} {name(t.tid)}")
    print("\nMETA-GATE RECORDS:")
    for r in rs.gate_records:
        print(f"  w{r.wave} accepted={r.accepted} cand={r.cand_solved} "
              f"inc={r.inc_solved} ext(c/i)={r.cand_extensions}/{r.inc_extensions} {r.note}")
    print("\nLINEAGE REPORT:")
    print(json.dumps(lineage_report(rs), indent=2, sort_keys=True))
    print("\nEVENTS:")
    for e in rs.events:
        print("  " + e)


def demo_counterfactual() -> None:
    a, f = build_adaptive(), build_frozen()
    print("=" * 88)
    print("COUNTERFACTUAL: adaptive (self-improving) vs frozen searcher")
    print("same tasks, same per-task budgets, same seeds")
    print("=" * 88)
    rep = counterfactual_report(a, f)
    print(json.dumps(rep, indent=2, sort_keys=True))
    name = lambda tid: task_label(rs, tid)
    only_a = rep["solved_only_by_adaptive"]
    if only_a:
        print("\nTasks reached ONLY via self-improvement:")
        for tid in only_a:
            print(f"  {tid} {name(tid)}")


# ---------------------------------------------------------------------------
# HONEST TEST SUITE. These verify integrity and measured claims -- not theater.
# Every empirical assertion below was first observed in a real run; tests
# document reality, they do not manufacture it.
# ---------------------------------------------------------------------------
def _assert(cond: bool, msg: str) -> None:
    if not cond:
        raise AssertionError(msg)


def test_vm_total_and_crash_safe() -> None:
    bad = [(6,), (9,), (4, 9), (19,), (33,), tuple(range(34)) * 5]
    for prog in bad:
        try:
            run_base_program(prog, [1, 2, 3])
        except VMCrash:
            continue
    _assert(run_base_program((4, 29), [1, 2, 3]) == 6, "INPUT RED_ADD broken")
    _assert(run_base_program((4, 16), [5, 5]) == 2, "INPUT LEN broken")


def test_macro_expansion_semantics() -> None:
    m1 = Macro(mid=100, body=(4, 29), depth=1, wave_discovered=0, parent_tasks=("T00",))
    m2 = Macro(mid=101, body=(100, 100, 11), depth=2, wave_discovered=1, parent_tasks=("T07",))
    macros = {100: m1, 101: m2}
    exp = expand_tokens((101,), macros)
    _assert(exp == (4, 29, 4, 29, 11), f"nested expansion wrong: {exp}")
    _assert(run_base_program(exp, [2, 3]) == 25, "macro semantics wrong (sum*sum)")


def test_synthesizer_receives_no_oracle() -> None:
    import inspect
    sig = inspect.signature(synthesize)
    params = set(sig.parameters)
    _assert("task_train_pairs" in params and "state" in params, "synth signature changed")
    for banned in ("oracle", "target", "gate", "holdout"):
        _assert(all(banned not in p for p in params),
                f"synthesize must not accept '{banned}'")
    src = (inspect.getsource(synthesize) + inspect.getsource(_score_tokens)
           + inspect.getsource(_mutate) + inspect.getsource(_random_tokens)
           + inspect.getsource(build_enum_table))
    for banned in ("ORACLES", "holdout_gate", "cf_gate", "TASK_NAME_BY_TID",
                   "TASK_FAMILY_BY_TID"):
        _assert(banned not in src, f"search path references {banned}")


def test_adopted_programs_are_synthesized_not_oracles() -> None:
    rs = build_adaptive()
    oracle_fns = {id(fn) for _, _, fn in ORACLES}
    _assert(len(rs.adopted_tokens) >= 19, "adaptive solved fewer than baseline floor")
    for tid, fn in rs.adopted_fns.items():
        _assert(id(fn) not in oracle_fns, f"{tid}: adopted fn IS an oracle object")
        _assert(hasattr(fn, "__rsi_vm_program__"), f"{tid}: adopted fn not a VM program")


def test_dual_gates_block_wrong_and_pass_right() -> None:
    tasks = build_sealed_tasks()
    sum_task = next(t for t in tasks if TASK_NAME_BY_TID[t.tid] == "sum")
    wrong = compile_program((4, 16), {})       # count, not sum
    right = compile_program((4, 29), {})       # sum
    _assert(not sum_task.holdout_gate(wrong), "holdout accepted a wrong program")
    _assert(not sum_task.cf_gate(wrong), "cf gate accepted a wrong program")
    _assert(sum_task.holdout_gate(right), "holdout rejected a correct program")
    _assert(sum_task.cf_gate(right), "cf gate rejected a correct program")
    # counterfactual distribution really differs from holdout distribution
    rng_h = random.Random(GATE_SEED); rng_c = random.Random(CF_GATE_SEED)
    xs_h = [rng_h.randint(0, 7) for _ in range(HOLDOUT_LENGTHS[0])]
    xs_c = [rng_c.randint(0, CF_VALMAX) for _ in range(CF_LENGTHS[0])]
    _assert(xs_h != xs_c, "gate distributions identical; sibling test vacuous")


def test_all_adoptions_pass_both_gates() -> None:
    rs = build_adaptive()
    for task in rs.tasks:
        fn = rs.adopted_fns.get(task.tid)
        if fn is None:
            continue
        _assert(task.holdout_gate(fn), f"{task.tid} fails holdout post-hoc")
        _assert(task.cf_gate(fn), f"{task.tid} fails counterfactual sibling gate")


def test_no_task_to_solution_lookup() -> None:
    import ast as _ast, sys, inspect
    mod = sys.modules[run_system.__module__]
    tree = _ast.parse(inspect.getsource(mod))
    banned = {"TASK_TO" + "_FN", "FEATURE_TO" + "_TASKS", "KNOWN_TASK" + "_HYPOTHESES"}
    assigned = set()
    for node in _ast.walk(tree):
        targets = []
        if isinstance(node, _ast.Assign):
            targets = node.targets
        elif isinstance(node, (_ast.AnnAssign, _ast.AugAssign)):
            targets = [node.target]
        for t in targets:
            if isinstance(t, _ast.Name):
                assigned.add(t.id)
    hit = banned & assigned
    _assert(not hit, f"forbidden lookup table assigned: {hit}")


def test_meta_gate_rejects_sabotage() -> None:
    rs = RunState(adaptive=True)
    rs.tasks = build_sealed_tasks()
    run_wave(rs, 0)
    v_before = rs.searcher.version
    junk = [Macro(mid=900, body=(7, 7, 7), depth=1, wave_discovered=0,
                  parent_tasks=("T00",)),
            Macro(mid=901, body=(9, 9, 9), depth=1, wave_discovered=0,
                  parent_tasks=("T00",))]
    bad = ImprovementProposal(wave=0, new_macros=junk,
                              new_weights={t: 0.001 for t in rs.searcher.vocab()},
                              note="sabotage")
    ok = meta_gate(rs, bad, 0)
    _assert(not ok, "meta-gate accepted sabotage macros")
    _assert(rs.searcher.version == v_before, "sabotage mutated the searcher")
    _assert(900 not in rs.searcher.macros and 901 not in rs.searcher.macros,
            "junk macros installed")


