def test_no_dynamic_python_evaluator_calls() -> None:
    import ast as _ast, pathlib
    src = pathlib.Path(__file__).read_text(encoding="utf-8")
    tree = _ast.parse(src)
    bad = []
    for node in _ast.walk(tree):
        if isinstance(node, _ast.Call) and isinstance(node.func, _ast.Name) \
                and node.func.id in {"eval", "exec"}:
            bad.append((node.func.id, getattr(node, "lineno", -1)))
    _assert(not bad, f"dynamic evaluator calls found: {bad}")


def test_selfgen_tasks_sealed_and_search_blind() -> None:
    import inspect
    src = (inspect.getsource(synthesize) + inspect.getsource(_score_tokens)
           + inspect.getsource(_mutate) + inspect.getsource(_mutate_drift)
           + inspect.getsource(build_enum_table))
    _assert("_ORACLE_REGISTRY" not in src,
            "search path references the oracle registry")
    rs = build_adaptive()
    g = next((t for t in rs.tasks if t.tid.startswith("G")), None)
    _assert(g is not None, "no self-generated task present")
    wrong = compile_program((4, 16), {})
    _assert(not g.holdout_gate(wrong) or not g.cf_gate(wrong),
            "self-generated task gates accept a wrong program")


def test_frontier_selfgen_discriminator() -> None:
    """Bridge mints are solvable inside a frozen span; FRONTIER mints are
    not. The open-endedness claim rests on adaptive solving its own frontier
    mints while frozen never solves any of its own."""
    a, f = build_adaptive(), build_frozen()
    a_frontier_solved = [t for t in a.adopted_tokens
                         if t.startswith("G") and a.gen_reach.get(t) == "frontier"]
    f_frontier_solved = [t for t in f.adopted_tokens
                         if t.startswith("G") and f.gen_reach.get(t) == "frontier"]
    _assert(len(a_frontier_solved) >= 1,
            "adaptive solved none of its own frontier mints")
    _assert(not f_frontier_solved,
            f"frozen crossed its own frontier: {f_frontier_solved}")


def test_drift_orchestrator_bookkeeping() -> None:
    rs = build_adaptive()
    _assert(DRIFT_MIN <= rs.drift_rate <= DRIFT_MAX, "drift rate out of bounds")
    cs = rs.channel_stats
    _assert(cs["drift"]["evals"] > 0 and cs["exploit"]["evals"] > 0,
            "a stochastic channel never ran")
    _assert(any("DRIFT_TUNE" in e for e in rs.events),
            "orchestrator control law left no trace")


def test_negative_grams_never_contradict_adoptions() -> None:
    rs = build_adaptive()
    for g in rs.neg_active:
        for toks in rs.adopted_tokens.values():
            _assert(not any(gg == g for gg in _grams(toks, len(g), len(g))),
                    f"active negative gram {g} occurs in an adopted program")


def test_rewrite_rules_formally_verified_small_domain() -> None:
    """Every stored meta-rule must hold on the exhaustive small domain
    (all inputs of length 0..3 over values 0..3), not merely on the train
    collisions that surfaced it."""
    rs = build_adaptive()
    _assert(rs.rewrite_rules, "no rewrite rules harvested")
    for long_p, short_p in rs.rewrite_rules:
        _assert(len(short_p) < len(long_p), "non-shortening rule stored")
        _assert(_rule_holds_small_domain(tuple(long_p), tuple(short_p),
                                         rs.searcher.macros),
                f"rule fails small-domain verification: {long_p}->{short_p}")


def test_cascade_threshold_bookkeeping() -> None:
    rs = build_adaptive()
    _assert(8 <= rs.screen_topbase <= 24, "screen breadth out of bounds")
    _assert(12_000 <= rs.screen_cap <= 40_000, "screen cap out of bounds")
    cs = rs.cascade_stats
    total = cs["screen_hits"] + cs["screen_misses"] + cs["clean_rejects"]
    _assert(total >= 1, "cascade never exercised")
    _assert(cs["screen_misses"] == 0 or any(
        "CASCADE_TUNE widen" in e for e in rs.events),
        "false negative occurred without widening response")


def test_via_operator_composition_semantics() -> None:
    # The generator can lift any installed list-producer macro into a
    # curriculum composition operator. Verify the plumbing end to end:
    # spec parse, transform freeze, oracle composition.
    rs = build_adaptive()
    mids = _list_producer_mids(rs)
    _assert(mids, 'no list-producer macro available for via lifting')
    mid = mids[0]
    spec = (f'via{mid}', 'T05', '')
    oracle = _gen_oracle(spec, rs)
    transform = _macro_transform(rs, mid)
    base = _ORACLE_REGISTRY['T05']
    for xs in TRAIN_INPUTS[:6]:
        _assert(oracle(list(xs)) == base(transform(list(xs))),
                f'via composition mismatch on {xs}')


# =========================================================================== #
# 9. HYPERDIMENSIONAL COMPUTING (HDC/VSA) & KURAMOTO OSCILLATOR ENGINE        #
# =========================================================================== #
class HDCSpace:
    """Hyperdimensional Computing / Vector Symbolic Architecture (VSA) space.
    Uses bipolar vectors (+1, -1) of dimension D.
    """
    def __init__(self, d: int = 10000, seed: int = SEED):
        self.d = d
        self.rng = random.Random(seed)
        self.vocab = {}

    def random_vector(self) -> List[int]:
        return [self.rng.choice([-1, 1]) for _ in range(self.d)]

    def get_vector(self, name: str) -> List[int]:
        if name not in self.vocab:
            self.vocab[name] = self.random_vector()
        return self.vocab[name]

    def bind(self, x: List[int], y: List[int]) -> List[int]:
        return [a * b for a, b in zip(x, y)]

    def bundle(self, vectors: List[List[int]]) -> List[int]:
        sums = [0] * self.d
        for v in vectors:
            for i in range(self.d):
                sums[i] += v[i]
        return [1 if s >= 0 else -1 for s in sums]

    def permute(self, x: List[int], shift: int = 1) -> List[int]:
        shift = shift % self.d
        return x[shift:] + x[:shift]

    def similarity(self, x: List[int], y: List[int]) -> float:
        dot = sum(a * b for a, b in zip(x, y))
        return dot / self.d


class KuramotoSolver:
    """Coupled Kuramoto Oscillator Network for program synthesis.
    Positions compete locally, and align globally with VSA target attractors.
    """
    def __init__(self, num_slots: int, vocab_size: int, seed: int = SEED):
        self.L = num_slots
        self.M = vocab_size
        self.rng = random.Random(seed)

    def solve(self, target_similarities: List[List[float]], steps: int = 150, dt: float = 0.05, 
              K: float = 2.0, J: float = 1.0, noise_std: float = 0.2) -> List[int]:
        phases = [[self.rng.uniform(0, 2 * math.pi) for _ in range(self.M)] for _ in range(self.L)]
        
        for _ in range(steps):
            new_phases = [[0.0] * self.M for _ in range(self.L)]
            for l in range(self.L):
                for j in range(self.M):
                    repulsion = 0.0
                    for k in range(self.M):
                        if k != j:
                            repulsion += math.sin(phases[l][j] - phases[l][k])
                    
                    c_lj = target_similarities[l][j]
                    attraction = c_lj * math.cos(phases[l][j])
                    
                    noise = self.rng.normalvariate(0.0, noise_std) if noise_std > 0 else 0.0
                    
                    dtheta = 1.0 - J * repulsion + K * attraction + noise
                    new_phases[l][j] = (phases[l][j] + dtheta * dt) % (2 * math.pi)
            phases = new_phases
            
        best_program = []
        for l in range(self.L):
            best_op = -1
            best_val = -2.0
            for j in range(self.M):
                val = math.cos(phases[l][j])
                if val > best_val:
                    best_val = val
                    best_op = j
            best_program.append(best_op)
        return best_program


class HDCAnalogicalTransfer:
    """Handles algebraic analogy queries using VSA.
    Translates structures: A is to B as C is to D => D = C * A^-1 * B
    """
    def __init__(self, hdc: HDCSpace):
        self.hdc = hdc

    def transfer(self, input_a: List[int], prog_a: List[int], input_b: List[int]) -> List[int]:
        # T = prog_a * input_a
        relation = self.hdc.bind(prog_a, input_a)
        # prog_b = input_b * relation
        prog_b = self.hdc.bind(input_b, relation)
        return prog_b


def demo_hdc_rsi() -> None:
    print("=" * 80)
    print("DEMO: NEXT-GENERATION CONTINUOUS-WAVE RSI (HDC/VSA & KURAMOTO OSCILLATORS)")
    print("DOMAIN: ABSTRACT STRATEGIC PLANNING & MULTI-AGENT DECISION MAKING")
    print("=" * 80)
    
    hdc = HDCSpace(d=10000, seed=42)
    # Define an abstract strategic planning vocabulary instead of simple arithmetic
    strategy_vocab = [
        "GATHER_INTEL",
        "ALLOCATE_RESOURCES",
        "BUILD_FORTRESS",
        "EXECUTE_STRIKE",
        "DIPLOMACY_NEGOTIATE"
    ]
    M = len(strategy_vocab)
    L = 3  # Plan length (steps)
    
    print(f"HDC Dimension: {hdc.d}")
    print(f"Strategic Action Vocabulary: {strategy_vocab}")
    
    action_vectors = [hdc.get_vector(name) for name in strategy_vocab]
    
    # 2. Define Domain A Strategy: [GATHER_INTEL, BUILD_FORTRESS, DIPLOMACY_NEGOTIATE]
    target_plan = ["GATHER_INTEL", "BUILD_FORTRESS", "DIPLOMACY_NEGOTIATE"]
    print(f"\nOriginal Target Plan (Domain A): {target_plan}")
    
    prog_a_vec = hdc.bundle([
        hdc.permute(action_vectors[0], 0),  # GATHER_INTEL at Step 0
        hdc.permute(action_vectors[2], 1),  # BUILD_FORTRESS at Step 1
        hdc.permute(action_vectors[4], 2)   # DIPLOMACY_NEGOTIATE at Step 2
    ])
    
    # Context A represents the environmental threat vector for Domain A
    context_a_vec = hdc.random_vector()
    # State A represents the resolved outcome state
    outcome_a_vec = hdc.bind(context_a_vec, prog_a_vec)
    
    # 3. Perform zero-shot analogical transfer to a new Context B (Domain B)
    print("\nPerforming zero-shot analogical transfer to Scenario Context B...")
    transfer_engine = HDCAnalogicalTransfer(hdc)
    context_b_vec = hdc.random_vector()
    
    # Target state B is obtained by applying the relationship learned in context A to context B
    state_b_vec = transfer_engine.transfer(context_a_vec, outcome_a_vec, context_b_vec)
    
    # Extract the strategic plan from the B outcome
    prog_b_vec = hdc.bind(context_b_vec, state_b_vec)
    
    print("Verifying target VSA vector similarity at each step of the plan:")
    for l in range(L):
        print(f"  Step {l}:")
        for j, action in enumerate(strategy_vocab):
            sim = hdc.similarity(prog_b_vec, hdc.permute(action_vectors[j], l))
            print(f"    Action {action}: similarity = {sim:.4f}")
            
    # 4. Solve using Kuramoto Solver (Continuous Synchronization)
    print("\nInitializing Kuramoto Oscillator Network for Strategic Decision Locking...")
    solver = KuramotoSolver(num_slots=L, vocab_size=M, seed=123)
    
    target_similarities = []
    for l in range(L):
        slot_sims = []
        for j in range(M):
            sim = hdc.similarity(prog_b_vec, hdc.permute(action_vectors[j], l))
            slot_sims.append(max(0.0, sim))
        target_similarities.append(slot_sims)
        
    print("Running Kuramoto phase iterations...")
    decoded_action_indices = solver.solve(target_similarities, steps=200, dt=0.04, K=3.0, J=1.5, noise_std=0.1)
    
    decoded_actions = [strategy_vocab[idx] for idx in decoded_action_indices]
    print(f"\nDecoded Strategy Plan from Oscillator Phase Locking: {decoded_actions}")
    print(f"Original Target Plan: {target_plan}")
    
    if decoded_actions == target_plan:
        print("\nSUCCESS: Phase-locking successfully converged on the correct strategic plan!")
    else:
        print("\nFAILURE: Phase-locking converged on incorrect plan.")


# --- HDC / Kuramoto Unit Tests (English) ---
def test_hdc_algebra_soundness() -> None:
    hdc = HDCSpace(d=4000, seed=101)
    v1 = hdc.random_vector()
    v2 = hdc.random_vector()
    
    bound = hdc.bind(v1, v2)
    unbound = hdc.bind(bound, v2)
    
    sim = hdc.similarity(unbound, v1)
    _assert(sim > 0.99, f"Binding inverse failed: sim={sim}")
    
    v1_perm = hdc.permute(v1, 1)
    sim_perm = hdc.similarity(v1, v1_perm)
    _assert(abs(sim_perm) < 0.1, f"Permutation not orthogonal: sim={sim_perm}")


def test_kuramoto_phase_locking() -> None:
    target_similarities = [
        [0.0, 0.0, 0.8, 0.0],
        [0.9, 0.0, 0.0, 0.0]
    ]
    solver = KuramotoSolver(num_slots=2, vocab_size=4, seed=42)
    best_prog = solver.solve(target_similarities, steps=100, dt=0.05, K=5.0, J=2.0, noise_std=0.0)
    _assert(best_prog == [2, 0], f"Kuramoto failed to phase lock: {best_prog}")


def test_zero_shot_analogy_transfer() -> None:
    hdc = HDCSpace(d=4000, seed=202)
    input_a = hdc.random_vector()
    prog_a = hdc.random_vector()
    state_a = hdc.bind(input_a, prog_a)
    
    input_b = hdc.random_vector()
    transfer_engine = HDCAnalogicalTransfer(hdc)
    
    state_b = transfer_engine.transfer(input_a, state_a, input_b)
    expected_state_b = hdc.bind(input_b, prog_a)
    sim = hdc.similarity(state_b, expected_state_b)
    _assert(sim > 0.99, f"Analogy transfer failed: sim={sim}")


