def test_gd_meta_select_structure() -> None:
    best, scores = gd_meta_select(None, {}, seed=3)
    _assert(best in GD_CONFIGS, f"chosen config invalid: {best}")
    _assert(len(scores) == len(GD_CONFIGS), "score table incomplete")
    _assert(all(0.0 <= v <= 1.0 for v in scores.values()),
            f"self-scores out of range: {scores}")


def test_gd_generation_drift_shows_qualitative_gain() -> None:
    base = gd_run_family(GD_SCARCE_FAMILY_B, (False, "debate", False),
                         None, {}, seed0=123)
    base_audit = sum(a for _, a in base) / len(base)
    hist = gd_generation_loop(gens=2, seed=SEED + 9, macros={})
    _assert(len(hist) == 2, "generation loop truncated")
    _assert(hist[-1]["prm_updates"] > 0, "GD-PRM never trained")
    _assert(hist[-1]["audit_acc"] > base_audit,
            f"no audited gain over baseline: {hist[-1]['audit_acc']} <= "
            f"{base_audit} (macros/PRM failed to extend reach)")


def test_prm_channel_bookkeeping_in_adaptive_run() -> None:
    rs = build_adaptive()
    _assert("prm" in rs.channel_stats, "prm channel absent from stats")
    _assert(any("PRM_STATE" in e for e in rs.events),
            "PRM training left no event trace")
    _assert(rs.prm is not None and getattr(rs.prm, "updates", 0) > 0,
            "adaptive arm carries no trained PRM")
    _assert(rs.wm_acts > 0,
            "adaptive arm never bootstrapped the world model")
    _assert(rs.prm_prefix_runs > 0, "PRM prefix featurization spent no acts")

TESTS.extend([
    test_wm_learns_declared_families,
    test_wm_never_mispredicts_where_it_predicts,
    test_wm_composed_prediction_sound_and_abstains,
    test_wm_learner_is_blind_to_implementation,
    test_prm_scorer_deterministic_and_separates,
    test_prm_beam_finds_sum_and_is_train_exact_only,
    test_prm_paths_are_oracle_free,
    test_gd_env_no_oracle_attribute_and_budget,
    test_gd_debate_resolves_designed_ambiguity,
    test_gd_distinguisher_finds_separating_input,
    test_gd_constitution_parsimony_prefers_min_cost,
    test_gd_pipeline_deterministic,
    test_gd_agent_and_selection_paths_oracle_free,
    test_gd_meta_select_structure,
    test_gd_generation_drift_shows_qualitative_gain,
    test_prm_channel_bookkeeping_in_adaptive_run,
])




# =========================================================================== #
# 12. REFLECTION TOWER (R0-R4) + CLOSURE PROBER                               #
#                                                                             #
# The unified system above is rich in forward gates but, before this          #
# section, had no backward arrow: acceptances were immutable, near-misses     #
# accumulated without being asked WHAT KIND of mistake they were, and the     #
# question "did we miss something?" had no internal measurement. This         #
# section adds a five-level reflective loop plus an honest limit-probing      #
# instrument. Every level consumes only legitimate signals (real             #
# executions, in-budget oracle queries, gate booleans, the system's own      #
# bookkeeping); sealed audits remain measurement-only everywhere.            #
#                                                                             #
#   R0  Belief retraction      Provenance ledger over accepted answers; any  #
#                              later labeled evidence that contradicts an    #
#                              accepted expression RETRACTS it, quarantines  #
#                              everything derived from it (minted tasks,     #
#                              PRM training episodes), and replays the PRM   #
#                              from the clean remainder.                     #
#   R1  Episodic reflection    Failures are classified into LESSON TYPES by  #
#                              mechanical predicates over what actually      #
#                              happened (train/holdout length windows,       #
#                              value-range windows, degenerate train         #
#                              statistics, crash kinds, overridden majority  #
#                              consensus). No oracle content is consulted.   #
#   R2  Lesson transfer        Lessons are keyed substrate-neutrally and     #
#                              applied ACROSS substrates: a length-          #
#                              generalization lesson learned on the stack    #
#                              VM reshapes the GD probe generator (size      #
#                              outliers) and the distinguisher pool, and     #
#                              vice versa. Measured by ablation.             #
#   R3  Reflection calibration Second-look budget per lesson type is         #
#                              reallocated multiplicatively from the         #
#                              measured ratio of VALIDATED retractions to    #
#                              WASTED second looks (the cost of reflecting   #
#                              is itself accounted).                         #
#   R4  Frame audit            "Did we miss something?" as a number: the     #
#                              fraction of failure episodes explained by NO  #
#                              known lesson type is monitored; recurring     #
#                              orphan signatures that do not blanket-match   #
#                              successes are registered as NEW auto lesson   #
#                              types, gated on retroactive coverage.         #
#                                                                             #
#   Closure prober             The limit-breakthrough attempt, done          #
#                              honestly: (a) a maximal-budget extended       #
#                              search assault on every expected-open wall,   #
#                              (b) an EXACT exhaustive certificate that no   #
#                              base-ISA program of expanded length <= N      #
#                              matches the wall's train vector              #
#                              (observational-equivalence enumeration,      #
#                              untruncated), and (c) a machine-checked      #
#                              constructor lemma derived from exhaustive    #
#                              small-domain execution, locating WHICH       #
#                              missing capability blocks each wall. The     #
#                              outcome -- breakthrough or certificate --    #
#                              is reported either way.                      #
# =========================================================================== #

# ---------------------------------------------------------------------------
# R0: provenance ledger and belief retraction.
# ---------------------------------------------------------------------------
@dataclass
class BeliefRecord:
    task: str
    expr_key: str
    expr: Optional[GDExpr]
    consensus: str
    evidence: List[Tuple[object, int]] = field(default_factory=list)
    derived: List[str] = field(default_factory=list)
    retracted: bool = False
    retraction_reason: str = ""


class ReflectionLedger:
    """Every acceptance carries its evidence and its descendants. Later
    labeled evidence is checked against the stored expression by REAL
    evaluation; a contradiction retracts the belief and quarantines the
    derivation cone. Sealed audits never enter this path."""

    def __init__(self) -> None:
        self.records: Dict[str, BeliefRecord] = {}
        self.events: List[str] = []
        self.validated_retractions = 0
        self.wasted_second_looks = 0

    def accept(self, task: str, expr: Optional[GDExpr], consensus: str,
               evidence: Sequence[Tuple[object, int]]) -> None:
        self.records[task] = BeliefRecord(
            task=task, expr_key=gd_expr_key(expr) if expr is not None else "",
            expr=expr, consensus=consensus, evidence=list(evidence))
        self.events.append(f"LEDGER_ACCEPT {task} key={self.records[task].expr_key}"
                           f" consensus={consensus} ev={len(evidence)}")

    def derive(self, parent: str, child: str) -> None:
        if parent in self.records:
            self.records[parent].derived.append(child)
            self.events.append(f"LEDGER_DERIVE {parent} -> {child}")

    def add_evidence(self, task: str, x: object, y: int) -> None:
        if task in self.records:
            self.records[task].evidence.append((x, int(y)))
            self.events.append(f"LEDGER_EVIDENCE {task} +1")

    def contradictions(self, macros: Dict[str, GDMacro]) -> List[str]:
        out = []
        for task, rec in sorted(self.records.items()):
            if rec.retracted or rec.expr is None:
                continue
            for x, y in rec.evidence:
                try:
                    got = gd_expr_eval(rec.expr, x, macros)
                except Exception:
                    got = None
                if got != y:
                    out.append(task)
                    break
        return out

    def quarantine_cone(self, task: str) -> List[str]:
        cone, stack = [], [task]
        seen = set()
        while stack:
            t = stack.pop()
            if t in seen:
                continue
            seen.add(t)
            cone.append(t)
            stack.extend(self.records.get(t, BeliefRecord(t, "", None, "")).derived)
        return cone

    def retract(self, task: str, reason: str) -> List[str]:
        cone = self.quarantine_cone(task)
        for t in cone:
            if t in self.records and not self.records[t].retracted:
                self.records[t].retracted = True
                self.records[t].retraction_reason = (
                    reason if t == task else f"derived_from:{task}")
        self.validated_retractions += 1
        self.events.append(f"LEDGER_RETRACT {task} cone={cone} reason={reason}")
        return cone

    def clean_records(self) -> List[BeliefRecord]:
        return [r for r in self.records.values()
                if not r.retracted and r.expr is not None]

    def replay_prm(self, macros: Dict[str, GDMacro],
                   seed: int) -> "StepScorer":
        """Deterministically rebuild the GD scorer from non-retracted,
        full-consensus beliefs only. Retraction therefore propagates into
        the learned reward model, not just the answer set."""
        prm = StepScorer(GD_PRM_FEATS)
        for rec in sorted(self.clean_records(), key=lambda r: r.task):
            if rec.consensus != "full":
                continue
            env = _LedgerFeatureEnv(rec.evidence)
            prm.update(gd_prm_features(env, rec.expr, macros, GD_MAX_COST), +1)
        return prm


class _LedgerFeatureEnv:
    """Minimal evaluation surface for PRM replay: real expression
    evaluation against ledger-stored evidence pairs. No oracle access."""

    def __init__(self, evidence: Sequence[Tuple[object, int]]):
        self.train: List[Tuple[object, int]] = list(evidence)
        self.acts = 0

    def eval_expr(self, expr: GDExpr, x: object,
                  macros: Dict[str, GDMacro]) -> Optional[int]:
        self.acts += 1
        try:
            return gd_expr_eval(expr, x, macros)
        except Exception:
            return None


# ---------------------------------------------------------------------------
# R1: lesson taxonomy. Predicates are mechanical functions of episode
# bookkeeping; episode dicts carry only legitimate fields.
# ---------------------------------------------------------------------------
LESSON_BUILTIN_TYPES: Tuple[str, ...] = (
    "GEN_GAP_LENGTH",        # train-exact, failed at longer evaluation lens
    "GEN_GAP_VALUE",         # passed length holdout, failed wider value range
    "TRAIN_DEGENERACY_LENGTH",  # ambiguity under degenerate train sizes
    "PRECONDITION_CRASH",    # crash class observed at evaluation stage
    "CONSENSUS_OVERRIDE",    # a majority-consensus belief was later retracted
)


@dataclass
class Lesson:
    ltype: str
    substrate: str           # "vm" | "gd"
    detail: Dict[str, object] = field(default_factory=dict)


def _sizes(objs: Sequence[object]) -> List[int]:
    out = []
    for o in objs:
        try:
            out.append(len(o))           # type: ignore[arg-type]
        except Exception:
            out.append(0)
    return out


def reflect_episode(ep: Dict[str, object]) -> List[Lesson]:
    """Classify one failure episode into zero or more builtin lessons.
    Fields consumed: substrate, stage, train_sizes, eval_sizes,
    train_valmax, eval_valmax, n_classes, crash, consensus, retracted."""
    out: List[Lesson] = []
    sub = str(ep.get("substrate", "?"))
    stage = str(ep.get("stage", ""))
    tsz = list(ep.get("train_sizes", []) or [])
    esz = list(ep.get("eval_sizes", []) or [])
    if stage in ("holdout_fail", "audit_mismatch") and tsz and esz \
            and max(esz) > max(tsz):
        out.append(Lesson("GEN_GAP_LENGTH", sub,
                          {"train_max": max(tsz), "eval_max": max(esz)}))
    tvm = ep.get("train_valmax")
    evm = ep.get("eval_valmax")
    if stage == "cf_fail" and isinstance(tvm, int) and isinstance(evm, int) \
            and evm > tvm:
        out.append(Lesson("GEN_GAP_VALUE", sub,
                          {"train_valmax": tvm, "eval_valmax": evm}))
    if int(ep.get("n_classes", 1) or 1) > 1 and tsz \
            and len(set(tsz)) <= 2 and max(tsz) <= 2:
        out.append(Lesson("TRAIN_DEGENERACY_LENGTH", sub,
                          {"train_sizes": sorted(set(tsz))}))
    if ep.get("crash"):
        out.append(Lesson("PRECONDITION_CRASH", sub,
                          {"crash": str(ep.get("crash"))}))
    if ep.get("retracted") and str(ep.get("consensus")) == "majority":
        out.append(Lesson("CONSENSUS_OVERRIDE", sub, {}))
    return out


class LessonBook:
    """Cross-substrate store of lessons (R1) and auto-discovered lesson
    types (R4). Lesson keys are substrate-neutral so that a lesson learned
    on one substrate reshapes behavior on the other (R2)."""

    def __init__(self) -> None:
        self.lessons: List[Lesson] = []
        self.auto_types: Dict[str, Tuple[Tuple[str, object], ...]] = {}
        self.events: List[str] = []

    def add(self, lessons: Sequence[Lesson]) -> None:
        for l in lessons:
            self.lessons.append(l)
            self.events.append(f"LESSON {l.ltype} from={l.substrate} {l.detail}")

    def count(self, ltype: str) -> int:
        return sum(1 for l in self.lessons if l.ltype == ltype)

    def active(self, ltype: str) -> bool:
        return self.count(ltype) >= 1

    def types_known(self) -> List[str]:
        return list(LESSON_BUILTIN_TYPES) + sorted(self.auto_types)

    def match_auto(self, ep: Dict[str, object]) -> List[str]:
        hits = []
        for name, sig in self.auto_types.items():
            if all(ep.get(k) == v for k, v in sig):
                hits.append(name)
        return hits


# ---------------------------------------------------------------------------
# R2: cross-substrate lesson application. A pure generator: given the book,
# emit extra probe inputs for a GD domain. Oracle-free by construction.
# ---------------------------------------------------------------------------
def lesson_probe_augment(domain: str, seed: int, book: LessonBook,
                         n_extra: int = 8) -> List[object]:
    rng = random.Random(seed * 6151 + 29)
    out: List[object] = []
    want_long = book.active("GEN_GAP_LENGTH") \
        or book.active("TRAIN_DEGENERACY_LENGTH")
    want_wide = book.active("GEN_GAP_VALUE")
    if not (want_long or want_wide):
        return out
    for _ in range(n_extra):
        size = rng.randint(6, 9) if want_long else rng.randint(0, 5)
        lo, hi = ((-9, 15) if want_wide else (-3, 9))
        if domain == "list":
            out.append([rng.randint(lo, hi) for _ in range(size)])
        elif domain == "string":
            alpha = "abcXYZ019 #"
            out.append("".join(rng.choice(alpha) for _ in range(size)))
        elif domain == "grid":
            r = max(1, min(4, size // 2))
            out.append([[rng.randint(max(0, lo), hi) for _ in range(size - r + 1)]
                        for _ in range(r)])
        else:
            d = {}
            for k in ("a", "b", "n", "items", "x", "y", "z", "w")[:max(1, size // 2)]:
                d[k] = rng.randint(max(0, lo), hi)
            out.append(d)
    return out


def gd_agent_enum_b(env: GDScarceEnv, macros: Dict[str, GDMacro],
                    max_cost: int, dedup_probes: Sequence[object],
                    max_reps: int = 12,
                    max_scan: int = 4000) -> List[GDExpr]:
    """Behavior-deduplicated enumeration: the WHOLE scan budget is spent and
    every distinct behavior (as seen on the supplied probes) gets one
    representative, up to max_reps. What counts as a distinct hypothesis is
    therefore decided by where the system has learned to look (R2); the
    budget is explicit and identical across ablation arms."""
    reps: List[GDExpr] = []
    seen_beh: set = set()
    scanned = 0
    for expr in gd_enumerate_exprs(macros, max_cost):
        scanned += 1
        if scanned > max_scan or len(reps) >= max_reps:
            break
        if not env.train_exact(expr, macros):
            continue
        beh = gd_behavior_key(env, expr, macros, dedup_probes)
        if beh in seen_beh:
            continue
        seen_beh.add(beh)
        reps.append(expr)
    return reps


def gd_debate_solve_r(env: GDScarceEnv, macros: Dict[str, GDMacro],
                      seed: int, book: LessonBook,
                      prm: Optional["StepScorer"] = None,
                      query_policy: str = "debate",
                      committee_full: bool = True,
                      max_cost: int = GD_MAX_COST,
                      max_scan: int = 4000,
                      max_reps: int = 12,
                      task_name: str = "?") -> GDEpisode:
    """Reflective debate: identical to gd_debate_solve except that the
    behavior-probe pool and the distinguisher candidate pool are augmented
    by lesson-driven generators (R2). Acceptance rules are unchanged."""
    probes = (gd_probe_pool(env.domain, seed, n=12)
              + lesson_probe_augment(env.domain, seed, book))
    pool: List[GDExpr] = []
    seen = set()
    committee: Dict[str, int] = {}
    agents: List[Tuple[str, List[GDExpr]]] = [
        ("enum", gd_agent_enum_b(env, macros, max_cost, probes,
                                 max_reps=max_reps, max_scan=max_scan))]
    if committee_full:
        agents.append(("stoch", gd_agent_stoch(env, macros, max_cost, seed)))
        if prm is not None:
            agents.append(("prm", gd_agent_prm_beam(env, macros, max_cost, prm)))
    for name, found in agents:
        committee[name] = len(found)
        for e in found:
            key = gd_expr_key(e)
            if key not in seen:
                seen.add(key)
                pool.append(e)
    if not pool:
        return GDEpisode(task_name, "", None, "none", 0,
                         env.queries_used, env.acts, committee)

    def classes() -> Dict[Tuple[object, ...], List[GDExpr]]:
        cl: Dict[Tuple[object, ...], List[GDExpr]] = {}
        for e in pool:
            cl.setdefault(gd_behavior_key(env, e, macros, probes), []).append(e)
        return cl

    def distinguish(reps: Sequence[GDExpr]) -> Optional[object]:
        cand = (gd_probe_pool(env.domain, seed + 1, n=100)
                + lesson_probe_augment(env.domain, seed + 2, book))
        best_x, best_k = None, 1
        for x in cand:
            outs = {env.eval_expr(r, x, macros) for r in reps}
            if len(outs) > best_k:
                best_x, best_k = x, len(outs)
        return best_x

    cl = classes()
    rng = random.Random(seed * 31337 + 5)
    while len(cl) > 1:
        reps = [sorted(v, key=lambda e: (gd_expr_cost(e), gd_expr_key(e)))[0]
                for v in cl.values()]
        if query_policy == "debate":
            x = distinguish(reps)
        else:
            cand = gd_probe_pool(env.domain, seed + 17, n=60)
            x = cand[rng.randrange(len(cand))]
        if x is None:
            break
        y = env.request_label(x)
        if y is None:
            break
        pool = [e for e in pool if env.eval_expr(e, x, macros) == y]
        if not pool:
            return GDEpisode(task_name, "", None, "none", 0,
                             env.queries_used, env.acts, committee)
        cl = classes()

    def pick(members: List[GDExpr]) -> GDExpr:
        return sorted(members, key=lambda e: (gd_expr_cost(e),
                                              gd_expr_key(e)))[0]

    finalists = tuple(sorted(gd_expr_key(pick(v)) for v in cl.values()))
    if len(cl) == 1:
        acc = pick(next(iter(cl.values())))
        return GDEpisode(task_name, gd_expr_key(acc), acc, "full", 1,
                         env.queries_used, env.acts, committee, finalists)
    ranked = sorted(((len(v), gd_expr_key(pick(v)), v) for v in cl.values()),
                    key=lambda z: (-z[0], z[1]))
    if len(ranked) > 1 and ranked[0][0] > ranked[1][0]:
        acc = pick(ranked[0][2])
        return GDEpisode(task_name, gd_expr_key(acc), acc, "majority",
                         len(cl), env.queries_used, env.acts, committee,
                         finalists)
    return GDEpisode(task_name, "", None, "none", len(cl),
                     env.queries_used, env.acts, committee, finalists)


# ---------------------------------------------------------------------------
# R3: reflection-budget calibration. Multiplicative reallocation per lesson
# type from validated-retraction vs wasted-second-look accounting.
# ---------------------------------------------------------------------------
R3_MIN_MULT, R3_MAX_MULT, R3_ETA = 0.25, 4.0, 0.25


class ReflectionBudget:
    def __init__(self) -> None:
        self.mult: Dict[str, float] = {t: 1.0 for t in LESSON_BUILTIN_TYPES}
        self.validated: Dict[str, int] = {t: 0 for t in LESSON_BUILTIN_TYPES}
        self.wasted: Dict[str, int] = {t: 0 for t in LESSON_BUILTIN_TYPES}
        self.events: List[str] = []

    def ensure(self, ltype: str) -> None:
        self.mult.setdefault(ltype, 1.0)
        self.validated.setdefault(ltype, 0)
        self.wasted.setdefault(ltype, 0)

    def record(self, ltype: str, validated: bool) -> None:
        self.ensure(ltype)
        if validated:
            self.validated[ltype] += 1
        else:
            self.wasted[ltype] += 1
        old = self.mult[ltype]
        v, w = self.validated[ltype], self.wasted[ltype]
        factor = (1 + R3_ETA) if v > w else (1 - R3_ETA) if w > v else 1.0
        self.mult[ltype] = min(R3_MAX_MULT, max(R3_MIN_MULT, old * factor))
        self.events.append(
            f"R3_TUNE {ltype} {old:.3f}->{self.mult[ltype]:.3f} v={v} w={w}")

    def second_looks(self, ltype: str, base: int = 1) -> int:
        self.ensure(ltype)
        return max(0, round(base * self.mult[ltype]))


# ---------------------------------------------------------------------------
# R4: frame audit. Monitors the unexplained-failure residual and registers
# new auto lesson types from recurring orphan signatures, gated on
# retroactive coverage and non-blanket matching of successes.
# ---------------------------------------------------------------------------
R4_ORPHAN_MIN = 3
R4_SUCCESS_MATCH_MAX = 0.05
_R4_SIG_KEYS = ("substrate", "stage", "outputs_constant", "sizes_constant",
                "crash")


def episode_fingerprint(ep: Dict[str, object]) -> Tuple[Tuple[str, object], ...]:
    return tuple((k, ep.get(k)) for k in _R4_SIG_KEYS)


class FrameAuditor:
    def __init__(self, book: LessonBook):
        self.book = book
        self.failures: List[Dict[str, object]] = []
        self.successes: List[Dict[str, object]] = []
        self.events: List[str] = []

    def observe(self, ep: Dict[str, object], success: bool) -> None:
        (self.successes if success else self.failures).append(dict(ep))

    def unexplained(self) -> List[Dict[str, object]]:
        out = []
        for ep in self.failures:
            if reflect_episode(ep):
                continue
            if self.book.match_auto(ep):
                continue
            out.append(ep)
        return out

    def residual_rate(self) -> float:
        if not self.failures:
            return 0.0
        return len(self.unexplained()) / len(self.failures)

    def audit(self) -> List[str]:
        """Cluster orphan failures by fingerprint; register a new auto type
        when a signature recurs >= R4_ORPHAN_MIN times among failures while
        matching <= R4_SUCCESS_MATCH_MAX of recorded successes."""
        newly: List[str] = []
        groups: Dict[Tuple, int] = {}
        for ep in self.unexplained():
            groups[episode_fingerprint(ep)] = groups.get(
                episode_fingerprint(ep), 0) + 1
        for sig, n in sorted(groups.items(), key=lambda kv: (-kv[1], str(kv[0]))):
            if n < R4_ORPHAN_MIN:
                continue
            s_match = sum(1 for ep in self.successes
                          if episode_fingerprint(ep) == sig)
            s_rate = s_match / max(1, len(self.successes))
            if s_rate > R4_SUCCESS_MATCH_MAX:
                self.events.append(
                    f"R4_REJECT sig={sig} n={n} success_rate={s_rate:.3f}")
                continue
            name = f"AUTO_LESSON_{len(self.book.auto_types)}"
            self.book.auto_types[name] = sig
            self.events.append(f"R4_REGISTER {name} sig={sig} n={n}")
            newly.append(name)
        return newly


# ---------------------------------------------------------------------------
# Reflective generation loop: the v1 loop plus the full R-tower. Acceptances
# enter the ledger with evidence; minted descendants are linked; each
# generation runs a contradiction sweep; retractions quarantine the cone and
# replay the PRM from clean beliefs; lessons accumulate and transfer.
# ---------------------------------------------------------------------------
def gd_reflective_generation_loop(gens: int, seed: int,
                                  macros: Dict[str, GDMacro],
                                  book: Optional[LessonBook] = None,
                                  budget: Optional[ReflectionBudget] = None
                                  ) -> Dict[str, object]:
    book = book if book is not None else LessonBook()
    budget = budget if budget is not None else ReflectionBudget()
    ledger = ReflectionLedger()
    auditor = FrameAuditor(book)
    registry: List[Tuple[object, ...]] = []
    solved_list: List[Tuple[str, GDExpr]] = []
    solved_dict: Dict[str, GDExpr] = {}
    prm = StepScorer(GD_PRM_FEATS)
    history: List[Dict[str, object]] = []
    name_to_parent: Dict[str, str] = {}
    for g in range(gens):
        if g == 0:
            minted = [("seed_list_sum_sq", "list", _gd_sq(_gdf("NUM_SUM")), ""),
                      ("seed_list_size_sq", "list", _gd_sq(_gdf("SIZE")), "")]
        else:
            raw = gd_mint_curriculum(solved_list, macros, registry,
                                     seed=seed + g, n=3)
            minted = []
            for nm, dom, fn in raw:
                parent = nm.split("[", 1)[-1].rstrip("]")
                minted.append((nm, dom, fn, parent))
        for name, domain, fn, parent in minted:
            task = make_scarce_task(name, domain, fn, seed=seed * 100 + g,
                                    query_budget=4)
            env = GDScarceEnv(task)
            ep = gd_debate_solve_r(env, macros, seed=seed * 100 + g,
                                   book=book, prm=prm if g > 0 else None,
                                   task_name=name)
            epd = {"substrate": "gd", "stage": "accept" if ep.accepted is not None
                   else "abstain", "n_classes": ep.n_classes,
                   "train_sizes": _sizes([x for x, _ in task.train]),
                   "outputs_constant": len({y for _, y in task.train}) == 1,
                   "sizes_constant": len(set(_sizes(
                       [x for x, _ in task.train]))) == 1,
                   "crash": None, "consensus": ep.consensus}
            auditor.observe(epd, success=ep.accepted is not None)
            if ep.accepted is None:
                book.add(reflect_episode(epd))
                continue
            ledger.accept(name, ep.accepted, ep.consensus, env.train)
            if parent:
                ledger.derive(parent, name)
                name_to_parent[name] = parent
            solved_list.append((name, ep.accepted))
            solved_dict[name] = ep.accepted
            prm.update(gd_prm_features(env, ep.accepted, macros,
                                       GD_MAX_COST), +1)
            losers = [e for e in gd_agent_enum(env, macros, GD_MAX_COST)
                      if gd_expr_key(e) != ep.accepted_key][:2]
            for e in losers:
                prm.update(gd_prm_features(env, e, macros, GD_MAX_COST), -1)
        # R0 sweep: any belief contradicted by its accumulated evidence?
        retracted_now: List[str] = []
        for t in ledger.contradictions(macros):
            cone = ledger.retract(t, "evidence_contradiction")
            retracted_now.extend(cone)
            for c in cone:
                solved_dict.pop(c, None)
            solved_list = [(n, e) for n, e in solved_list
                           if n not in set(cone)]
            book.add([Lesson("CONSENSUS_OVERRIDE", "gd", {"task": t})]
                     if ledger.records[t].consensus == "majority" else [])
        if retracted_now:
            prm = ledger.replay_prm(macros, seed)
        for m in gd_mine_macros(solved_dict, macros, min_support=2,
                                max_new=2):
            macros[m.name] = m
        eps = gd_run_family(GD_SCARCE_FAMILY_B, (True, "debate", True),
                            prm, macros, seed0=seed * 1000 + g * 10)
        history.append({
            "gen": g, "prm_updates": prm.updates,
            "solved_minted": len(solved_list),
            "retracted": len(retracted_now),
            "lessons": {t: book.count(t) for t in book.types_known()
                        if book.count(t)},
            "residual_rate": round(auditor.residual_rate(), 4),
            "macros": sorted(macros),
            "audit_acc": round(sum(a for _, a in eps) / len(eps), 4),
        })
    return {"history": history, "ledger": ledger, "book": book,
            "auditor": auditor, "budget": budget, "prm": prm,
            "macros": macros}


# ---------------------------------------------------------------------------
# CLOSURE PROBER. (a) Maximal-budget assault on every expected-open wall;
# (b) exact exhaustive certificate "no base-ISA program of expanded length
# <= N matches the train vector" via untruncated observational-equivalence
# enumeration; (c) machine-checked constructor lemma from exhaustive
# small-domain execution. Outcomes are reported either way.
# ---------------------------------------------------------------------------
CERT_MAX_LEN = 6
CERT_CLASS_CAP = 600_000
_CERT_TABLE: Optional[EnumTable] = None


def _cert_table() -> EnumTable:
    global _CERT_TABLE
    if _CERT_TABLE is None:
        _CERT_TABLE = build_enum_table(SearcherState(),
                                       surface_max=CERT_MAX_LEN,
                                       class_cap=CERT_CLASS_CAP)
    return _CERT_TABLE


def closure_certificate(task: SealedTask) -> Dict[str, object]:
    tab = _cert_table()
    vec = task_target_vector(task)
    reachable = vec in tab.solutions
    return {"tid": task.tid,
            "name": TASK_NAME_BY_TID.get(task.tid, task.tid),
            "certified_blocked_le": (None if reachable or tab.truncated
                                     else CERT_MAX_LEN),
            "reachable_within": CERT_MAX_LEN if reachable else None,
            "witness": list(tab.solutions.get(vec, ())) if reachable else None,
            "classes_per_len": list(tab.classes_per_len),
            "truncated": tab.truncated}


def no_int_to_list_constructor_lemma() -> Dict[str, object]:
    """Exhaustive small-domain execution lemma: over ALL pure-int stacks of
    depth <= 3 with values 0..3, no base op except INPUT ever pushes a list.
    Hence every list value in any program is value-derived from the input
    list; constant-list broadcast is inexpressible in the base ISA. This is
    executed, not assumed."""
    from itertools import product as _prod
    offenders: List[Tuple[str, Tuple[int, ...]]] = []
    checked = 0
    inp = (1, 2)
    for depth in range(0, 4):
        for vals in _prod(range(4), repeat=depth):
            for op in range(N_BASE_OPS):
                st: List[object] = list(vals)
                checked += 1
                try:
                    step_op(st, op, inp)
                except VMCrash:
                    continue
                if any(isinstance(v, tuple) for v in st) and op != 4:
                    offenders.append((OP_NAMES[op], vals))
    return {"checked_transitions": checked,
            "offending_ops": sorted({o for o, _ in offenders}),
            "lemma_holds": not offenders}


def wall_breakthrough_attempt(rs_state: SearcherState,
                              prm: Optional["StepScorer"],
                              seed: int) -> List[Dict[str, object]]:
    """The honest limit-breakthrough protocol: every expected-open wall gets
    an extended-budget assault (heavy stochastic search across both
    channels, plus the PRM beam when a trained scorer is supplied). Any
    train-exact find is then verified by BOTH sealed gates. Results --
    breakthrough or best-score residue plus certificate -- are recorded
    as measured."""
    tasks = build_sealed_tasks()
    walls = [t for t in tasks if TASK_FAMILY_BY_TID.get(t.tid) == "search"]
    rows: List[Dict[str, object]] = []
    for task in walls:
        res = synthesize(task.train_pairs, task.tid, rs_state,
                         seed=seed + int(task.tid[1:]),
                         restarts=12, iters=1500, drift_rate=0.5)
        best = res.best_score
        solved = res.solved
        gates = False
        via = "stochastic_extended"
        if not solved and prm is not None \
                and getattr(prm, "seen", 0) >= PRM_MIN_UPDATES:
            res2, _ = prm_beam_synthesize(task.train_pairs, task.tid,
                                          rs_state, prm,
                                          seed=seed ^ 0xA5A5)
            if res2.best_score > best:
                best = res2.best_score
            if res2.solved:
                solved, res, via = True, res2, "prm_beam"
        if solved:
            fn = compile_program(res.tokens, rs_state.macros)
            gates = task.holdout_gate(fn) and task.cf_gate(fn)
        rows.append({"tid": task.tid,
                     "name": TASK_NAME_BY_TID.get(task.tid, "?"),
                     "train_exact_found": solved, "passed_gates": gates,
                     "via": via if solved else "",
                     "best_score": round(best, 4),
                     "evals": res.evals_used,
                     "certificate": closure_certificate(task)})
    return rows


def closure_report(prm: Optional["StepScorer"] = None,
                   seed: int = SEED) -> Dict[str, object]:
    lemma = no_int_to_list_constructor_lemma()
    rows = wall_breakthrough_attempt(SearcherState(), prm, seed)
    return {"constructor_lemma": lemma, "walls": rows,
            "summary": {
                "walls_total": len(rows),
                "broken": sum(1 for r in rows if r["passed_gates"]),
                "certified_blocked_le6": sum(
                    1 for r in rows
                    if r["certificate"]["certified_blocked_le"] == CERT_MAX_LEN),
            }}


# ---------------------------------------------------------------------------
# Reflection battery (CLI: --mode reflection-battery).
# ---------------------------------------------------------------------------
def _make_length_hidden_task(seed: int, budget: int) -> GDScarceTask:
    """Designed cross-substrate transfer probe: hidden = min(SIZE, 5)
    (expression cost 5). On every input of size <= 5 this equals plain
    SIZE, so default probes (sizes 0..5) see ONE behavior class and the
    constitution's parsimony then picks the cheap wrong answer with full
    consensus. Only size >= 6 inputs expose the split. Train inputs are all
    small; the AUDIT set deliberately contains long inputs so the mistake
    is measurable."""
    rng = random.Random(seed * 13 + 7)
    fn = (lambda x: min(gd_features(x)["SIZE"], 5))
    train = [[rng.randint(0, 7) for _ in range(rng.randint(1, 4))]
             for _ in range(5)]
    audit = (gd_scarce_inputs("list", seed + 5000, 10)
             + [[0] * 6, [1] * 7, list(range(8)), [2] * 9])
    return GDScarceTask("length_hidden_min_size5", "list", fn, train,
                        audit, budget)


def reflection_battery() -> Dict[str, object]:
    out: Dict[str, object] = {}
    print("=" * 88)
    print("REFLECTION TOWER BATTERY (R0 retraction / R1 lessons / R2 transfer"
          " / R3 calibration / R4 frame audit) + CLOSURE PROBER")
    print("=" * 88)

    # -- B1: R0 poisoning drill ------------------------------------------------
    print("\n[B1] R0 retraction drill: a wrong majority acceptance is planted,"
          " one later label arrives, the cone is quarantined, PRM replays")
    macros: Dict[str, GDMacro] = {}
    ledger = ReflectionLedger()
    wrong = _gd_feature("NUM_SUM")          # planted wrong belief
    right_task = make_scarce_task("poison_parent", "list", _gdf("NUM_MAX"),
                                  seed=71, query_budget=2)
    ledger.accept("poison_parent", wrong, "majority",
                  [(x, y) for x, y in right_task.train[:2]
                   if _gdf("NUM_SUM")(x) == y])
    ledger.derive("poison_parent", "poison_child")
    ledger.accept("poison_child", _gd_feature("NUM_SUM"), "full", [])
    prm0 = ledger.replay_prm(macros, seed=1)
    env = GDScarceEnv(right_task)
    x = [2, 5, 1]
    y = env.request_label(x)
    ledger.add_evidence("poison_parent", x, y)
    contradicted = ledger.contradictions(macros)
    cone = ledger.retract(contradicted[0], "evidence_contradiction") \
        if contradicted else []
    prm1 = ledger.replay_prm(macros, seed=1)
    print(f"  contradicted={contradicted} retracted_cone={cone}")
    print(f"  prm replay digest before/after: {prm0.digest()} ->"
          f" {prm1.digest()} (clean beliefs only)")
    out["B1"] = {"contradicted": contradicted, "cone": cone,
                 "prm_changed": prm0.digest() != prm1.digest()}

    # -- B2: R2 cross-substrate transfer ablation --------------------------------
    print("\n[B2] R2 transfer: VM-substrate length lesson reshapes GD probes;"
          " hidden = min(SIZE,5), separable only at size >= 6")
    vm_episode = {"substrate": "vm", "stage": "holdout_fail",
                  "train_sizes": list(TRAIN_LENGTHS),
                  "eval_sizes": list(HOLDOUT_LENGTHS)}
    book_on = LessonBook()
    book_on.add(reflect_episode(vm_episode))
    book_off = LessonBook()
    rows = {}
    for label, book in (("lesson_off", book_off), ("lesson_on", book_on)):
        t = _make_length_hidden_task(seed=SEED + 31, budget=3)
        e = GDScarceEnv(t)
        ep = gd_debate_solve_r(e, {}, seed=SEED + 31, book=book,
                               max_cost=5, max_scan=140_000,
                               max_reps=100_000, task_name=t.name)
        aud = t.audit(ep.accepted, {})
        rows[label] = {"consensus": ep.consensus, "classes": ep.n_classes,
                       "queries": ep.queries,
                       "accepted": ep.accepted_key, "audit": round(aud, 3)}
        print(f"  {label:<10} consensus={ep.consensus:<8}"
              f" classes={ep.n_classes} q={ep.queries}"
              f" accepted={ep.accepted_key or '-':<24} audit={aud:.2f}")
    print("  (the lesson came from the STACK-VM substrate; the gain appears"
          " on the GD substrate -> measured transfer)")
    out["B2"] = rows

    # -- B3: reflective generations -------------------------------------------
    print("\n[B3] reflective generations: ledger + lessons + residual rate")
    res = gd_reflective_generation_loop(gens=3, seed=SEED + 9, macros={})
    for h in res["history"]:
        print(f"  gen={h['gen']} solved={h['solved_minted']}"
              f" retracted={h['retracted']} audit={h['audit_acc']:.2f}"
              f" residual={h['residual_rate']:.2f}"
              f" lessons={h['lessons']} macros={h['macros']}")
    out["B3"] = res["history"]

    # -- B4: R3 calibration curve ----------------------------------------------
    print("\n[B4] R3 budget calibration under a validated/wasted stream")
    rb = ReflectionBudget()
    stream = [("GEN_GAP_LENGTH", True), ("GEN_GAP_LENGTH", True),
              ("TRAIN_DEGENERACY_LENGTH", False),
              ("TRAIN_DEGENERACY_LENGTH", False),
              ("GEN_GAP_LENGTH", True), ("GEN_GAP_VALUE", False)]
    for lt, ok in stream:
        rb.record(lt, ok)
    for lt in sorted(rb.mult):
        if rb.validated[lt] + rb.wasted[lt]:
            print(f"  {lt:<26} mult={rb.mult[lt]:.3f}"
                  f" validated={rb.validated[lt]} wasted={rb.wasted[lt]}"
                  f" second_looks(base=2)={rb.second_looks(lt, 2)}")
    out["B4"] = {lt: rb.mult[lt] for lt in rb.mult}

    # -- B5: R4 frame audit ------------------------------------------------------
    print("\n[B5] R4 frame audit: orphan failure signature -> new auto type")
    book = LessonBook()
    fa = FrameAuditor(book)
    orphan = {"substrate": "gd", "stage": "abstain", "n_classes": 5,
              "train_sizes": [3, 4, 3], "outputs_constant": True,
              "sizes_constant": False, "crash": None}
    for _ in range(4):
        fa.observe(dict(orphan), success=False)
    fa.observe({"substrate": "gd", "stage": "accept", "n_classes": 1,
                "train_sizes": [2, 3], "outputs_constant": False,
                "sizes_constant": False, "crash": None}, success=True)
    before = fa.residual_rate()
    newly = fa.audit()
    after = fa.residual_rate()
    print(f"  residual before={before:.2f} -> after={after:.2f}"
          f" registered={newly}")
    out["B5"] = {"before": before, "after": after, "new_types": newly}

    # -- B6: closure prober -------------------------------------------------------
    print("\n[B6] closure prober: maximal-budget wall assault + exact"
          " certificates + constructor lemma")
    prm = None
    try:
        summ = load_summary("adaptive.json")
        ps = summ.get("prm_state")
        if ps:
            prm = StepScorer(int(ps.get("n_feats", PRM_N_FEATS)))
            prm.w = [float(v) for v in ps["w"]]
            prm.wsum = [float(v) for v in ps["wsum"]]
            prm.updates = int(ps["updates"])
            prm.seen = int(ps["seen"])
    except Exception:
        pass
    rep = closure_report(prm=prm, seed=SEED)
    lem = rep["constructor_lemma"]
    print(f"  constructor lemma: checked={lem['checked_transitions']}"
          f" int-stack transitions; non-INPUT list creators ="
          f" {lem['offending_ops'] or 'NONE'} -> holds={lem['lemma_holds']}")
    for r in rep["walls"]:
        c = r["certificate"]
        print(f"  {r['tid']} {r['name']:<28} extended-search best="
              f"{r['best_score']:.2f} evals={r['evals']}"
              f" broken={r['passed_gates']}"
              f" cert: blocked_le={c['certified_blocked_le']}"
              f" truncated={c['truncated']}")
    s = rep["summary"]
    print(f"  summary: walls={s['walls_total']} broken={s['broken']}"
          f" certified_blocked_le{CERT_MAX_LEN}={s['certified_blocked_le6']}")
    print("  reading: the breakthrough attempt was made at maximal budget;"
          " where it failed, the blockage is now a machine certificate plus"
          " an executed constructor lemma, not an assumption.")
    out["B6"] = rep
    print("\nreflection battery complete.")
    return out


# ---------------------------------------------------------------------------
# Reflection-tower and closure-prober tests (registered in TESTS below).
# ---------------------------------------------------------------------------
def test_r0_retraction_cascades_and_prm_replay() -> None:
    macros: Dict[str, GDMacro] = {}
    led = ReflectionLedger()
    led.accept("p", _gd_feature("NUM_SUM"), "majority", [])
    led.derive("p", "c1")
    led.accept("c1", _gd_feature("NUM_SUM"), "full",
               [([1, 1], 2)])                       # consistent for the child
    led.derive("c1", "c2")
    led.accept("c2", _gd_feature("NUM_SUM"), "full", [([2], 2)])
    d0 = led.replay_prm(macros, seed=1).digest()
    led.add_evidence("p", [2, 5, 1], 5)             # truth says MAX, not SUM
    bad = led.contradictions(macros)
    _assert(bad == ["p"], f"contradiction sweep wrong: {bad}")
    cone = led.retract("p", "evidence_contradiction")
    _assert(set(cone) == {"p", "c1", "c2"},
            f"quarantine cone incomplete: {cone}")
    _assert(all(led.records[t].retracted for t in cone),
            "cone members not marked retracted")
    d1 = led.replay_prm(macros, seed=1).digest()
    _assert(d0 != d1, "PRM replay ignored the retraction")
    _assert(led.replay_prm(macros, seed=1).digest() == d1,
            "PRM replay nondeterministic")


def test_r0_ledger_records_provenance() -> None:
    res = gd_reflective_generation_loop(gens=2, seed=SEED + 9, macros={})
    led: ReflectionLedger = res["ledger"]
    _assert(len(led.records) >= 4, "ledger nearly empty after two gens")
    for rec in led.records.values():
        _assert(rec.evidence, f"{rec.task} accepted without stored evidence")
    derived = [r for r in led.records.values() if r.derived]
    minted = [t for t in led.records if t.startswith("M_")]
    _assert(not minted or derived,
            "minted descendants exist but no derivation edge was recorded")


def test_r1_lessons_from_mechanical_predicates() -> None:
    vm_ep = {"substrate": "vm", "stage": "holdout_fail",
             "train_sizes": list(TRAIN_LENGTHS),
             "eval_sizes": list(HOLDOUT_LENGTHS)}
    ls = reflect_episode(vm_ep)
    _assert(any(l.ltype == "GEN_GAP_LENGTH" for l in ls),
            f"length generalization gap not recognized: {ls}")
    cf_ep = {"substrate": "vm", "stage": "cf_fail",
             "train_valmax": 7, "eval_valmax": CF_VALMAX}
    _assert(any(l.ltype == "GEN_GAP_VALUE" for l in reflect_episode(cf_ep)),
            "value-range gap not recognized")
    gd_ep = {"substrate": "gd", "stage": "abstain", "n_classes": 5,
             "train_sizes": [1, 1, 1, 1, 1]}
    _assert(any(l.ltype == "TRAIN_DEGENERACY_LENGTH"
                for l in reflect_episode(gd_ep)),
            "degenerate-train ambiguity not recognized")
    ok_ep = {"substrate": "gd", "stage": "accept", "n_classes": 1,
             "train_sizes": [2, 4, 3]}
    _assert(not reflect_episode(ok_ep),
            "lesson predicates fire on a clean success episode")


def test_r2_transfer_resolves_length_hidden_ambiguity() -> None:
    vm_episode = {"substrate": "vm", "stage": "holdout_fail",
                  "train_sizes": list(TRAIN_LENGTHS),
                  "eval_sizes": list(HOLDOUT_LENGTHS)}
    book_on = LessonBook()
    book_on.add(reflect_episode(vm_episode))
    _assert(book_on.active("GEN_GAP_LENGTH"), "lesson failed to register")
    t_off = _make_length_hidden_task(seed=SEED + 31, budget=3)
    ep_off = gd_debate_solve_r(GDScarceEnv(t_off), {}, seed=SEED + 31,
                               book=LessonBook(), max_cost=5,
                               max_scan=140_000, max_reps=100_000,
                               task_name=t_off.name)
    t_on = _make_length_hidden_task(seed=SEED + 31, budget=3)
    ep_on = gd_debate_solve_r(GDScarceEnv(t_on), {}, seed=SEED + 31,
                              book=book_on, max_cost=5,
                              max_scan=140_000, max_reps=100_000,
                              task_name=t_on.name)
    # Without the lesson the committee CONVERGES (one behavior class on the
    # blind probes), parsimony picks the cheap answer, and the audit shows
    # it wrong on long inputs -- convergence is not truth.
    _assert(ep_off.consensus in ("full", "majority")
            and ep_off.accepted is not None
            and t_off.audit(ep_off.accepted, {}) < 1.0,
            f"baseline should converge wrongly on blind probes: {ep_off},"
            f" audit={t_off.audit(ep_off.accepted, {})}")
    _assert(ep_on.consensus == "full"
            and ep_on.accepted_key.startswith("MIN(")
            and t_on.audit(ep_on.accepted, {}) == 1.0,
            f"VM->GD lesson transfer failed to resolve it: {ep_on}")
    _assert(ep_on.queries <= 3, "transfer overspent the scarce budget")


def test_r2_reflective_paths_are_oracle_free() -> None:
    import inspect
    src = (inspect.getsource(gd_debate_solve_r)
           + inspect.getsource(lesson_probe_augment)
           + inspect.getsource(reflect_episode)
           + inspect.getsource(ReflectionLedger)
           + inspect.getsource(FrameAuditor))
    for banned in ("._fn", "audit_inputs", "GD_SCARCE_FAMILY", "holdout_gate",
                   "cf_gate", "_ORACLE_REGISTRY"):
        _assert(banned not in src, f"reflective path references {banned}")


def test_r3_budget_bookkeeping_bounded() -> None:
    rb = ReflectionBudget()
    for _ in range(20):
        rb.record("GEN_GAP_LENGTH", True)
        rb.record("GEN_GAP_VALUE", False)
    _assert(R3_MIN_MULT <= rb.mult["GEN_GAP_VALUE"] <= R3_MAX_MULT
            and R3_MIN_MULT <= rb.mult["GEN_GAP_LENGTH"] <= R3_MAX_MULT,
            "budget multipliers escaped their bounds")
    _assert(rb.mult["GEN_GAP_LENGTH"] > rb.mult["GEN_GAP_VALUE"],
            "validated lesson type not favored over wasted one")
    _assert(rb.second_looks("GEN_GAP_VALUE", 1) <=
            rb.second_looks("GEN_GAP_LENGTH", 1),
            "second-look allocation ignores the calibration")
    _assert(any("R3_TUNE" in e for e in rb.events),
            "calibration left no trace")


def test_r4_discovers_orphan_failure_type() -> None:
    book = LessonBook()
    fa = FrameAuditor(book)
    orphan = {"substrate": "gd", "stage": "abstain", "n_classes": 5,
              "train_sizes": [3, 4, 3], "outputs_constant": True,
              "sizes_constant": False, "crash": None}
    for _ in range(R4_ORPHAN_MIN + 1):
        fa.observe(dict(orphan), success=False)
    fa.observe({"substrate": "gd", "stage": "accept", "n_classes": 1,
                "train_sizes": [2, 3], "outputs_constant": False,
                "sizes_constant": False, "crash": None}, success=True)
    before = fa.residual_rate()
    newly = fa.audit()
    _assert(before == 1.0, f"orphan should be unexplained at first: {before}")
    _assert(newly and newly[0].startswith("AUTO_LESSON_"),
            f"frame audit failed to register the recurring orphan: {newly}")
    _assert(fa.residual_rate() == 0.0,
            "new type does not retroactively explain its own orphans")
    fa2 = FrameAuditor(LessonBook())
    blanket = dict(orphan)
    for _ in range(R4_ORPHAN_MIN + 1):
        fa2.observe(dict(blanket), success=False)
        fa2.observe(dict(blanket), success=True)   # same signature succeeds too
    _assert(not fa2.audit(),
            "frame audit registered a signature that blanket-matches successes")


def test_closure_certificates_walls_blocked_le6() -> None:
    tasks = build_sealed_tasks()
    walls = [t for t in tasks if TASK_FAMILY_BY_TID.get(t.tid) == "search"]
    _assert(len(walls) == 4, "wall set changed unexpectedly")
    for t in walls:
        c = closure_certificate(t)
        _assert(not c["truncated"],
                "certificate enumeration truncated; certificate invalid")
        _assert(c["certified_blocked_le"] == CERT_MAX_LEN,
                f"{t.tid} {c['name']}: expected-open wall is reachable within"
                f" length {CERT_MAX_LEN}; witness={c['witness']}")


def test_certificates_consistent_with_solved_tasks() -> None:
    rs = build_adaptive()
    for tid, toks in rs.adopted_tokens.items():
        task = next(t for t in rs.tasks if t.tid == tid)
        c = closure_certificate(task)
        if c["certified_blocked_le"] is not None:
            exp = expand_tokens(toks, rs.searcher.macros)
            _assert(len(exp) > CERT_MAX_LEN,
                    f"{tid}: certificate contradicts an adopted program of"
                    f" expanded length {len(exp)} <= {CERT_MAX_LEN}")


def test_no_int_to_list_constructor_lemma() -> None:
    lem = no_int_to_list_constructor_lemma()
    _assert(lem["lemma_holds"],
            f"constructor lemma violated by {lem['offending_ops']}")
    _assert(lem["checked_transitions"] >= 2000,
            "lemma domain too small to be meaningful")


def test_reflective_clean_run_has_no_false_retractions() -> None:
    res = gd_reflective_generation_loop(gens=2, seed=SEED + 9, macros={})
    led: ReflectionLedger = res["ledger"]
    _assert(led.validated_retractions == 0,
            "clean self-labeled run produced retractions (false positives)")
    hist = res["history"]
    _assert(hist[-1]["audit_acc"] >= 1.0 - 1e-9,
            f"reflective loop lost audited accuracy vs v1: {hist[-1]}")
    _assert(hist[-1]["residual_rate"] <= 0.5,
            f"unexplained-failure residual unexpectedly high: {hist[-1]}")


TESTS.extend([
    test_r0_retraction_cascades_and_prm_replay,
    test_r0_ledger_records_provenance,
    test_r1_lessons_from_mechanical_predicates,
    test_r2_transfer_resolves_length_hidden_ambiguity,
    test_r2_reflective_paths_are_oracle_free,
    test_r3_budget_bookkeeping_bounded,
    test_r4_discovers_orphan_failure_type,
    test_closure_certificates_walls_blocked_le6,
    test_certificates_consistent_with_solved_tasks,
    test_no_int_to_list_constructor_lemma,
    test_reflective_clean_run_has_no_false_retractions,
])


# =========================================================================== #
# 13. CAPABILITY HORIZON                                                      #
#                                                                             #
# Section 12 converted "the walls are open" into machine certificates: no    #
# base-ISA program of expanded length <= 6 matches any wall's train vector,  #
# and an executed lemma shows the base ISA has no int->list constructor.     #
# This section pushes on the boundary itself, in three honest moves:         #
#                                                                             #
#   1. DEEPER CERTIFICATES. The full length-7 equivalence table dies of      #
#      memory (measured: >4M signature classes exceed the container). A     #
#      targeted scanner avoids holding deep frontiers: stacks are kept only  #
#      up to a hold level; deeper classes are stored as (parent, op) pairs   #
#      and reconstructed on demand. This certifies the walls to length 7     #
#      exactly, and sweeps length 8 for reachability (complete, dedup-free). #
#                                                                             #
#   2. SYSTEM-INITIATED CAPABILITY REQUESTS. A dormant catalog of            #
#      primitives exists OUTSIDE the searcher's vocabulary. The system       #
#      cannot write new semantics (it has no codegen substrate), but it CAN  #
#      mechanically locate which type signature its ISA is missing for a     #
#      certified-blocked task -- from its own residues plus the constructor #
#      lemma -- and emit a request that names the gap. Activation is        #
#      therefore system-triggered and designer-stocked; this is stated, not  #
#      hidden. No oracle content flows into the trigger.                     #
#                                                                             #
#   3. EXACT WALL CHARACTERIZATION. With the requested primitive granted,    #
#      the searcher retries at the maximal declared budget, and a            #
#      designer-supplied EXPRESSIBILITY WITNESS (clearly labeled, never      #
#      counted as solved) is verified through every sealed gate. Each wall   #
#      ends with a quantified band: certified-unreachable depth vs           #
#      witness-expressible depth vs search-attained depth.                   #
#                                                                             #
# Extended primitive ids live in [EXT_ID_BASE, EXT_ID_MAX] = [60, 99]:       #
# above every base op (< 34) and below every macro (>= 100), so existing     #
# "is a macro" predicates (t >= MACRO_ID_BASE) and base tables are           #
# untouched. When the catalog is dormant -- the default -- every code path  #
# behaves exactly as before; tests pin this inertness.                       #
# =========================================================================== #

EXT_ID_BASE = 60
EXT_ID_MAX = 99


@dataclass(frozen=True)
class CapabilitySpec:
    name: str
    ext_id: int
    ins: Tuple[str, ...]            # rightmost-first, like OP_TYPES
    outs: Tuple[str, ...]
    impl: Callable[[List[object], Tuple[int, ...]], None]
    rationale: str


def _bcast_impl(stack: List[object], inp: Tuple[int, ...]) -> None:
    """BCAST: pop int s (top), pop list xs, push the constant list
    (s,) * len(xs). This is exactly the int->list constructor whose absence
    the executed lemma certifies for the base ISA."""
    s = _pop_int(stack)
    xs = _pop_list(stack)
    _push(stack, tuple([s] * len(xs)))


DORMANT_CAPABILITY_CATALOG: Dict[str, CapabilitySpec] = {
    "BCAST": CapabilitySpec(
        name="BCAST", ext_id=EXT_ID_BASE, ins=("i", "l"), outs=("l",),
        impl=_bcast_impl,
        rationale=("signature gap (int,list)->list; constructor lemma: no "
                   "base op creates a list from pure-int stacks except "
                   "INPUT, so constant-list broadcast is inexpressible")),
}


def ext_op_name(t: int) -> str:
    for spec in DORMANT_CAPABILITY_CATALOG.values():
        if spec.ext_id == t:
            return spec.name
    return f"EXT{t}"


def activate_capability(state: SearcherState, name: str) -> CapabilitySpec:
    """Admit a dormant primitive into the live ISA and this searcher's
    vocabulary. Module-global registries make the op executable through
    every dispatch site; the searcher records the grant in its history."""
    spec = DORMANT_CAPABILITY_CATALOG[name]
    EXT_IMPL[spec.ext_id] = spec.impl
    EXT_TYPES[spec.ext_id] = (spec.ins, spec.outs)
    state.extended[spec.ext_id] = spec.name
    state.history.append(f"CAPABILITY_GRANT {spec.name} id={spec.ext_id}")
    state.version += 1
    return spec


def deactivate_all_capabilities(state: Optional[SearcherState] = None) -> None:
    EXT_IMPL.clear()
    EXT_TYPES.clear()
    if state is not None:
        state.extended.clear()


def _apply_tok(stacks: List[Tuple[object, ...]],
               inputs: Sequence[Tuple[int, ...]],
               t: int) -> Optional[List[Tuple[object, ...]]]:
    """Apply one token to per-input stacks; None on crash/overflow. Handles
    base ops and granted extended ops; macros are not valid here."""
    fn = OP_IMPL[t] if t < N_BASE_OPS else EXT_IMPL.get(t)
    if fn is None:
        return None
    out: List[Tuple[object, ...]] = []
    for st, xs in zip(stacks, inputs):
        s = list(st)
        try:
            fn(s, xs)
        except VMCrash:
            return None
        if len(s) > ENUM_STACK_DEPTH:
            return None
        out.append(tuple(s))
    return out


def targeted_reach_scan(targets: Dict[str, Tuple[int, ...]],
                        depth: int,
                        vocab: Sequence[int],
                        hold_level: int = 6,
                        class_cap: int = 700_000,
                        out_json: Optional[str] = None,
                        dedup_deep: bool = True,
                        progress_every: int = 250_000) -> Dict[str, object]:
    """Exact reachability scan for specific train vectors, deeper than the
    full table can go in memory.

    Phase 1 (lengths 1..hold_level): the standard observational-equivalence
    table, full signatures held (known to fit at hold_level=6).
    Phase 2 (hold_level+1): every held class is extended by every token;
    terminal states are checked against the targets; distinct deeper classes
    are stored ONLY as marshal-canonical signature bytes -> (parent index,
    token), never as live stacks.
    Phase 3 (hold_level+2): each stored (parent, token) pair reconstructs
    its stacks from the held frontier and is extended once more, checking
    targets without dedup -- complete for reachability, no storage.

    Soundness: signatures span ALL train inputs, so equal signatures have
    equal continuations on them (OE pruning preserves reachability of any
    train vector); the cross-length shallow prune replaces a prefix by a
    shorter behavioral twin (reachability preserved at <= length); the
    engine stack-depth bound (8) cannot bind for programs of length <= 8
    since depth grows at most 1 per token from the empty stack; and every
    level must report untruncated for its certificate to be emitted."""
    import marshal as _marshal
    if depth > hold_level + 2:
        raise ValueError("scanner supports at most hold_level + 2")
    state = SearcherState()
    tab = build_enum_table(state, surface_max=hold_level,
                           class_cap=class_cap, keep_frontiers=True,
                           vocab_override=list(vocab))
    found: Dict[str, Dict[str, object]] = {}
    for name, vec in targets.items():
        if vec in tab.solutions:
            found[name] = {"length": len(tab.solutions[vec]),
                           "tokens": list(tab.solutions[vec])}
    report: Dict[str, object] = {
        "vocab": [int(t) for t in vocab],
        "targets": {k: list(v) for k, v in targets.items()},
        "classes_per_len": list(tab.classes_per_len),
        "truncated": tab.truncated,
        "max_certified_len": (hold_level if not tab.truncated else None),
        "found": found, "scanned_deep": {},
    }

    def _checkpoint() -> None:
        if out_json:
            with open(out_json, "w") as f:
                json.dump(report, f, sort_keys=True)

    _checkpoint()
    if tab.truncated or depth <= hold_level:
        return report
    held = list(tab.frontiers[hold_level - 1].keys())
    tab.frontiers = None     # free shallower levels; keep only held stacks
    tab.solutions = {}
    inputs = TRAIN_INPUTS
    target_vecs = {v: k for k, v in targets.items()}
    # ---- phase 2: hold_level + 1 -------------------------------------------
    deep: Dict[bytes, Tuple[int, int]] = {}
    scanned = 0
    for idx, sig in enumerate(held):
        stacks = list(sig)
        for t in vocab:
            scanned += 1
            ns = _apply_tok(stacks, inputs, t)
            if ns is None:
                continue
            if all(len(s) == 1 and isinstance(s[0], int) for s in ns):
                vec = tuple(s[0] for s in ns)
                hit = target_vecs.get(vec)
                if hit is not None and hit not in found:
                    found[hit] = {"length": hold_level + 1,
                                  "parent_index": idx, "token": int(t)}
            if dedup_deep:
                key = _marshal.dumps(tuple(ns))
                if key not in deep:
                    deep[key] = (idx, t)
        if progress_every and idx % 50_000 == 0:
            report["scanned_deep"][f"L{hold_level+1}_progress"] = idx
            _checkpoint()
    report["classes_per_len"].append(len(deep) if dedup_deep else -1)
    report["max_certified_len"] = hold_level + 1
    report["found"] = found
    report["scanned_deep"][f"L{hold_level+1}"] = scanned
    _checkpoint()
    if depth <= hold_level + 1:
        return report
    # ---- phase 3: hold_level + 2 (reachability only, no storage) ------------
    scanned8 = 0
    done = 0
    for (idx, t7) in deep.values():
        stacks7 = _apply_tok(list(held[idx]), inputs, t7)
        done += 1
        if stacks7 is None:      # pragma: no cover - phase 2 admitted it
            continue
        for t in vocab:
            scanned8 += 1
            ns = _apply_tok(stacks7, inputs, t)
            if ns is None:
                continue
            if all(len(s) == 1 and isinstance(s[0], int) for s in ns):
                vec = tuple(s[0] for s in ns)
                hit = target_vecs.get(vec)
                if hit is not None and hit not in found:
                    found[hit] = {"length": hold_level + 2,
                                  "parent_index": idx,
                                  "tokens_tail": [int(t7), int(t)]}
        if progress_every and done % 200_000 == 0:
            report["scanned_deep"][f"L{hold_level+2}_progress"] = done
            _checkpoint()
    report["max_certified_len"] = hold_level + 2
    report["found"] = found
    report["scanned_deep"][f"L{hold_level+2}"] = scanned8
    _checkpoint()
    return report


def wall_targets() -> Dict[str, Tuple[int, ...]]:
    tasks = build_sealed_tasks()
    return {t.tid: task_target_vector(t) for t in tasks
            if TASK_FAMILY_BY_TID.get(t.tid) == "search"}


# ---------------------------------------------------------------------------
# System-initiated capability requests. The trigger is mechanical and
# oracle-free: it reads the system's OWN residues for certified-blocked
# tasks, measures which op family dominates its best failed attempts, checks
# whether that family's type-signature space has a gap the dormant catalog
# could fill, and cross-references the executed constructor lemma. The
# output is a REQUEST naming the gap -- the system locating what it is
# missing. Stocking the catalog remains a designer act, stated as such.
# ---------------------------------------------------------------------------
ISA_FAMILIES: Dict[str, Tuple[int, ...]] = {
    "zip_elementwise": (23, 24, 25, 26),
    "scan": (27, 28),
    "reduce": (29, 30),
}


def isa_has_signature(ins: Tuple[str, ...], outs: Tuple[str, ...]) -> bool:
    for sig in list(OP_TYPES.values()) + list(EXT_TYPES.values()):
        if sig == (ins, outs):
            return True
    return False


LIST_CONSUMING_OPS: Tuple[int, ...] = tuple(
    sorted(t for t, (ins, _outs) in OP_TYPES.items() if "l" in ins))


def propose_capability_requests(rs: "RunState",
                                blocked_tids: Sequence[str]) -> List[Dict[str, object]]:
    """Mechanical locator: a request fires when a task is machine-certified
    blocked, the executed constructor lemma holds, and a dormant primitive
    fills a type-signature gap absent from the live ISA. Residue statistics
    (the list-consuming token mass of the system's best failures) are
    attached as measured evidence of where search pressure sits -- they are
    reported, not used as a tuned threshold. No oracle content enters."""
    requests: List[Dict[str, object]] = []
    lemma = no_int_to_list_constructor_lemma()
    for tid in sorted(blocked_tids):
        own = sorted((r for r in rs.residues if r.get("tid") == tid),
                     key=lambda r: -float(r.get("best", 0.0)))[:6]
        toks = [t for r in own for t in r.get("tokens", [])]
        if not toks:
            continue
        list_mass = sum(1 for t in toks if t in LIST_CONSUMING_OPS) / len(toks)
        fam_mass = {
            fam: round(sum(1 for t in toks if t in ids) / len(toks), 4)
            for fam, ids in ISA_FAMILIES.items()}
        for name, spec in DORMANT_CAPABILITY_CATALOG.items():
            gap_open = not isa_has_signature(spec.ins, spec.outs)
            if gap_open and lemma["lemma_holds"] and list_mass > 0.0:
                requests.append({
                    "tid": tid, "capability": name,
                    "list_consuming_mass": round(list_mass, 4),
                    "family_masses": fam_mass,
                    "signature_gap": [list(spec.ins), list(spec.outs)],
                    "lemma_checked_transitions":
                        lemma["checked_transitions"],
                    "rationale": spec.rationale})
    return requests


# ---------------------------------------------------------------------------
# Admission trial: grant the requested primitive, retry every wall at the
# maximal declared budget through BOTH search channels, verify any find with
# the sealed gates, then revoke. Outcomes are recorded either way.
# ---------------------------------------------------------------------------
def capability_admission_trial(name: str, seed: int = SEED,
                               restarts: int = 12,
                               iters: int = 1500) -> Dict[str, object]:
    st = SearcherState()
    spec = activate_capability(st, name)
    rows: List[Dict[str, object]] = []
    try:
        tasks = [t for t in build_sealed_tasks()
                 if TASK_FAMILY_BY_TID.get(t.tid) == "search"]
        prm = None
        try:
            summ = load_summary("adaptive.json")
            ps = summ.get("prm_state")
            if ps:
                prm = StepScorer(int(ps.get("n_feats", PRM_N_FEATS)))
                prm.w = [float(v) for v in ps["w"]]
                prm.wsum = [float(v) for v in ps["wsum"]]
                prm.updates = int(ps["updates"])
                prm.seen = int(ps["seen"])
        except Exception:
            prm = None
        for task in tasks:
            res = synthesize(task.train_pairs, task.tid, st,
                             seed=seed + int(task.tid[1:]),
                             restarts=restarts, iters=iters, drift_rate=0.5)
            best, solved, via = res.best_score, res.solved, "stochastic"
            if not solved and prm is not None \
                    and getattr(prm, "seen", 0) >= PRM_MIN_UPDATES:
                res2, _ = prm_beam_synthesize(task.train_pairs, task.tid,
                                              st, prm, seed=seed ^ 0x5A5A)
                if res2.best_score > best:
                    best = res2.best_score
                if res2.solved:
                    solved, res, via = True, res2, "prm_beam"
            gates = False
            if solved:
                fn = compile_program(res.tokens, st.macros)
                gates = task.holdout_gate(fn) and task.cf_gate(fn)
            rows.append({"tid": task.tid,
                         "name": TASK_NAME_BY_TID.get(task.tid, "?"),
                         "train_exact_found": bool(solved),
                         "passed_gates": bool(gates),
                         "via": via if solved else "",
                         "best_score": round(best, 4),
                         "evals": res.evals_used})
    finally:
        deactivate_all_capabilities(st)
    return {"capability": spec.name, "granted_id": spec.ext_id,
            "restarts": restarts, "iters": iters, "walls": rows,
            "any_broken": any(r["passed_gates"] for r in rows)}


# ---------------------------------------------------------------------------
# Designer-supplied expressibility witness for T29 under BCAST. Verified by
# real execution through every sealed gate; explicitly labeled and NEVER
# counted as solved by the system -- its role is to bound the wall from
# above: the task is EXPRESSIBLE at this exact depth once the requested
# constructor exists, while reachability below stays machine-certified.
# ---------------------------------------------------------------------------
T29_BCAST_WITNESS_TOKENS: Tuple[int, ...] = (
    4, 5, 3, 60,        # INPUT DUP PUSH3 BCAST        -> [xs, B3]
    6, 8, 26,           # SWAP OVER ZMAX               -> [B3, max(x,3)]
    6, 24,              # SWAP ZSUB                    -> [relu(x-3)] = c
    5, 1, 60,           # DUP PUSH1 BCAST              -> [c, B1]
    8, 8, 26,           # OVER OVER ZMAX               -> [c, B1, max(c,1)]
    6, 24,              # SWAP ZSUB                    -> [c, relu(c-1)]
    24,                 # ZSUB                         -> [min(c,1)] = [x>3]
    29,                 # RED_ADD                      -> count
)


def t29_expressibility_witness() -> Dict[str, object]:
    st = SearcherState()
    activate_capability(st, "BCAST")
    try:
        task = next(t for t in build_sealed_tasks() if t.tid == "T29")
        fn = compile_program(T29_BCAST_WITNESS_TOKENS, st.macros)
        train_ok = all(fn(list(xs)) == y for xs, y in task.train_pairs)
        hold_ok = task.holdout_gate(fn)
        cf_ok = task.cf_gate(fn)
        return {"tid": "T29",
                "name": TASK_NAME_BY_TID.get("T29", "?"),
                "tokens": list(T29_BCAST_WITNESS_TOKENS),
                "expanded_len": len(T29_BCAST_WITNESS_TOKENS),
                "gates": {"train": train_ok, "holdout": hold_ok, "cf": cf_ok},
                "designer_supplied": True,
                "counts_as_solved": False}
    finally:
        deactivate_all_capabilities(st)


# ---------------------------------------------------------------------------
# Horizon report: every boundary fact in one place. Reads the deep-scan
# artifact when present; computes the BCAST-augmented certificate live.
# ---------------------------------------------------------------------------
def horizon_report(run_trial: bool = True,
                   trial_restarts: int = 12,
                   trial_iters: int = 1500) -> Dict[str, object]:
    out: Dict[str, object] = {}
    out["lemma"] = no_int_to_list_constructor_lemma()
    deep = None
    for path in ("closure_scan.json", "closure_scan_L7.json"):
        if os.path.exists(path):
            with open(path) as f:
                deep = json.load(f)
            out["deep_scan_artifact"] = path
            break
    out["base_certificates"] = deep
    rs = build_adaptive()
    blocked = sorted(wall_targets())
    out["requests"] = propose_capability_requests(rs, blocked)
    st = SearcherState()
    activate_capability(st, "BCAST")
    try:
        out["bcast_certificate"] = targeted_reach_scan(
            wall_targets(), depth=7,
            vocab=list(range(N_BASE_OPS)) + [EXT_ID_BASE],
            hold_level=6, class_cap=900_000, dedup_deep=False)
    finally:
        deactivate_all_capabilities(st)
    if run_trial:
        out["admission_trial"] = capability_admission_trial(
            "BCAST", restarts=trial_restarts, iters=trial_iters)
    out["witness"] = t29_expressibility_witness()
    bands = {}
    base_max = (deep or {}).get("max_certified_len")
    bc = out["bcast_certificate"]
    for tid in blocked:
        bands[tid] = {
            "base_unreachable_le": base_max,
            "bcast_unreachable_le": (bc["max_certified_len"]
                                     if tid not in bc["found"] else None),
            "expressible_at": (out["witness"]["expanded_len"]
                               if tid == "T29"
                               and all(out["witness"]["gates"].values())
                               else None),
        }
    out["bands"] = bands
    return out


def print_horizon_report(rep: Dict[str, object]) -> None:
    print("=" * 88)
    print("CAPABILITY HORIZON REPORT")
    print("=" * 88)
    lem = rep["lemma"]
    print(f"constructor lemma: {lem['checked_transitions']} transitions,"
          f" non-INPUT list creators={lem['offending_ops'] or 'NONE'},"
          f" holds={lem['lemma_holds']}")
    deep = rep.get("base_certificates")
    if deep:
        print(f"base-ISA deep scan [{rep.get('deep_scan_artifact')}]:"
              f" classes_per_len={deep['classes_per_len']}"
              f" max_certified_len={deep['max_certified_len']}"
              f" walls_found={sorted(deep['found']) or 'NONE'}")
    for req in rep["requests"]:
        print(f"REQUEST {req['tid']}: capability={req['capability']}"
              f" list_mass={req['list_consuming_mass']:.2f}"
              f" gap={req['signature_gap']}")
    bc = rep["bcast_certificate"]
    print(f"BCAST-augmented certificate: classes_per_len="
          f"{bc['classes_per_len']} max_certified_len="
          f"{bc['max_certified_len']} walls_found="
          f"{sorted(bc['found']) or 'NONE'}")
    trial = rep.get("admission_trial")
    if trial:
        for r in trial["walls"]:
            print(f"  trial {r['tid']} {r['name']:<28}"
                  f" found={r['train_exact_found']}"
                  f" gates={r['passed_gates']} best={r['best_score']:.2f}"
                  f" evals={r['evals']}")
        print(f"  trial verdict: any_broken={trial['any_broken']}"
              f" (restarts={trial['restarts']} x iters={trial['iters']})")
    w = rep["witness"]
    print(f"WITNESS {w['tid']} {w['name']}: len={w['expanded_len']}"
          f" gates={w['gates']} designer_supplied={w['designer_supplied']}"
          f" counts_as_solved={w['counts_as_solved']}")
    for tid, b in sorted(rep["bands"].items()):
        print(f"  band {tid}: base unreachable<= {b['base_unreachable_le']},"
              f" +BCAST unreachable<= {b['bcast_unreachable_le']},"
              f" expressible@ {b['expressible_at']}")
    print("reading: the system located its missing constructor from its own"
          " residues, the grant was trialed at maximal budget, and each wall"
          " is now a quantified band instead of a mystery. Reachable-set"
          " expansion still required the designer-stocked catalog; that"
          " dependency is the measured result, not a footnote.")


