def test_extension_registry_dormant_inertness() -> None:
    _assert(not EXT_IMPL and not EXT_TYPES,
            "extension registries must be empty unless granted")
    _assert(SearcherState().vocab() == list(range(N_BASE_OPS)),
            "dormant vocab changed")
    try:
        step_op([], EXT_ID_BASE, (1,))
        _assert(False, "ungranted extended op executed")
    except VMCrash:
        pass
    try:
        expand_tokens((EXT_ID_BASE,), {})
        _assert(False, "ungranted extended op expanded as if known")
    except VMCrash:
        pass


def test_bcast_semantics_and_typing_agree() -> None:
    st = SearcherState()
    activate_capability(st, "BCAST")
    try:
        _assert(EXT_ID_BASE in st.vocab(), "granted op missing from vocab")
        stack: List[object] = []
        step_op(stack, 4, (5, 9, 2))      # INPUT
        step_op(stack, 3, (5, 9, 2))      # PUSH3
        step_op(stack, EXT_ID_BASE, (5, 9, 2))
        _assert(stack == [(3, 3, 3)], f"BCAST semantics wrong: {stack}")
        sigs = build_type_sigs({})
        _assert(static_plausible((4, 3, EXT_ID_BASE, 29), sigs),
                "typed pipeline rejects a valid BCAST program")
        _assert(_sim_types((3, EXT_ID_BASE), sigs) is None,
                "BCAST type-checks without a list beneath the scalar")
        _assert(expand_tokens((4, 3, EXT_ID_BASE), {}) == (4, 3, EXT_ID_BASE),
                "granted op not treated as a terminal token")
    finally:
        deactivate_all_capabilities(st)
    _assert(not EXT_IMPL, "deactivation leaked an active extension")


def test_capability_request_is_mechanical_and_oracle_free() -> None:
    rs = build_adaptive()
    reqs = propose_capability_requests(rs, sorted(wall_targets()))
    _assert(any(r["capability"] == "BCAST" for r in reqs),
            f"no BCAST request derived from real residues: {reqs}")
    r0 = next(r for r in reqs if r["capability"] == "BCAST")
    _assert(r0["list_consuming_mass"] >= 0.20 and r0["signature_gap"] ==
            [["i", "l"], ["l"]]
            and r0["lemma_checked_transitions"] >= 2000,
            f"request evidence malformed: {r0}")
    import inspect
    src = (inspect.getsource(propose_capability_requests)
           + inspect.getsource(isa_has_signature))
    for banned in ("._fn", "holdout_gate", "cf_gate", "audit",
                   "_ORACLE_REGISTRY"):
        _assert(banned not in src, f"request trigger references {banned}")


def test_witness_passes_gates_and_is_never_counted_solved() -> None:
    w = t29_expressibility_witness()
    _assert(all(w["gates"].values()),
            f"witness failed a sealed gate: {w['gates']}")
    _assert(w["designer_supplied"] is True and w["counts_as_solved"] is False,
            "witness labeling violated")
    rs = build_adaptive()
    _assert("T29" not in rs.adopted_tokens,
            "wall appears in adopted set; certificates inconsistent")
    for toks in rs.adopted_tokens.values():
        _assert(tuple(toks) != tuple(w["tokens"]),
                "designer witness leaked into the adopted set")
    _assert(not EXT_IMPL, "witness check leaked an active extension")


def test_targeted_scan_cross_validates_full_table() -> None:
    tab = build_enum_table(SearcherState(), surface_max=4, class_cap=700_000)
    ctrl_vec = next(iter(tab.solutions))
    tgt = dict(wall_targets())
    tgt["CTRL"] = ctrl_vec
    rep = targeted_reach_scan(tgt, depth=4, vocab=list(range(N_BASE_OPS)),
                              hold_level=4, class_cap=700_000)
    _assert(rep["classes_per_len"][:4] == tab.classes_per_len,
            "scanner class counts diverge from the reference table")
    _assert("CTRL" in rep["found"], "scanner missed a reachable control")
    for tid in wall_targets():
        _assert((task_target_vector(next(
            t for t in build_sealed_tasks() if t.tid == tid))
            in tab.solutions) == (tid in rep["found"]),
            f"scanner/table reachability disagreement on {tid}")


def test_deep_scan_artifact_certifies_walls() -> None:
    path = ("closure_scan.json" if os.path.exists("closure_scan.json")
            else "closure_scan_L7.json")
    _assert(os.path.exists(path), "deep scan artifact missing; run "
            "--mode horizon-scan first")
    with open(path) as f:
        rep = json.load(f)
    _assert(rep["truncated"] is False, "deep scan base table truncated")
    _assert(rep["classes_per_len"][5] == 332509,
            f"L6 class count drifted: {rep['classes_per_len']}")
    _assert(int(rep["max_certified_len"]) >= 7,
            f"deep certificate shallower than 7: {rep}")
    _assert(not rep["found"],
            f"deep scan reached a wall vector: {rep['found']}")
    _assert(set(rep["targets"]) == set(wall_targets()),
            "deep scan targets drifted from the wall set")


def test_bcast_certificate_consistent_with_witness() -> None:
    st = SearcherState()
    activate_capability(st, "BCAST")
    try:
        rep = targeted_reach_scan(
            wall_targets(), depth=5,
            vocab=list(range(N_BASE_OPS)) + [EXT_ID_BASE],
            hold_level=5, class_cap=900_000)
    finally:
        deactivate_all_capabilities(st)
    _assert(rep["truncated"] is False, "BCAST table truncated")
    _assert(not rep["found"],
            f"wall reachable within 5 even though witness needs 19:"
            f" {rep['found']}")
    w = t29_expressibility_witness()
    _assert(w["expanded_len"] > rep["max_certified_len"],
            "witness length contradicts the unreachability certificate")


def test_admission_trial_is_honest_and_revokes() -> None:
    rep = capability_admission_trial("BCAST", restarts=2, iters=150)
    _assert(not EXT_IMPL and not EXT_TYPES,
            "admission trial leaked the granted capability")
    for r in rep["walls"]:
        _assert(r["passed_gates"] is False or r["train_exact_found"],
                "gates claimed without a train-exact program")
        _assert(0.0 <= r["best_score"] <= 1.0, "score out of range")
    _assert(rep["any_broken"] == any(r["passed_gates"]
                                     for r in rep["walls"]),
            "summary contradicts rows")


TESTS.extend([
    test_extension_registry_dormant_inertness,
    test_bcast_semantics_and_typing_agree,
    test_capability_request_is_mechanical_and_oracle_free,
    test_witness_passes_gates_and_is_never_counted_solved,
    test_targeted_scan_cross_validates_full_table,
    test_deep_scan_artifact_certifies_walls,
    test_bcast_certificate_consistent_with_witness,
    test_admission_trial_is_honest_and_revokes,
])


# =========================================================================== #
# 14. HYPERDIMENSIONAL INTERFERENCE FIELD (measured, not mystified)           #
#                                                                             #
# External proposal (paraphrased): represent programs as trajectories in a   #
# hyperdimensional vector space; cancel failure regions by adding inverted   #
# trajectory vectors ("destructive interference"); crystallize recurring     #
# successful trajectories into new primitives; and -- the proposal's        #
# central safety claim -- self-deception becomes geometrically impossible   #
# because deceptive candidates lose projection onto the objective vector.   #
#                                                                             #
# The real algebra underneath is Vector Symbolic Architecture: random        #
# bipolar hypervectors are quasi-orthogonal, position-permuted bundling      #
# encodes sequences, and cosine similarity gives a global, soft memory of    #
# where success and failure live. That part is implementable and is          #
# implemented here as ONE more proposal-shaping channel feeding the same     #
# sealed gates as everything else.                                           #
#                                                                             #
# The claims that are NOT implementable are stated and then measured:        #
#   * "superposition executes many variants at once" -- bundles support      #
#     similarity queries, not execution; decoding to discrete ops is         #
#     mandatory and is exactly what the sampler below does.                  #
#   * "smooth semantic drift" -- representation distance is smooth by        #
#     construction; program BEHAVIOR is discontinuous. The smoothness probe  #
#     quantifies the gap.                                                    #
#   * "self-deception geometrically impossible" -- the deception probe       #
#     constructs candidates with near-maximal field similarity that fail     #
#     the sealed gates. Similarity is not validity; gates stay load-bearing. #
#                                                                             #
# Pre-registered predictions (before the battery was first run):             #
#   P1 walls stay unsolved under field shaping at any budget -- this is      #
#      entailed by the Section-13 certificates: no proposal distribution     #
#      reaches a vector that does not exist at <= the certified length.      #
#   P2 the deception probe refutes the impossibility claim with numbers.     #
#   P3 representation-vs-behavior correlation is weak (smooth map,           #
#      discontinuous territory).                                             #
#   P4 on solvable controls the field may help or may be a wash; whichever   #
#      way it lands is reported under equal eval budgets and frozen seeds.   #
# =========================================================================== #

HDV_DIM = 1024
HDV_SEED = 0xC0FFEE


def hdv_token(t: int) -> Tuple[int, ...]:
    rng = random.Random((HDV_SEED, int(t)).__hash__())
    return tuple(1 if rng.random() < 0.5 else -1 for _ in range(HDV_DIM))


_HDV_CACHE: Dict[int, Tuple[int, ...]] = {}


def _hdv(t: int) -> Tuple[int, ...]:
    v = _HDV_CACHE.get(t)
    if v is None:
        v = hdv_token(t)
        _HDV_CACHE[t] = v
    return v


def hdv_encode(tokens: Sequence[int]) -> List[int]:
    """Position-permuted bundling: sum_i roll(V[token_i], i). The standard
    VSA sequence encoding; integer-exact, deterministic."""
    acc = [0] * HDV_DIM
    for i, t in enumerate(tokens):
        v = _hdv(int(t))
        k = i % HDV_DIM
        for j in range(HDV_DIM):
            acc[j] += v[(j - k) % HDV_DIM]
    return acc


def hdv_cos(a: Sequence[int], b: Sequence[int]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    na = math.sqrt(sum(x * x for x in a)) or 1.0
    nb = math.sqrt(sum(y * y for y in b)) or 1.0
    return dot / (na * nb)


class InterferenceField:
    """Global soft memory over program space: successes bundle positively
    (per-family normalized so no task family dominates the superposition --
    the honest version of 'objective vector design'), failures bundle
    negatively. score() is a cosine against this field. The field shapes
    PROPOSALS only; it never touches scoring, gating, or adoption."""

    def __init__(self) -> None:
        self.vec: List[float] = [0.0] * HDV_DIM
        self.n_success = 0
        self.n_failure = 0

    def add_success(self, tokens: Sequence[int], weight: float = 1.0) -> None:
        e = hdv_encode(tokens)
        for j in range(HDV_DIM):
            self.vec[j] += weight * e[j]
        self.n_success += 1

    def add_failure(self, tokens: Sequence[int], weight: float = 1.0) -> None:
        e = hdv_encode(tokens)
        for j in range(HDV_DIM):
            self.vec[j] -= weight * e[j]
        self.n_failure += 1

    def score(self, tokens: Sequence[int]) -> float:
        if not self.n_success and not self.n_failure:
            return 0.0
        return hdv_cos(hdv_encode(tokens), self.vec)


def build_interference_field(rs: "RunState",
                             family_balanced: bool = True) -> InterferenceField:
    field = InterferenceField()
    by_family: Dict[str, List[Tuple[int, ...]]] = {}
    for tid, toks in sorted(rs.adopted_tokens.items()):
        fam = TASK_FAMILY_BY_TID.get(tid, "mint")
        by_family.setdefault(fam, []).append(tuple(toks))
    for fam, progs in sorted(by_family.items()):
        w = (1.0 / len(progs)) if family_balanced else 1.0
        for p in progs:
            field.add_success(p, weight=w)
    for r in sorted(rs.residues, key=lambda r: -float(r.get("best", 0.0)))[:24]:
        if float(r.get("best", 0.0)) >= 0.3:
            field.add_failure(tuple(r.get("tokens", ())), weight=0.5)
    return field


@dataclass
class HDCSearchResult:
    tid: str
    solved: bool
    best_score: float
    evals_used: int
    tokens: Tuple[int, ...]


def hdc_search(task_pairs: Sequence[Tuple[Tuple[int, ...], int]],
               tid: str, state: SearcherState, seed: int,
               restarts: int, iters: int,
               field: Optional[InterferenceField],
               k_cands: int = 4) -> HDCSearchResult:
    """Hill-climb identical across arms; the ONLY arm difference is candidate
    preselection. Each iteration drafts k_cands mutations; the field arm
    keeps the field-similarity argmax, the plain arm keeps the first draft.
    At most ONE candidate is scored per iteration in both arms (iterations
    whose drafts all fail static typing score nothing), so both arms share
    the identical iteration budget and the same per-iteration eval ceiling;
    realized eval counts are reported per arm.
    Field similarity consumes vector arithmetic, never an evaluation."""
    sigs = build_type_sigs(state.macros)
    best: Tuple[int, ...] = ()
    best_s = -1.0
    evals = 0
    tid_salt = sum((i + 1) * ord(c) for i, c in enumerate(tid))
    for r in range(restarts):
        rng = random.Random(seed * 1000003 + tid_salt * 9176 + r * 97)
        cur = _random_tokens(rng, state)
        for _try in range(200):          # type-feasible start, else last draw
            if static_plausible(cur, sigs):
                break
            cur = _random_tokens(rng, state)
        cur_s = -1.0
        for _ in range(iters):
            drafts = []
            for _k in range(k_cands):
                cand = _mutate(rng, state, list(cur))
                if static_plausible(cand, sigs):
                    drafts.append(tuple(cand))
            if not drafts:
                continue
            if field is not None and len(drafts) > 1:
                pick = max(drafts, key=lambda d: field.score(d))
            else:
                pick = drafts[0]
            evals += 1
            s = _score_tokens(pick, state.macros, task_pairs)
            if s >= cur_s:
                cur, cur_s = list(pick), s
            if cur_s > best_s or (cur_s == best_s
                                  and len(cur) < len(best or cur) + 1):
                best, best_s = tuple(cur), cur_s
            if best_s >= 1.0:
                return HDCSearchResult(tid, True, 1.0, evals, best)
    return HDCSearchResult(tid, best_s >= 1.0, max(best_s, 0.0), evals, best)


def hdc_ab_experiment(tids: Sequence[str], seed: int = SEED,
                      restarts: int = 4, iters: int = 300
                      ) -> Dict[str, object]:
    rs = build_adaptive()
    field = build_interference_field(rs)
    tasks = {t.tid: t for t in build_sealed_tasks()}
    rows: List[Dict[str, object]] = []
    for tid in tids:
        task = tasks[tid]
        plain = hdc_search(task.train_pairs, tid, rs.searcher.clone(),
                           seed, restarts, iters, field=None)
        shaped = hdc_search(task.train_pairs, tid, rs.searcher.clone(),
                            seed, restarts, iters, field=field)
        gates_p = gates_s = False
        if plain.solved:
            fnp = compile_program(plain.tokens, rs.searcher.macros)
            gates_p = task.holdout_gate(fnp) and task.cf_gate(fnp)
        if shaped.solved:
            fns = compile_program(shaped.tokens, rs.searcher.macros)
            gates_s = task.holdout_gate(fns) and task.cf_gate(fns)
        rows.append({"tid": tid,
                     "name": TASK_NAME_BY_TID.get(tid, "?"),
                     "family": TASK_FAMILY_BY_TID.get(tid, "?"),
                     "plain": {"best": plain.best_score,
                               "evals": plain.evals_used,
                               "solved": plain.solved, "gates": gates_p},
                     "shaped": {"best": shaped.best_score,
                                "evals": shaped.evals_used,
                                "solved": shaped.solved, "gates": gates_s}})
    return {"field_n_success": field.n_success,
            "field_n_failure": field.n_failure,
            "restarts": restarts, "iters": iters, "rows": rows}


# ---------------------------------------------------------------------------
# Deception probe: candidates engineered to keep near-maximal similarity to
# the success field while breaking real behavior. If the proposal's claim
# held, these would be "energetically impossible"; instead they are
# perfectly representable, score high on the field, and only the sealed
# gates kill them.
# ---------------------------------------------------------------------------
def deception_probe(n: int = 3) -> Dict[str, object]:
    rs = build_adaptive()
    field = build_interference_field(rs)
    tasks = {t.tid: t for t in build_sealed_tasks()}
    rows: List[Dict[str, object]] = []
    swap = {29: 30, 30: 29, 14: 15, 15: 14, 9: 10, 10: 9}
    for tid, toks in sorted(rs.adopted_tokens.items()):
        if tid not in tasks or len(rows) >= n:
            continue
        toks = tuple(toks)
        idxs = [i for i, t in enumerate(toks) if t in swap]
        if not idxs:
            continue
        i = idxs[-1]
        corrupted = toks[:i] + (swap[toks[i]],) + toks[i + 1:]
        task = tasks[tid]
        try:
            fn = compile_program(corrupted, rs.searcher.macros)
            train_ok = all(fn(list(xs)) == y for xs, y in task.train_pairs)
            gate_ok = train_ok and task.holdout_gate(fn) and task.cf_gate(fn)
        except VMCrash:
            train_ok = gate_ok = False
        rows.append({"tid": tid,
                     "cos_original": round(field.score(toks), 4),
                     "cos_corrupted": round(field.score(corrupted), 4),
                     "train_exact": train_ok,
                     "passes_gates": gate_ok})
    return {"rows": rows,
            "claim_refuted": any(
                r["cos_corrupted"] >= 0.7 * r["cos_original"]
                and not r["passes_gates"] for r in rows)}


# ---------------------------------------------------------------------------
# Smoothness probe: distance in representation space vs distance in behavior
# space across single-token mutations of real adopted programs.
# ---------------------------------------------------------------------------
def _behavior_distance(a: Sequence[int], b: Sequence[int],
                       macros: Dict[int, Macro]) -> float:
    diff = 0
    for xs in TRAIN_INPUTS:
        try:
            va = run_base_program(expand_tokens(a, macros), xs)
        except VMCrash:
            va = ("crash",)
        try:
            vb = run_base_program(expand_tokens(b, macros), xs)
        except VMCrash:
            vb = ("crash",)
        if va != vb:
            diff += 1
    return diff / len(TRAIN_INPUTS)


def _spearman(xs: Sequence[float], ys: Sequence[float]) -> float:
    def ranks(v: Sequence[float]) -> List[float]:
        order = sorted(range(len(v)), key=lambda i: v[i])
        r = [0.0] * len(v)
        i = 0
        while i < len(order):
            j = i
            while j + 1 < len(order) and v[order[j + 1]] == v[order[i]]:
                j += 1
            avg = (i + j) / 2 + 1
            for k in range(i, j + 1):
                r[order[k]] = avg
            i = j + 1
        return r
    rx, ry = ranks(xs), ranks(ys)
    mx = sum(rx) / len(rx)
    my = sum(ry) / len(ry)
    num = sum((a - mx) * (b - my) for a, b in zip(rx, ry))
    dx = math.sqrt(sum((a - mx) ** 2 for a in rx)) or 1.0
    dy = math.sqrt(sum((b - my) ** 2 for b in ry)) or 1.0
    return num / (dx * dy)


def smoothness_probe(n_mutations: int = 120,
                     seed: int = SEED) -> Dict[str, object]:
    rs = build_adaptive()
    rng = random.Random(seed * 7919 + 11)
    progs = [tuple(t) for t in rs.adopted_tokens.values() if len(t) >= 3]
    pairs: List[Tuple[float, float]] = []
    vocab = rs.searcher.vocab()
    while len(pairs) < n_mutations and progs:
        p = progs[rng.randrange(len(progs))]
        i = rng.randrange(len(p))
        t2 = vocab[rng.randrange(len(vocab))]
        if t2 == p[i]:
            continue
        q = p[:i] + (t2,) + p[i + 1:]
        dcos = 1.0 - hdv_cos(hdv_encode(p), hdv_encode(q))
        dbeh = _behavior_distance(p, q, rs.searcher.macros)
        pairs.append((dcos, dbeh))
    dcs = [a for a, _ in pairs]
    dbs = [b for _, b in pairs]
    return {"n": len(pairs),
            "mean_dcos": round(sum(dcs) / len(dcs), 4),
            "max_dcos": round(max(dcs), 4),
            "frac_behavior_jump_ge_half":
                round(sum(1 for b in dbs if b >= 0.5) / len(dbs), 4),
            "spearman": round(_spearman(dcs, dbs), 4)}


# ---------------------------------------------------------------------------
# Battery (CLI: --mode hdc-battery).
# ---------------------------------------------------------------------------
def hdc_battery() -> Dict[str, object]:
    out: Dict[str, object] = {}
    print("=" * 88)
    print("HYPERDIMENSIONAL INTERFERENCE-FIELD BATTERY"
          " (VSA channel measured against frozen machinery)")
    print("=" * 88)
    rs_a = build_adaptive()
    rs_f = build_frozen()
    sealed = {t.tid for t in build_sealed_tasks()}
    # Pre-declared control rule: adaptive-solved sealed tasks of MEDIUM
    # measured difficulty (expanded length 7..10) -- short programs solve
    # instantly and macro-ladder tasks never solve at this budget, so only
    # this band gives the A/B comparison dynamic range.
    controls = sorted(
        tid for tid, toks in rs_a.adopted_tokens.items()
        if tid in sealed
        and 7 <= len(expand_tokens(tuple(toks), rs_a.searcher.macros)) <= 10
    )[:6]
    walls = sorted(wall_targets())
    print(f"\n[H1] A/B search, equal eval budgets, frozen seeds;"
          f" controls={controls} walls={walls}")
    ab = hdc_ab_experiment(controls + walls)
    out["H1"] = ab
    p_solved = s_solved = 0
    for r in ab["rows"]:
        p, s = r["plain"], r["shaped"]
        p_solved += p["gates"]
        s_solved += s["gates"]
        print(f"  {r['tid']} {r['name']:<28} plain best={p['best']:.2f}"
              f" evals={p['evals']} gates={p['gates']} | shaped"
              f" best={s['best']:.2f} evals={s['evals']}"
              f" gates={s['gates']}")
    print(f"  totals: plain gate-solved={p_solved}"
          f" shaped gate-solved={s_solved}"
          f" (field: +{ab['field_n_success']} successes,"
          f" -{ab['field_n_failure']} failures)")
    print("\n[H2] deception probe: near-field candidates vs sealed gates")
    dec = deception_probe()
    out["H2"] = dec
    for r in dec["rows"]:
        print(f"  {r['tid']}: cos(orig)={r['cos_original']:.3f}"
              f" cos(corrupted)={r['cos_corrupted']:.3f}"
              f" train_exact={r['train_exact']}"
              f" gates={r['passes_gates']}")
    print(f"  'self-deception geometrically impossible' refuted:"
          f" {dec['claim_refuted']}")
    print("\n[H3] smoothness probe: representation vs behavior distance")
    sm = smoothness_probe()
    out["H3"] = sm
    print(f"  n={sm['n']} mean_dcos={sm['mean_dcos']:.3f}"
          f" max_dcos={sm['max_dcos']:.3f}"
          f" behavior_jump>=0.5 in {sm['frac_behavior_jump_ge_half']:.0%}"
          f" of single-token mutations; spearman={sm['spearman']:.3f}")
    print("  reading: the map is smooth, the territory is not;"
          " interference shaping is a proposal prior, the gates remain the"
          " only arbiter; walls stay where the certificates put them.")
    return out


# ---------------------------------------------------------------------------
# Section 14 tests.
# ---------------------------------------------------------------------------
def test_hdv_encoding_deterministic_and_positional() -> None:
    a = hdv_encode((4, 29))
    _assert(a == hdv_encode((4, 29)), "encoding nondeterministic")
    _assert(abs(hdv_cos(a, a) - 1.0) < 1e-9, "self-cosine != 1")
    b = hdv_encode((29, 4))
    _assert(hdv_cos(a, b) < 0.9, "position permutation lost ordering")
    c = hdv_encode((4, 30))
    _assert(hdv_cos(a, c) < 0.999, "distinct tokens indistinguishable")


def test_interference_paths_are_oracle_free() -> None:
    import inspect
    src = (inspect.getsource(InterferenceField)
           + inspect.getsource(build_interference_field)
           + inspect.getsource(hdc_search))
    for banned in ("._fn", "holdout_gate", "cf_gate", "audit",
                   "_ORACLE_REGISTRY", "task_target_vector"):
        _assert(banned not in src, f"interference path references {banned}")


def test_hdc_budget_parity_and_wall_consistency() -> None:
    rs = build_adaptive()
    field = build_interference_field(rs)
    tasks = {t.tid: t for t in build_sealed_tasks()}
    wall = tasks["T29"]
    a = hdc_search(wall.train_pairs, "T29", rs.searcher.clone(), SEED,
                   restarts=1, iters=80, field=None)
    b = hdc_search(wall.train_pairs, "T29", rs.searcher.clone(), SEED,
                   restarts=1, iters=80, field=field)
    _assert(0 < a.evals_used <= 80 and 0 < b.evals_used <= 80,
            f"eval budget ceiling violated: {a.evals_used} vs"
            f" {b.evals_used} (cap 80)")
    _assert(not a.solved and not b.solved,
            "certified-blocked wall claimed solved; certificate violated")
    _assert(0.0 <= a.best_score <= 1.0 and 0.0 <= b.best_score <= 1.0,
            "scores out of range")


def test_deception_probe_refutes_similarity_validity() -> None:
    dec = deception_probe()
    _assert(len(dec["rows"]) >= 2, "probe found too few corruptible programs")
    _assert(dec["claim_refuted"],
            f"no high-similarity gate-failing candidate found: {dec}")
    for r in dec["rows"]:
        _assert(r["cos_corrupted"] <= 1.0 and r["cos_original"] <= 1.0,
                "cosine out of range")


def test_smoothness_probe_quantifies_discontinuity() -> None:
    sm = smoothness_probe(n_mutations=100)
    _assert(sm["n"] >= 100, "probe undersampled")
    _assert(sm["mean_dcos"] < 0.30,
            f"representation distance not smooth: {sm}")
    _assert(sm["frac_behavior_jump_ge_half"] >= 0.25,
            f"behavior unexpectedly continuous: {sm}")
    _assert(abs(sm["spearman"]) < 0.6,
            f"representation distance strongly predicts behavior: {sm}")


TESTS.extend([
    test_hdv_encoding_deterministic_and_positional,
    test_interference_paths_are_oracle_free,
    test_hdc_budget_parity_and_wall_consistency,
    test_deception_probe_refutes_similarity_validity,
    test_smoothness_probe_quantifies_discontinuity,
])


# =========================================================================== #
# 15. DUAL-CHANNEL ADJUDICATION (clash layer) + LINEAGE GATE SCORE            #
#                                                                             #
# External proposal (paraphrased): pair the semantic verifier with an        #
# independent causal-trace verifier operating at kernel telemetry level      #
# (syscalls, clock dilation, ASLR, cache flushes), route candidates through  #
# an adjudication matrix exploiting the two channels' low failure            #
# covariance, quarantine suspicious passes, and gate lineage on an explicit  #
# multi-generational accept score.                                           #
#                                                                             #
# Category boundary, stated plainly: candidates here are PURE token          #
# programs on a deterministic VM -- no syscalls, no clock, no filesystem,    #
# no cross-call state. Kernel perturbation of such candidates would be       #
# theater, so it is not built. The HONEST mapping of the causal-trace idea   #
# to this substrate is structural: judge a candidate not only by WHAT it     #
# outputs (semantic channel: the sealed train/holdout/cf gates) but by HOW   #
# it is shaped (structural channel: does every token carry weight, does the  #
# execution profile sit inside the adopted population's envelope). The two   #
# channels provably see different things: a train-preserving bloat suffix    #
# (e.g. PUSH0 ADD) passes EVERY semantic gate by construction -- identical   #
# outputs everywhere -- yet is pure deadweight only the structural channel   #
# can flag. That is the proposal's "GVM pass + TCRO anomaly" cell, made      #
# concrete and measurable. Failure covariance between the channels is       #
# measured, not assumed.                                                     #
#                                                                             #
# The lineage gate below is computed retroactively over the CACHED adaptive  #
# run -- no rerun, no tuning; unit weights are declared, components are     #
# recomputed from the run's own event log and cross-checked by tests        #
# against independently derived facts.                                       #
# =========================================================================== #

# ---------------------------------------------------------------------------
# Structural channel: trace profile + ablation slack.
# ---------------------------------------------------------------------------
def trace_profile(tokens: Sequence[int],
                  macros: Dict[int, Macro]) -> Dict[str, float]:
    """Execution-shape features measured by REAL runs over the train
    inputs: expanded length, distinct base ops, realized max stack depth,
    and whether the input is ever read. No oracle content."""
    expanded = expand_tokens(tokens, macros)
    max_depth = 0
    crashes = 0
    for xs in TRAIN_INPUTS:
        stack: List[object] = []
        try:
            for op in expanded:
                step_op(stack, op, xs)
                if len(stack) > max_depth:
                    max_depth = len(stack)
        except VMCrash:
            crashes += 1
    return {"expanded_len": float(len(expanded)),
            "distinct_ops": float(len(set(expanded))),
            "max_depth": float(max_depth),
            "reads_input": float(any(op == 4 for op in expanded)),
            "crash_frac": crashes / len(TRAIN_INPUTS)}


def ablation_slack(tokens: Sequence[int], macros: Dict[int, Macro],
                   pairs: Sequence[Tuple[Tuple[int, ...], int]],
                   max_window: int = 2) -> Dict[str, object]:
    """Token-level ablation isolation: fraction of contiguous deletions
    (window 1..max_window) that leave the program train-exact. A genuinely
    minimal program has zero slack; any deletable window is deadweight the
    semantic gates cannot see when the outputs are unchanged."""
    toks = tuple(tokens)
    tried = 0
    slack_hits: List[Tuple[int, int]] = []
    witness: Optional[Tuple[int, ...]] = None
    for w in range(1, max_window + 1):
        for i in range(0, len(toks) - w + 1):
            cand = toks[:i] + toks[i + w:]
            if not cand:
                continue
            tried += 1
            # Real execution only: the static type approximation is
            # conservative and rejects some enum-adopted valid programs
            # (measured), which would hide their deadweight variants.
            if _score_tokens(cand, macros, pairs) >= 1.0:
                slack_hits.append((i, w))
                if witness is None or len(cand) < len(witness):
                    witness = cand
    return {"tried": tried,
            "slack_frac": (len(slack_hits) / tried) if tried else 0.0,
            "slack_windows": slack_hits[:8],
            "shorter_equivalent": list(witness) if witness else None}


def population_envelope(profiles: Sequence[Dict[str, float]]
                        ) -> Dict[str, Tuple[float, float]]:
    keys = ("expanded_len", "distinct_ops", "max_depth")
    env: Dict[str, Tuple[float, float]] = {}
    for k in keys:
        vals = [p[k] for p in profiles]
        mu = sum(vals) / len(vals)
        var = sum((v - mu) ** 2 for v in vals) / max(1, len(vals) - 1)
        env[k] = (mu, math.sqrt(var))
    return env


STRUCT_Z_MAX = 3.0


def structural_gate(tokens: Sequence[int], macros: Dict[int, Macro],
                    pairs: Sequence[Tuple[Tuple[int, ...], int]],
                    envelope: Dict[str, Tuple[float, float]]
                    ) -> Dict[str, object]:
    prof = trace_profile(tokens, macros)
    abl = ablation_slack(tokens, macros, pairs)
    anomalies: List[str] = []
    if abl["slack_frac"] > 0.0:
        anomalies.append(f"deadweight_slack={abl['slack_frac']:.3f}")
    for k, (mu, sd) in envelope.items():
        if sd > 1e-9 and abs(prof[k] - mu) / sd > STRUCT_Z_MAX:
            anomalies.append(f"{k}_z={(prof[k] - mu) / sd:.2f}")
    if prof["crash_frac"] > 0.0:
        anomalies.append(f"crash_frac={prof['crash_frac']:.3f}")
    return {"stable": not anomalies, "anomalies": anomalies,
            "profile": prof, "ablation": abl}


# ---------------------------------------------------------------------------
# Clash adjudication matrix + quarantine lab.
# ---------------------------------------------------------------------------
def clash_adjudicate(semantic_pass: bool,
                     struct_report: Dict[str, object]) -> str:
    if not semantic_pass:
        return "reject"
    return "promote" if struct_report["stable"] else "quarantine"


def final_clash_verdict(tokens: Sequence[int], macros: Dict[int, Macro],
                        task: SealedTask,
                        envelope: Dict[str, Tuple[float, float]]
                        ) -> Tuple[str, Dict[str, object]]:
    """Raw adjudication, with quarantine resolved by the stress lab: the
    document's full pipeline cell-by-cell. Returns (final, detail)."""
    try:
        fn = compile_program(tokens, macros)
        sem = (all(fn(list(xs)) == y for xs, y in task.train_pairs)
               and task.holdout_gate(fn) and task.cf_gate(fn))
    except VMCrash:
        sem = False
    struct = structural_gate(tokens, macros, task.train_pairs, envelope)
    raw = clash_adjudicate(sem, struct)
    if raw != "quarantine":
        return raw, {"raw": raw, "struct": struct}
    lab = quarantine_stress(tokens, macros, task)
    final = ("promote" if lab["verdict"] == "cleared" else lab["verdict"])
    return final, {"raw": raw, "struct": struct, "lab": lab}


def quarantine_stress(tokens: Sequence[int], macros: Dict[int, Macro],
                      task: SealedTask) -> Dict[str, object]:
    """High-stress pass for quarantined candidates: deeper ablation (window
    up to 3), full gate re-verification, and a determinism replay. A
    candidate whose deeper ablation exposes a shorter train-exact equivalent
    is rejected as bloat WITH the minimal form attached; a candidate that
    survives everything is cleared (structural false positive)."""
    abl = ablation_slack(tokens, macros, task.train_pairs, max_window=3)
    fn1 = compile_program(tokens, macros)
    fn2 = compile_program(tokens, macros)
    replay_ok = all(fn1(list(xs)) == fn2(list(xs))
                    for xs, _ in task.train_pairs)
    gates_ok = (task.holdout_gate(fn1) and task.cf_gate(fn1))
    if abl["shorter_equivalent"] is not None:
        return {"verdict": "reject_bloat",
                "minimal_form": abl["shorter_equivalent"],
                "replay_ok": replay_ok, "gates_ok": gates_ok}
    if replay_ok and gates_ok:
        return {"verdict": "cleared", "minimal_form": None,
                "replay_ok": replay_ok, "gates_ok": gates_ok}
    return {"verdict": "reject", "minimal_form": None,
            "replay_ok": replay_ok, "gates_ok": gates_ok}


# ---------------------------------------------------------------------------
# Failure-covariance experiment over a constructed candidate population:
#   genuine    -- the adopted sealed-task programs (semantic pass expected)
#   bloated    -- adopted + train-preserving PUSH0 ADD suffix (semantic pass
#                 BY CONSTRUCTION; only the structural channel can object)
#   corrupted  -- one semantics-bearing token swapped (semantic fail)
# ---------------------------------------------------------------------------
_CLASH_SWAP = {29: 30, 30: 29, 14: 15, 15: 14, 9: 10, 10: 9}


def clash_population(rs: "RunState") -> List[Dict[str, object]]:
    tasks = {t.tid: t for t in build_sealed_tasks()}
    out: List[Dict[str, object]] = []
    for tid, toks in sorted(rs.adopted_tokens.items()):
        if tid not in tasks:
            continue
        toks = tuple(toks)
        out.append({"kind": "genuine", "tid": tid, "tokens": toks})
        out.append({"kind": "bloated", "tid": tid,
                    "tokens": toks + (0, 9)})
        idxs = [i for i, t in enumerate(toks) if t in _CLASH_SWAP]
        if idxs:
            i = idxs[-1]
            out.append({"kind": "corrupted", "tid": tid,
                        "tokens": toks[:i] + (_CLASH_SWAP[toks[i]],)
                        + toks[i + 1:]})
    return out


def failure_covariance_experiment(rs: Optional["RunState"] = None
                                  ) -> Dict[str, object]:
    rs = rs if rs is not None else build_adaptive()
    tasks = {t.tid: t for t in build_sealed_tasks()}
    genuine_profiles = [trace_profile(t, rs.searcher.macros)
                        for tid, t in sorted(rs.adopted_tokens.items())
                        if tid in tasks]
    env = population_envelope(genuine_profiles)
    cells: Dict[Tuple[bool, bool], int] = {}
    rows: List[Dict[str, object]] = []
    verdict_counts: Dict[str, int] = {}
    for cand in clash_population(rs):
        task = tasks[cand["tid"]]
        toks = cand["tokens"]
        sem = False
        try:
            fn = compile_program(toks, rs.searcher.macros)
            sem = (all(fn(list(xs)) == y for xs, y in task.train_pairs)
                   and task.holdout_gate(fn) and task.cf_gate(fn))
        except VMCrash:
            sem = False
        struct = structural_gate(toks, rs.searcher.macros,
                                 task.train_pairs, env)
        verdict = clash_adjudicate(sem, struct)
        verdict_counts[verdict] = verdict_counts.get(verdict, 0) + 1
        cells[(sem, struct["stable"])] = cells.get(
            (sem, struct["stable"]), 0) + 1
        rows.append({"kind": cand["kind"], "tid": cand["tid"],
                     "semantic_pass": sem,
                     "structural_stable": struct["stable"],
                     "verdict": verdict,
                     "anomalies": struct["anomalies"]})
    n = len(rows)
    a = cells.get((True, True), 0)
    b = cells.get((True, False), 0)
    c = cells.get((False, True), 0)
    d = cells.get((False, False), 0)
    denom = math.sqrt(max(1, (a + b) * (c + d) * (a + c) * (b + d)))
    phi = (a * d - b * c) / denom
    by_kind: Dict[str, Dict[str, int]] = {}
    final_by_kind: Dict[str, Dict[str, int]] = {}
    for r in rows:
        k = by_kind.setdefault(r["kind"], {})
        k[r["verdict"]] = k.get(r["verdict"], 0) + 1
    for cand in clash_population(rs):
        fin, _detail = final_clash_verdict(cand["tokens"],
                                           rs.searcher.macros,
                                           tasks[cand["tid"]], env)
        fk = final_by_kind.setdefault(cand["kind"], {})
        fk[fin] = fk.get(fin, 0) + 1
    return {"n": n, "cells": {"pass_stable": a, "pass_anomaly": b,
                              "fail_stable": c, "fail_anomaly": d},
            "phi": round(phi, 4), "verdicts": verdict_counts,
            "by_kind": by_kind, "final_by_kind": final_by_kind,
            "rows": rows}


# ---------------------------------------------------------------------------
# Lineage gate score, recomputed from the cached adaptive run's event log.
# Unit weights, declared; components cross-checked by tests against
# independently derived run facts.
# ---------------------------------------------------------------------------
def lineage_accept_scores(rs: Optional["RunState"] = None
                          ) -> Dict[str, object]:
    rs = rs if rs is not None else build_adaptive()
    tasks = {t.tid: t for t in build_sealed_tasks()}
    genuine_profiles = [trace_profile(t, rs.searcher.macros)
                        for tid, t in sorted(rs.adopted_tokens.items())
                        if tid in tasks]
    env = population_envelope(genuine_profiles)
    waves: Dict[int, List[Tuple[str, int]]] = {}
    for e in rs.events:
        parts = e.split()
        if len(parts) >= 4 and parts[1] == "ADOPT" and parts[0][0] == "w":
            w = int(parts[0][1:])
            exp = next((p for p in parts if p.startswith("len=")), "len=0/exp0")
            elen = int(exp.split("exp")[-1])
            waves.setdefault(w, []).append((parts[2], elen))
    rows: List[Dict[str, object]] = []
    cum_len: List[int] = []
    total = 0.0
    for w in sorted(waves):
        ads = waves[w]
        sealed = [tid for tid, _ in ads if tid in tasks]
        ext = [tid for tid in sealed
               if TASK_FAMILY_BY_TID.get(tid) in ("string_like", "external")
               or tid >= "T17"]
        mints = [tid for tid, _ in ads
                 if tid not in tasks and tid.startswith("G")]
        stab = 0
        for tid in sealed:
            fin, _d = final_clash_verdict(tuple(rs.adopted_tokens[tid]),
                                          rs.searcher.macros,
                                          tasks[tid], env)
            stab += 1 if fin == "promote" else 0
        stab_rate = (stab / len(sealed)) if sealed else 1.0
        prev_mean = (sum(cum_len) / len(cum_len)) if cum_len else 0.0
        new_lens = [el for _, el in ads]
        cum_len.extend(new_lens)
        new_mean = sum(cum_len) / len(cum_len)
        bloat_pen = max(0.0, new_mean - prev_mean) if prev_mean else 0.0
        score = (len(sealed) + len(ext) + len(mints) + stab_rate
                 - 0.1 * bloat_pen)
        total += score
        rows.append({"wave": w, "semantic_gain": len(sealed),
                     "heldout_transfer_gain": len(ext),
                     "lineage_gain": len(mints),
                     "perturbation_stability": round(stab_rate, 4),
                     "complexity_bloat_penalty": round(bloat_pen, 4),
                     "rsi_accept_score": round(score, 4)})
    return {"per_wave": rows, "total": round(total, 4),
            "lineage_gain_total": sum(r["lineage_gain"] for r in rows),
            "semantic_gain_total": sum(r["semantic_gain"] for r in rows)}


# ---------------------------------------------------------------------------
# Verifier pin: tamper-evidence for the L3 prohibition. The semantic
# verifiers are frozen by design; this pins their SOURCE so any mutation of
# gate-construction code is detectable across runs and recorded artifacts.
# ---------------------------------------------------------------------------
def verifier_pin() -> str:
    import inspect
    blob = "".join(inspect.getsource(o) for o in
                   (SealedTask, _make_gate, build_sealed_tasks,
                    task_target_vector))
    return hashlib.sha256(blob.encode()).hexdigest()[:16]


# ---------------------------------------------------------------------------
# Battery (CLI: --mode clash-battery).
# ---------------------------------------------------------------------------
def clash_battery() -> Dict[str, object]:
    out: Dict[str, object] = {}
    print("=" * 88)
    print("CLASH LAYER BATTERY (semantic x structural adjudication,"
          " failure covariance, lineage gate)")
    print("=" * 88)
    rs = build_adaptive()
    print("\n[C1] failure covariance over constructed population"
          " (genuine / bloated / corrupted)")
    cov = failure_covariance_experiment(rs)
    out["C1"] = cov
    for kind in ("genuine", "bloated", "corrupted"):
        print(f"  {kind:<10} -> {cov['by_kind'].get(kind, {})}")
    print(f"  cells: {cov['cells']}  phi={cov['phi']}")
    print(f"  lab-final routing: {cov['final_by_kind']}")
    print("  reading: bloated candidates pass EVERY semantic gate by"
          " construction and are flagged only structurally -- the"
          " channels' failures are not the same failures.")
    print("\n[C2] quarantine lab on a bloated quarantinee")
    tasks = {t.tid: t for t in build_sealed_tasks()}
    tid0 = sorted(t for t in rs.adopted_tokens if t in tasks)[0]
    bl = tuple(rs.adopted_tokens[tid0]) + (0, 9)
    lab = quarantine_stress(bl, rs.searcher.macros, tasks[tid0])
    out["C2"] = {"tid": tid0, "lab": lab}
    print(f"  {tid0}+PUSH0,ADD -> verdict={lab['verdict']}"
          f" minimal_form={lab['minimal_form']}"
          f" (gates_ok={lab['gates_ok']} -- the gates STILL pass it;"
          f" only ablation recovers the true program)")
    print("\n[C3] lineage gate score, recomputed from the cached run")
    lin = lineage_accept_scores(rs)
    out["C3"] = lin
    for r in lin["per_wave"]:
        print(f"  w{r['wave']}: sem={r['semantic_gain']}"
              f" ext={r['heldout_transfer_gain']}"
              f" lineage={r['lineage_gain']}"
              f" stab={r['perturbation_stability']:.2f}"
              f" bloat_pen={r['complexity_bloat_penalty']:.2f}"
              f" score={r['rsi_accept_score']:.2f}")
    print(f"  totals: score={lin['total']}"
          f" lineage_gain={lin['lineage_gain_total']}"
          f" semantic_gain={lin['semantic_gain_total']}")
    print(f"\n[C4] verifier pin (L3 tamper-evidence): {verifier_pin()}")
    out["C4"] = verifier_pin()
    print("\nclash battery complete.")
    return out


# ---------------------------------------------------------------------------
# Section 15 tests.
# ---------------------------------------------------------------------------
def test_adopted_programs_have_zero_ablation_slack() -> None:
    rs = build_adaptive()
    tasks = {t.tid: t for t in build_sealed_tasks()}
    checked = 0
    for tid, toks in sorted(rs.adopted_tokens.items()):
        if tid not in tasks:
            continue
        abl = ablation_slack(tuple(toks), rs.searcher.macros,
                             tasks[tid].train_pairs)
        _assert(abl["slack_frac"] == 0.0,
                f"{tid} carries deadweight: {abl}")
        checked += 1
    _assert(checked >= 20, f"too few adopted programs checked: {checked}")


def test_bloat_passes_semantic_gates_but_not_structural() -> None:
    rs = build_adaptive()
    tasks = {t.tid: t for t in build_sealed_tasks()}
    tid = sorted(t for t in rs.adopted_tokens if t in tasks)[0]
    task = tasks[tid]
    bl = tuple(rs.adopted_tokens[tid]) + (0, 9)
    fn = compile_program(bl, rs.searcher.macros)
    _assert(all(fn(list(xs)) == y for xs, y in task.train_pairs)
            and task.holdout_gate(fn) and task.cf_gate(fn),
            "bloat construct unexpectedly failed semantic gates")
    genuine = [trace_profile(t, rs.searcher.macros)
               for k, t in sorted(rs.adopted_tokens.items()) if k in tasks]
    rep = structural_gate(bl, rs.searcher.macros, task.train_pairs,
                          population_envelope(genuine))
    _assert(not rep["stable"] and any("deadweight" in a
                                      for a in rep["anomalies"]),
            f"structural channel missed the deadweight: {rep}")
    _assert(clash_adjudicate(True, rep) == "quarantine",
            "clash matrix misrouted the pass+anomaly cell")


def test_clash_matrix_routes_all_cells() -> None:
    stable = {"stable": True, "anomalies": []}
    anom = {"stable": False, "anomalies": ["x"]}
    _assert(clash_adjudicate(True, stable) == "promote", "cell 1")
    _assert(clash_adjudicate(True, anom) == "quarantine", "cell 2")
    _assert(clash_adjudicate(False, stable) == "reject", "cell 3")
    _assert(clash_adjudicate(False, anom) == "reject", "cell 4")


def test_quarantine_lab_recovers_minimal_form() -> None:
    rs = build_adaptive()
    tasks = {t.tid: t for t in build_sealed_tasks()}
    tid = sorted(t for t in rs.adopted_tokens if t in tasks)[0]
    orig = tuple(rs.adopted_tokens[tid])
    lab = quarantine_stress(orig + (0, 9), rs.searcher.macros, tasks[tid])
    _assert(lab["verdict"] == "reject_bloat",
            f"lab failed to reject bloat: {lab}")
    _assert(tuple(lab["minimal_form"]) == orig,
            f"recovered form is not the original: {lab['minimal_form']}")
    lab2 = quarantine_stress(orig, rs.searcher.macros, tasks[tid])
    _assert(lab2["verdict"] == "cleared",
            f"lab rejected a genuine program: {lab2}")


def test_failure_covariance_channels_disagree_on_bloat() -> None:
    cov = failure_covariance_experiment()
    _assert(cov["cells"]["pass_anomaly"] >= 20,
            f"bloat cell underpopulated: {cov['cells']}")
    bk = cov["by_kind"]
    fk = cov["final_by_kind"]
    _assert(set(bk.get("bloated", {})) == {"quarantine"},
            f"bloated candidates not uniformly quarantined: {bk}")
    _assert(set(fk.get("bloated", {})) == {"reject_bloat"},
            f"lab failed to convict bloat: {fk}")
    _assert(set(fk.get("corrupted", {})) == {"reject"},
            f"corrupted candidates not uniformly rejected: {fk}")
    _assert(set(fk.get("genuine", {})) == {"promote"},
            f"genuine candidates not finally promoted: {fk}")
    _assert(abs(cov["phi"]) < 0.99,
            "channels are fully covariant; second channel adds nothing")


def test_lineage_scores_match_cached_run_facts() -> None:
    rs = build_adaptive()
    lin = lineage_accept_scores(rs)
    tasks = {t.tid for t in build_sealed_tasks()}
    sealed_adopted = sum(1 for t in rs.adopted_tokens if t in tasks)
    tasks_set = tasks
    mint_adopted = sum(1 for t in rs.adopted_tokens
                       if t not in tasks_set and t.startswith("G"))
    _assert(lin["semantic_gain_total"] == sealed_adopted,
            f"semantic totals diverge: {lin['semantic_gain_total']}"
            f" vs {sealed_adopted}")
    _assert(lin["lineage_gain_total"] == mint_adopted,
            f"lineage totals diverge: {lin['lineage_gain_total']}"
            f" vs {mint_adopted}")
    _assert(mint_adopted >= 10,
            f"frontier-mint count implausibly low: {mint_adopted}")
    _assert(all(r["perturbation_stability"] == 1.0
                for r in lin["per_wave"]),
            "an adopted program failed its own structural envelope")


def test_verifier_pin_is_stable_and_meaningful() -> None:
    p1, p2 = verifier_pin(), verifier_pin()
    _assert(p1 == p2 and len(p1) == 16, "verifier pin unstable")


TESTS.extend([
    test_adopted_programs_have_zero_ablation_slack,
    test_bloat_passes_semantic_gates_but_not_structural,
    test_clash_matrix_routes_all_cells,
    test_quarantine_lab_recovers_minimal_form,
    test_failure_covariance_channels_disagree_on_bloat,
    test_lineage_scores_match_cached_run_facts,
    test_verifier_pin_is_stable_and_meaningful,
])


# =========================================================================== #
# 16. SELF-FORGE: SYSTEM-SYNTHESIZED PRIMITIVES                               #
#                                                                             #
# The Section-13 certificates located the failure of general-domain RSI      #
# precisely: the system had no substrate in which to WRITE new semantics.    #
# Macros are compositions inside the old closure; the dormant catalog        #
# shifted authorship of each new primitive to the designer. This section     #
# replaces per-primitive designer stocking with ONE designer-provided        #
# GENERATIVE substrate -- a tiny total combinator language -- inside which   #
# the system itself synthesizes, verifies, and registers new primitives      #
# from nothing but the train pairs its search was always allowed to see.     #
#                                                                             #
#   Substrate (designer-provided, declared):                                 #
#     fold over the input list with a 3-int accumulator. Init values,        #
#     step updates, and the output projection are depth-bounded scalar       #
#     expression trees over {t1,t2,t3,x} + consts {0..3} with ops            #
#     {ADD,SUB,MUL,MAX,MIN,IFPOS}. Total by construction: one pass,          #
#     bounded trees, overflow-guarded ints.                                  #
#                                                                             #
#   What the SYSTEM does (no oracle anywhere before the sealed gates):       #
#     1. derives a spec = the wall task's train pairs (always legitimate);   #
#     2. stochastically synthesizes a fold program matching the spec;        #
#     3. compiles it to a native op and registers it through the Section-13  #
#        extension registry (ids 61+);                                       #
#     4. the ordinary stack-VM search then solves the wall WITH the new op   #
#        and the solution must pass the sealed holdout+cf gates AND the      #
#        Section-15 structural channel before adoption;                      #
#     5. forged ops lift across substrates: each list->int forge is          #
#        registered as a GD feature atom, extending the general-domain       #
#        expression language the debate pipeline searches.                   #
#                                                                             #
#   Honesty boundary, pre-registered: the substrate itself is still a        #
#   designer act -- the dependency moved up one level, from "designer        #
#   writes each primitive" to "designer provides one generative language".   #
#   The new closure has its own walls (anything needing more state than      #
#   three ints in one pass); a declared out-of-closure spec (median) is      #
#   attempted at the same budget and its failure is reported, not hidden.    #
# =========================================================================== #

FORGE_OPS: Tuple[str, ...] = ("ADD", "SUB", "MUL", "MAX", "MIN", "IFPOS")
FORGE_VARS: Tuple[str, ...] = ("t1", "t2", "t3", "x")
FORGE_CONSTS: Tuple[int, ...] = (0, 1, 2, 3)
FORGE_DEPTH_MAX = 4
FORGE_INT_CAP = 10 ** 9
FORGE_ID_BASE = 61          # self-forged primitive ids: 61..99


def forge_tree_eval(tree: object, t1: int, t2: int, t3: int, x: int) -> int:
    """Total recursive evaluator for scalar trees. Trees are nested tuples
    (op, left, right) | ("IFPOS", c, a, b) | ("var", name) | ("const", k)."""
    tag = tree[0]
    if tag == "const":
        return tree[1]
    if tag == "var":
        n = tree[1]
        return t1 if n == "t1" else t2 if n == "t2" else t3 if n == "t3" else x
    if tag == "IFPOS":
        c = forge_tree_eval(tree[1], t1, t2, t3, x)
        branch = tree[2] if c > 0 else tree[3]
        return forge_tree_eval(branch, t1, t2, t3, x)
    a = forge_tree_eval(tree[1], t1, t2, t3, x)
    b = forge_tree_eval(tree[2], t1, t2, t3, x)
    if tag == "ADD":
        v = a + b
    elif tag == "SUB":
        v = a - b
    elif tag == "MUL":
        v = a * b
    elif tag == "MAX":
        v = a if a >= b else b
    else:
        v = a if a <= b else b
    if v > FORGE_INT_CAP or v < -FORGE_INT_CAP:
        raise VMCrash("forge_int_overflow")
    return v


def _forge_tree_vars(tree: object) -> List[Tuple[str, str]]:
    tag = tree[0]
    if tag == "var":
        return [tree]
    if tag == "const":
        return []
    return [v for kid in tree[1:] for v in _forge_tree_vars(kid)]


def forge_tree_depth(tree: object) -> int:
    tag = tree[0]
    if tag in ("const", "var"):
        return 1
    if tag == "IFPOS":
        return 1 + max(forge_tree_depth(tree[1]), forge_tree_depth(tree[2]),
                       forge_tree_depth(tree[3]))
    return 1 + max(forge_tree_depth(tree[1]), forge_tree_depth(tree[2]))


def _forge_rand_tree(rng: random.Random, depth: int,
                     allow_vars: Sequence[str]) -> object:
    if depth <= 1 or rng.random() < 0.30:
        if allow_vars and rng.random() < 0.62:
            return ("var", allow_vars[rng.randrange(len(allow_vars))])
        return ("const", FORGE_CONSTS[rng.randrange(len(FORGE_CONSTS))])
    op = FORGE_OPS[rng.randrange(len(FORGE_OPS))]
    if op == "IFPOS":
        return ("IFPOS", _forge_rand_tree(rng, depth - 1, allow_vars),
                _forge_rand_tree(rng, depth - 1, allow_vars),
                _forge_rand_tree(rng, depth - 1, allow_vars))
    return (op, _forge_rand_tree(rng, depth - 1, allow_vars),
            _forge_rand_tree(rng, depth - 1, allow_vars))


def _forge_mutate_tree(rng: random.Random, tree: object,
                       allow_vars: Sequence[str]) -> object:
    if rng.random() < 0.35:
        return _forge_rand_tree(rng, rng.randint(1, FORGE_DEPTH_MAX),
                                allow_vars)
    tag = tree[0]
    if tag in ("const", "var"):
        return _forge_rand_tree(rng, rng.randint(1, 2), allow_vars)
    kids = list(tree[1:])
    i = rng.randrange(len(kids))
    kids[i] = _forge_mutate_tree(rng, kids[i], allow_vars)
    cand = (tag,) + tuple(kids)
    if forge_tree_depth(cand) > FORGE_DEPTH_MAX:
        return tree
    return cand


@dataclass(frozen=True)
class FoldSpec:
    """One forged primitive: list -> int, single pass, 3-int state."""
    init: Tuple[object, object, object]     # const-only trees
    step: Tuple[object, object, object]     # trees over t1,t2,t3,x
    out: object                             # tree over t1,t2,t3

    def key(self) -> str:
        return hashlib.sha256(repr((self.init, self.step,
                                    self.out)).encode()).hexdigest()[:12]


def fold_spec_eval(spec: FoldSpec, xs: Sequence[int]) -> int:
    t1 = forge_tree_eval(spec.init[0], 0, 0, 0, 0)
    t2 = forge_tree_eval(spec.init[1], 0, 0, 0, 0)
    t3 = forge_tree_eval(spec.init[2], 0, 0, 0, 0)
    for x in xs:
        n1 = forge_tree_eval(spec.step[0], t1, t2, t3, x)
        n2 = forge_tree_eval(spec.step[1], t1, t2, t3, x)
        n3 = forge_tree_eval(spec.step[2], t1, t2, t3, x)
        t1, t2, t3 = n1, n2, n3
    return forge_tree_eval(spec.out, t1, t2, t3, 0)


def _forge_rand_spec(rng: random.Random) -> FoldSpec:
    step = [_forge_rand_tree(rng, rng.randint(2, FORGE_DEPTH_MAX),
                             FORGE_VARS) for _ in range(3)]
    if rng.random() < 0.45:
        step[2] = ("var", "x")        # generic fold idiom: track prev elem
    return FoldSpec(
        init=tuple(_forge_rand_tree(rng, rng.randint(1, 3), ())
                   for _ in range(3)),
        step=tuple(step),
        out=_forge_rand_tree(rng, rng.randint(1, 2), ("t1", "t2", "t3")))


def _forge_mutate_spec(rng: random.Random, spec: FoldSpec) -> FoldSpec:
    slot = rng.randrange(7)
    init, step, out = list(spec.init), list(spec.step), spec.out
    if slot < 3:
        init[slot] = _forge_mutate_tree(rng, init[slot], ())
    elif slot < 6:
        step[slot - 3] = _forge_mutate_tree(rng, step[slot - 3], FORGE_VARS)
    else:
        out = _forge_mutate_tree(rng, out, ("t1", "t2", "t3"))
    return FoldSpec(tuple(init), tuple(step), out)


def forge_tree_nodes(tree: object) -> int:
    tag = tree[0]
    if tag in ("const", "var"):
        return 1
    return 1 + sum(forge_tree_nodes(k) for k in tree[1:])


def forge_simplify_tree(tree: object) -> object:
    """Deterministic identity/constant folding. Behavior-preserving."""
    tag = tree[0]
    if tag in ("const", "var"):
        return tree
    kids = [forge_simplify_tree(k) for k in tree[1:]]
    if all(k[0] == "const" for k in kids):
        try:
            if tag == "IFPOS":
                return kids[1] if kids[0][1] > 0 else kids[2]
            a, b = kids[0][1], kids[1][1]
            v = (a + b if tag == "ADD" else a - b if tag == "SUB"
                 else a * b if tag == "MUL"
                 else max(a, b) if tag == "MAX" else min(a, b))
            if -FORGE_INT_CAP <= v <= FORGE_INT_CAP:
                return ("const", v)
        except Exception:
            pass
    if tag == "ADD":
        if kids[0] == ("const", 0):
            return kids[1]
        if kids[1] == ("const", 0):
            return kids[0]
    if tag == "SUB" and kids[1] == ("const", 0):
        return kids[0]
    if tag == "MUL":
        if ("const", 0) in kids:
            return ("const", 0)
        if kids[0] == ("const", 1):
            return kids[1]
        if kids[1] == ("const", 1):
            return kids[0]
    if tag in ("MAX", "MIN") and kids[0] == kids[1]:
        return kids[0]
    if tag == "IFPOS" and kids[1] == kids[2]:
        return kids[1]
    return (tag,) + tuple(kids)


def forge_simplify_spec(spec: FoldSpec) -> FoldSpec:
    return FoldSpec(tuple(forge_simplify_tree(t) for t in spec.init),
                    tuple(forge_simplify_tree(t) for t in spec.step),
                    forge_simplify_tree(spec.out))


def forge_spec_nodes(spec: FoldSpec) -> int:
    return (sum(forge_tree_nodes(t) for t in spec.init)
            + sum(forge_tree_nodes(t) for t in spec.step)
            + forge_tree_nodes(spec.out))


FORGE_NEG_FIELD_MIN = 40
FORGE_NEG_FIELD_COS = 0.90


def forge_struct_tokens(spec: FoldSpec) -> List[int]:
    """Preorder structural walk of a spec as small ints (tags, var slots,
    const buckets). Purely syntactic; no behavior, no labels."""
    tags = ("ADD", "SUB", "MUL", "MAX", "MIN", "IFPOS")
    out: List[int] = []

    def walk(t: object) -> None:
        tag = t[0]
        if tag == "const":
            out.append(50 + (int(t[1]) % 7))
        elif tag == "var":
            out.append(60 + ("t1", "t2", "t3", "x").index(t[1]))
        else:
            out.append(1 + tags.index(tag))
            for k in t[1:]:
                walk(k)
    for tree in spec.init:
        out.append(90)
        walk(tree)
    for tree in spec.step:
        out.append(91)
        walk(tree)
    out.append(92)
    walk(spec.out)
    return out[:64]


class ForgeNegField:
    """Bundled hypervector memory of structurally zero-scoring specs.
    Advisory pre-evaluation filter: a candidate whose structure vector is
    too similar to the accumulated failure field is skipped without
    execution. Soundness is measured, not assumed: every train-exact spec
    that search collects is retro-checked against the field, and a
    near-block on a collected exact counts as a false_near violation."""

    def __init__(self) -> None:
        self.counts: Optional[List[int]] = None
        self.entries = 0
        self.skips = 0
        self.false_near = 0

    def add(self, spec: FoldSpec) -> None:
        v = hdv_encode(forge_struct_tokens(spec))
        if self.counts is None:
            self.counts = [0] * len(v)
        for i, x in enumerate(v):
            self.counts[i] += x
        self.entries += 1

    def _field(self) -> Optional[List[int]]:
        if self.counts is None or self.entries < FORGE_NEG_FIELD_MIN:
            return None
        return [1 if c > 0 else -1 for c in self.counts]

    def similarity(self, spec: FoldSpec) -> float:
        f = self._field()
        if f is None:
            return 0.0
        return hdv_cos(hdv_encode(forge_struct_tokens(spec)), f)

    def should_skip(self, spec: FoldSpec) -> bool:
        if self.similarity(spec) >= FORGE_NEG_FIELD_COS:
            self.skips += 1
            return True
        return False

    def retro_check_exact(self, spec: FoldSpec) -> None:
        if self.similarity(spec) >= FORGE_NEG_FIELD_COS:
            self.false_near += 1

    def stats(self) -> Dict[str, int]:
        return {"entries": self.entries, "skips": self.skips,
                "false_near": self.false_near,
                "active": int(self._field() is not None)}


FORGE_SYM_TRANSFORMS: Tuple[Tuple[str, Callable[[List[int]], List[int]]],
                            ...] = (
    ("t+1", lambda xs: [x + 1 for x in xs]),
    ("t+3", lambda xs: [x + 3 for x in xs]),
    ("t+7", lambda xs: [x + 7 for x in xs]),
    ("x*2", lambda xs: [x * 2 for x in xs]),
)


def forge_sym_violations(spec: FoldSpec,
                         probe_inputs: Sequence[Sequence[int]]) -> int:
    """Task-agnostic symmetry self-consistency: compare the candidate to
    ITSELF under declared transforms. No labels are consulted, so no
    oracle can leak; a candidate that changes output under translation or
    positive scaling reveals absolute-threshold structure. Which (if any)
    symmetry a task truly has is never told to the system: the count is
    used only as a tier among train-exact candidates, and when no
    candidate is fully self-symmetric the ranking reduces to the previous
    (cluster size, MDL) rule."""
    v = 0
    for xs in probe_inputs:
        try:
            base = fold_spec_eval(spec, list(xs))
        except VMCrash:
            return len(probe_inputs) * len(FORGE_SYM_TRANSFORMS)
        for _name, tf in FORGE_SYM_TRANSFORMS:
            try:
                if fold_spec_eval(spec, tf(list(xs))) != base:
                    v += 1
            except VMCrash:
                v += 1
    return v


def forge_sym_probe_inputs(seed: int, n: int = 12) -> List[List[int]]:
    """Inputs for symmetry self-consistency, kept on the train value
    manifold (0..7) so the declared transforms (+1,+3,+7, x2) stay below
    sentinel-graft territory; the value range is substrate, declared."""
    rng = random.Random(seed * 11 + 13)
    lens = (2, 3, 5, 8, 13)
    return [[rng.randint(0, 7) for _ in range(lens[i % len(lens)])]
            for i in range(n)]


def forge_self_probes(seed: int, n: int = 30) -> List[List[int]]:
    """Unlabeled probe inputs for behavioral clustering. No labels exist,
    so no oracle can leak; lengths and values intentionally exceed the
    train distribution."""
    rng = random.Random(seed * 7 + 5)
    lens = (2, 3, 5, 8, 12, 16, 20, 34)
    return [[rng.randint(0, 15) for _ in range(lens[i % len(lens)])]
            for i in range(n)]


def _forge_probe_key(spec: FoldSpec, probes: Sequence[Sequence[int]]
                     ) -> Tuple[int, ...]:
    out = []
    for xs in probes:
        try:
            out.append(fold_spec_eval(spec, xs))
        except VMCrash:
            out.append(10 ** 12)
    return tuple(out)


def forge_score(spec: FoldSpec,
                pairs: Sequence[Tuple[Tuple[int, ...], int]]) -> float:
    hits = 0
    for xs, y in pairs:
        try:
            if fold_spec_eval(spec, xs) == y:
                hits += 1
        except VMCrash:
            pass
    return hits / len(pairs)


_FORGE_XGRID: Tuple[int, ...] = (0, 1, 2, 3, 4, 5, 7, 15)
_FORGE_XLIB_CACHE: Optional[List[object]] = None


def _forge_element_library(max_nodes: int = 6) -> List[object]:
    """Exhaustive bottom-up enumeration of element functions g(x) over
    leaves {x, C0..C3} and the forge ops, deduplicated by observational
    equivalence on a fixed value grid. Deterministic; substrate-level, not
    task-tuned."""
    global _FORGE_XLIB_CACHE
    if _FORGE_XLIB_CACHE is not None:
        return _FORGE_XLIB_CACHE
    def sig(tree: object) -> Tuple[int, ...]:
        out = []
        for x in _FORGE_XGRID:
            try:
                out.append(forge_tree_eval(tree, 0, 0, 0, x))
            except VMCrash:
                out.append(10 ** 12)
        return tuple(out)
    by_size: Dict[int, List[object]] = {1: []}
    seen: Dict[Tuple[int, ...], object] = {}
    for leaf in ([("var", "x")] + [("const", c) for c in FORGE_CONSTS]):
        s = sig(leaf)
        if s not in seen:
            seen[s] = leaf
            by_size[1].append(leaf)
    for n in range(2, max_nodes + 1):
        by_size[n] = []
        for la in range(1, n - 1 + 1):
            lb = n - 1 - la
            if lb < 1:
                continue
            for ta in by_size.get(la, []):
                for tb in by_size.get(lb, []):
                    for op in ("ADD", "SUB", "MUL", "MAX", "MIN"):
                        tr = (op, ta, tb)
                        s = sig(tr)
                        if s not in seen:
                            seen[s] = tr
                            by_size[n].append(tr)
        for lc in range(1, n - 3 + 1):
            for la in range(1, n - 2 - lc + 1):
                lb = n - 2 - lc - la
                if lb < 1:
                    continue
                for tc in by_size.get(lc, []):
                    for ta in by_size.get(la, []):
                        for tb in by_size.get(lb, []):
                            tr = ("IFPOS", tc, ta, tb)
                            s = sig(tr)
                            if s not in seen:
                                seen[s] = tr
                                by_size[n].append(tr)
    _FORGE_XLIB_CACHE = [t for n in sorted(by_size) for t in by_size[n]]
    return _FORGE_XLIB_CACHE


_FORGE_INITS: Tuple[object, ...] = (
    ("const", 0), ("const", 1), ("const", 2), ("const", 3),
    ("SUB", ("const", 0), ("const", 1)),                      # -1
    ("ADD", ("const", 3), ("const", 1)),                      # 4
    ("MUL", ("ADD", ("const", 3), ("const", 1)),
     ("ADD", ("const", 3), ("const", 1))),                    # 16
)


def _forge_single_state_pass(pairs: Sequence[Tuple[Tuple[int, ...], int]]
                             ) -> Tuple[Optional[FoldSpec], int]:
    """Deterministic exhaustive pass over the single-accumulator subclass:
    t1' = OP(t1, g(x)) for every library g, every accumulate op, every
    declared init; out = t1. Exact within this subclass."""
    lib = _forge_element_library()
    zero = ("const", 0)
    evals = 0
    hits: List[FoldSpec] = []
    for g in lib:
        for op in ("ADD", "MAX", "MIN", "MUL"):
            step1 = (op, ("var", "t1"), g)
            for init in _FORGE_INITS:
                spec = FoldSpec((init, zero, zero),
                                (step1, zero, zero), ("var", "t1"))
                evals += 1
                if forge_score(spec, pairs) >= 1.0:
                    hits.append(spec)
    return hits, evals


def _forge_donor_pool() -> List[object]:
    """Structured graft donors for the triple-state phase: the element
    library plus threshold/selector templates over the state variables."""
    pool: List[object] = list(_forge_element_library())
    atoms = ([("var", v) for v in FORGE_VARS]
             + [("const", c) for c in FORGE_CONSTS])
    branches = atoms + [("ADD", ("var", v), ("const", 1))
                        for v in ("t1", "t2", "t3")]
    for tcond in atoms:
        for a in branches:
            for b in branches:
                pool.append(("IFPOS", ("SUB", ("var", "x"), tcond), a, b))
    first_order_end = len(pool)
    # second-order latch idiom (generic 'first occurrence' family):
    # once a state var turns non-negative it keeps its value, otherwise the
    # inner selector fires. Composes every threshold template once.
    ifpos_donors = [d for d in pool if d[0] == "IFPOS"]
    for v in ("t1", "t2", "t3"):
        guard = ("ADD", ("var", v), ("const", 1))
        for d in ifpos_donors:
            pool.append(("IFPOS", guard, ("var", v), d))
    for v in ("t1", "t2", "t3"):
        pool.append(("ADD", ("var", v), ("const", 1)))
        pool.append(("MAX", ("var", v), ("var", "x")))
    pool.append(("var", "x"))
    return pool, first_order_end


def forge_synthesize(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                     seed: int, restarts: int = 60,
                     iters: int = 1200) -> Dict[str, object]:
    """Stochastic hill-climb over fold programs, scored ONLY on the supplied
    train pairs. Behavior-memo dedup on the train outputs avoids rescoring
    equivalent specs. No gate, no oracle, no task identity in scope."""
    probes = forge_self_probes(seed)
    sym_base = forge_sym_probe_inputs(seed)
    ext_probes = list(probes) + [tf(list(xs))
                                 for _n, tf in FORGE_SYM_TRANSFORMS
                                 for xs in sym_base]

    def _champion(hits: List[FoldSpec], evals: int, r_used: int
                  ) -> Dict[str, object]:
        clusters: Dict[Tuple[int, ...], List[FoldSpec]] = {}
        for h in hits:
            clusters.setdefault(_forge_probe_key(h, ext_probes), []).append(h)
        viol: Dict[str, int] = {}

        def _v(s: FoldSpec) -> int:
            k = repr(s)
            if k not in viol:
                viol[k] = forge_sym_violations(s, sym_base)
            return viol[k]

        def _tier(members: List[FoldSpec]) -> int:
            return 0 if any(_v(s) == 0 for s in members) else 1

        ranked = sorted(clusters.items(),
                        key=lambda kv: (_tier(kv[1]), -len(kv[1]),
                                        min(forge_spec_nodes(
                                            forge_simplify_spec(s))
                                            for s in kv[1])))
        champ_key, members = ranked[0]
        champ_raw = min(members,
                        key=lambda s: (_v(s),
                                       forge_spec_nodes(
                                           forge_simplify_spec(s)),
                                       repr(s)))
        champ = forge_simplify_spec(champ_raw)
        # HDC cross-check (diagnostic only; sealed gates stay the judge):
        # encode each cluster fingerprint as a hypervector and verify that
        # exact-distinct clusters stay separated in similarity space.
        vecs = []
        for key in clusters:
            toks = [(i * 131 + (int(o) % 997)) % 100003
                    for i, o in enumerate(key)]
            vecs.append(hdv_encode(toks[:64]))
        max_cos = 0.0
        for i in range(len(vecs)):
            for j in range(i + 1, len(vecs)):
                max_cos = max(max_cos, hdv_cos(vecs[i], vecs[j]))
        return {"found": True, "spec": champ, "score": 1.0,
                "evals": evals, "restarts_used": r_used,
                "exact_found": len(hits),
                "behavior_clusters": len(clusters),
                "champion_cluster": len(members),
                "sym_viol": _v(champ_raw),
                "sym_tier": _tier(members),
                "hdc_max_offdiag_cos": round(max_cos, 3),
                "hdc_clusters_distinct": bool(max_cos < 0.999)}

    hits1, e1 = _forge_single_state_pass(pairs)
    if hits1:
        return _champion(hits1, e1, 0)
    collect_target = 12
    collected: List[FoldSpec] = []
    collected_keys: set = set()
    a_restarts = (restarts * 5) // 8
    shape_probes = sym_base[:6]
    sym_evals = 0
    regime_hits = {"free": 0, "shaped": 0}
    neg_field = ForgeNegField()

    def _shaped_score(spec: FoldSpec, regime_b: bool) -> float:
        """Regime B fitness: on the train-exact ridge, prefer symmetry
        self-consistency. Labels and gates are never consulted; the
        penalty band (0.96, 1.0) sits strictly above every non-exact
        score, so the climb walks the exact manifold toward invariance."""
        nonlocal sym_evals
        raw = forge_score(spec, pairs)
        if (not regime_b) or raw < 1.0:
            return raw
        v = forge_sym_violations(spec, shape_probes)
        sym_evals += 1
        return 1.0 if v == 0 else 0.96 + 0.04 * (1.0 - min(v, 24) / 24.0)
    donors_full, _first_end = _forge_donor_pool()
    donors_core = (donors_full[:_first_end]
                   + donors_full[len(donors_full) - 7:])
    best: Optional[FoldSpec] = None
    best_s = -1.0
    evals = e1
    elites: List[Tuple[float, FoldSpec]] = []

    def _elite_add(s: float, sp: FoldSpec) -> None:
        elites.append((s, sp))
        elites.sort(key=lambda z: -z[0])
        del elites[12:]

    def _crossover(rng: random.Random, base: FoldSpec) -> FoldSpec:
        donor = elites[rng.randrange(len(elites))][1]
        slot = rng.randrange(7)
        init, step, out = list(base.init), list(base.step), base.out
        if slot < 3:
            init[slot] = donor.init[slot]
        elif slot < 6:
            step[slot - 3] = donor.step[slot - 3]
        else:
            out = donor.out
        return FoldSpec(tuple(init), tuple(step), out)

    for r in range(restarts):
        regime_b = (r % 8) >= 5    # interleaved chambers: 5 free / 3 shaped
        rng = random.Random(seed * 1_000_003 + r * 7919 + 13)
        cur = _forge_rand_spec(rng)
        cur_s = _shaped_score(cur, regime_b)
        evals += 1
        stall = 0
        greedy_regime = (r % 2 == 1)   # portfolio: blind/greedy alternate
        for _ in range(iters):
            roll = rng.random()
            if elites and roll < 0.20:
                cand = _crossover(rng, cur)
            elif roll < 0.55 and not greedy_regime:
                slot = rng.randrange(4)
                init, step, out = (list(cur.init), list(cur.step), cur.out)
                if slot < 3:
                    step[slot] = donors_core[
                        rng.randrange(len(donors_core))]
                else:
                    donor = donors_core[rng.randrange(len(donors_core))]
                    if all(v[1] != "x" for v in _forge_tree_vars(donor)):
                        out = donor
                cand = FoldSpec(tuple(init), tuple(step), out)
            elif roll < 0.55:
                # greedy coordinate step: sample candidates for ONE slot,
                # keep the train-score argmax. Every probe is a real,
                # counted evaluation; no oracle, no task identity.
                slot = rng.randrange(7)
                init, step, out = (list(cur.init), list(cur.step), cur.out)
                if slot < 3:
                    options = [donors_full[rng.randrange(len(donors_full))]
                               for _ in range(8)]
                    scored = []
                    for d in options:
                        step2 = list(step)
                        step2[slot] = d
                        sp = FoldSpec(tuple(init), tuple(step2), out)
                        evals += 1
                        scored.append((forge_score(sp, pairs), d))
                    step[slot] = max(scored, key=lambda z: z[0])[1]
                elif slot == 3:
                    scored = []
                    for v in ("t1", "t2", "t3"):
                        sp = FoldSpec(tuple(init), tuple(step), ("var", v))
                        evals += 1
                        scored.append((forge_score(sp, pairs), ("var", v)))
                    out = max(scored, key=lambda z: z[0])[1]
                else:
                    scored = []
                    for ini in _FORGE_INITS:
                        init2 = list(init)
                        init2[slot - 4] = ini
                        sp = FoldSpec(tuple(init2), tuple(step), out)
                        evals += 1
                        scored.append((forge_score(sp, pairs), ini))
                    init[slot - 4] = max(scored, key=lambda z: z[0])[1]
                cand = FoldSpec(tuple(init), tuple(step), out)
            else:
                cand = _forge_mutate_spec(rng, cur)
            if neg_field.should_skip(cand):
                stall += 1
                continue
            evals += 1
            s = _shaped_score(cand, regime_b)
            if s == 0.0:
                neg_field.add(cand)
            if s >= cur_s:
                if s == cur_s:
                    stall += 1
                else:
                    stall = 0
                cur, cur_s = cand, s
            else:
                stall += 1
            if cur_s > best_s:
                best, best_s = cur, cur_s
            if cur_s >= 0.6:
                _elite_add(cur_s, cur)
            if cur_s >= 1.0:
                pk = _forge_probe_key(cur, ext_probes)
                if (pk, repr(forge_simplify_spec(cur))) not in \
                        collected_keys:
                    collected_keys.add((pk,
                                        repr(forge_simplify_spec(cur))))
                    collected.append(cur)
                    neg_field.retro_check_exact(cur)
                    regime_hits["shaped" if regime_b else "free"] += 1
                if len(collected) >= collect_target:
                    out = _champion(collected, evals, r + 1)
                    out["regime_hits"] = dict(regime_hits)
                    out["sym_evals"] = sym_evals
                    out["neg_field"] = neg_field.stats()
                    return out
                break    # fresh restart keeps search paths independent
            if stall >= 400:
                break
    if collected:
        out = _champion(collected, evals, restarts)
        out["regime_hits"] = dict(regime_hits)
        out["sym_evals"] = sym_evals
        out["neg_field"] = neg_field.stats()
        return out
    return {"found": False, "spec": best,
            "score": round(max(best_s, 0.0), 4), "evals": evals,
            "restarts_used": restarts}


def compile_forged(spec: FoldSpec) -> Callable[[List[object],
                                                Tuple[int, ...]], None]:
    """Wrap a fold spec as a stack-VM extended-op implementation:
    pop list, push int. Crash-safe and total like every base op."""
    def impl(stack: List[object], inp: Tuple[int, ...]) -> None:
        xs = _pop_list(stack)
        _push(stack, fold_spec_eval(spec, xs))
    return impl


FORGED_REGISTRY: Dict[str, FoldSpec] = {}


def forge_admit(state: SearcherState, name: str,
                spec: FoldSpec) -> CapabilitySpec:
    """Register a SYSTEM-synthesized primitive through the same extension
    registry the dormant catalog uses. The provenance differs and is
    recorded: the implementation was forged by search, not stocked."""
    ext_id = FORGE_ID_BASE + len(FORGED_REGISTRY)
    if ext_id > EXT_ID_MAX:
        raise ValueError("forge id space exhausted")
    cap = CapabilitySpec(name=name, ext_id=ext_id, ins=("l",), outs=("i",),
                         impl=compile_forged(spec),
                         rationale="self-forged fold primitive"
                                   f" key={spec.key()}")
    FORGED_REGISTRY[name] = spec
    EXT_IMPL[ext_id] = cap.impl
    EXT_TYPES[ext_id] = (cap.ins, cap.outs)
    state.extended[ext_id] = name
    state.history.append(f"SELF_FORGE {name} id={ext_id} key={spec.key()}")
    state.version += 1
    return cap


def forge_revoke_all(state: Optional[SearcherState] = None) -> None:
    for nm in list(FORGED_REGISTRY):
        FORGED_REGISTRY.pop(nm)
    deactivate_all_capabilities(state)
    GD_EXTRA_FEATURES.clear()


# ---------------------------------------------------------------------------
# Cross-substrate lift: every forged list->int primitive can be registered
# as a general-domain FEATURE atom; the GD evaluator and enumerator consult
# this registry, so forged semantics become searchable in the debate
# pipeline across list/string/grid/dict inputs (applied to the numeric
# projection of the object).
# ---------------------------------------------------------------------------
GD_EXTRA_FEATURES: Dict[str, Callable[[Sequence[int]], int]] = {}


def gd_register_forged_feature(name: str, spec: FoldSpec) -> str:
    fname = f"SF_{name}"

    def fn(nums: Sequence[int]) -> int:
        try:
            return int(fold_spec_eval(spec, list(nums)))
        except VMCrash:
            return 0
    GD_EXTRA_FEATURES[fname] = fn
    return fname


# ---------------------------------------------------------------------------
# The forge loop over the certified walls, end to end:
# spec from train pairs -> forge -> admit -> stack-VM search -> sealed gates
# -> structural channel -> adopt. Plus the declared out-of-closure probe.
# ---------------------------------------------------------------------------
def forge_enum_solve(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                     state: SearcherState, max_len: int = 3
                     ) -> Tuple[Optional[Tuple[int, ...]], int]:
    """Deterministic exhaustive scan over short programs in the CURRENT
    vocabulary (base + macros + admitted extensions), static-pruned. This is
    the documented short-program path: exact coverage by enumeration, with
    stochastic search reserved for longer programs."""
    from itertools import product as _prod
    vocab = sorted(state.vocab())
    sigs = build_type_sigs(state.macros)
    scored = 0
    for L in range(1, max_len + 1):
        for tk in _prod(vocab, repeat=L):
            cand = list(tk)
            if not static_plausible(cand, sigs):
                continue
            scored += 1
            if _score_tokens(cand, state.macros, pairs) >= 1.0:
                return tuple(tk), scored
    return None, scored


def forge_walls_run(seed: int = SEED, restarts: int = 320,
                    iters: int = 2000,
                    out_json: Optional[str] = "forge_results.json"
                    ) -> Dict[str, object]:
    st = SearcherState()
    rows: List[Dict[str, object]] = []
    tasks = [t for t in build_sealed_tasks()
             if TASK_FAMILY_BY_TID.get(t.tid) == "search"]
    genuine_env = None
    try:
        rs = build_adaptive()
        sealed = {t.tid: t for t in build_sealed_tasks()}
        profs = [trace_profile(tuple(tk), rs.searcher.macros)
                 for tid, tk in sorted(rs.adopted_tokens.items())
                 if tid in sealed]
        genuine_env = population_envelope(profs)
    except Exception:
        genuine_env = {"expanded_len": (5.0, 3.0),
                       "distinct_ops": (3.0, 2.0), "max_depth": (3.0, 2.0)}
    adopted: Dict[str, List[int]] = {}
    for task in tasks:
        forged = forge_synthesize(task.train_pairs, seed=seed
                                  + int(task.tid[1:]), restarts=restarts,
                                  iters=iters)
        row: Dict[str, object] = {
            "tid": task.tid, "name": TASK_NAME_BY_TID.get(task.tid, "?"),
            "forge_found": bool(forged["found"]),
            "forge_score": forged["score"],
            "forge_evals": forged["evals"],
            "restarts_used": forged["restarts_used"],
            "exact_found": forged.get("exact_found"),
            "champion_cluster": forged.get("champion_cluster"),
            "sym_viol": forged.get("sym_viol"),
            "regime_hits": forged.get("regime_hits"),
            "neg_field": forged.get("neg_field"),
            "sym_tier": forged.get("sym_tier"),
            "hdc_clusters_distinct": forged.get("hdc_clusters_distinct"),
            "gates": False, "final_verdict": "", "tokens": None,
            "spec_key": forged["spec"].key() if forged["spec"] else None}
        if forged["found"]:
            cap = forge_admit(st, f"FORGE_{task.tid}", forged["spec"])
            toks, n_enum = forge_enum_solve(task.train_pairs, st, max_len=3)
            row["solver"] = "enum" if toks else "stochastic"
            row["enum_scored"] = n_enum
            if toks is None:
                res = synthesize(task.train_pairs, task.tid, st,
                                 seed=seed ^ 0x16, restarts=8, iters=900,
                                 drift_rate=0.3)
                toks = tuple(res.tokens) if res.solved else None
            if toks is not None:
                fn = compile_program(toks, st.macros)
                gates = task.holdout_gate(fn) and task.cf_gate(fn)
                row["gates"] = bool(gates)
                row["tokens"] = list(toks)
                if gates:
                    fin, detail = final_clash_verdict(toks, st.macros,
                                                      task, genuine_env)
                    row["final_verdict"] = fin
                    if fin == "promote":
                        adopted[task.tid] = list(toks)
            row["granted_id"] = cap.ext_id
        rows.append(row)
    # declared out-of-closure probe: median needs order statistics; a
    # one-pass 3-int fold cannot hold them. Same budget, honest outcome.
    rng = random.Random(seed * 31 + 7)
    med_pairs = []
    for L in (1, 2, 3, 4, 6):
        for _ in range(5):
            xs = tuple(rng.randint(0, 7) for _ in range(L))
            med_pairs.append((xs, sorted(xs)[len(xs) // 2]))
    med = forge_synthesize(med_pairs, seed=seed + 999, restarts=restarts,
                           iters=iters)
    med_hold_ok = False
    if med["found"]:
        hrng = random.Random(seed * 101 + 9)
        med_hold_ok = True
        for L in HOLDOUT_LENGTHS:
            for _ in range(6):
                xs = [hrng.randint(0, 7) for _ in range(L)]
                try:
                    if fold_spec_eval(med["spec"], xs) != \
                            sorted(xs)[len(xs) // 2]:
                        med_hold_ok = False
                except VMCrash:
                    med_hold_ok = False
    report = {"rows": rows,
              "walls_forged": sum(1 for r in rows if r["forge_found"]),
              "walls_gated_adopted": sum(1 for r in rows
                                         if r["final_verdict"] == "promote"),
              "out_of_closure_probe": {
                  "name": "median_of_list",
                  "found_train": bool(med["found"]),
                  "train_best": med["score"],
                  "holdout_ok": bool(med_hold_ok),
                  "verified": bool(med["found"] and med_hold_ok),
                  "evals": med["evals"]},
              "adopted_tokens": adopted,
              "searcher_history": list(st.history)}
    if out_json:
        ser = json.loads(json.dumps(report, default=str))
        with open(out_json, "w") as f:
            json.dump(ser, f, sort_keys=True)
    return report


def forge_downstream_demo(report: Dict[str, object],
                          seed: int = SEED) -> Dict[str, object]:
    """Recursion beat: two gate-adopted wall solutions compose into a
    SELF-MINTED task (system-labeled, like the existing mint factory), and
    the stack search solves it using the forged ops -- improvement enabling
    the next improvement. Counterfactual: without the forged ops the same
    mint is structurally out of reach (its parts were certified blocked)."""
    adopted = report["adopted_tokens"]
    if len(adopted) < 2:
        return {"ran": False, "reason": "needs two adopted walls"}
    (tid_a, toks_a), (tid_b, toks_b) = sorted(adopted.items())[:2]
    st = SearcherState()
    for tid in sorted(FORGED_REGISTRY):
        spec = FORGED_REGISTRY[tid]
        ext_id = FORGE_ID_BASE + sorted(FORGED_REGISTRY).index(tid)
        EXT_IMPL[ext_id] = compile_forged(spec)
        EXT_TYPES[ext_id] = (("l",), ("i",))
        st.extended[ext_id] = tid
    fa = compile_program(tuple(toks_a), st.macros)
    fb = compile_program(tuple(toks_b), st.macros)
    rng = random.Random(seed * 17 + 3)
    pairs = []
    for L in (1, 2, 3, 4, 6):
        for _ in range(4):
            xs = [rng.randint(0, 7) for _ in range(L)]
            pairs.append((tuple(xs), fa(list(xs)) + fb(list(xs))))
    # Recursion beat, taken literally: the system composes its OWN two
    # adopted programs with each binary scalar op before any fresh search.
    toks = None
    evals = 0
    comp_scores: List[float] = []
    for comb in (9, 10, 11):          # ADD, SUB, MUL
        for cand in (tuple(toks_a) + tuple(toks_b) + (comb,),
                     tuple(toks_b) + tuple(toks_a) + (comb,)):
            evals += 1
            sc = _score_tokens(list(cand), st.macros, pairs)
            comp_scores.append(round(sc, 3))
            if sc >= 1.0:
                toks = cand
                break
        if toks is not None:
            break
    if toks is None:
        toks, n_enum = forge_enum_solve(pairs, st, max_len=3)
        evals += n_enum
    if toks is None:
        res = synthesize(pairs, f"MINT_{tid_a}_{tid_b}", st,
                         seed=seed ^ 0xF0, restarts=8, iters=900,
                         drift_rate=0.3)
        toks = tuple(res.tokens) if res.solved else None
        evals += res.evals_used
    hold_ok = False
    if toks is not None:
        fn = compile_program(toks, st.macros)
        hxs = [[rng.randint(0, 7) for _ in range(L)] for L in (5, 8, 13)]
        hold_ok = all(fn(list(xs)) == fa(list(xs)) + fb(list(xs))
                      for xs in hxs)
    return {"ran": True, "mint": f"{tid_a}+{tid_b}",
            "solved": toks is not None, "self_holdout_ok": bool(hold_ok),
            "tokens": list(toks) if toks is not None else None,
            "evals": evals, "comp_scores": comp_scores}


# ---------------------------------------------------------------------------
# General-domain bridge demo: a scarce GD task whose hidden function is a
# forged semantics. Without the lift the debate pipeline converges wrong or
# abstains; with the forged feature atom it reaches full consensus and a
# perfect sealed audit.
# ---------------------------------------------------------------------------
def gd_bridge_demo(spec: FoldSpec, seed: int = SEED) -> Dict[str, object]:
    rng = random.Random(seed * 13 + 5)
    hidden = (lambda x: int(fold_spec_eval(
        spec, list(_gd_numbers(x)))))
    train = [[rng.randint(0, 7) for _ in range(rng.randint(2, 5))]
             for _ in range(5)]
    out: Dict[str, object] = {}
    for label in ("before", "after"):
        if label == "after":
            gd_register_forged_feature("BRIDGE", spec)
        t = make_scarce_task("bridge_forged_semantics", "list", hidden,
                             seed=seed + 77, query_budget=2,
                             train_inputs=[list(z) for z in train])
        env = GDScarceEnv(t)
        ep = gd_debate_solve(env, {}, seed=seed + 77, task_name=t.name)
        out[label] = {"consensus": ep.consensus,
                      "accepted": ep.accepted_key,
                      "queries": ep.queries,
                      "audit": round(t.audit(ep.accepted, {}), 4)
                      if ep.accepted is not None else 0.0}
    GD_EXTRA_FEATURES.clear()
    return out


# ---------------------------------------------------------------------------
# Battery (CLI: --mode forge-battery).
# ---------------------------------------------------------------------------
def forge_battery() -> Dict[str, object]:
    print("=" * 88)
    print("SELF-FORGE BATTERY (system-synthesized primitives, sealed-gate"
          " admission, cross-substrate lift)")
    print("=" * 88)
    out: Dict[str, object] = {}
    print("\n[F1] forging the four certified walls from their train pairs"
          " (declared budget: 320 restarts x 2000 iters per wall)")
    rep = forge_walls_run()
    out["F1"] = rep
    for r in rep["rows"]:
        print(f"  {r['tid']} {r['name']:<28} forged={r['forge_found']}"
              f" exact={r['exact_found']}"
              f" consensus={r['champion_cluster']}"
              f" sym={r['sym_viol']}/t{r['sym_tier']}"
              f" evals={r['forge_evals']}"
              f" | gates={r['gates']} verdict={r['final_verdict'] or '-'}"
              f" tokens={r['tokens']}")
    p = rep["out_of_closure_probe"]
    print(f"  declared out-of-closure probe [{p['name']}]:"
          f" train_found={p['found_train']} train_best={p['train_best']:.2f}"
          f" holdout_ok={p['holdout_ok']} verified={p['verified']}"
          f" evals={p['evals']}")
    print("    <- train-only fits can be coincidence; sealed verification"
          " separates semantics from luck. The verified wall stands.")
    print(f"  totals: forged={rep['walls_forged']}/4"
          f" gate-adopted={rep['walls_gated_adopted']}/4")
    print("\n[F2] cross-substrate lift: forged semantics as a GD feature")
    spec = (FORGED_REGISTRY.get("FORGE_T29")
            or (rep["rows"][0].get("spec_key") and None))
    if "FORGE_T29" in FORGED_REGISTRY:
        bridge = gd_bridge_demo(FORGED_REGISTRY["FORGE_T29"])
        out["F2"] = bridge
        for k in ("before", "after"):
            b = bridge[k]
            print(f"  {k:<7} consensus={b['consensus']:<8}"
                  f" accepted={b['accepted'] or '-':<22}"
                  f" q={b['queries']} audit={b['audit']:.2f}")
        print("  (same debate machinery; the only change is the"
              " system-forged atom in its expression language)")
    print("\n[F3] recursion beat: self-minted composition of two adopted"
          " walls, solved with the forged ops")
    down = forge_downstream_demo(rep)
    out["F3"] = down
    rep["downstream"] = down
    with open("forge_results.json", "w") as f:
        json.dump(json.loads(json.dumps(rep, default=str)), f,
                  sort_keys=True)
    print(f"  {down}")
    forge_revoke_all()
    print("\n[F4] provenance: every grant in the searcher history")
    for h in rep["searcher_history"]:
        print(f"  {h}")
    print("\nreading: the system wrote the semantics, search found them,"
          " the sealed gates and the structural channel admitted them, and"
          " the same primitives transferred to the general-domain pipeline."
          " The substrate is still a designer act -- one level up -- and"
          " the new closure's own wall is shown, not hidden.")
    return out


# ---------------------------------------------------------------------------
# Section 16 tests.
# ---------------------------------------------------------------------------
def test_forge_language_total_and_deterministic() -> None:
    rng = random.Random(11)
    for _ in range(200):
        spec = _forge_rand_spec(rng)
        xs = [rng.randint(-3, 9) for _ in range(rng.randint(0, 6))]
        try:
            a = fold_spec_eval(spec, xs)
            b = fold_spec_eval(spec, xs)
            _assert(a == b, "fold spec nondeterministic")
            _assert(isinstance(a, int), "fold spec returned non-int")
        except VMCrash:
            pass
        _assert(forge_tree_depth(spec.out) <= FORGE_DEPTH_MAX,
                "depth bound violated")


def test_forge_synthesis_paths_are_oracle_free() -> None:
    import inspect
    src = (inspect.getsource(forge_synthesize)
           + inspect.getsource(forge_score)
           + inspect.getsource(fold_spec_eval)
           + inspect.getsource(forge_walls_run))
    _assert("_ORACLE_REGISTRY" not in src,
            "forge path references _ORACLE_REGISTRY")
    pre_gate = (inspect.getsource(forge_synthesize)
                + inspect.getsource(forge_score))
    for banned in ("holdout_gate", "cf_gate", "audit", "._fn"):
        _assert(banned not in pre_gate,
                f"pre-admission forge consults {banned}")


def test_forge_finds_count_above_threshold() -> None:
    task = next(t for t in build_sealed_tasks() if t.tid == "T29")
    res = forge_synthesize(task.train_pairs, seed=SEED + 29,
                           restarts=40, iters=900)
    _assert(res["found"], f"forge missed the easiest wall: {res['score']}")
    spec = res["spec"]
    chk = [([0, 5, 2, 7], 2), ([4, 4, 4], 3), ([], 0),
           ([9, 0, 3, 15, 4], 3)]
    for xs, y in chk:
        _assert(fold_spec_eval(spec, xs) == y,
                f"forged spec wrong off-train: {xs}")


def test_forge_results_walls_fall_through_sealed_gates() -> None:
    _assert(os.path.exists("forge_results.json"),
            "forge artifact missing; run --mode forge-battery first")
    with open("forge_results.json") as f:
        rep = json.load(f)
    _assert(rep["walls_forged"] >= 3,
            f"too few walls forged: {rep['walls_forged']}")
    _assert(rep["walls_gated_adopted"] >= 2,
            f"too few walls passed sealed gates + clash:"
            f" {rep['walls_gated_adopted']}")
    rejected = [r for r in rep["rows"]
                if r["forge_found"] and not r["gates"]]
    _assert(len(rejected) + rep["walls_gated_adopted"] == 4,
            "wall bookkeeping inconsistent")
    for r in rep["rows"]:
        _assert(r["exact_found"] >= r["champion_cluster"] >= 1,
                f"consensus bookkeeping broken: {r}")
        if r["final_verdict"] == "promote":
            _assert(r["gates"] is True, "promoted without gates")
            _assert(r["tokens"] is not None and len(r["tokens"]) <= 4,
                    f"adopted wall program suspiciously long: {r}")
    down = rep.get("downstream") or {}
    _assert(down.get("solved") is True and
            down.get("self_holdout_ok") is True,
            f"recursion beat failed: {down}")
    _assert(down.get("tokens") and len(down["tokens"]) == 5,
            f"mint solution shape unexpected: {down}")
    p = rep["out_of_closure_probe"]
    _assert(p["verified"] is False,
            "median verifiably fell inside the closure; boundary wrong")
    if p["found_train"]:
        _assert(p["holdout_ok"] is False,
                "probe bookkeeping inconsistent")


def test_forged_admission_is_clean_and_revocable() -> None:
    task = next(t for t in build_sealed_tasks() if t.tid == "T29")
    res = forge_synthesize(task.train_pairs, seed=SEED + 29,
                           restarts=40, iters=900)
    _assert(res["found"], "forge failed under test budget")
    st = SearcherState()
    cap = forge_admit(st, "FORGE_TEST", res["spec"])
    try:
        _assert(cap.ext_id >= FORGE_ID_BASE and cap.ext_id <= EXT_ID_MAX,
                "forged id outside reserved space")
        _assert(cap.ext_id in st.vocab(), "forged op missing from vocab")
        prog = (4, cap.ext_id)
        fn = compile_program(prog, st.macros)
        _assert(all(fn(list(xs)) == y for xs, y in task.train_pairs),
                "forged op via VM diverges from spec")
        _assert(task.holdout_gate(fn) and task.cf_gate(fn),
                "forged solution failed a sealed gate")
        _assert(any("SELF_FORGE" in h for h in st.history),
                "provenance not recorded")
    finally:
        forge_revoke_all(st)
    _assert(not EXT_IMPL and not GD_EXTRA_FEATURES,
            "forge revocation leaked state")


def test_gd_bridge_lifts_forged_semantics() -> None:
    task = next(t for t in build_sealed_tasks() if t.tid == "T29")
    res = forge_synthesize(task.train_pairs, seed=SEED + 29,
                           restarts=40, iters=900)
    _assert(res["found"], "forge failed under test budget")
    try:
        bridge = gd_bridge_demo(res["spec"])
    finally:
        GD_EXTRA_FEATURES.clear()
    b, a = bridge["before"], bridge["after"]
    _assert(not (b["consensus"] == "full" and b["audit"] == 1.0),
            f"hidden forged semantics solvable without the lift: {b}")
    _assert(a["consensus"] == "full" and a["audit"] == 1.0
            and str(a["accepted"]).startswith("F:SF_"),
            f"lifted feature failed to solve the GD task: {a}")


def test_forge_downstream_mint_solvable_only_with_forged_ops() -> None:
    _assert(os.path.exists("forge_results.json"), "forge artifact missing")
    with open("forge_results.json") as f:
        rep = json.load(f)
    _assert(len(rep["adopted_tokens"]) >= 2, "needs two adopted walls")
    (tid_a, toks_a), (tid_b, toks_b) = sorted(
        rep["adopted_tokens"].items())[:2]
    for toks in (toks_a, toks_b):
        _assert(any(t >= FORGE_ID_BASE for t in toks),
                "adopted wall solution does not use a forged op")
    plain = SearcherState()
    for toks in (toks_a, toks_b):
        try:
            compile_program(tuple(toks), plain.macros)
            ran = True
        except VMCrash:
            ran = False
        _assert(not ran, "forged-op program executable without the grant")


TESTS.extend([
    test_forge_language_total_and_deterministic,
    test_forge_synthesis_paths_are_oracle_free,
    test_forge_finds_count_above_threshold,
    test_forge_results_walls_fall_through_sealed_gates,
    test_forged_admission_is_clean_and_revocable,
    test_gd_bridge_lifts_forged_semantics,
    test_forge_downstream_mint_solvable_only_with_forged_ops,
])


def test_forge_symmetry_prior_oracle_free() -> None:
    import inspect
    zero = ("const", 0)
    inv = FoldSpec((zero, zero, ("const", 16)),
                   (("ADD", ("var", "t1"),
                     ("IFPOS", ("SUB", ("var", "x"), ("var", "t3")),
                      ("const", 1), zero)), zero, ("var", "x")),
                   ("var", "t1"))
    thr = FoldSpec((zero, zero, zero),
                   (("ADD", ("var", "t1"),
                     ("IFPOS", ("SUB", ("var", "x"), ("const", 3)),
                      ("const", 1), zero)), zero, zero),
                   ("var", "t1"))
    probes = forge_sym_probe_inputs(SEED)
    v_inv = forge_sym_violations(inv, probes)
    v_thr = forge_sym_violations(thr, probes)
    _assert(v_inv == 0, f"difference-based spec not self-symmetric: {v_inv}")
    _assert(v_thr > 0, "threshold spec unexpectedly self-symmetric")
    s = inspect.getsource(forge_sym_violations)
    for banned in ("holdout", "cf_gate", "hidden", "TASKS", "T29", "T30",
                   "T31", "T32"):
        _assert(banned not in s, f"symmetry prior references {banned}")


TESTS.append(test_forge_symmetry_prior_oracle_free)


# =========================================================================== #
# 17. REAL-ARTIFACT HARNESS: FILES, TOOLS, SKILLS, RESIDUE CURRICULUM        #
#                                                                             #
# Everything before this section lives in sealed in-memory tasks. This       #
# section moves the same discipline into a real file workspace:              #
#                                                                             #
#   * SealedFileTask: raw input files on disk, a visible check the agent     #
#     may run, and HIDDEN expectations that exist only in harness memory --  #
#     they are never written into the workspace and no agent code path can   #
#     reach them.                                                            #
#   * Tool action layer: read/write/parse/patch operations, every call       #
#     logged as a deterministic ActionTrace (input/output hashes, status).   #
#   * Skill memory: the agent's pipeline improves ONLY through adopted       #
#     SkillProposals. Proposals are mined mechanically from failure          #
#     residues on SELF-GENERATED validation instances (whose truth the      #
#     system legitimately knows, mint-style), validated for strict           #
#     improvement, and otherwise rejected into a registry that blocks        #
#     re-proposal. Eval instances use unseen seeds; their hidden checks      #
#     are consulted only by the harness for final scoring.                   #
#   * Residue curriculum: remaining failure signatures spawn amplified       #
#     validation variants; a second proposal round must measurably improve.  #
#   * Repo-repair-mini: a tiny on-disk repository with one seeded bug;       #
#     the repair skill searches single-line patches accepted on visible      #
#     io-pairs only; hidden pairs grade the result afterwards.               #
#                                                                             #
# Honesty boundary, declared: the rule-constructor library is designer       #
# substrate (same standing as the forge's fold language). The system         #
# selects, parameterizes, validates, adopts, and persists; it does not       #
# author new rule KINDS. That residual authorship is reported, not hidden.   #
# =========================================================================== #

FILEWORLD_ROOT = os.path.join(os.getcwd(), "fileworld")
FW_FAMILIES: Tuple[str, ...] = ("csv_normalize", "log_aggregate",
                                "config_migrate", "repo_repair")
FW_KNOWN_CFG_KEYS: Tuple[str, ...] = ("host", "port", "debug", "name")


@dataclass
class ActionTrace:
    action: str
    input_hash: str
    output_hash: str
    cost: float
    status: str          # committed | reverted | observed


def _fw_hash(data: object) -> str:
    return hashlib.sha256(repr(data).encode()).hexdigest()[:12]


@dataclass
class SealedFileTask:
    tid: str
    family: str
    workdir: str
    visible_expected: Dict[str, object]      # also written to workspace
    hidden_expected: Dict[str, object]       # MEMORY ONLY -- never on disk
    self_generated: bool = False             # validation instances only
    seed: int = 0


def fw_validation_truth(task: SealedFileTask) -> Dict[str, object]:
    """Truth access for the skill validator. Legal ONLY on self-generated
    validation instances (the system made them, so it knows the answer --
    the same legitimacy as the mint factory). Raises on eval tasks."""
    if not task.self_generated:
        raise PermissionError("hidden expectations are sealed on eval tasks")
    return task.hidden_expected


def fw_sealed_hidden_score(task: SealedFileTask) -> float:
    """Harness-side final grading. Reads the agent's artifact from disk and
    compares against in-memory hidden expectations. Agents never call this;
    a test scans their sources."""
    fam = task.family
    try:
        if fam == "repo_repair":
            return _fw_repo_hidden_score(task)
        path = os.path.join(task.workdir, "out.json")
        with open(path) as f:
            got = json.load(f)
    except Exception:
        return 0.0
    want = task.hidden_expected
    if fam == "csv_normalize":
        rows = want["rows"]
        if not isinstance(got, list) or len(got) != len(rows):
            return 0.0
        hits = sum(1 for g, w in zip(got, rows) if g == w)
        return hits / len(rows)
    if fam == "log_aggregate":
        keys = ("counts", "max_latency", "over_100")
        hits = sum(1 for k in keys if got.get(k) == want[k])
        return hits / len(keys)
    if fam == "config_migrate":
        return 1.0 if got == want["config"] else 0.0
    return 0.0


# --------------------------------------------------------------------------
# Tool action layer.
# --------------------------------------------------------------------------
class ToolSession:
    def __init__(self, task: SealedFileTask):
        self.task = task
        self.traces: List[ActionTrace] = []

    def _log(self, action: str, inp: object, out: object,
             status: str = "observed", cost: float = 1.0) -> None:
        self.traces.append(ActionTrace(action, _fw_hash(inp), _fw_hash(out),
                                       cost, status))

    def read_file(self, rel: str) -> str:
        with open(os.path.join(self.task.workdir, rel)) as f:
            data = f.read()
        self._log("read_file", rel, data)
        return data

    def write_file(self, rel: str, content: str) -> None:
        path = os.path.join(self.task.workdir, rel)
        with open(path, "w") as f:
            f.write(content)
        self._log("write_file", (rel, content), len(content), "committed")

    def write_json(self, rel: str, obj: object) -> None:
        self.write_file(rel, json.dumps(obj, sort_keys=True))

    def parse_json(self, text: str) -> object:
        obj = json.loads(text)
        self._log("parse_json", text, obj)
        return obj

    def list_dir(self, rel: str = ".") -> List[str]:
        out = sorted(os.listdir(os.path.join(self.task.workdir, rel)))
        self._log("list_dir", rel, out)
        return out

    def run_visible_check(self) -> Tuple[bool, List[Tuple[str, ...]]]:
        ok, residues = fw_visible_check(self.task)
        self._log("run_visible_check", self.task.tid, (ok, residues))
        return ok, residues

    def apply_patch(self, rel: str, old_line: str, new_line: str) -> bool:
        path = os.path.join(self.task.workdir, rel)
        with open(path) as f:
            text = f.read()
        if text.count(old_line) != 1:
            self._log("apply_patch", (rel, old_line), "no-unique-match",
                      "reverted")
            return False
        with open(path, "w") as f:
            f.write(text.replace(old_line, new_line))
        self._log("apply_patch", (rel, old_line, new_line), "ok",
                  "committed")
        return True

    def revert_file(self, rel: str, content: str) -> None:
        path = os.path.join(self.task.workdir, rel)
        with open(path, "w") as f:
            f.write(content)
        self._log("revert_file", rel, len(content), "reverted")


def fw_visible_check(task: SealedFileTask) -> Tuple[bool,
                                                    List[Tuple[str, ...]]]:
    """The check the agent may run. Compares only the VISIBLE expectations
    (a small prefix/projection of the truth) and returns residue
    signatures on mismatch."""
    fam, res = task.family, []
    try:
        if fam == "repo_repair":
            ok, res = _fw_repo_visible_check(task)
            return ok, res
        with open(os.path.join(task.workdir, "out.json")) as f:
            got = json.load(f)
    except Exception:
        return False, [(fam, "missing_or_invalid_output")]
    ve = task.visible_expected
    if fam == "csv_normalize":
        rows = ve["rows_prefix"]
        gp = got[:len(rows)] if isinstance(got, list) else []
        for g, w in zip(gp, rows):
            for k in w:
                if not isinstance(g, dict) or g.get(k) != w[k]:
                    res.append((fam, f"field:{k}",
                                str(g.get(k) if isinstance(g, dict)
                                    else None)[:24], str(w[k])[:24]))
        if len(gp) < len(rows):
            res.append((fam, "too_few_rows"))
    elif fam == "log_aggregate":
        if set(got.get("counts", {})) != set(ve["count_keys"]):
            res.append((fam, "count_keys", str(sorted(got.get("counts",
                                                              {})))))
        for k in ("max_latency", "over_100"):
            if k not in got:
                res.append((fam, "missing_key", k))
    elif fam == "config_migrate":
        if got.get("server", {}).get("host") != ve["host"]:
            res.append((fam, "flat_keys"))
        ek = ve.get("sample_extra_key")
        if ek and ek not in got.get("extra", {}):
            res.append((fam, "lost_unknown", ek))
    return (not res), res


# --------------------------------------------------------------------------
# Generators (seeded, deterministic). Hidden truth stays in memory.
# --------------------------------------------------------------------------
def _fw_mkdir(tid: str) -> str:
    import shutil
    d = os.path.join(FILEWORLD_ROOT, tid)
    if os.path.isdir(d):
        shutil.rmtree(d)
    os.makedirs(d, exist_ok=True)
    return d


_FW_NAMES = ("alice", "bob", "carol", "dave", "erin", "frank")


def gen_csv_normalize(seed: int, self_gen: bool = False) -> SealedFileTask:
    rng = random.Random(seed)
    tid = f"FWC{seed}"
    d = _fw_mkdir(tid)
    rows_truth: List[Dict[str, object]] = []
    lines = ["name,date,amount"]
    for _ in range(rng.randint(6, 10)):
        nm = rng.choice(_FW_NAMES)
        y, mo, da = 2024, rng.randint(1, 12), rng.randint(1, 28)
        amt = rng.randint(40, 4000)
        style = rng.randrange(3)
        if style == 0:
            ds = f"{y:04d}-{mo:02d}-{da:02d}"
        elif style == 1:
            ds = f"{mo:02d}/{da:02d}/{y:04d}"
        else:
            ds = f"{da:02d}.{mo:02d}.{y:04d}"
        pad = " " * rng.randint(0, 2)
        amts = (f"${amt}" if rng.random() < 0.5 else str(amt))
        lines.append(f"{pad}{nm}{pad},{ds}, {amts}")
        if rng.random() < 0.25:
            lines.append("")
        rows_truth.append({"name": nm,
                           "date": f"{y:04d}-{mo:02d}-{da:02d}",
                           "amount": amt})
    with open(os.path.join(d, "data.csv"), "w") as f:
        f.write("\n".join(lines) + "\n")
    visible = {"rows_prefix": rows_truth[:2]}
    with open(os.path.join(d, "visible_expected.json"), "w") as f:
        json.dump(visible, f, sort_keys=True)
    return SealedFileTask(tid, "csv_normalize", d, visible,
                          {"rows": rows_truth}, self_gen, seed)


def gen_log_aggregate(seed: int, self_gen: bool = False) -> SealedFileTask:
    rng = random.Random(seed)
    tid = f"FWL{seed}"
    d = _fw_mkdir(tid)
    counts: Dict[str, int] = {}
    mx = 0
    over = 0
    lines = []
    for _ in range(rng.randint(12, 20)):
        if rng.random() < 0.15:
            lines.append('{"level": "INFO", "latency_ms":')   # malformed
            continue
        lv = rng.choice(("INFO", "WARN", "ERROR"))
        lat = rng.randint(5, 240)
        counts[lv] = counts.get(lv, 0) + 1
        mx = max(mx, lat)
        over += 1 if lat > 100 else 0
        lines.append(json.dumps({"level": lv, "latency_ms": lat}))
    with open(os.path.join(d, "events.jsonl"), "w") as f:
        f.write("\n".join(lines) + "\n")
    visible = {"count_keys": sorted(counts)}
    with open(os.path.join(d, "visible_expected.json"), "w") as f:
        json.dump(visible, f, sort_keys=True)
    hidden = {"counts": counts, "max_latency": mx, "over_100": over}
    return SealedFileTask(tid, "log_aggregate", d, visible, hidden,
                          self_gen, seed)


def gen_config_migrate(seed: int, self_gen: bool = False) -> SealedFileTask:
    rng = random.Random(seed)
    tid = f"FWG{seed}"
    d = _fw_mkdir(tid)
    host = f"10.0.{rng.randint(0, 9)}.{rng.randint(2, 99)}"
    port = rng.choice((80, 443, 8080, 9090))
    debug = rng.choice(("true", "false"))
    name = rng.choice(("svc-a", "svc-b", "svc-c"))
    extras = {f"k_{rng.randrange(100):02d}": str(rng.randrange(50))
              for _ in range(rng.randint(1, 3))}
    lines = [f"host={host}", f"port={port}", f"debug={debug}",
             f"name={name}"] + [f"{k}={v}" for k, v in sorted(
                 extras.items())]
    rng.shuffle(lines)
    with open(os.path.join(d, "app.cfg"), "w") as f:
        f.write("\n".join(lines) + "\n")
    truth = {"server": {"host": host, "port": port},
             "flags": {"debug": debug == "true"},
             "app": {"name": name},
             "extra": extras}
    visible = {"host": host,
               "sample_extra_key": sorted(extras)[0] if extras else None}
    with open(os.path.join(d, "visible_expected.json"), "w") as f:
        json.dump(visible, f, sort_keys=True)
    return SealedFileTask(tid, "config_migrate", d, visible,
                          {"config": truth}, self_gen, seed)


_FW_CALC_OK = (
    "def add(a, b):\n    return a + b\n\n"
    "def clamp(x, lo, hi):\n    if x < lo:\n        return lo\n"
    "    if x >= hi:\n        return hi\n    return x\n\n"
    "def scale(xs, n):\n    return [v * n for v in xs]\n")
_FW_BUGS = (("return a + b", "return a - b"),
            ("if x >= hi:", "if x < hi:"),
            ("return [v * n for v in xs]",
             "return [v * n + 1 for v in xs]"))


def _fw_calc_ref(fn: str, args: tuple) -> object:
    if fn == "add":
        return args[0] + args[1]
    if fn == "clamp":
        x, lo, hi = args
        return lo if x < lo else (hi if x >= hi else x)
    return [v * args[1] for v in args[0]]


def gen_repo_repair(seed: int, self_gen: bool = False) -> SealedFileTask:
    rng = random.Random(seed)
    tid = f"FWR{seed}"
    d = _fw_mkdir(tid)
    os.makedirs(os.path.join(d, "repo"), exist_ok=True)
    good, bad = _FW_BUGS[rng.randrange(len(_FW_BUGS))]
    src = _FW_CALC_OK.replace(good, bad)
    with open(os.path.join(d, "repo", "calc.py"), "w") as f:
        f.write(src)
    cases = [("add", (rng.randint(1, 9), rng.randint(1, 9))),
             ("clamp", (rng.randint(-3, 12), 0, 7)),
             ("clamp", (7, 0, 7)),
             ("scale", ((1, rng.randint(2, 5)), rng.randint(2, 4)))]
    visible_cases = [(f, a, _fw_calc_ref(f, a)) for f, a in cases]
    hidden_cases = visible_cases + [
        ("add", (0, 0), 0), ("clamp", (0, 0, 7), 0),
        ("clamp", (9, 0, 7), 7), ("clamp", (6, 0, 7), 6),
        ("scale", ((2, 3, 4), 3), [6, 9, 12])]
    with open(os.path.join(d, "visible_cases.json"), "w") as f:
        json.dump([[f_, list(a), r if not isinstance(r, list) else r]
                   for f_, a, r in visible_cases], f)
    visible = {"n_cases": len(visible_cases)}
    return SealedFileTask(tid, "repo_repair", d, visible,
                          {"cases": hidden_cases}, self_gen, seed)


def _fw_load_calc(workdir: str, tag: str):
    """Load repo/calc.py fresh. Single-character patches keep file SIZE and
    (within one second) MTIME identical, so a previously written
    __pycache__ entry would validate against the OLD bytecode and silently
    undo the patch. Wipe the cache and invalidate finders before loading."""
    import importlib
    import importlib.util
    import shutil
    shutil.rmtree(os.path.join(workdir, "repo", "__pycache__"),
                  ignore_errors=True)
    importlib.invalidate_caches()
    path = os.path.join(workdir, "repo", "calc.py")
    spec = importlib.util.spec_from_file_location(f"fw_calc_{tag}", path)
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


def _fw_run_cases(workdir: str, cases, tag: str) -> float:
    try:
        mod = _fw_load_calc(workdir, tag)
    except Exception:
        return 0.0
    hits = 0
    for f_, a, want in cases:
        try:
            got = getattr(mod, f_)(*a)
            got = list(got) if isinstance(got, list) else got
            want2 = list(want) if isinstance(want, list) else want
            hits += 1 if got == want2 else 0
        except Exception:
            pass
    return hits / len(cases)


def _fw_repo_visible_check(task: SealedFileTask):
    with open(os.path.join(task.workdir, "visible_cases.json")) as f:
        raw = json.load(f)
    cases = [(f_, tuple(tuple(x) if isinstance(x, list) and f_ == "scale"
                        and i == 0 else x for i, x in enumerate(a)), r)
             for f_, a, r in raw]
    frac = _fw_run_cases(task.workdir, cases,
                         f"v{task.seed}_{random.randrange(10**6)}")
    res = [] if frac >= 1.0 else [("repo_repair", "visible_test_fail",
                                   f"{frac:.2f}")]
    return frac >= 1.0, res


def _fw_repo_hidden_score(task: SealedFileTask) -> float:
    return _fw_run_cases(task.workdir, task.hidden_expected["cases"],
                         f"h{task.seed}_{random.randrange(10**6)}")


FW_GENERATORS = {"csv_normalize": gen_csv_normalize,
                 "log_aggregate": gen_log_aggregate,
                 "config_migrate": gen_config_migrate,
                 "repo_repair": gen_repo_repair}


# --------------------------------------------------------------------------
# Skill substrate: rule constructors (declared designer library), the
# adaptive pipeline that applies adopted rules, and the frozen baseline.
# --------------------------------------------------------------------------
def _fw_date_iso(val: str) -> Optional[str]:
    v = val.strip()
    if len(v) == 10 and v[4] == "-" and v[7] == "-":
        return v
    if len(v) == 10 and v[2] == "/" and v[5] == "/":
        return f"{v[6:10]}-{v[0:2]}-{v[3:5]}"
    if len(v) == 10 and v[2] == "." and v[5] == ".":
        return f"{v[6:10]}-{v[3:5]}-{v[0:2]}"
    return None


def fw_rule(kind: str, **params) -> Dict[str, object]:
    return {"kind": kind, "params": dict(sorted(params.items()))}


def fw_rule_key(rule: Dict[str, object]) -> str:
    return _fw_hash((rule["kind"], tuple(sorted(rule["params"].items()))))


FW_RULE_KINDS: Tuple[str, ...] = (
    "strip_fields", "skip_blank_rows", "date_iso", "amount_int",
    "jsonl_skip_malformed", "metric_over", "nest_rename",
    "preserve_unknown", "patch_search")


def fw_frozen_agent(task: SealedFileTask, sess: ToolSession) -> None:
    fam = task.family
    if fam == "csv_normalize":
        text = sess.read_file("data.csv")
        lines = text.strip().split("\n")
        hdr = lines[0].split(",")
        rows = [dict(zip(hdr, ln.split(","))) for ln in lines[1:]]
        sess.write_json("out.json", rows)
    elif fam == "log_aggregate":
        text = sess.read_file("events.jsonl")
        counts: Dict[str, int] = {}
        for ln in text.strip().split("\n"):
            try:
                ev = sess.parse_json(ln)
                counts[ev["level"]] = counts.get(ev["level"], 0) + 1
            except Exception:
                counts["?"] = counts.get("?", 0) + 1
        sess.write_json("out.json", {"counts": counts})
    elif fam == "config_migrate":
        text = sess.read_file("app.cfg")
        flat = {}
        for ln in text.strip().split("\n"):
            if "=" in ln:
                k, v = ln.split("=", 1)
                flat[k] = v
        sess.write_json("out.json", flat)
    # repo_repair: frozen agent applies no patch.


def fw_adaptive_agent(task: SealedFileTask, sess: ToolSession,
                      skills: Sequence[Dict[str, object]]) -> None:
    fam = task.family
    kinds = {s["kind"]: s["params"] for s in skills}
    if fam == "csv_normalize":
        text = sess.read_file("data.csv")
        lines = text.split("\n")
        hdr = [h.strip() for h in lines[0].split(",")]
        rows = []
        for ln in lines[1:]:
            if "skip_blank_rows" in kinds and not ln.strip():
                continue
            if not ln:
                continue
            vals = ln.split(",")
            if len(vals) != len(hdr):
                continue
            rec = dict(zip(hdr, vals))
            if "strip_fields" in kinds:
                rec = {k: v.strip() for k, v in rec.items()}
            if "date_iso" in kinds and "date" in rec:
                iso = _fw_date_iso(rec["date"])
                rec["date"] = iso if iso is not None else rec["date"]
            if "amount_int" in kinds and "amount" in rec:
                raw = rec["amount"].replace("$", "").replace(",", "")
                raw = raw.strip()
                rec["amount"] = int(raw) if raw.isdigit() else rec["amount"]
            rows.append(rec)
        sess.write_json("out.json", rows)
    elif fam == "log_aggregate":
        text = sess.read_file("events.jsonl")
        counts: Dict[str, int] = {}
        lats: List[int] = []
        for ln in text.strip().split("\n"):
            try:
                ev = sess.parse_json(ln)
            except Exception:
                if "jsonl_skip_malformed" in kinds:
                    continue
                counts["?"] = counts.get("?", 0) + 1
                continue
            counts[ev["level"]] = counts.get(ev["level"], 0) + 1
            lats.append(int(ev["latency_ms"]))
        out: Dict[str, object] = {"counts": counts}
        if lats:
            out["max_latency"] = max(lats)
        if "metric_over" in kinds:
            thr = int(kinds["metric_over"]["threshold"])
            out[kinds["metric_over"]["outkey"]] = sum(
                1 for v in lats if v > thr)
        sess.write_json("out.json", out)
    elif fam == "config_migrate":
        text = sess.read_file("app.cfg")
        flat = {}
        for ln in text.strip().split("\n"):
            if "=" in ln:
                k, v = ln.split("=", 1)
                flat[k] = v
        if "nest_rename" in kinds:
            out2 = {"server": {"host": flat.get("host", ""),
                               "port": int(flat.get("port", "0"))},
                    "flags": {"debug": flat.get("debug") == "true"},
                    "app": {"name": flat.get("name", "")}}
            if "preserve_unknown" in kinds:
                out2["extra"] = {k: v for k, v in flat.items()
                                 if k not in FW_KNOWN_CFG_KEYS}
            sess.write_json("out.json", out2)
        else:
            sess.write_json("out.json", flat)
    elif fam == "repo_repair" and "patch_search" in kinds:
        _fw_patch_search(task, sess)


_FW_CMP_SWAPS = (("x < hi", "x >= hi"), ("x >= hi", "x < hi"),
                 ("x < lo", "x <= lo"), ("x <= lo", "x < lo"))
_FW_ARITH_SWAPS = (("a + b", "a - b"), ("a - b", "a + b"),
                   ("v * n + 1", "v * n"), ("v * n", "v * n + 1"))


def _fw_patch_search(task: SealedFileTask, sess: ToolSession) -> None:
    original = sess.read_file(os.path.join("repo", "calc.py"))
    ok, _ = sess.run_visible_check()
    if ok:
        return
    lines = original.split("\n")
    cands: List[Tuple[str, str]] = []
    for ln in lines:
        for old, new in _FW_CMP_SWAPS + _FW_ARITH_SWAPS:
            if old in ln:
                cands.append((ln, ln.replace(old, new)))
    for old_ln, new_ln in cands:
        if old_ln == new_ln:
            continue
        if not sess.apply_patch(os.path.join("repo", "calc.py"),
                                old_ln, new_ln):
            continue
        ok, _ = sess.run_visible_check()
        if ok:
            return
        sess.revert_file(os.path.join("repo", "calc.py"), original)


# --------------------------------------------------------------------------
# Residue mining -> mechanical proposals -> validation gate -> adoption.
# --------------------------------------------------------------------------
def fw_mine_residues(task: SealedFileTask,
                     out_got: object) -> List[Tuple[str, ...]]:
    """Compare agent output to validation truth (self-generated tasks only)
    and emit residue signatures."""
    truth = fw_validation_truth(task)
    fam = task.family
    res: List[Tuple[str, ...]] = []
    if fam == "csv_normalize":
        rows = truth["rows"]
        got = out_got if isinstance(out_got, list) else []
        if len(got) != len(rows):
            res.append((fam, "row_count"))
        for g, w in zip(got, rows):
            if not isinstance(g, dict):
                continue
            if g.get("name") != w["name"]:
                res.append((fam, "whitespace", "name"))
            gd = str(g.get("date", ""))
            if gd != w["date"]:
                if "/" in gd:
                    res.append((fam, "date_format", "MDY_slash"))
                elif "." in gd:
                    res.append((fam, "date_format", "DMY_dot"))
                else:
                    res.append((fam, "date_format", "other"))
            if g.get("amount") != w["amount"]:
                res.append((fam, "amount_symbol",
                            str(g.get("amount"))[:12]))
    elif fam == "log_aggregate":
        got = out_got if isinstance(out_got, dict) else {}
        if got.get("counts") != truth["counts"]:
            res.append((fam, "malformed_line"))
        for k in ("max_latency", "over_100"):
            if k not in got:
                res.append((fam, "missing_key", k))
            elif got[k] != truth[k]:
                res.append((fam, "wrong_value", k))
    elif fam == "config_migrate":
        got = out_got if isinstance(out_got, dict) else {}
        if "server" not in got:
            res.append((fam, "flat_keys"))
        else:
            want = truth["config"]
            if got.get("extra") != want["extra"]:
                res.append((fam, "lost_unknown"))
            if got != want:
                res.append((fam, "type_or_shape"))
    elif fam == "repo_repair":
        cases = truth["cases"]
        frac = _fw_run_cases(task.workdir, cases,
                             f"m{task.seed}_{random.randrange(10**6)}")
        if frac < 1.0:
            res.append((fam, "failing_cases", f"{frac:.2f}"))
    return res


def fw_propose_from_residues(residues: Sequence[Tuple[str, ...]]
                             ) -> List[Dict[str, object]]:
    """Mechanical residue->rule mapping over the declared constructor
    library. Parameters come FROM the residue content."""
    props: List[Dict[str, object]] = []
    seen = set()

    def add(rule):
        k = fw_rule_key(rule)
        if k not in seen:
            seen.add(k)
            props.append(rule)
    for sig in residues:
        fam, kind = sig[0], sig[1]
        if fam == "csv_normalize":
            if kind == "whitespace":
                add(fw_rule("strip_fields"))
            elif kind == "row_count":
                add(fw_rule("skip_blank_rows"))
            elif kind == "date_format":
                add(fw_rule("date_iso", formats=sig[2]))
            elif kind == "amount_symbol":
                add(fw_rule("amount_int"))
        elif fam == "log_aggregate":
            if kind == "malformed_line":
                add(fw_rule("jsonl_skip_malformed"))
            elif kind in ("missing_key", "wrong_value") and \
                    sig[2] == "over_100":
                add(fw_rule("metric_over", threshold=100,
                            outkey="over_100"))
        elif fam == "config_migrate":
            if kind == "flat_keys":
                add(fw_rule("nest_rename"))
            elif kind in ("lost_unknown", "type_or_shape"):
                add(fw_rule("preserve_unknown",
                            known=",".join(FW_KNOWN_CFG_KEYS)))
        elif fam == "repo_repair" and kind == "failing_cases":
            add(fw_rule("patch_search", ops="cmp,arith"))
    return props


@dataclass
class SkillMemory:
    adopted: List[Dict[str, object]] = field(default_factory=list)
    rejected_keys: List[str] = field(default_factory=list)
    log: List[Dict[str, object]] = field(default_factory=list)

    def save(self, path: str) -> None:
        with open(path, "w") as f:
            json.dump({"adopted": self.adopted,
                       "rejected_keys": self.rejected_keys,
                       "log": self.log}, f, sort_keys=True)

    @staticmethod
    def load(path: str) -> "SkillMemory":
        with open(path) as f:
            d = json.load(f)
        return SkillMemory(d["adopted"], d["rejected_keys"], d["log"])


def fw_validation_score(tasks: Sequence[SealedFileTask],
                        skills: Sequence[Dict[str, object]]) -> float:
    total = 0.0
    for t in tasks:
        # regenerate to wipe prior outputs/patches
        FW_GENERATORS[t.family](t.seed, self_gen=True)
        sess = ToolSession(t)
        fw_adaptive_agent(t, sess, skills)
        truth = fw_validation_truth(t)
        if t.family == "repo_repair":
            total += _fw_run_cases(t.workdir, truth["cases"],
                                   f"s{t.seed}_{random.randrange(10**6)}")
        else:
            try:
                with open(os.path.join(t.workdir, "out.json")) as f:
                    got = json.load(f)
            except Exception:
                got = None
            if t.family == "csv_normalize":
                rows = truth["rows"]
                gp = got if isinstance(got, list) else []
                hits = sum(1 for g, w in zip(gp, rows) if g == w)
                total += hits / max(len(gp), len(rows), 1)
            elif t.family == "log_aggregate":
                keys = ("counts", "max_latency", "over_100")
                total += (sum(1 for k in keys
                              if isinstance(got, dict)
                              and got.get(k) == truth[k]) / len(keys))
            else:
                want = truth["config"]
                gd = got if isinstance(got, dict) else {}
                total += sum(1 for sect in
                             ("server", "flags", "app", "extra")
                             if gd.get(sect) == want.get(sect)) / 4.0
    return total / len(tasks)


def fw_skill_round(memory: SkillMemory,
                   val_tasks: Sequence[SealedFileTask]) -> Dict[str, object]:
    """One mine->propose->validate->adopt/reject round."""
    residues: List[Tuple[str, ...]] = []
    for t in val_tasks:
        FW_GENERATORS[t.family](t.seed, self_gen=True)
        sess = ToolSession(t)
        fw_adaptive_agent(t, sess, memory.adopted)
        try:
            with open(os.path.join(t.workdir, "out.json")) as f:
                got = json.load(f)
        except Exception:
            got = None
        residues.extend(fw_mine_residues(t, got))
    proposals = fw_propose_from_residues(residues)
    base = fw_validation_score(val_tasks, memory.adopted)
    decided = []
    pending = []
    for rule in proposals:
        k = fw_rule_key(rule)
        if k in memory.rejected_keys:
            decided.append({"rule": rule, "status": "rejected_cached"})
        elif not any(fw_rule_key(r) == k for r in memory.adopted):
            pending.append(rule)
    # Fixpoint passes: each adoption is new evidence, so rules that showed
    # no gain earlier get re-validated within the round. Anti-resurrection
    # is preserved by finalizing rejections only when the round converges.
    for _pass in range(4):
        progressed = False
        still = []
        for rule in pending:
            cand = fw_validation_score(val_tasks, memory.adopted + [rule])
            if cand > base + 1e-9:
                memory.adopted.append(rule)
                base = cand
                progressed = True
                decided.append({"rule": rule, "status": "adopted",
                                "validation": round(cand, 4)})
            else:
                still.append(rule)
        pending = still
        if not progressed or not pending:
            break
    for rule in pending:
        memory.rejected_keys.append(fw_rule_key(rule))
        decided.append({"rule": rule, "status": "rejected"})
    memory.log.extend(decided)
    return {"n_residues": len(residues), "proposals": len(proposals),
            "decided": decided, "validation_after": round(base, 4)}


def fw_curriculum_amplify(memory: SkillMemory,
                          val_tasks: List[SealedFileTask],
                          seed: int) -> List[SealedFileTask]:
    """Residues remaining after round 1 spawn amplified validation
    variants of the same families (new seeds)."""
    residues: List[Tuple[str, ...]] = []
    for t in val_tasks:
        FW_GENERATORS[t.family](t.seed, self_gen=True)
        sess = ToolSession(t)
        fw_adaptive_agent(t, sess, memory.adopted)
        try:
            with open(os.path.join(t.workdir, "out.json")) as f:
                got = json.load(f)
        except Exception:
            got = None
        residues.extend(fw_mine_residues(t, got))
    fams = sorted({r[0] for r in residues})
    new = []
    for i, fam in enumerate(fams):
        for j in range(2):
            new.append(FW_GENERATORS[fam](seed + 31 * i + j,
                                          self_gen=True))
    return new


# --------------------------------------------------------------------------
# A/B evaluation on UNSEEN eval seeds; results artifact for the tests.
# --------------------------------------------------------------------------
FW_VAL_SEED_BASE = 5000
FW_EVAL_SEED_BASE = 9000


def file_world_run(seed: int = SEED,
                   out_json: Optional[str] = "file_world_results.json"
                   ) -> Dict[str, object]:
    os.makedirs(FILEWORLD_ROOT, exist_ok=True)
    val_tasks = [FW_GENERATORS[fam](FW_VAL_SEED_BASE + i, self_gen=True)
                 for i, fam in enumerate(FW_FAMILIES)]
    memory = SkillMemory()
    r1 = fw_skill_round(memory, val_tasks)
    extra = fw_curriculum_amplify(memory, val_tasks, FW_VAL_SEED_BASE + 100)
    r2 = fw_skill_round(memory, val_tasks + extra)
    val_r2_on_r1 = round(fw_validation_score(val_tasks, memory.adopted), 4)
    per_family: Dict[str, Dict[str, float]] = {}
    trace_sample = None
    for i, fam in enumerate(FW_FAMILIES):
        fr_scores, ad_scores = [], []
        for j in range(3):
            s = FW_EVAL_SEED_BASE + 10 * i + j
            t = FW_GENERATORS[fam](s)
            sess = ToolSession(t)
            fw_frozen_agent(t, sess)
            fr_scores.append(fw_sealed_hidden_score(t))
            t2 = FW_GENERATORS[fam](s)
            sess2 = ToolSession(t2)
            fw_adaptive_agent(t2, sess2, memory.adopted)
            ad_scores.append(fw_sealed_hidden_score(t2))
            if fam == "repo_repair" and trace_sample is None and any(
                    tr.action == "apply_patch" and tr.status == "committed"
                    for tr in sess2.traces):
                trace_sample = [(tr.action, tr.status)
                                for tr in sess2.traces]
        per_family[fam] = {
            "frozen": round(sum(fr_scores) / len(fr_scores), 4),
            "adaptive": round(sum(ad_scores) / len(ad_scores), 4)}
    report = {
        "round1": r1, "round2": r2,
        "validation_round1": r1["validation_after"],
        "validation_round2": r2["validation_after"],
        "validation_round2_on_r1": val_r2_on_r1,
        "adopted_rules": memory.adopted,
        "rejected_count": len(memory.rejected_keys),
        "per_family": per_family,
        "frozen_mean": round(sum(v["frozen"]
                                 for v in per_family.values()) / 4, 4),
        "adaptive_mean": round(sum(v["adaptive"]
                                   for v in per_family.values()) / 4, 4),
        "val_seeds": [t.seed for t in val_tasks],
        "eval_seed_base": FW_EVAL_SEED_BASE,
        "repair_trace_sample": trace_sample,
    }
    memory.save(os.path.join(FILEWORLD_ROOT, "skills_archive.json"))
    if out_json:
        with open(out_json, "w") as f:
            json.dump(json.loads(json.dumps(report, default=str)), f,
                      sort_keys=True)
    return report


def file_battery() -> Dict[str, object]:
    print("=" * 88)
    print("REAL-ARTIFACT HARNESS BATTERY (files, tools, skills, residue"
          " curriculum, repo repair)")
    print("=" * 88)
    rep = file_world_run()
    print("\n[W1] skill rounds on self-generated validation instances")
    print(f"  round1: residues={rep['round1']['n_residues']}"
          f" proposals={rep['round1']['proposals']}"
          f" validation_after={rep['validation_round1']:.4f}")
    print(f"  round2 (residue-amplified curriculum):"
          f" residues={rep['round2']['n_residues']}"
          f" proposals={rep['round2']['proposals']}"
          f" validation_after={rep['validation_round2']:.4f}"
          f" | on round-1 set: {rep['validation_round2_on_r1']:.4f}")
    print("  adopted rules:")
    for r in rep["adopted_rules"]:
        print(f"    {r['kind']:<22} {r['params']}")
    print(f"  rejected (cached, never re-proposed): {rep['rejected_count']}")
    print("\n[W2] sealed hidden A/B on UNSEEN eval seeds"
          " (3 instances/family)")
    for fam, v in rep["per_family"].items():
        print(f"  {fam:<16} frozen={v['frozen']:.3f}"
              f" adaptive={v['adaptive']:.3f}")
    print(f"  means: frozen={rep['frozen_mean']:.3f}"
          f" adaptive={rep['adaptive_mean']:.3f}")
    print("\n[W3] repair action trace (sample)")
    print(f"  {rep['repair_trace_sample']}")
    print("\nreading: the pipeline improves only through validated skill"
          " adoptions mined from its own failures; hidden expectations"
          " never touch the workspace; eval seeds are unseen; the rule"
          " library itself remains designer substrate, reported as such.")
    return rep


# --------------------------------------------------------------------------
# Section 17 tests.
# --------------------------------------------------------------------------
def test_fw_generators_deterministic() -> None:
    for fam in FW_FAMILIES:
        t1 = FW_GENERATORS[fam](4242)
        h1 = {fn: _fw_hash(open(os.path.join(t1.workdir, fn)).read())
              for fn in sorted(os.listdir(t1.workdir))
              if os.path.isfile(os.path.join(t1.workdir, fn))}
        t2 = FW_GENERATORS[fam](4242)
        h2 = {fn: _fw_hash(open(os.path.join(t2.workdir, fn)).read())
              for fn in sorted(os.listdir(t2.workdir))
              if os.path.isfile(os.path.join(t2.workdir, fn))}
        _assert(h1 == h2, f"{fam} generator nondeterministic")
        _assert(t1.hidden_expected == t2.hidden_expected,
                f"{fam} hidden truth nondeterministic")


def test_fw_hidden_expectations_never_on_disk() -> None:
    t = gen_csv_normalize(777)
    canary = json.dumps(t.hidden_expected["rows"], sort_keys=True)
    blob = ""
    for root, _dirs, files in os.walk(t.workdir):
        for fn in files:
            _assert("hidden" not in fn.lower(),
                    f"suspicious filename {fn}")
            blob += open(os.path.join(root, fn)).read()
    _assert(canary not in blob, "hidden truth leaked into workspace")
    try:
        fw_validation_truth(t)
        leaked = True
    except PermissionError:
        leaked = False
    _assert(not leaked, "eval-task truth accessible to validator")


def test_fw_agents_never_touch_sealed_scoring() -> None:
    import inspect
    src = (inspect.getsource(fw_adaptive_agent)
           + inspect.getsource(fw_frozen_agent)
           + inspect.getsource(_fw_patch_search)
           + inspect.getsource(ToolSession))
    for banned in ("fw_sealed_hidden_score", "hidden_expected",
                   "fw_validation_truth", "_fw_repo_hidden_score"):
        _assert(banned not in src, f"agent path references {banned}")


def test_fw_results_adaptive_beats_frozen_on_hidden() -> None:
    _assert(os.path.exists("file_world_results.json"),
            "artifact missing; run --mode file-battery first")
    with open("file_world_results.json") as f:
        rep = json.load(f)
    _assert(rep["adaptive_mean"] > rep["frozen_mean"],
            f"no adaptive gain: {rep['adaptive_mean']}"
            f" vs {rep['frozen_mean']}")
    perfect = sum(1 for v in rep["per_family"].values()
                  if v["adaptive"] == 1.0)
    weak_frozen = sum(1 for v in rep["per_family"].values()
                      if v["frozen"] < 1.0)
    _assert(perfect >= 3, f"adaptive perfect on only {perfect} families")
    _assert(weak_frozen >= 3, "frozen baseline suspiciously strong")
    for fam, v in rep["per_family"].items():
        _assert(v["adaptive"] >= v["frozen"] - 1e-9,
                f"adaptive regressed on {fam}")


def test_fw_skill_gate_rejects_and_blocks_reuse() -> None:
    val = [gen_csv_normalize(6101, self_gen=True)]
    mem = SkillMemory()
    bogus = fw_rule("metric_over", threshold=100, outkey="over_100")
    base = fw_validation_score(val, mem.adopted)
    cand = fw_validation_score(val, mem.adopted + [bogus])
    _assert(cand <= base + 1e-9, "bogus rule unexpectedly helped")
    mem.rejected_keys.append(fw_rule_key(bogus))
    out = fw_skill_round(mem, val)
    for d in out["decided"]:
        if fw_rule_key(d["rule"]) == fw_rule_key(bogus):
            _assert(d["status"] == "rejected_cached",
                    "rejected rule was re-validated")
    _assert(all(fw_rule_key(r) != fw_rule_key(bogus)
                for r in mem.adopted), "rejected rule adopted")


def test_fw_skills_do_not_encode_eval_ids() -> None:
    _assert(os.path.exists("file_world_results.json"), "artifact missing")
    with open("file_world_results.json") as f:
        rep = json.load(f)
    eval_base = rep["eval_seed_base"]
    for rule in rep["adopted_rules"]:
        rs = json.dumps(rule)
        _assert(str(eval_base) not in rs, f"eval seed leaked into {rs}")
        for i in range(4):
            for j in range(3):
                _assert(f"FW" + "CLGR"[i] + str(eval_base + 10 * i + j)
                        not in rs, "eval tid leaked into rule")
    _assert(all(s < eval_base for s in rep["val_seeds"]),
            "validation seeds overlap eval range")


def test_fw_curriculum_round_two_improves() -> None:
    _assert(os.path.exists("file_world_results.json"), "artifact missing")
    with open("file_world_results.json") as f:
        rep = json.load(f)
    _assert(rep["validation_round2_on_r1"]
            >= rep["validation_round1"] - 1e-9, "curriculum regressed")
    _assert(rep["validation_round2_on_r1"] > 0.95,
            f"round-2 validation low: {rep['validation_round2_on_r1']}")


def test_fw_repair_single_line_patch_passes_hidden() -> None:
    _assert(os.path.exists("file_world_results.json"), "artifact missing")
    with open("file_world_results.json") as f:
        rep = json.load(f)
    fam = rep["per_family"]["repo_repair"]
    _assert(fam["adaptive"] == 1.0, f"repair failed hidden: {fam}")
    _assert(fam["frozen"] < 1.0, "frozen repair suspiciously perfect")
    traces = rep["repair_trace_sample"]
    n_commit = sum(1 for a, st in traces
                   if a == "apply_patch" and st == "committed")
    n_revert = sum(1 for a, st in traces if st == "reverted")
    _assert(n_commit - n_revert == 1,
            f"patch not minimal: {n_commit} commits, {n_revert} reverts")


def test_fw_traces_deterministic_and_archive_roundtrip() -> None:
    t = gen_log_aggregate(8181)
    s1 = ToolSession(t)
    fw_frozen_agent(t, s1)
    sig1 = [(tr.action, tr.input_hash, tr.output_hash) for tr in s1.traces]
    t2 = gen_log_aggregate(8181)
    s2 = ToolSession(t2)
    fw_frozen_agent(t2, s2)
    sig2 = [(tr.action, tr.input_hash, tr.output_hash) for tr in s2.traces]
    _assert(sig1 == sig2, "traces nondeterministic")
    _assert(all(tr.status in ("committed", "reverted", "observed")
                for tr in s1.traces), "invalid trace status")
    arch = os.path.join(FILEWORLD_ROOT, "skills_archive.json")
    _assert(os.path.exists(arch), "archive missing; run file-battery")
    mem = SkillMemory.load(arch)
    _assert(len(mem.adopted) >= 4, f"too few skills: {len(mem.adopted)}")
    ev = gen_csv_normalize(9555)
    sess = ToolSession(ev)
    fw_adaptive_agent(ev, sess, mem.adopted)
    _assert(fw_sealed_hidden_score(ev) == 1.0,
            "reloaded skills lost capability")


TESTS.extend([
    test_fw_generators_deterministic,
    test_fw_hidden_expectations_never_on_disk,
    test_fw_agents_never_touch_sealed_scoring,
    test_fw_results_adaptive_beats_frozen_on_hidden,
    test_fw_skill_gate_rejects_and_blocks_reuse,
    test_fw_skills_do_not_encode_eval_ids,
    test_fw_curriculum_round_two_improves,
    test_fw_repair_single_line_patch_passes_hidden,
    test_fw_traces_deterministic_and_archive_roundtrip,
])


