def solve_file_task_reference(task: ArtifactFileTask,
                              layer: ToolActionLayer) -> None:
    if task.tid == "F001":
        rows = layer.parse_csv("input/orders.csv")
        status_counts: Dict[str, int] = {}
        total = 0
        for row in rows:
            status_counts[row["status"]] = status_counts.get(row["status"], 0) + 1
            total += int(round(float(row["amount"]) * 100))
        out = {
            "average_amount_cents": total // max(1, len(rows)),
            "row_count": len(rows),
            "status_counts": dict(sorted(status_counts.items())),
            "total_amount_cents": total,
        }
        layer.write_file("output/status_summary.json",
                         json.dumps(out, indent=2, sort_keys=True))
    elif task.tid == "F002":
        raw = layer.read_file("input/logs.jsonl")
        events = [json.loads(line) for line in raw.splitlines() if line.strip()]
        anomalous = [e for e in events if e.get("level") in ("WARN", "ERROR")]
        service_counts: Dict[str, int] = {}
        for event in anomalous:
            service = str(event["service"])
            service_counts[service] = service_counts.get(service, 0) + 1
        errors = [e for e in anomalous if e.get("level") == "ERROR"]
        warnings = [e for e in anomalous if e.get("level") == "WARN"]
        out = {
            "error_count": len(errors),
            "first_error_ts": errors[0]["ts"] if errors else "",
            "service_counts": dict(sorted(service_counts.items())),
            "warning_count": len(warnings),
        }
        layer.write_file("output/anomaly_report.json",
                         json.dumps(out, indent=2, sort_keys=True))
    elif task.tid == "F003":
        layer.apply_patch("repo/math_utils.py", "return a - b", "return a + b")
        layer.run_tests(task.train_check)
    elif task.tid == "F004":
        rows = layer.parse_xlsx("input/tickets.xlsx")
        headers = rows[0]
        records = [dict(zip(headers, row)) for row in rows[1:]]
        status_counts: Dict[str, int] = {}
        total = 0
        for record in records:
            status = str(record["status"])
            status_counts[status] = status_counts.get(status, 0) + 1
            total += int(round(float(record["amount"]) * 100))
        out = {
            "headers": headers,
            "row_count": len(records),
            "status_counts": dict(sorted(status_counts.items())),
            "total_amount_cents": total,
        }
        layer.write_file("output/xlsx_summary.json",
                         json.dumps(out, indent=2, sort_keys=True))
    else:
        raise ValueError(f"unknown file task {task.tid}")


def run_real_artifact_harness(save_path: str = "") -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    with tempfile.TemporaryDirectory(prefix="metaforge_file_tasks_") as tmp:
        root = Path(tmp)
        for task in build_real_artifact_tasks():
            workspace = task.provision(root)
            layer = ToolActionLayer(workspace, task.allowed_tools)
            solve_file_task_reference(task, layer)
            train = task.run_train(workspace)
            hidden = task.run_hidden(workspace)
            results.append({
                "tid": task.tid,
                "family": task.family,
                "train_ok": train.ok,
                "hidden_ok": hidden.ok,
                "residues": sorted(set(train.residues + hidden.residues)),
                "trace": [trace.as_dict() for trace in layer.traces],
                "trace_digest": _digest_json(
                    [trace.as_dict() for trace in layer.traces]),
            })
    report = {
        "all_hidden_passed": all(r["hidden_ok"] for r in results),
        "task_count": len(results),
        "tasks": results,
        "surface": "ArtifactFileTask + ToolActionLayer",
    }
    if save_path:
        Path(save_path).write_text(json.dumps(report, indent=2,
                                              sort_keys=True),
                                   encoding="utf-8")
    return report


def test_real_artifact_harness_provisions_public_files() -> None:
    task = build_real_artifact_tasks()[0]
    with tempfile.TemporaryDirectory() as tmp:
        workspace = task.provision(Path(tmp))
        _assert((workspace / "input/orders.csv").exists(),
                "public input file missing")
        _assert((workspace / "public_instruction.txt").exists(),
                "public instruction missing")
        schema = json.loads(
            (workspace / "expected_artifact_schema.json").read_text(
                encoding="utf-8"))
        _assert("output/status_summary.json" in schema,
                "expected artifact schema missing output")


def test_real_artifact_tool_action_layer_trace_and_path_guard() -> None:
    task = build_real_artifact_tasks()[0]

    def run_once() -> List[Dict[str, object]]:
        with tempfile.TemporaryDirectory() as tmp:
            workspace = task.provision(Path(tmp))
            layer = ToolActionLayer(workspace, task.allowed_tools)
            rows = layer.parse_csv("input/orders.csv")
            _assert(len(rows) == 3, "CSV parser returned wrong row count")
            layer.write_file("output/tmp.txt", "ok\n")
            try:
                layer.read_file("../escape.txt")
            except ValueError:
                pass
            else:
                raise AssertionError("path escape was not rejected")
            return [trace.as_dict() for trace in layer.traces]

    first = run_once()
    second = run_once()
    _assert(first == second, "tool trace is not deterministic")
    _assert(first[-1]["failure_type"] == "path_escape",
            "path guard did not record the failure type")
    _assert(first[-1]["status"] == "reverted",
            "rejected action did not record reverted status")


def test_real_artifact_hidden_file_gate_blocks_train_only_artifact() -> None:
    task = build_real_artifact_tasks()[0]
    with tempfile.TemporaryDirectory() as tmp:
        workspace = task.provision(Path(tmp))
        out = workspace / "output"
        out.mkdir()
        (out / "status_summary.json").write_text(json.dumps({
            "row_count": 3,
            "status_counts": {"fail": 1, "ok": 2},
        }, sort_keys=True), encoding="utf-8")
        train = task.run_train(workspace)
        hidden = task.run_hidden(workspace)
        _assert(train.ok, f"train gate unexpectedly failed: {train}")
        _assert(not hidden.ok, "hidden gate accepted incomplete artifact")
        _assert("missing_total_amount_cents" in hidden.residues,
                f"unexpected hidden residues: {hidden.residues}")


