def gd_small_int_expr(value: int) -> Optional[GDXExpr]:
    if value in GDX_CONSTS:
        return _gdx_const(value)
    for a in GDX_CONSTS:
        for b in GDX_CONSTS:
            if a + b == value:
                return _gdx_bin("ADD", _gdx_const(a), _gdx_const(b))
    return None


def gd_lesson_candidates(env: GDScarceEnv, book: LessonBook,
                         max_cost: int) -> List[GDXExpr]:
    out: List[GDXExpr] = []
    if book.active("GEN_GAP_LENGTH") or book.active("TRAIN_DEGENERACY_LENGTH"):
        length_features = ("SIZE", "STR_LEN", "ROWS", "COLS", "AREA",
                           "NUM_COUNT")
        for feat in length_features:
            for cap in (4, 5, 6):
                cap_expr = gd_small_int_expr(cap)
                if cap_expr is None:
                    continue
                expr = _gdx_bin("MIN", _gdx_feature(feat), cap_expr)
                if gdx_expr_cost(expr) <= max_cost:
                    out.append(expr)
    return out


# Heterogeneous-domain self-improvement harness.
#
# This is deliberately not a claim of unbounded general intelligence. It broadens the runtime
# from one list[int] VM benchmark to a feature-level synthesis layer that can
# operate over lists, strings, grids, and dict/record-like objects. The searcher
# sees only train examples. Candidate improvements are reusable expression
# macros mined from solved programs, and they are accepted only if they solve
# fresh frontier tasks under the same expression-cost budget.
# ---------------------------------------------------------------------------

GDX_FEATURES: Tuple[str, ...] = (
    "SIZE", "NUM_SUM", "NUM_COUNT", "NUM_MAX", "NUM_MIN",
    "FIRST_NUM", "LAST_NUM", "STR_LEN", "VOWELS", "DIGITS",
    "UPPER", "ROWS", "COLS", "AREA", "FIELDS",
    "ATOM_COUNT", "LEAVES", "DEPTH", "FIELD_COUNT", "STR_COUNT",
    "LIST_COUNT", "DICT_COUNT", "NODE_COUNT", "EDGE_COUNT",
)

GDX_CONSTS: Tuple[int, ...] = (0, 1, 2, 3)
GDX_BINARY_OPS: Tuple[str, ...] = ("ADD", "SUB", "MUL", "MAX", "MIN")


def _gdx_numbers(obj) -> List[int]:
    out: List[int] = []
    if isinstance(obj, bool):
        return [int(obj)]
    if isinstance(obj, int):
        return [obj]
    if isinstance(obj, float):
        return [int(obj)]
    if isinstance(obj, str):
        return [int(ch) for ch in obj if ch.isdigit()]
    if isinstance(obj, dict):
        for k in sorted(obj, key=lambda x: str(x)):
            out.extend(_gdx_numbers(obj[k]))
        return out
    if isinstance(obj, (list, tuple)):
        for v in obj:
            out.extend(_gdx_numbers(v))
        return out
    return out


def _gdx_flat_strings(obj) -> List[str]:
    if isinstance(obj, str):
        return [obj]
    if isinstance(obj, dict):
        out: List[str] = []
        for k in sorted(obj, key=lambda x: str(x)):
            out.extend(_gdx_flat_strings(obj[k]))
        return out
    if isinstance(obj, (list, tuple)):
        out: List[str] = []
        for v in obj:
            out.extend(_gdx_flat_strings(v))
        return out
    return []


def _gdx_shape(obj) -> Tuple[int, int]:
    if isinstance(obj, (list, tuple)) and obj and all(isinstance(r, (list, tuple)) for r in obj):
        rows = len(obj)
        cols = max((len(r) for r in obj), default=0)
        return rows, cols
    if isinstance(obj, (list, tuple)) and obj and all(isinstance(r, dict) for r in obj):
        keys = set()
        for row in obj:
            keys.update(str(k) for k in row)
        return len(obj), len(keys)
    if isinstance(obj, dict) and isinstance(obj.get("rows"), (list, tuple)):
        return _gdx_shape(obj["rows"])
    return 0, 0


def _gd_object_stats(obj) -> Dict[str, int]:
    stats = {
        "ATOM_COUNT": 0,
        "LEAVES": 0,
        "DEPTH": 0,
        "FIELD_COUNT": 0,
        "STR_COUNT": 0,
        "LIST_COUNT": 0,
        "DICT_COUNT": 0,
        "NODE_COUNT": 0,
        "EDGE_COUNT": 0,
    }

    def rec(x, depth: int) -> None:
        stats["DEPTH"] = max(stats["DEPTH"], depth)
        if isinstance(x, dict):
            stats["DICT_COUNT"] += 1
            stats["FIELD_COUNT"] += len(x)
            if isinstance(x.get("nodes"), (list, tuple)):
                stats["NODE_COUNT"] += len(x["nodes"])
            if isinstance(x.get("edges"), (list, tuple)):
                stats["EDGE_COUNT"] += len(x["edges"])
            if not x:
                stats["LEAVES"] += 1
            for key in sorted(x, key=lambda k: str(k)):
                rec(x[key], depth + 1)
            return
        if isinstance(x, (list, tuple)):
            stats["LIST_COUNT"] += 1
            if not x:
                stats["LEAVES"] += 1
            for item in x:
                rec(item, depth + 1)
            return
        stats["ATOM_COUNT"] += 1
        stats["LEAVES"] += 1
        if isinstance(x, str):
            stats["STR_COUNT"] += 1

    rec(obj, 1)
    return {k: int(v) for k, v in stats.items()}


def gd_object_features(obj) -> Dict[str, int]:
    nums = _gdx_numbers(obj)
    strings = _gdx_flat_strings(obj)
    text = "".join(strings)
    rows, cols = _gdx_shape(obj)
    size = len(obj) if hasattr(obj, "__len__") else len(nums)
    vowels = sum(1 for ch in text.lower() if ch in "aeiou")
    digits = sum(1 for ch in text if ch.isdigit())
    upper = sum(1 for ch in text if ch.isupper())
    out = {
        "SIZE": int(size),
        "NUM_SUM": int(sum(nums)),
        "NUM_COUNT": int(len(nums)),
        "NUM_MAX": int(max(nums)) if nums else 0,
        "NUM_MIN": int(min(nums)) if nums else 0,
        "FIRST_NUM": int(nums[0]) if nums else 0,
        "LAST_NUM": int(nums[-1]) if nums else 0,
        "STR_LEN": int(sum(len(s) for s in strings)),
        "VOWELS": int(vowels),
        "DIGITS": int(digits),
        "UPPER": int(upper),
        "ROWS": int(rows),
        "COLS": int(cols),
        "AREA": int(rows * cols),
        "FIELDS": int(len(obj)) if isinstance(obj, dict) else 0,
    }
    out.update(_gd_object_stats(obj))
    return out


@dataclass(frozen=True)
class GDXExpr:
    op: str
    args: Tuple["GDXExpr", ...] = ()
    name: str = ""
    value: int = 0


@dataclass(frozen=True)
class GDXMacro:
    name: str
    body: GDXExpr
    source_tasks: Tuple[str, ...]


@dataclass(frozen=True)
class GDXTask:
    name: str
    domain: str
    train: Tuple[Tuple[object, int], ...]
    holdout: Tuple[Tuple[object, int], ...]


def _gdx_feature(name: str) -> GDXExpr:
    return GDXExpr("FEATURE", name=name)


def _gdx_const(value: int) -> GDXExpr:
    return GDXExpr("CONST", value=int(value))


def _gdx_slot() -> GDXExpr:
    return GDXExpr("SLOT", name="slot")


def _gdx_macro_call(name: str, arg: GDXExpr) -> GDXExpr:
    return GDXExpr("MACRO", (arg,), name=name)


def _gdx_bin(op: str, a: GDXExpr, b: GDXExpr) -> GDXExpr:
    if op in ("ADD", "MUL", "MAX", "MIN") and gdx_expr_key(b) < gdx_expr_key(a):
        a, b = b, a
    return GDXExpr(op, (a, b))


def gdx_expr_key(e: GDXExpr) -> str:
    if e.op == "FEATURE":
        return f"F:{e.name}"
    if e.op == "CONST":
        return f"C:{e.value}"
    if e.op == "SLOT":
        return "SLOT"
    if e.op == "MACRO":
        return f"{e.name}({gdx_expr_key(e.args[0])})"
    return f"{e.op}({','.join(gdx_expr_key(a) for a in e.args)})"


def gdx_expr_cost(e: GDXExpr) -> int:
    if e.op in ("FEATURE", "CONST", "SLOT"):
        return 1
    return 1 + sum(gdx_expr_cost(a) for a in e.args)


def gdx_expr_eval(e: GDXExpr, obj, macros: Dict[str, GDXMacro],
                 slot_value: Optional[int] = None) -> int:
    if e.op == "FEATURE":
        return gd_object_features(obj).get(e.name, 0)
    if e.op == "CONST":
        return e.value
    if e.op == "SLOT":
        if slot_value is None:
            raise ValueError("slot used without value")
        return int(slot_value)
    if e.op == "MACRO":
        if e.name not in macros:
            raise ValueError(f"unknown macro {e.name}")
        arg = gdx_expr_eval(e.args[0], obj, macros, slot_value)
        return gdx_expr_eval(macros[e.name].body, obj, macros, arg)
    a = gdx_expr_eval(e.args[0], obj, macros, slot_value)
    b = gdx_expr_eval(e.args[1], obj, macros, slot_value)
    if e.op == "ADD":
        return a + b
    if e.op == "SUB":
        return a - b
    if e.op == "MUL":
        return a * b
    if e.op == "MAX":
        return a if a >= b else b
    if e.op == "MIN":
        return a if a <= b else b
    raise ValueError(f"unknown op {e.op}")


def gdx_enumerate_exprs(macros: Dict[str, GDXMacro],
                       max_cost: int,
                       features: Sequence[str] = GDX_FEATURES) -> List[GDXExpr]:
    by_cost: Dict[int, List[GDXExpr]] = {}
    seen: set = set()

    def add(cost: int, expr: GDXExpr) -> None:
        key = gdx_expr_key(expr)
        if cost <= max_cost and key not in seen:
            seen.add(key)
            by_cost.setdefault(cost, []).append(expr)

    for f in features:
        add(1, _gdx_feature(f))
    for c in GDX_CONSTS:
        add(1, _gdx_const(c))

    for cost in range(2, max_cost + 1):
        for mname in sorted(macros):
            for sub_cost, exprs in list(by_cost.items()):
                if 1 + sub_cost == cost:
                    for e in exprs:
                        add(cost, _gdx_macro_call(mname, e))
        for op in GDX_BINARY_OPS:
            for left_cost in range(1, cost):
                right_cost = cost - 1 - left_cost
                if right_cost < 1:
                    continue
                for a in by_cost.get(left_cost, []):
                    for b in by_cost.get(right_cost, []):
                        if op in ("ADD", "MUL", "MAX", "MIN") and gdx_expr_key(b) < gdx_expr_key(a):
                            continue
                        add(cost, _gdx_bin(op, a, b))

    out: List[GDXExpr] = []
    for c in range(1, max_cost + 1):
        out.extend(by_cost.get(c, []))
    return out


def gdx_synthesize(task: GDXTask,
                  macros: Dict[str, GDXMacro],
                  max_cost: int) -> Optional[GDXExpr]:
    exprs = gdx_enumerate_exprs(macros, max_cost)
    best_partial: Optional[Tuple[int, GDXExpr]] = None
    for expr in exprs:
        hits = 0
        ok = True
        for x, y in task.train:
            try:
                got = gdx_expr_eval(expr, x, macros)
            except Exception:
                ok = False
                break
            if got == y:
                hits += 1
            else:
                ok = False
                break
        if ok:
            return expr
        if best_partial is None or hits > best_partial[0]:
            best_partial = (hits, expr)
    return None


def gdx_validates(task: GDXTask, expr: GDXExpr, macros: Dict[str, GDXMacro]) -> bool:
    for x, y in task.holdout:
        try:
            if gdx_expr_eval(expr, x, macros) != y:
                return False
        except Exception:
            return False
    return True


def _gdx_template_from_unary_subtree(e: GDXExpr) -> Optional[GDXExpr]:
    leaves: List[str] = []

    def walk(node: GDXExpr) -> Optional[GDXExpr]:
        if node.op == "FEATURE":
            leaves.append(node.name)
            return _gdx_slot()
        if node.op in ("CONST", "SLOT"):
            return node
        if node.op == "MACRO":
            inner = walk(node.args[0])
            if inner is None:
                return None
            return _gdx_macro_call(node.name, inner)
        if len(node.args) != 2:
            return None
        a = walk(node.args[0])
        b = walk(node.args[1])
        if a is None or b is None:
            return None
        return _gdx_bin(node.op, a, b)

    templ = walk(e)
    if templ is None or len(set(leaves)) != 1:
        return None
    if gdx_expr_cost(templ) < 3:
        return None
    return templ


def _gdx_subexprs(e: GDXExpr) -> Iterable[GDXExpr]:
    yield e
    for a in e.args:
        yield from _gdx_subexprs(a)


def gdx_mine_macros(solved: Dict[str, GDXExpr],
                   existing: Dict[str, GDXMacro],
                   min_support: int = 2,
                   max_new: int = 3) -> List[GDXMacro]:
    supports: Dict[str, List[str]] = {}
    templates: Dict[str, GDXExpr] = {}
    for task_name, expr in solved.items():
        per_task = set()
        for sub in _gdx_subexprs(expr):
            templ = _gdx_template_from_unary_subtree(sub)
            if templ is None:
                continue
            key = gdx_expr_key(templ)
            per_task.add(key)
            templates[key] = templ
        for key in per_task:
            supports.setdefault(key, []).append(task_name)

    existing_keys = {gdx_expr_key(m.body) for m in existing.values()}
    ranked = sorted(
        ((key, tasks) for key, tasks in supports.items()
         if len(tasks) >= min_support and key not in existing_keys),
        key=lambda kv: (-len(kv[1]), gdx_expr_cost(templates[kv[0]]), kv[0]),
    )
    out: List[GDXMacro] = []
    next_id = len(existing)
    for key, tasks in ranked[:max_new]:
        out.append(GDXMacro(f"GM{next_id}", templates[key], tuple(sorted(tasks))))
        next_id += 1
    return out


def _gdx_pairs(inputs: Sequence[object], fn: Callable[[object], int]) -> Tuple[Tuple[object, int], ...]:
    return tuple((x, int(fn(x))) for x in inputs)


def build_gdx_domain_tasks() -> Tuple[List[GDXTask], List[GDXTask], List[GDXTask]]:
    warmup_inputs = {
        "list": ([1, 2, 3], [2, 4], [5], [0, 3, 6]),
        "string": ("a1B", "hello22", "XYZ9", "codex2026"),
        "grid": (
            [[1, 2], [3, 4]],
            [[0], [1], [2]],
            [[5, 6, 7]],
            [[1, 0], [2, 3], [4, 5]],
        ),
        "record": (
            {"a": 1, "b": 2},
            {"x": [2, 3], "y": 4},
            {"items": [1, 1, 1], "tax": 2},
            {"left": 5, "right": 6, "n": 1},
        ),
    }
    holdout_inputs = {
        "list": ([7, 1], [2, 2, 2, 2], [8], [1, 3, 5, 7, 9]),
        "string": ("AI007", "MetaForge5", "rsi", "LONG42x"),
        "grid": (
            [[1], [2], [3], [4]],
            [[1, 2, 3], [4, 5, 6]],
            [[9, 8]],
            [[0, 0, 0], [1, 1, 1], [2, 2, 2]],
        ),
        "record": (
            {"a": 10, "b": -2},
            {"z": [3, 4, 5]},
            {"name": "A12", "v": 5},
            {"p": 2, "q": 3, "r": 4, "s": 5},
        ),
    }

    train: List[GDXTask] = [
        GDXTask("list_sum_square", "list", _gdx_pairs(warmup_inputs["list"], lambda x: gd_object_features(x)["NUM_SUM"] ** 2),
               _gdx_pairs(holdout_inputs["list"], lambda x: gd_object_features(x)["NUM_SUM"] ** 2)),
        GDXTask("string_len_square", "string", _gdx_pairs(warmup_inputs["string"], lambda x: gd_object_features(x)["STR_LEN"] ** 2),
               _gdx_pairs(holdout_inputs["string"], lambda x: gd_object_features(x)["STR_LEN"] ** 2)),
        GDXTask("grid_area_square", "grid", _gdx_pairs(warmup_inputs["grid"], lambda x: gd_object_features(x)["AREA"] ** 2),
               _gdx_pairs(holdout_inputs["grid"], lambda x: gd_object_features(x)["AREA"] ** 2)),
        GDXTask("record_sum_square", "record", _gdx_pairs(warmup_inputs["record"], lambda x: gd_object_features(x)["NUM_SUM"] ** 2),
               _gdx_pairs(holdout_inputs["record"], lambda x: gd_object_features(x)["NUM_SUM"] ** 2)),
        GDXTask("string_digit_square", "string", _gdx_pairs(warmup_inputs["string"], lambda x: gd_object_features(x)["DIGITS"] ** 2),
               _gdx_pairs(holdout_inputs["string"], lambda x: gd_object_features(x)["DIGITS"] ** 2)),
    ]

    frontier_inputs = {
        "list": ([1, 2, 3], [4, 5], [0, 1, 2, 3], [7]),
        "string": ("a1b2", "OpenAI7", "XYZ99", "rsi2026"),
        "grid": (
            [[1, 2], [3, 4]],
            [[1], [2], [3]],
            [[0, 0, 0]],
            [[5, 5], [6, 6], [7, 7]],
        ),
        "record": (
            {"a": 1, "b": 2, "c": 3},
            {"items": [2, 2], "tax": 1},
            {"name": "A12", "score": 4},
            {"x": 5},
        ),
    }
    frontier_holdout = {
        "list": ([3, 3, 3], [8, 1], [2, 4, 6, 8], [0, 0, 5]),
        "string": ("K2", "Data123", "abc", "WARM77"),
        "grid": (
            [[9], [8], [7], [6]],
            [[1, 2, 3], [4, 5, 6]],
            [[0, 0]],
            [[1, 1], [2, 2]],
        ),
        "record": (
            {"a": 10, "b": -1},
            {"q": [3, 3, 3], "r": 1},
            {"label": "B7", "n": 2},
            {"x": 1, "y": 2, "z": 3},
        ),
    }

    frontier: List[GDXTask] = [
        GDXTask("list_sum_plus_size_square", "list",
               _gdx_pairs(frontier_inputs["list"], lambda x: (gd_object_features(x)["NUM_SUM"] + gd_object_features(x)["SIZE"]) ** 2),
               _gdx_pairs(frontier_holdout["list"], lambda x: (gd_object_features(x)["NUM_SUM"] + gd_object_features(x)["SIZE"]) ** 2)),
        GDXTask("string_len_plus_digits_square", "string",
               _gdx_pairs(frontier_inputs["string"], lambda x: (gd_object_features(x)["STR_LEN"] + gd_object_features(x)["DIGITS"]) ** 2),
               _gdx_pairs(frontier_holdout["string"], lambda x: (gd_object_features(x)["STR_LEN"] + gd_object_features(x)["DIGITS"]) ** 2)),
        GDXTask("grid_rows_plus_cols_square", "grid",
               _gdx_pairs(frontier_inputs["grid"], lambda x: (gd_object_features(x)["ROWS"] + gd_object_features(x)["COLS"]) ** 2),
               _gdx_pairs(frontier_holdout["grid"], lambda x: (gd_object_features(x)["ROWS"] + gd_object_features(x)["COLS"]) ** 2)),
        GDXTask("record_sum_plus_fields_square", "record",
               _gdx_pairs(frontier_inputs["record"], lambda x: (gd_object_features(x)["NUM_SUM"] + gd_object_features(x)["FIELDS"]) ** 2),
               _gdx_pairs(frontier_holdout["record"], lambda x: (gd_object_features(x)["NUM_SUM"] + gd_object_features(x)["FIELDS"]) ** 2)),
        GDXTask("list_sum_fourth", "list",
               _gdx_pairs(frontier_inputs["list"], lambda x: gd_object_features(x)["NUM_SUM"] ** 4),
               _gdx_pairs(frontier_holdout["list"], lambda x: gd_object_features(x)["NUM_SUM"] ** 4)),
        GDXTask("string_len_fourth", "string",
               _gdx_pairs(frontier_inputs["string"], lambda x: gd_object_features(x)["STR_LEN"] ** 4),
               _gdx_pairs(frontier_holdout["string"], lambda x: gd_object_features(x)["STR_LEN"] ** 4)),
        GDXTask("grid_area_fourth", "grid",
               _gdx_pairs(frontier_inputs["grid"], lambda x: gd_object_features(x)["AREA"] ** 4),
               _gdx_pairs(frontier_holdout["grid"], lambda x: gd_object_features(x)["AREA"] ** 4)),
        GDXTask("record_sum_fourth", "record",
               _gdx_pairs(frontier_inputs["record"], lambda x: gd_object_features(x)["NUM_SUM"] ** 4),
               _gdx_pairs(frontier_holdout["record"], lambda x: gd_object_features(x)["NUM_SUM"] ** 4)),
    ]

    unsupported: List[GDXTask] = [
        GDXTask("string_contains_ai", "semantic_text",
               _gdx_pairs(("AI lab", "plain", "OpenAI", "rsi"), lambda x: 1 if "AI" in x else 0),
               _gdx_pairs(("Nope", "AI", "machine", "AIM"), lambda x: 1 if "AI" in x else 0)),
        GDXTask("grid_diagonal_sum", "spatial_relation",
               _gdx_pairs(([[1, 2], [3, 4]], [[5]], [[1, 0], [0, 1]], [[2, 3, 4], [5, 6, 7]]),
                         lambda x: sum(x[i][i] for i in range(min(len(x), len(x[0]))))),
               _gdx_pairs(([[9, 8], [7, 6]], [[1, 2, 3]], [[1], [2], [3]], [[0, 1], [2, 3]]),
                         lambda x: sum(x[i][i] for i in range(min(len(x), len(x[0])))))),
    ]
    return train, frontier, unsupported


def gdx_solve_tasks(tasks: Sequence[GDXTask],
                   macros: Dict[str, GDXMacro],
                   max_cost: int) -> Dict[str, object]:
    rows = []
    solved: Dict[str, GDXExpr] = {}
    for task in tasks:
        expr = gdx_synthesize(task, macros, max_cost)
        valid = bool(expr is not None and gdx_validates(task, expr, macros))
        if valid and expr is not None:
            solved[task.name] = expr
        rows.append({
            "name": task.name,
            "domain": task.domain,
            "validated": valid,
            "expr": gdx_expr_key(expr) if expr is not None else "",
        })
    return {
        "validated": sum(1 for r in rows if r["validated"]),
        "total": len(rows),
        "rows": rows,
        "solved_exprs": solved,
    }


