# =========================================================================== #
# 23. CONTINUOUS FUNCTIONAL SUBSTRATE (CFS): the measured core of            #
#     "computation as interference on manifolds, replacing token code"       #
#                                                                             #
# The radical claim under test, taken seriously: drop the token grammar      #
# entirely. A candidate program IS a real vector v; its behavior is          #
# f_v(xs) = round(<v, phi(xs)>) for a fixed feature map phi; synthesis is    #
# continuous geometry -- superposition crossover, resonance toward elites,   #
# and DESTRUCTIVE INTERFERENCE that projects out the accumulated failure     #
# direction. No tokens, no mutation, no discrete grammar anywhere in the     #
# search.                                                                     #
#                                                                             #
# The counter-thesis, also under test: every executable substrate has a      #
# decoder, the decoder is designer-written code, and the reachable class is  #
# exactly image(decode). If walls reappear at span(phi)'s boundary, the      #
# grammar did not disappear -- it migrated into phi.                         #
#                                                                             #
# Unique to the continuous substrate: least squares gives a CLOSED-FORM      #
# in-principle ceiling. ridge-fit on the train pairs tells us whether a      #
# train-exact vector exists AT ALL, separating search failure from class    #
# failure -- something the discrete forge could never certify cheaply.       #
# Sealed holdout/cf gates remain the only judge of semantics, unchanged.     #
# =========================================================================== #

CFS_DIM_NAMES: Tuple[str, ...] = (
    "len", "sum", "max", "min", "first", "last", "sum_sq", "sum_idx",
    "sum_i_xi", "ascents", "descents", "plateaus",
    "cnt_gt0", "cnt_gt1", "cnt_gt2", "cnt_gt3", "cnt_gt4", "cnt_gt5",
    "cnt_gt6", "cnt_gt7",
    "sumgt0", "sumgt2", "sumgt4", "sumgt6", "range", "parity_sum",
)
CFS_D = len(CFS_DIM_NAMES)
CFS_OUT_CAP = 10 ** 9


def cfs_phi(xs: Sequence[int]) -> List[float]:
    """Fixed feature map. Generic aggregations only; no task-shaped
    features (no first-index-of-max, no longest-run). This vocabulary IS
    the substrate's grammar, and it is a designer act -- declared."""
    n = len(xs)
    if n == 0:
        base = {nm: 0.0 for nm in CFS_DIM_NAMES}
        base["len"] = 0.0
        return [base[nm] for nm in CFS_DIM_NAMES]
    asc = sum(1 for i in range(1, n) if xs[i] > xs[i - 1])
    dsc = sum(1 for i in range(1, n) if xs[i] < xs[i - 1])
    plt = sum(1 for i in range(1, n) if xs[i] == xs[i - 1])
    vals = {
        "len": float(n), "sum": float(sum(xs)), "max": float(max(xs)),
        "min": float(min(xs)), "first": float(xs[0]), "last": float(xs[-1]),
        "sum_sq": float(sum(x * x for x in xs)),
        "sum_idx": float(sum(range(n))),
        "sum_i_xi": float(sum(i * x for i, x in enumerate(xs))),
        "ascents": float(asc), "descents": float(dsc),
        "plateaus": float(plt),
        "range": float(max(xs) - min(xs)),
        "parity_sum": float(sum(xs) % 2),
    }
    for t in range(8):
        vals[f"cnt_gt{t}"] = float(sum(1 for x in xs if x > t))
    for t in (0, 2, 4, 6):
        vals[f"sumgt{t}"] = float(sum(x for x in xs if x > t))
    return [vals[nm] for nm in CFS_DIM_NAMES]


def cfs_decode(v: Sequence[float]) -> Callable[[List[int]], int]:
    def fn(xs: List[int]) -> int:
        s = 0.0
        for a, b in zip(v, cfs_phi(xs)):
            s += a * b
        if s != s or abs(s) > CFS_OUT_CAP:
            raise VMCrash("cfs overflow")
        return int(round(s))
    return fn


def cfs_score(v: Sequence[float],
              pairs: Sequence[Tuple[Tuple[int, ...], int]]) -> float:
    fn = cfs_decode(v)
    hits = 0
    for xs, y in pairs:
        try:
            if fn(list(xs)) == y:
                hits += 1
        except VMCrash:
            pass
    return hits / len(pairs)


def cfs_ridge_fit(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                  lam: float = 1e-6) -> List[float]:
    """Closed-form ridge regression via Gaussian elimination: the
    in-principle ceiling of the substrate. If even this cannot reach
    train-exact after rounding, no vector can -- a class failure, not a
    search failure."""
    A = [cfs_phi(xs) for xs, _y in pairs]
    y = [float(_y) for _xs, _y in pairs]
    d = CFS_D
    M = [[lam if i == j else 0.0 for j in range(d)] for i in range(d)]
    b = [0.0] * d
    for row, yv in zip(A, y):
        for i in range(d):
            if row[i] == 0.0:
                continue
            b[i] += row[i] * yv
            for j in range(d):
                M[i][j] += row[i] * row[j]
    for col in range(d):                      # gaussian elimination
        piv = max(range(col, d), key=lambda r: abs(M[r][col]))
        if abs(M[piv][col]) < 1e-12:
            continue
        M[col], M[piv] = M[piv], M[col]
        b[col], b[piv] = b[piv], b[col]
        inv = 1.0 / M[col][col]
        for r in range(d):
            if r == col:
                continue
            f = M[r][col] * inv
            if f == 0.0:
                continue
            for j in range(col, d):
                M[r][j] -= f * M[col][j]
            b[r] -= f * b[col]
    out = [0.0] * d
    for i in range(d):
        out[i] = b[i] / M[i][i] if abs(M[i][i]) > 1e-12 else 0.0
    return out


def _cfs_fit_support(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                     support: Sequence[int]) -> List[float]:
    """Ridge fit restricted to a feature support; zeros elsewhere."""
    full = cfs_ridge_fit([(xs, y) for xs, y in pairs]) if not support \
        else None
    if full is not None:
        return full
    A = [[cfs_phi(xs)[j] for j in support] for xs, _y in pairs]
    y = [float(_y) for _xs, _y in pairs]
    d = len(support)
    lam = 1e-6
    M = [[lam if i == j else 0.0 for j in range(d)] for i in range(d)]
    b = [0.0] * d
    for row, yv in zip(A, y):
        for i in range(d):
            if row[i] == 0.0:
                continue
            b[i] += row[i] * yv
            for j in range(d):
                M[i][j] += row[i] * row[j]
    for col in range(d):
        piv = max(range(col, d), key=lambda r: abs(M[r][col]))
        if abs(M[piv][col]) < 1e-12:
            continue
        M[col], M[piv] = M[piv], M[col]
        b[col], b[piv] = b[piv], b[col]
        inv = 1.0 / M[col][col]
        for r in range(d):
            if r == col:
                continue
            f = M[r][col] * inv
            if f == 0.0:
                continue
            for j in range(col, d):
                M[r][j] -= f * M[col][j]
            b[r] -= f * b[col]
    out = [0.0] * CFS_D
    for k, j in enumerate(support):
        out[j] = b[k] / M[k][k] if abs(M[k][k]) > 1e-12 else 0.0
    return out


def cfs_sparsify(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                 v0: Sequence[float]
                 ) -> Tuple[List[float], List[str]]:
    """Continuous MDL: among the infinitely many train-exact vectors,
    prefer minimal support. Greedy backward elimination: repeatedly drop
    the smallest-coefficient feature whose removal (after exact refit on
    the remaining support) preserves train-exactness."""
    support = [j for j in range(CFS_D) if abs(v0[j]) > 1e-9]
    v = list(v0)
    if cfs_score(v, pairs) < 1.0:
        return v, [CFS_DIM_NAMES[j] for j in support]
    changed = True
    while changed and len(support) > 1:
        changed = False
        order = sorted(support, key=lambda j: abs(v[j]))
        for j in order:
            cand_support = [k for k in support if k != j]
            cand = _cfs_fit_support(pairs, cand_support)
            if cfs_score(cand, pairs) >= 1.0:
                support = cand_support
                v = cand
                changed = True
                break
    return v, [CFS_DIM_NAMES[j] for j in sorted(support)]


def cfs_synthesize(pairs: Sequence[Tuple[Tuple[int, ...], int]],
                   seed: int, steps: int = 3000, pop: int = 24,
                   interference: bool = True) -> Dict[str, object]:
    """Pure geometric search. Operators: superposition crossover,
    resonance toward the elite, gaussian jitter, and (when enabled)
    destructive interference -- projecting out the bundled direction of
    zero-scoring vectors. No tokens, no oracle, no gate access."""
    rng = random.Random(seed * 9176 + 5)
    def _exact_and_smooth(v: Sequence[float]) -> Tuple[float, float]:
        fn = cfs_decode(v)
        hits = 0
        sq = 0.0
        for xs, y in pairs:
            try:
                got = fn(list(xs))
            except VMCrash:
                sq += 1e6
                continue
            hits += 1 if got == y else 0
            sq += float((got - y) * (got - y))
        return hits / len(pairs), 1.0 / (1.0 + sq)

    P = [[rng.gauss(0.0, 0.4) for _ in range(CFS_D)] for _ in range(pop)]
    SS = [_exact_and_smooth(v) for v in P]
    S = [e for e, _m in SS]
    SM = [m for _e, m in SS]
    evals = pop
    fail_bundle = [0.0] * CFS_D
    fail_n = 0
    interfered = 0
    best_i = max(range(pop), key=lambda i: S[i])
    for step in range(steps):
        i = rng.randrange(pop)
        op = rng.random()
        a = P[i]
        if op < 0.35:
            j = rng.randrange(pop)
            lam = rng.random()
            cand = [lam * x + (1 - lam) * y for x, y in zip(a, P[j])]
        elif op < 0.70:
            eta = 0.3 * rng.random()
            cand = [x + eta * (bx - x) + rng.gauss(0, 0.05)
                    for x, bx in zip(a, P[best_i])]
        else:
            cand = [x + rng.gauss(0, 0.15) for x in a]
        if interference and fail_n >= 10:
            nrm = math.sqrt(sum(f * f for f in fail_bundle)) or 1.0
            fh = [f / nrm for f in fail_bundle]
            dot = sum(c * f for c, f in zip(cand, fh))
            if abs(dot) > 0.2:
                cand = [c - dot * f for c, f in zip(cand, fh)]
                interfered += 1
        sc, sm = _exact_and_smooth(cand)
        evals += 1
        if sc == 0.0:
            nrm = math.sqrt(sum(c * c for c in cand)) or 1.0
            for k in range(CFS_D):
                fail_bundle[k] += cand[k] / nrm
            fail_n += 1
        if (sc, sm) >= (S[i], SM[i]):
            P[i], S[i], SM[i] = cand, sc, sm
            if (sc, sm) > (S[best_i], SM[best_i]):
                best_i = i
        if S[best_i] >= 1.0:
            return {"found": True, "v": P[best_i], "score": 1.0,
                    "evals": evals, "steps": step + 1,
                    "interfered": interfered, "fail_n": fail_n}
    return {"found": S[best_i] >= 1.0, "v": P[best_i],
            "score": round(S[best_i], 4), "evals": evals, "steps": steps,
            "interfered": interfered, "fail_n": fail_n}


# --------------------------------------------------------------------------
# Capability propagation ledger (the honest core of "substrate flipping")
# with deterministic cascade revocation (the honest core of "rollback").
# --------------------------------------------------------------------------
PROPAGATION_LEDGER: List[Dict[str, str]] = []


def propagate_capability(name: str, fn: Callable[[Sequence[int]], int]
                         ) -> None:
    """Register a gate-adopted primitive (forged fold spec or CFS vector,
    via a numeric closure) as a general-domain feature atom, recording the
    act in the ledger so revocation can cascade."""
    key = f"F:{name}"
    GD_EXTRA_FEATURES[key] = fn
    PROPAGATION_LEDGER.append({"kind": "gd_feature", "key": key,
                               "name": name})


def revoke_propagated() -> int:
    n = 0
    for entry in list(PROPAGATION_LEDGER):
        if entry["kind"] == "gd_feature":
            GD_EXTRA_FEATURES.pop(entry["key"], None)
            n += 1
        PROPAGATION_LEDGER.remove(entry)
    return n


# --------------------------------------------------------------------------
# Battery: walls + median through the continuous substrate, with the
# least-squares ceiling, an interference ablation, and sealed gates.
# --------------------------------------------------------------------------
def cfs_battery() -> Dict[str, object]:
    print("=" * 88)
    print("CONTINUOUS FUNCTIONAL SUBSTRATE BATTERY (programs as vectors,"
          " synthesis as geometry)")
    print("=" * 88)
    tasks = {t.tid: t for t in build_sealed_tasks()
             if t.tid in ("T29", "T30", "T31", "T32")}
    rows = []
    print("\n[C1] walls: geometric search + closed-form ceiling + sealed"
          " gates")
    for tid in ("T29", "T30", "T31", "T32"):
        task = tasks[tid]
        res = cfs_synthesize(task.train_pairs, seed=SEED + 700 + int(tid[1:]))
        vfit = cfs_ridge_fit(task.train_pairs)
        fit_exact = cfs_score(vfit, task.train_pairs) >= 1.0
        support: List[str] = []
        if res["found"]:
            best_v, support = cfs_sparsify(task.train_pairs, res["v"])
        elif fit_exact:
            best_v, support = cfs_sparsify(task.train_pairs, vfit)
        else:
            best_v = res["v"]
        train_ok = cfs_score(best_v, task.train_pairs) >= 1.0
        gates = False
        if train_ok:
            fn = cfs_decode(best_v)
            gates = bool(task.holdout_gate(fn) and task.cf_gate(fn))
        row = {"tid": tid, "search_found": bool(res["found"]),
               "search_score": res["score"], "evals": res["evals"],
               "interfered": res["interfered"], "fail_n": res["fail_n"],
               "fit_exact": bool(fit_exact), "train_exact": bool(train_ok),
               "gates": bool(gates), "support": support}
        rows.append(row)
        print(f"  {tid} search={row['search_found']}"
              f" (score {row['search_score']})"
              f" lstsq_ceiling_exact={row['fit_exact']}"
              f" gates={row['gates']}"
              f" support={row['support']}")
    gated = [r["tid"] for r in rows if r["gates"]]
    fitted_not_gated = [r["tid"] for r in rows
                        if r["train_exact"] and not r["gates"]]
    print(f"  totals: sealed-gate adopted {len(gated)}/4 {gated};"
          f" train-exact-but-rejected {fitted_not_gated}")
    print("  <- where train-exact vectors exist but every one fails the"
          " sealed gates, the wall sits at span(phi): the grammar did not"
          " disappear, it migrated into the decoder.")
    rng = random.Random(SEED * 31 + 7)
    med_pairs = []
    for L in TRAIN_LENGTHS:
        for _ in range(5):
            xs = tuple(rng.randint(0, 7) for _ in range(L))
            med_pairs.append((xs, sorted(xs)[len(xs) // 2]))
    mfit = cfs_ridge_fit(med_pairs)
    m_exact = cfs_score(mfit, med_pairs) >= 1.0
    print(f"\n[C2] median probe: lstsq train-exact={m_exact}"
          f" (continuous ceiling, no search needed)")
    print("\n[C3] interference ablation on T29 (same seed)")
    on = cfs_synthesize(tasks["T29"].train_pairs, seed=SEED + 729,
                        interference=True)
    off = cfs_synthesize(tasks["T29"].train_pairs, seed=SEED + 729,
                         interference=False)
    print(f"  ON : found={on['found']} steps={on['steps']}"
          f" interfered={on['interfered']}")
    print(f"  OFF: found={off['found']} steps={off['steps']}")
    print("\n[C4] propagation ledger + cascade revocation")
    n_before = len(GD_EXTRA_FEATURES)
    if gated:
        tid = gated[0]
        row_v = next(r for r in rows if r["tid"] == tid)
        # re-derive the adopted vector deterministically for the closure
        vv, _sup = cfs_sparsify(
            tasks[tid].train_pairs,
            cfs_ridge_fit(tasks[tid].train_pairs))
        propagate_capability(f"CFS_{tid}",
                             lambda xs, _v=tuple(vv):
                             cfs_decode(list(_v))(list(xs)))
        n_mid = len(GD_EXTRA_FEATURES)
        n_rev = revoke_propagated()
        print(f"  propagated CFS_{tid}: features {n_before}->{n_mid},"
              f" cascade revoked {n_rev} -> {len(GD_EXTRA_FEATURES)}")
    rep = {"rows": rows, "gated": gated,
           "train_exact_but_rejected": fitted_not_gated,
           "median_fit_exact": bool(m_exact),
           "ablation": {"on_steps": on["steps"], "off_steps": off["steps"],
                        "on_found": bool(on["found"]),
                        "off_found": bool(off["found"]),
                        "interfered": on["interfered"]},
           "ledger_clean": len(PROPAGATION_LEDGER) == 0}
    with open("cfs_results.json", "w") as f:
        json.dump(rep, f, sort_keys=True)
    print("\nreading: the substrate has no tokens anywhere, yet its"
          " reachable class is exactly image(decode); sealed gates stay"
          " the judge; interference and the closed-form ceiling are"
          " measured, not asserted.")
    return rep


# --------------------------------------------------------------------------
# Section 23 tests.
# --------------------------------------------------------------------------
def test_cfs_decoder_total_deterministic() -> None:
    v = [0.1 * i for i in range(CFS_D)]
    fn = cfs_decode(v)
    a = [fn([1, 2, 3]), fn([]), fn([7] * 34)]
    b = [fn([1, 2, 3]), fn([]), fn([7] * 34)]
    _assert(a == b, "cfs decoder nondeterministic")
    _assert(all(isinstance(x, int) for x in a), "cfs decoder not total")
    p1 = cfs_phi([0, 5, 2])
    p2 = cfs_phi([0, 5, 2])
    _assert(p1 == p2 and len(p1) == CFS_D, "phi inconsistent")


def test_cfs_search_oracle_free_and_interference_bookkeeping() -> None:
    import inspect
    src = (inspect.getsource(cfs_synthesize) + inspect.getsource(cfs_score)
           + inspect.getsource(cfs_ridge_fit) + inspect.getsource(cfs_phi))
    for banned in ("holdout_gate", "cf_gate", "hidden_expected",
                   "HOLDOUT_LENGTHS", "fw_sealed"):
        _assert(banned not in src, f"cfs search references {banned}")
    pairs = [((1, 2, 3), 6), ((2, 2), 4), ((5,), 5), ((0, 0, 7), 7),
             ((3, 1), 4), ((1, 1, 1, 1), 4)]
    res = cfs_synthesize(pairs, seed=SEED + 41, steps=1200)
    _assert(res["evals"] > 0 and res["fail_n"] >= 0
            and res["interfered"] >= 0, "interference bookkeeping broken")
    _assert(res["score"] > 0.0, "geometric search made no progress at all")
    # the closed-form ceiling is the certifying half of the substrate
    w = cfs_ridge_fit(pairs)
    _assert(cfs_score(w, pairs) >= 1.0,
            "least-squares ceiling cannot reach the sum task")
    r2 = cfs_synthesize(pairs, seed=SEED + 41, steps=1200)
    _assert(res["score"] == r2["score"] and res["steps"] == r2["steps"],
            "cfs search nondeterministic")


def test_cfs_results_walls_and_propagation() -> None:
    _assert(os.path.exists("cfs_results.json"),
            "cfs artifact missing; run --mode cfs-battery first")
    with open("cfs_results.json") as f:
        rep = json.load(f)
    by = {r["tid"]: r for r in rep["rows"]}
    _assert(by["T29"]["gates"] is True,
            "T29 (in-span by construction) failed sealed gates on CFS")
    for tid in ("T30", "T31", "T32"):
        r = by[tid]
        if not r["gates"]:
            _assert(r["fit_exact"] or not r["search_found"],
                    f"{tid} bookkeeping inconsistent: {r}")
    _assert(all(isinstance(r.get("support"), list) for r in rep["rows"]),
            "named supports missing")
    _assert(rep["median_fit_exact"] in (True, False), "median probe absent")
    _assert(rep["ledger_clean"] is True, "propagation ledger not cascaded")
    _assert(rep["ablation"]["on_found"] in (True, False),
            "ablation missing")


TESTS.extend([
    test_cfs_decoder_total_deterministic,
    test_cfs_search_oracle_free_and_interference_bookkeeping,
    test_cfs_results_walls_and_propagation,
])


# =========================================================================== #
# 24. EXPANSION RULES: self-extending quest, dynamic capacity, speculative   #
#     adoption -- each compiled to a measurement, each fenced by the gates.   #
#                                                                             #
# Rule 1 (infinite quest generator): the previous section proved the wall    #
# at T30/T32 is a span(phi) deficiency -- a representational gap, not a       #
# search gap. So the honest "generate harder problems for yourself" is: mine #
# the residue of what span(phi) CANNOT express, synthesize a NEW feature      #
# dimension that closes it, and quiz the system on a fresh holdout. The       #
# system extends its own substrate vocabulary from its own failures.         #
#                                                                             #
# Rule 2 (dynamic capacity): capacity limits (feature dimension here, the    #
# direct analogue of MAX_MACROS / network width) grow ONLY when stagnation   #
# is detected AND the growth is justified by passing the sealed gates. Width #
# is spent to cross a measured wall, never inflated for its own sake.         #
#                                                                             #
# Rule 3 (speculative adoption + rollback): the steel core of "adopt on      #
# reasonable probability, roll back on failure" -- WITHOUT weakening the      #
# gates, because median_of_list is the standing proof that train-likelihood  #
# is not semantics. A speculative candidate is provisionally installed in a  #
# scratch ledger and MEASURED; the sealed holdout+cf gates remain the sole   #
# arbiter of permanent adoption; rejected speculations cascade-roll-back to  #
# the last certified state, leaving no residue. Boldness lives in front of   #
# the gate, never inside it.                                                  #
# =========================================================================== #

# --------------------------------------------------------------------------
# Rule 1: self-extending feature vocabulary from span(phi) residues.
# --------------------------------------------------------------------------
def quest_candidate_features() -> Dict[str, Callable[[Sequence[int]],
                                                     float]]:
    """A bank of NEW candidate dimensions outside the base phi vocabulary.
    These are still a designer-declared library (honesty boundary intact);
    Rule 1's autonomy is in SELECTING and INSTALLING from failure residue,
    parameterized by what the residue shows -- not in authoring the kinds.
    Several are exactly the position/run primitives whose absence the base
    phi made into a wall (argmax index, longest ascending run)."""
    def _argmax_index(xs):
        if not xs:
            return 0.0
        best, bi = xs[0], 0
        for i, x in enumerate(xs):
            if x > best:
                best, bi = x, i
        return float(bi)

    def _argmin_index(xs):
        if not xs:
            return 0.0
        best, bi = xs[0], 0
        for i, x in enumerate(xs):
            if x < best:
                best, bi = x, i
        return float(bi)

    def _longest_asc_run(xs):
        if not xs:
            return 0.0
        best = run = 1
        for i in range(1, len(xs)):
            run = run + 1 if xs[i] > xs[i - 1] else 1
            best = max(best, run)
        return float(best)

    def _longest_eq_run(xs):
        if not xs:
            return 0.0
        best = run = 1
        for i in range(1, len(xs)):
            run = run + 1 if xs[i] == xs[i - 1] else 1
            best = max(best, run)
        return float(best)

    def _first_ascent_index(xs):
        for i in range(1, len(xs)):
            if xs[i] > xs[i - 1]:
                return float(i)
        return -1.0

    def _idx_last_max(xs):
        if not xs:
            return 0.0
        best, bi = xs[0], 0
        for i, x in enumerate(xs):
            if x >= best:
                best, bi = x, i
        return float(bi)

    return {"argmax_index": _argmax_index, "argmin_index": _argmin_index,
            "longest_asc_run": _longest_asc_run,
            "longest_eq_run": _longest_eq_run,
            "first_ascent_index": _first_ascent_index,
            "idx_last_max": _idx_last_max}


def quest_phi_extended(extra_names: Sequence[str]
                       ) -> Callable[[Sequence[int]], List[float]]:
    bank = quest_candidate_features()

    def phi_ext(xs: Sequence[int]) -> List[float]:
        base = cfs_phi(xs)
        return base + [bank[nm](xs) for nm in extra_names]
    return phi_ext


def quest_fit_with_phi(pairs, phi: Callable[[Sequence[int]], List[float]],
                       lam: float = 1e-6) -> Tuple[List[float], float]:
    """Ridge fit + train-exact score under an arbitrary feature map."""
    A = [phi(xs) for xs, _y in pairs]
    y = [float(_y) for _xs, _y in pairs]
    d = len(A[0])
    M = [[lam if i == j else 0.0 for j in range(d)] for i in range(d)]
    b = [0.0] * d
    for row, yv in zip(A, y):
        for i in range(d):
            if row[i] == 0.0:
                continue
            b[i] += row[i] * yv
            for j in range(d):
                M[i][j] += row[i] * row[j]
    for col in range(d):
        piv = max(range(col, d), key=lambda r: abs(M[r][col]))
        if abs(M[piv][col]) < 1e-12:
            continue
        M[col], M[piv] = M[piv], M[col]
        b[col], b[piv] = b[piv], b[col]
        inv = 1.0 / M[col][col]
        for r in range(d):
            if r == col:
                continue
            f = M[r][col] * inv
            if f == 0.0:
                continue
            for j in range(col, d):
                M[r][j] -= f * M[col][j]
            b[r] -= f * b[col]
    w = [b[i] / M[i][i] if abs(M[i][i]) > 1e-12 else 0.0 for i in range(d)]

    def fn(xs):
        s = sum(a * p for a, p in zip(w, phi(xs)))
        if s != s or abs(s) > CFS_OUT_CAP:
            raise VMCrash("ext overflow")
        return int(round(s))
    hits = 0
    for xs, yv in pairs:
        try:
            hits += 1 if fn(list(xs)) == yv else 0
        except VMCrash:
            pass
    return w, hits / len(pairs)


def quest_sparsify_ext(pairs, phi: Callable[[Sequence[int]], List[float]]
                       ) -> Tuple[List[float], List[int], float]:
    """Continuous MDL in the EXTENDED feature space. Among train-exact
    weight vectors, drive toward minimal support so the surviving
    dimensions carry real structure rather than train coincidence -- this
    is what buys sealed-gate generalization (cnt_gt3 for T29, etc.)."""
    d = len(phi([0]))

    def fit(support):
        A = [[phi(xs)[j] for j in support] for xs, _y in pairs]
        y = [float(_y) for _xs, _y in pairs]
        n = len(support)
        lam = 1e-6
        M = [[lam if i == j else 0.0 for j in range(n)] for i in range(n)]
        b = [0.0] * n
        for row, yv in zip(A, y):
            for i in range(n):
                if row[i] == 0.0:
                    continue
                b[i] += row[i] * yv
                for j in range(n):
                    M[i][j] += row[i] * row[j]
        for col in range(n):
            piv = max(range(col, n), key=lambda r: abs(M[r][col]))
            if abs(M[piv][col]) < 1e-12:
                continue
            M[col], M[piv] = M[piv], M[col]
            b[col], b[piv] = b[piv], b[col]
            inv = 1.0 / M[col][col]
            for r in range(n):
                if r == col:
                    continue
                f = M[r][col] * inv
                if f == 0.0:
                    continue
                for j in range(col, n):
                    M[r][j] -= f * M[col][j]
                b[r] -= f * b[col]
        w = [0.0] * d
        for k, j in enumerate(support):
            w[j] = b[k] / M[k][k] if abs(M[k][k]) > 1e-12 else 0.0
        return w

    def score(w):
        hits = 0
        for xs, yv in pairs:
            s = sum(a * p for a, p in zip(w, phi(xs)))
            if s == s and abs(s) <= CFS_OUT_CAP and int(round(s)) == yv:
                hits += 1
        return hits / len(pairs)

    support = list(range(d))
    w = fit(support)
    if score(w) < 1.0:
        return w, support, score(w)
    changed = True
    while changed and len(support) > 1:
        changed = False
        order = sorted(support, key=lambda j: abs(w[j]))
        for j in order:
            cand_sup = [k for k in support if k != j]
            cw = fit(cand_sup)
            if score(cw) >= 1.0:
                support, w = cand_sup, cw
                changed = True
                break
    return w, support, 1.0


def quest_extend_until_expressive(task, max_new: int = 2) -> Dict[str,
                                                                  object]:
    """Rule 1 + Rule 2 fused. Detect the span(phi) wall (base map gives a
    train-exact fit that still fails the sealed gates), then GROW the
    feature dimension one residue-selected atom at a time until the sealed
    gates pass on a vector that is train-exact -- or give up honestly. Each
    added dimension is a capacity increase justified only by gate passage."""
    base_w0 = cfs_ridge_fit(task.train_pairs)
    base_w, _bsup = cfs_sparsify(task.train_pairs, base_w0)
    base_fn = cfs_decode(base_w)
    base_train = cfs_score(base_w, task.train_pairs) >= 1.0
    base_gates = bool(base_train and task.holdout_gate(base_fn)
                      and task.cf_gate(base_fn))
    trace = [{"dim": CFS_D, "added": None, "train_exact": base_train,
              "gates": base_gates}]
    if base_gates:
        return {"tid": task.tid, "needed_extension": False,
                "added": [], "final_gates": True, "final_dim": CFS_D,
                "trace": trace}
    bank = list(quest_candidate_features().keys())
    added: List[str] = []
    for _ in range(max_new):
        best_choice = None
        for nm in bank:
            if nm in added:
                continue
            phi = quest_phi_extended(added + [nm])
            w, _sup, tr = quest_sparsify_ext(task.train_pairs, phi)
            if tr < 1.0:
                continue

            def fn(xs, _w=w, _phi=phi):
                s = sum(a * p for a, p in zip(_w, _phi(xs)))
                if s != s or abs(s) > CFS_OUT_CAP:
                    raise VMCrash("ext overflow")
                return int(round(s))
            g = bool(task.holdout_gate(fn) and task.cf_gate(fn))
            if g:
                best_choice = (nm, True)
                break
            if best_choice is None:
                best_choice = (nm, False)
        if best_choice is None:
            break
        nm, g = best_choice
        added.append(nm)
        trace.append({"dim": CFS_D + len(added), "added": nm,
                      "train_exact": True, "gates": g})
        if g:
            return {"tid": task.tid, "needed_extension": True,
                    "added": added, "final_gates": True,
                    "final_dim": CFS_D + len(added), "trace": trace}
    return {"tid": task.tid, "needed_extension": True, "added": added,
            "final_gates": False, "final_dim": CFS_D + len(added),
            "trace": trace}


# --------------------------------------------------------------------------
# Rule 3: double-ledger speculative adoption with cascade rollback.
# --------------------------------------------------------------------------
@dataclass
class SpeculativeLedger:
    certified: Dict[str, object] = field(default_factory=dict)
    scratch: Dict[str, object] = field(default_factory=dict)
    history: List[Dict[str, object]] = field(default_factory=list)

    def speculate(self, name: str, payload: object) -> None:
        """Provisionally install into scratch only. Nothing certified is
        touched until the gate decides."""
        self.scratch[name] = payload

    def finalize(self, name: str, gate_pass: bool) -> str:
        if gate_pass:
            self.certified[name] = self.scratch.pop(name)
            self.history.append({"name": name, "status": "adopted"})
            return "adopted"
        self.scratch.pop(name, None)
        self.history.append({"name": name, "status": "rolled_back"})
        return "rolled_back"

    def rollback_all_scratch(self) -> int:
        n = len(self.scratch)
        for nm in list(self.scratch):
            self.history.append({"name": nm, "status": "rolled_back"})
        self.scratch.clear()
        return n

    def checkpoint(self) -> Dict[str, object]:
        return dict(self.certified)

    def restore(self, ckpt: Dict[str, object]) -> None:
        self.certified = dict(ckpt)
        self.scratch.clear()


def speculative_round(ledger: SpeculativeLedger, task,
                      candidates: Sequence[Tuple[str, List[float],
                                                 Callable]]
                      ) -> Dict[str, object]:
    """Take bold candidates (even train-only fits), MEASURE each behind the
    sealed gates, adopt the passers, roll back the rest. The gate is never
    bypassed; speculation only decides what gets measured."""
    ckpt = ledger.checkpoint()
    decided = []
    for name, _w, fn in candidates:
        ledger.speculate(name, _w)
        gate_pass = bool(task.holdout_gate(fn) and task.cf_gate(fn))
        status = ledger.finalize(name, gate_pass)
        decided.append({"name": name, "status": status,
                        "gate_pass": gate_pass})
    residue = ledger.rollback_all_scratch()
    return {"decided": decided, "scratch_residue_after": residue,
            "certified_count": len(ledger.certified),
            "checkpoint_consistent": set(ckpt).issubset(
                set(ledger.certified))}


# --------------------------------------------------------------------------
# Battery for Section 24.
# --------------------------------------------------------------------------
def expansion_battery() -> Dict[str, object]:
    print("=" * 88)
    print("EXPANSION BATTERY (self-extending quest, dynamic capacity,"
          " speculative adoption with rollback)")
    print("=" * 88)
    tasks = {t.tid: t for t in build_sealed_tasks()
             if t.tid in ("T29", "T30", "T31", "T32")}
    print("\n[E1] Rule 1+2: grow span(phi) from residue until sealed gates"
          " pass")
    ext_rows = []
    for tid in ("T29", "T30", "T31", "T32"):
        r = quest_extend_until_expressive(tasks[tid])
        ext_rows.append(r)
        print(f"  {tid}: needed_extension={r['needed_extension']}"
              f" added={r['added']}"
              f" dim {CFS_D}->{r['final_dim']}"
              f" final_gates={r['final_gates']}")
    closed = [r["tid"] for r in ext_rows if r["final_gates"]]
    print(f"  walls closed under self-extended substrate: {len(closed)}/4"
          f" {closed}")
    print("\n[E2] Rule 3: speculative adoption, sealed-gate finalization,"
          " cascade rollback")
    ledger = SpeculativeLedger()
    # bold candidate set for T30 incl. the train-only ridge fit (a likely
    # Goodhart trap) AND a genuine extended-substrate solution.
    t30 = tasks["T30"]
    w_base = cfs_ridge_fit(t30.train_pairs)
    trap_fn = cfs_decode(w_base)
    r1 = quest_extend_until_expressive(t30)
    cand = [("t30_trainfit_trap", w_base, trap_fn)]
    if r1["final_gates"]:
        phi = quest_phi_extended(r1["added"])
        w_ext, _ = quest_fit_with_phi(t30.train_pairs, phi)

        def good_fn(xs, _w=w_ext, _phi=phi):
            s = sum(a * p for a, p in zip(_w, _phi(xs)))
            if s != s or abs(s) > CFS_OUT_CAP:
                raise VMCrash("x")
            return int(round(s))
        cand.append(("t30_extended_true", w_ext, good_fn))
    out = speculative_round(ledger, t30, cand)
    for d in out["decided"]:
        print(f"  candidate {d['name']:<22} gate_pass={d['gate_pass']}"
              f" -> {d['status']}")
    print(f"  scratch residue after round: {out['scratch_residue_after']}"
          f" (must be 0); certified: {out['certified_count']}")
    print("  <- the train-fit trap is measured and rolled back; only a"
          " gate-passing candidate is permanently adopted. median_of_list"
          " remains the proof that this discipline is necessary.")
    rep = {"extension_rows": ext_rows, "walls_closed": closed,
           "speculative": out}
    with open("expansion_results.json", "w") as f:
        json.dump(json.loads(json.dumps(rep, default=str)), f,
                  sort_keys=True)
    print("\nreading: capacity grew only to cross measured walls; bold"
          " speculation ran in front of the sealed gates and rolled back"
          " cleanly; no rule weakened the verifier.")
    return rep


# --------------------------------------------------------------------------
# Section 24 tests.
# --------------------------------------------------------------------------
def test_quest_extension_closes_span_phi_walls() -> None:
    tasks = {t.tid: t for t in build_sealed_tasks()}
    r30 = quest_extend_until_expressive(tasks["T30"])
    r32 = quest_extend_until_expressive(tasks["T32"])
    _assert(r30["final_gates"] is True,
            f"T30 not closed by self-extension: {r30['added']}")
    _assert(r32["final_gates"] is True,
            f"T32 not closed by self-extension: {r32['added']}")
    _assert(r30["needed_extension"] is True
            and len(r30["added"]) >= 1, "T30 should need new dimensions")
    _assert(r30["final_dim"] > CFS_D, "capacity did not grow")
    # monotone trace: every step is train-exact, dim strictly grows
    dims = [s["dim"] for s in r30["trace"]]
    _assert(dims == sorted(dims) and len(set(dims)) == len(dims),
            "capacity trace not strictly increasing")


def test_speculative_adoption_gate_fenced_and_rolls_back() -> None:
    tasks = {t.tid: t for t in build_sealed_tasks()}
    t30 = tasks["T30"]
    ledger = SpeculativeLedger()
    w = cfs_ridge_fit(t30.train_pairs)
    trap = cfs_decode(w)
    _assert(cfs_score(w, t30.train_pairs) >= 1.0,
            "trap should be train-exact (that is the point)")
    out = speculative_round(ledger, t30, [("trap", w, trap)])
    d = out["decided"][0]
    _assert(d["gate_pass"] is False and d["status"] == "rolled_back",
            "train-only trap was not rejected by the gate")
    _assert(out["scratch_residue_after"] == 0
            and len(ledger.scratch) == 0, "scratch ledger left residue")
    _assert(len(ledger.certified) == 0, "trap leaked into certified state")
    # checkpoint/restore integrity
    ledger.certified["real"] = [1.0]
    ck = ledger.checkpoint()
    ledger.speculate("temp", [9.9])
    ledger.restore(ck)
    _assert("temp" not in ledger.scratch and "real" in ledger.certified,
            "restore did not return to certified checkpoint")


def test_expansion_results_consistent() -> None:
    _assert(os.path.exists("expansion_results.json"),
            "expansion artifact missing; run --mode expansion-battery")
    with open("expansion_results.json") as f:
        rep = json.load(f)
    _assert(len(rep["walls_closed"]) >= 3,
            f"too few walls closed: {rep['walls_closed']}")
    sp = rep["speculative"]
    _assert(sp["scratch_residue_after"] == 0, "speculation left residue")
    names = {d["name"]: d for d in sp["decided"]}
    if "t30_trainfit_trap" in names:
        _assert(names["t30_trainfit_trap"]["status"] == "rolled_back",
                "train-fit trap survived")


TESTS.extend([
    test_quest_extension_closes_span_phi_walls,
    test_speculative_adoption_gate_fenced_and_rolls_back,
    test_expansion_results_consistent,
])


# =========================================================================== #
# 25. GENERATIVE FEATURE GRAMMAR -- a measured reach extension of Rule 1.     #
#                                                                             #
# Section 24 Rule 1 grew span(phi) by SELECTING from a fixed six-feature bank #
# (quest_candidate_features). Its own honesty note conceded the boundary: the #
# system selects and installs but does not AUTHOR the kinds of feature. This  #
# section moves that boundary outward WITHOUT moving the gate. A small typed  #
# grammar -- generic reductions, elementwise comparators, mask aggregators -- #
# composes an unbounded family of feature EXPRESSIONS. The system enumerates  #
# them deterministically and installs any expression that crosses the SAME    #
# sealed holdout+cf gate under the SAME train-exact + MDL discipline used by   #
# Section 24. Boldness still lives in front of the gate, never inside it.      #
#                                                                             #
# What this is NOT. It is not unbounded self-improvement and it is not a      #
# singularity step. The grammar PRIMITIVES are still designer-declared; the   #
# regress of "who authored the primitives" is not terminated, only pushed one #
# level out -- from six named features to a generative space over a handful   #
# of named primitive operations. The claim is exactly the measured delta in   #
# grammar_battery(): a witness wall that the fixed bank PROVABLY cannot close  #
# (it exhausts its candidates and the sealed gate still fails), closed by a    #
# composed feature under the identical gate; plus an honest give-up on a       #
# target outside the grammar's closure, proving the larger search space did    #
# not buy a weaker verifier.                                                  #
# =========================================================================== #

# --- typed primitive libraries (generic; no task-specific constants) -------
def _gr_red_max(xs):   return float(max(xs)) if xs else 0.0
def _gr_red_min(xs):   return float(min(xs)) if xs else 0.0
def _gr_red_sum(xs):   return float(sum(xs))
def _gr_red_len(xs):   return float(len(xs))
def _gr_red_first(xs): return float(xs[0]) if xs else 0.0
def _gr_red_last(xs):  return float(xs[-1]) if xs else 0.0
def _gr_red_mean(xs):  return float(sum(xs)) / len(xs) if xs else 0.0

GRAMMAR_REDUCERS: Dict[str, Callable[[Sequence[int]], float]] = {
    "max": _gr_red_max, "min": _gr_red_min, "sum": _gr_red_sum,
    "len": _gr_red_len, "first": _gr_red_first, "last": _gr_red_last,
    "mean": _gr_red_mean,
}

GRAMMAR_CMPS: Dict[str, Callable[[float, float], float]] = {
    "eq": lambda x, t: 1.0 if float(x) == t else 0.0,
    "gt": lambda x, t: 1.0 if float(x) > t else 0.0,
    "ge": lambda x, t: 1.0 if float(x) >= t else 0.0,
    "lt": lambda x, t: 1.0 if float(x) < t else 0.0,
    "le": lambda x, t: 1.0 if float(x) <= t else 0.0,
}


def _gr_agg_count(mask, xs): return float(sum(mask))
def _gr_agg_msum(mask, xs):  return float(sum(m * x for m, x in zip(mask, xs)))
def _gr_agg_midx(mask, xs):  return float(sum(m * i for i, m in
                                              enumerate(mask)))

GRAMMAR_AGGS: Dict[str, Callable[[Sequence[float], Sequence[int]], float]] = {
    "count": _gr_agg_count, "msum": _gr_agg_msum, "midx": _gr_agg_midx,
}


def grammar_feature_bank() -> Dict[str, Callable[[Sequence[int]], float]]:
    """Deterministic enumeration of composed feature expressions of the form
        aggregator( [comparator(x_i, reducer(xs)) for i], xs ).
    Sorted nested order => a fixed, reproducible vocabulary. The number of
    expressions is |agg|*|cmp|*|red|; the grammar (not the list) is the
    designer act, so new feature KINDS arise by composition, not by hand."""
    bank: Dict[str, Callable[[Sequence[int]], float]] = {}
    for an in sorted(GRAMMAR_AGGS):
        for cn in sorted(GRAMMAR_CMPS):
            for rn in sorted(GRAMMAR_REDUCERS):
                a, c, r = GRAMMAR_AGGS[an], GRAMMAR_CMPS[cn], \
                    GRAMMAR_REDUCERS[rn]

                def feat(xs, _a=a, _c=c, _r=r):
                    t = _r(xs)
                    mask = [_c(x, t) for x in xs]
                    return _a(mask, xs)
                bank[f"{an}_{cn}_{rn}"] = feat
    return bank


def grammar_phi_extended(extra_names: Sequence[str]
                         ) -> Callable[[Sequence[int]], List[float]]:
    bank = grammar_feature_bank()

    def phi_ext(xs: Sequence[int]) -> List[float]:
        return cfs_phi(xs) + [bank[nm](xs) for nm in extra_names]
    return phi_ext


def grammar_extend_until_expressive(task, max_new: int = 2
                                    ) -> Dict[str, object]:
    """Same control flow as quest_extend_until_expressive, but candidate
    dimensions are drawn from the GENERATIVE grammar instead of the fixed
    bank. The gate (task.holdout_gate and task.cf_gate), the train-exact
    requirement, and the MDL sparsifier are byte-for-byte the Section 24/23
    machinery -- nothing in the verifier is relaxed."""
    base_w0 = cfs_ridge_fit(task.train_pairs)
    base_w, _ = cfs_sparsify(task.train_pairs, base_w0)
    base_fn = cfs_decode(base_w)
    base_train = cfs_score(base_w, task.train_pairs) >= 1.0
    base_gates = bool(base_train and task.holdout_gate(base_fn)
                      and task.cf_gate(base_fn))
    trace = [{"dim": CFS_D, "added": None, "train_exact": base_train,
              "gates": base_gates}]
    if base_gates:
        return {"tid": task.tid, "needed_extension": False, "added": [],
                "final_gates": True, "final_dim": CFS_D, "trace": trace}
    bank = list(grammar_feature_bank().keys())
    added: List[str] = []
    for _ in range(max_new):
        best_choice = None
        for nm in bank:
            if nm in added:
                continue
            phi = grammar_phi_extended(added + [nm])
            w, _sup, tr = quest_sparsify_ext(task.train_pairs, phi)
            if tr < 1.0:
                continue

            def fn(xs, _w=w, _phi=phi):
                s = sum(av * pv for av, pv in zip(_w, _phi(xs)))
                if s != s or abs(s) > CFS_OUT_CAP:
                    raise VMCrash("ext overflow")
                return int(round(s))
            g = bool(task.holdout_gate(fn) and task.cf_gate(fn))
            if g:
                best_choice = (nm, True)
                break
            if best_choice is None:
                best_choice = (nm, False)
        if best_choice is None:
            break
        nm, g = best_choice
        added.append(nm)
        trace.append({"dim": CFS_D + len(added), "added": nm,
                      "train_exact": True, "gates": g})
        if g:
            return {"tid": task.tid, "needed_extension": True, "added": added,
                    "final_gates": True, "final_dim": CFS_D + len(added),
                    "trace": trace}
    return {"tid": task.tid, "needed_extension": True, "added": added,
            "final_gates": False, "final_dim": CFS_D + len(added),
            "trace": trace}


# --- sealed witness + give-up oracles (live ONLY inside gate closures) ------
def _grammar_witness_oracle(xs):
    """count of elements equal to the maximum. Not in span(cfs_phi) (needs the
    max value and its multiplicity jointly); not in the positional fixed bank;
    IS in grammar closure as count(eq(max))."""
    if not xs:
        return 0
    m = max(xs)
    return sum(1 for x in xs if x == m)


def _grammar_giveup_oracle(xs):
    """second-largest value: requires order, expressible by neither the base
    map, the fixed bank, nor this grammar -- the system must give up honestly
    rather than false-adopt a train-coincidental fit."""
    if not xs:
        return 0
    if len(xs) == 1:
        return xs[0]
    return sorted(xs)[-2]


def grammar_witness_task():
    return seal_task("W_cnt_eq_max", "grammar_witness",
                     _grammar_witness_oracle)


def grammar_giveup_task():
    return seal_task("W_second_largest", "grammar_giveup",
                     _grammar_giveup_oracle)


def grammar_battery() -> Dict[str, object]:
    print("=" * 88)
    print("GRAMMAR BATTERY (generative feature-expression reach extension"
          " of Section 24 Rule 1)")
    print("=" * 88)
    wt = grammar_witness_task()

    # (A) base span(phi) wall
    bw0 = cfs_ridge_fit(wt.train_pairs)
    bw, _ = cfs_sparsify(wt.train_pairs, bw0)
    bfn = cfs_decode(bw)
    base_train = cfs_score(bw, wt.train_pairs) >= 1.0
    base_gates = bool(base_train and wt.holdout_gate(bfn) and wt.cf_gate(bfn))
    # (B) fixed bank (Section 24) attempt
    rb = quest_extend_until_expressive(wt, max_new=2)
    # (C) generative grammar attempt
    rg = grammar_extend_until_expressive(wt, max_new=2)
    # (D) honest give-up target under the grammar
    gv = grammar_extend_until_expressive(grammar_giveup_task(), max_new=2)

    print(f"\n[G1] witness target = count(elements == max)")
    print(f"  (A) base cfs_phi      : train_exact={base_train}"
          f" sealed_gates={base_gates}  -> span(phi) wall={base_train and not base_gates}")
    print(f"  (B) fixed bank (S.24) : added={rb['added']}"
          f" final_gates={rb['final_gates']}"
          f"  -> bank cannot close={rb['final_gates'] is False}")
    print(f"  (C) grammar (S.25)    : added={rg['added']}"
          f" final_gates={rg['final_gates']} dim {CFS_D}->{rg['final_dim']}"
          f"  -> grammar closes={rg['final_gates'] is True}")
    print(f"\n[G2] give-up target = second-largest value (outside grammar"
          f" closure)")
    print(f"  grammar           : added={gv['added']}"
          f" final_gates={gv['final_gates']}"
          f"  -> honest give-up (no false adoption)={gv['final_gates'] is False}")

    reach_extended = bool((base_train and not base_gates)
                          and rb["final_gates"] is False
                          and rg["final_gates"] is True)
    gate_intact = bool(gv["final_gates"] is False)
    rep = {
        "witness_tid": wt.tid,
        "base_train_exact": base_train, "base_gates": base_gates,
        "fixed_bank_added": rb["added"],
        "fixed_bank_final_gates": rb["final_gates"],
        "grammar_added": rg["added"],
        "grammar_final_gates": rg["final_gates"],
        "grammar_final_dim": rg["final_dim"],
        "giveup_final_gates": gv["final_gates"],
        "reach_extended_over_fixed_bank": reach_extended,
        "gate_not_weakened": gate_intact,
        "grammar_feature_count": len(grammar_feature_bank()),
    }
    with open("grammar_results.json", "w") as f:
        json.dump(json.loads(json.dumps(rep, default=str)), f,
                  sort_keys=True)
    print(f"\nreading: the fixed bank exhausts {rb['added']} and the sealed"
          f" gate still fails; one composed feature {rg['added']} crosses the"
          f" SAME gate. measured reach extension over Section 24 ="
          f" {reach_extended}; verifier left intact = {gate_intact}.")
    print("boundary kept honest: grammar primitives remain designer-declared;"
          " this is one level of regress removed, not a singularity.")
    return rep


# --------------------------------------------------------------------------
# Section 25 tests.
# --------------------------------------------------------------------------
def test_grammar_features_are_oracle_free() -> None:
    """Every grammar feature is a pure function of xs: it must never accept or
    consult a label/oracle. We assert arity-1 and value-stability under a
    decoy global oracle name."""
    bank = grammar_feature_bank()
    _assert(len(bank) == len(GRAMMAR_AGGS) * len(GRAMMAR_CMPS)
            * len(GRAMMAR_REDUCERS), "grammar size mismatch")
    import inspect
    for nm, fn in bank.items():
        sig = inspect.signature(fn)
        # one positional input (xs); the rest are bound defaults (_a,_c,_r)
        required = [p for p in sig.parameters.values()
                    if p.default is inspect.Parameter.empty]
        _assert(len(required) == 1,
                f"grammar feature {nm} takes more than xs")
    # count(eq(max)) must equal the witness target on probe inputs
    cem = bank["count_eq_max"]
    for xs in ([5, 5, 3], [7], [1, 2, 2], [4, 4, 4, 1]):
        _assert(int(cem(xs)) == _grammar_witness_oracle(xs),
                f"count_eq_max disagrees with target on {xs}")


def test_grammar_closes_wall_that_fixed_bank_cannot() -> None:
    """The core measured delta. On the sealed witness:
       (A) base cfs_phi is train-exact but fails the sealed gate (a real
           span(phi) wall, not a search failure);
       (B) the Section 24 fixed-bank extension exhausts its candidates and
           STILL fails the sealed gate (final_gates False);
       (C) the Section 25 grammar extension closes the wall under the SAME
           sealed gate by composing count(eq(max))."""
    wt = grammar_witness_task()
    bw0 = cfs_ridge_fit(wt.train_pairs)
    bw, _ = cfs_sparsify(wt.train_pairs, bw0)
    bfn = cfs_decode(bw)
    base_train = cfs_score(bw, wt.train_pairs) >= 1.0
    base_gates = bool(base_train and wt.holdout_gate(bfn) and wt.cf_gate(bfn))
    _assert(base_train and not base_gates,
            "witness is not a clean span(phi) wall under the base map")

    rb = quest_extend_until_expressive(wt, max_new=2)
    _assert(rb["final_gates"] is False,
            f"fixed bank unexpectedly closed the witness: {rb['added']}")

    rg = grammar_extend_until_expressive(wt, max_new=2)
    _assert(rg["final_gates"] is True,
            f"grammar failed to close the witness: {rg['added']}")
    _assert("count_eq_max" in rg["added"],
            f"grammar closed via unexpected feature: {rg['added']}")
    _assert(rg["final_dim"] > CFS_D, "capacity did not grow")


def test_grammar_extension_is_deterministic() -> None:
    wt = grammar_witness_task()
    a = grammar_extend_until_expressive(wt, max_new=2)
    b = grammar_extend_until_expressive(wt, max_new=2)
    _assert(a["added"] == b["added"]
            and a["final_gates"] == b["final_gates"]
            and a["final_dim"] == b["final_dim"],
            "grammar extension is not deterministic")
    # enumeration order itself must be stable
    k1 = list(grammar_feature_bank().keys())
    k2 = list(grammar_feature_bank().keys())
    _assert(k1 == k2, "grammar enumeration order is not stable")


def test_grammar_gate_not_weakened_honest_giveup() -> None:
    """A larger search space must not buy a weaker verifier. On a target
    outside the grammar's closure (second-largest, which needs order), the
    grammar must detect the wall, try train-exact candidates, and still give
    up honestly (final_gates False) -- proving the sealed gate, not train
    likelihood, is the arbiter."""
    gt = grammar_giveup_task()
    r = grammar_extend_until_expressive(gt, max_new=2)
    _assert(r["needed_extension"] is True,
            "give-up target should present a wall")
    _assert(r["final_gates"] is False,
            f"grammar false-adopted on an unexpressible target: {r['added']}")
    # and the direct train-only ridge trap is rejected by the same gate
    w = cfs_ridge_fit(gt.train_pairs)
    trap = cfs_decode(w)
    _assert(cfs_score(w, gt.train_pairs) >= 1.0,
            "trap must be train-exact (that is the point)")
    _assert(not (gt.holdout_gate(trap) and gt.cf_gate(trap)),
            "train-only trap leaked through the sealed gate")


def test_grammar_battery_artifact_consistent() -> None:
    rep = grammar_battery()
    _assert(rep["reach_extended_over_fixed_bank"] is True,
            "battery did not record a reach extension over the fixed bank")
    _assert(rep["gate_not_weakened"] is True,
            "battery did not confirm the gate stayed intact")
    _assert(os.path.exists("grammar_results.json"),
            "grammar battery artifact was not written")


TESTS.extend([
    test_grammar_features_are_oracle_free,
    test_grammar_closes_wall_that_fixed_bank_cannot,
    test_grammar_extension_is_deterministic,
    test_grammar_gate_not_weakened_honest_giveup,
    test_grammar_battery_artifact_consistent,
])


# =========================================================================== #
# 26. DEPTH-2 GRAMMAR: masked reductions -- the next measured rung.           #
#                                                                             #
# Section 25 gave Rule 1 a depth-1 grammar: features of the form              #
# aggregator([comparator(x_i, reducer(xs))], xs) with aggregators count /     #
# masked-sum / masked-index. Those aggregators are LINEAR in the mask, so     #
# they can tally or sum a selected subset but cannot extract its EXTREMUM.    #
# A target like "max of the elements below the mean" is therefore a wall the  #
# depth-1 grammar provably cannot cross (it exhausts its candidates and the   #
# sealed gate still fails).                                                   #
#                                                                             #
# This section adds exactly one compositional level: a REDUCTION over the     #
# masked subsequence -- op in {max, min, sum, mean} applied to                #
# {x_i : comparator(x_i, reducer(xs))}. The verifier is unchanged: same       #
# train-exact requirement, same sealed holdout+cf gate, same MDL sparsifier.  #
# grammar2 is a strict SUPERSET of the depth-1 grammar, so it closes          #
# everything Section 25 closed PLUS the extremum-of-subset family.            #
#                                                                             #
# This is rung N+1 on a finite ladder, NOT a singularity. The primitive ops,  #
# comparators, and reducers are still designer-declared; one more level of    #
# composition is unlocked, the regress is relocated, not terminated. The      #
# claim is only the measured delta in grammar2_battery(): a witness wall that  #
# the fixed bank AND the depth-1 grammar cannot close, closed under the        #
# identical gate, plus an honest give-up on a target outside even depth-2.    #
# =========================================================================== #

# --- depth-2 primitive: reduction over a comparator-masked subsequence ------
def _g2_op_max(v):  return float(max(v)) if v else 0.0
def _g2_op_min(v):  return float(min(v)) if v else 0.0
def _g2_op_sum(v):  return float(sum(v))
def _g2_op_mean(v): return float(sum(v)) / len(v) if v else 0.0

GRAMMAR2_OPS: Dict[str, Callable[[Sequence[int]], float]] = {
    "max": _g2_op_max, "min": _g2_op_min, "sum": _g2_op_sum,
    "mean": _g2_op_mean,
}

# Threshold references for the mask: the generic reducers from Section 25 that
# return a meaningful per-sequence level (len is excluded -- thresholding a
# value against a count is not a level comparison).
GRAMMAR2_REFS: Dict[str, Callable[[Sequence[int]], float]] = {
    "max": GRAMMAR_REDUCERS["max"], "min": GRAMMAR_REDUCERS["min"],
    "mean": GRAMMAR_REDUCERS["mean"], "first": GRAMMAR_REDUCERS["first"],
    "last": GRAMMAR_REDUCERS["last"],
}


def grammar2_feature_bank() -> Dict[str, Callable[[Sequence[int]], float]]:
    """Depth-1 grammar (Section 25) UNION depth-2 masked reductions. The depth-1
    keys come first (already sorted); the depth-2 keys are appended in sorted
    nested order, so the full enumeration is deterministic and grammar2 is a
    strict superset of grammar."""
    bank: Dict[str, Callable[[Sequence[int]], float]] = \
        dict(grammar_feature_bank())
    for on in sorted(GRAMMAR2_OPS):
        for cn in sorted(GRAMMAR_CMPS):
            for rn in sorted(GRAMMAR2_REFS):
                op, cmp, ref = GRAMMAR2_OPS[on], GRAMMAR_CMPS[cn], \
                    GRAMMAR2_REFS[rn]

                def feat(xs, _op=op, _cmp=cmp, _ref=ref):
                    t = _ref(xs)
                    sub = [x for x in xs if _cmp(x, t) >= 1.0]
                    return _op(sub)
                bank[f"mred_{on}_{cn}_{rn}"] = feat
    return bank


def grammar2_phi_extended(extra_names: Sequence[str]
                          ) -> Callable[[Sequence[int]], List[float]]:
    bank = grammar2_feature_bank()

    def phi_ext(xs: Sequence[int]) -> List[float]:
        return cfs_phi(xs) + [bank[nm](xs) for nm in extra_names]
    return phi_ext


def grammar2_extend_until_expressive(task, max_new: int = 2
                                     ) -> Dict[str, object]:
    """Same control flow as grammar_extend_until_expressive, drawing candidate
    dimensions from the depth-2 grammar. Nothing in the verifier is relaxed."""
    base_w0 = cfs_ridge_fit(task.train_pairs)
    base_w, _ = cfs_sparsify(task.train_pairs, base_w0)
    base_fn = cfs_decode(base_w)
    base_train = cfs_score(base_w, task.train_pairs) >= 1.0
    base_gates = bool(base_train and task.holdout_gate(base_fn)
                      and task.cf_gate(base_fn))
    trace = [{"dim": CFS_D, "added": None, "train_exact": base_train,
              "gates": base_gates}]
    if base_gates:
        return {"tid": task.tid, "needed_extension": False, "added": [],
                "final_gates": True, "final_dim": CFS_D, "trace": trace}
    bank = list(grammar2_feature_bank().keys())
    added: List[str] = []
    for _ in range(max_new):
        best_choice = None
        for nm in bank:
            if nm in added:
                continue
            phi = grammar2_phi_extended(added + [nm])
            w, _sup, tr = quest_sparsify_ext(task.train_pairs, phi)
            if tr < 1.0:
                continue

            def fn(xs, _w=w, _phi=phi):
                s = sum(av * pv for av, pv in zip(_w, _phi(xs)))
                if s != s or abs(s) > CFS_OUT_CAP:
                    raise VMCrash("ext overflow")
                return int(round(s))
            g = bool(task.holdout_gate(fn) and task.cf_gate(fn))
            if g:
                best_choice = (nm, True)
                break
            if best_choice is None:
                best_choice = (nm, False)
        if best_choice is None:
            break
        nm, g = best_choice
        added.append(nm)
        trace.append({"dim": CFS_D + len(added), "added": nm,
                      "train_exact": True, "gates": g})
        if g:
            return {"tid": task.tid, "needed_extension": True, "added": added,
                    "final_gates": True, "final_dim": CFS_D + len(added),
                    "trace": trace}
    return {"tid": task.tid, "needed_extension": True, "added": added,
            "final_gates": False, "final_dim": CFS_D + len(added),
            "trace": trace}


# --- sealed witness + give-up oracles (live ONLY inside gate closures) ------
def _grammar2_witness_oracle(xs):
    """max of the elements strictly below the mean. Needs an EXTREMUM over a
    computed subset -- outside span(cfs_phi), outside the positional fixed
    bank, and outside the depth-1 grammar (whose aggregators are linear in the
    mask). In grammar2 closure as mred_max_lt_mean."""
    if not xs:
        return 0
    m = sum(xs) / len(xs)
    sub = [x for x in xs if x < m]
    return max(sub) if sub else 0


def _grammar2_giveup_oracle(xs):
    """second-largest value: a sort-position target (ties make it differ from
    max-below-max), outside even the depth-2 grammar. The system must give up
    honestly rather than false-adopt a train-coincidental fit."""
    if not xs:
        return 0
    if len(xs) == 1:
        return xs[0]
    return sorted(xs)[-2]


def grammar2_witness_task():
    return seal_task("W2_max_below_mean", "grammar2_witness",
                     _grammar2_witness_oracle)


def grammar2_giveup_task():
    return seal_task("W2_second_largest", "grammar2_giveup",
                     _grammar2_giveup_oracle)


def grammar2_battery() -> Dict[str, object]:
    print("=" * 88)
    print("GRAMMAR-2 BATTERY (depth-2 masked-reduction reach extension of"
          " Section 25)")
    print("=" * 88)
    wt = grammar2_witness_task()

    bw0 = cfs_ridge_fit(wt.train_pairs)
    bw, _ = cfs_sparsify(wt.train_pairs, bw0)
    bfn = cfs_decode(bw)
    base_train = cfs_score(bw, wt.train_pairs) >= 1.0
    base_gates = bool(base_train and wt.holdout_gate(bfn) and wt.cf_gate(bfn))
    rb = quest_extend_until_expressive(wt, max_new=2)          # fixed bank
    r1 = grammar_extend_until_expressive(wt, max_new=2)        # depth-1
    r2 = grammar2_extend_until_expressive(wt, max_new=2)       # depth-2
    gv = grammar2_extend_until_expressive(grammar2_giveup_task(), max_new=2)

    print("\n[H1] witness target = max(elements strictly below the mean)")
    print(f"  (A) base cfs_phi      : train_exact={base_train}"
          f" sealed_gates={base_gates}"
          f"  -> span(phi) wall={base_train and not base_gates}")
    print(f"  (B) fixed bank (S.24) : final_gates={rb['final_gates']}"
          f" added={rb['added']}  -> cannot close={rb['final_gates'] is False}")
    print(f"  (C) depth-1 grm (S.25): final_gates={r1['final_gates']}"
          f" added={r1['added']}  -> cannot close={r1['final_gates'] is False}")
    print(f"  (D) depth-2 grm (S.26): final_gates={r2['final_gates']}"
          f" added={r2['added']} dim {CFS_D}->{r2['final_dim']}"
          f"  -> closes={r2['final_gates'] is True}")
    print("\n[H2] give-up target = second-largest value (outside depth-2"
          " closure)")
    print(f"  depth-2 grammar   : final_gates={gv['final_gates']}"
          f" added={gv['added']}"
          f"  -> honest give-up={gv['final_gates'] is False}")

    reach = bool((base_train and not base_gates)
                 and rb["final_gates"] is False
                 and r1["final_gates"] is False
                 and r2["final_gates"] is True)
    gate_intact = bool(gv["final_gates"] is False)
    rep = {
        "witness_tid": wt.tid,
        "base_train_exact": base_train, "base_gates": base_gates,
        "fixed_bank_final_gates": rb["final_gates"],
        "depth1_final_gates": r1["final_gates"],
        "depth1_added": r1["added"],
        "depth2_final_gates": r2["final_gates"],
        "depth2_added": r2["added"],
        "depth2_final_dim": r2["final_dim"],
        "giveup_final_gates": gv["final_gates"],
        "reach_extended_over_depth1": reach,
        "gate_not_weakened": gate_intact,
        "grammar2_feature_count": len(grammar2_feature_bank()),
    }
    with open("grammar2_results.json", "w") as f:
        json.dump(json.loads(json.dumps(rep, default=str)), f, sort_keys=True)
    print(f"\nreading: the fixed bank and the depth-1 grammar both exhaust"
          f" their candidates and the sealed gate still fails; one masked"
          f" reduction {r2['added']} crosses the SAME gate. measured reach"
          f" extension over Section 25 = {reach}; verifier intact = {gate_intact}.")
    print("boundary kept honest: ops/comparators/reducers remain designer-"
          "declared; this is one more rung, not a singularity.")
    return rep


