def test_grammar2_features_are_oracle_free() -> None:
    bank = grammar2_feature_bank()
    expect = (len(grammar_feature_bank())
              + len(GRAMMAR2_OPS) * len(GRAMMAR_CMPS) * len(GRAMMAR2_REFS))
    _assert(len(bank) == expect, f"grammar2 size mismatch {len(bank)}/{expect}")
    import inspect
    for nm, fn in bank.items():
        required = [p for p in inspect.signature(fn).parameters.values()
                    if p.default is inspect.Parameter.empty]
        _assert(len(required) == 1, f"grammar2 feature {nm} takes more than xs")
    mrm = bank["mred_max_lt_mean"]
    for xs in ([1, 2, 9], [5, 5, 5], [0, 10, 1, 1], [3, 3, 3, 12]):
        _assert(int(mrm(xs)) == _grammar2_witness_oracle(xs),
                f"mred_max_lt_mean disagrees with target on {xs}")


def test_grammar2_closes_wall_that_depth1_cannot() -> None:
    """The core measured delta of this section. On the sealed witness
    (max of elements below the mean):
       (A) base cfs_phi is a span(phi) wall;
       (B) the Section 24 fixed bank cannot close it;
       (C) the Section 25 depth-1 grammar cannot close it (its aggregators are
           linear in the mask -- no extremum of a subset);
       (D) the Section 26 depth-2 grammar closes it under the SAME sealed gate
           via mred_max_lt_mean."""
    wt = grammar2_witness_task()
    bw0 = cfs_ridge_fit(wt.train_pairs)
    bw, _ = cfs_sparsify(wt.train_pairs, bw0)
    bfn = cfs_decode(bw)
    base_train = cfs_score(bw, wt.train_pairs) >= 1.0
    base_gates = bool(base_train and wt.holdout_gate(bfn) and wt.cf_gate(bfn))
    _assert(base_train and not base_gates,
            "witness is not a clean span(phi) wall")

    rb = quest_extend_until_expressive(wt, max_new=2)
    _assert(rb["final_gates"] is False,
            f"fixed bank unexpectedly closed the witness: {rb['added']}")

    r1 = grammar_extend_until_expressive(wt, max_new=2)
    _assert(r1["final_gates"] is False,
            f"depth-1 grammar unexpectedly closed the witness: {r1['added']}")

    r2 = grammar2_extend_until_expressive(wt, max_new=2)
    _assert(r2["final_gates"] is True,
            f"depth-2 grammar failed to close the witness: {r2['added']}")
    _assert("mred_max_lt_mean" in r2["added"],
            f"depth-2 closed via unexpected feature: {r2['added']}")
    _assert(r2["final_dim"] > CFS_D, "capacity did not grow")


def test_grammar2_extension_is_deterministic() -> None:
    wt = grammar2_witness_task()
    a = grammar2_extend_until_expressive(wt, max_new=2)
    b = grammar2_extend_until_expressive(wt, max_new=2)
    _assert(a["added"] == b["added"]
            and a["final_gates"] == b["final_gates"]
            and a["final_dim"] == b["final_dim"],
            "depth-2 extension is not deterministic")
    _assert(list(grammar2_feature_bank().keys())
            == list(grammar2_feature_bank().keys()),
            "grammar2 enumeration order is not stable")
    # superset property: every depth-1 key is present in grammar2
    d1 = set(grammar_feature_bank().keys())
    d2 = set(grammar2_feature_bank().keys())
    _assert(d1 <= d2, "grammar2 is not a superset of grammar")


def test_grammar2_gate_not_weakened_honest_giveup() -> None:
    gt = grammar2_giveup_task()
    r = grammar2_extend_until_expressive(gt, max_new=2)
    _assert(r["needed_extension"] is True,
            "give-up target should present a wall")
    _assert(r["final_gates"] is False,
            f"depth-2 false-adopted on an unexpressible target: {r['added']}")
    w = cfs_ridge_fit(gt.train_pairs)
    trap = cfs_decode(w)
    _assert(cfs_score(w, gt.train_pairs) >= 1.0,
            "trap must be train-exact (that is the point)")
    _assert(not (gt.holdout_gate(trap) and gt.cf_gate(trap)),
            "train-only trap leaked through the sealed gate")


