def set_seed(seed: int):
    """Set global random seeds for reproducibility."""
    random.seed(seed)
    if np:
        np.random.seed(seed)
    if torch:
        torch.manual_seed(seed)
        if torch.cuda.is_available():
            torch.cuda.manual_seed_all(seed)
    print(f"[System] Global seed set to: {seed}")

def main():
    mp.set_start_method("spawn", force=True)

    # Backward compatibility: explicit --mode handling
    if len(sys.argv) > 2 and sys.argv[1] == "--mode" and sys.argv[2] == "hrm-life":
        run_hrm_life()
        sys.exit(0)

    parser = argparse.ArgumentParser(description="SystemTest CLI")
    
    # Global flags
    parser.add_argument("--seed", type=int, default=int(time.time()) % 100000, help="Global random seed (time-based by default)")
    parser.add_argument("--allow-net", action="store_true", help="Opt-in to network access (OEIS, etc)")

    subparsers = parser.add_subparsers(dest="command", help="Subcommand to run")

    # 1. Benchmark
    bench_parser = subparsers.add_parser("benchmark", help="Run orchestrator benchmark suite")
    bench_parser.add_argument("--suite", default="program_synthesis_v1", help="Benchmark suite name")
    bench_parser.add_argument("--rounds", type=int, default=20, help="Number of rounds")
    bench_parser.add_argument("--agents", type=int, default=8, help="Number of agents")
    bench_parser.add_argument("--trials", type=int, default=10, help="Number of trials")

    # 2. Orchestrator Smoke (Default safe run)
    smoke_parser = subparsers.add_parser("orchestrator-smoke", help="Run 20-round smoke test")

    # 3. HRM Life
    hrm_parser = subparsers.add_parser("hrm-life", help="Run infinite HRM life loop")

    # 4. Synthesis Verification
    synth_parser = subparsers.add_parser("synthesis", help="Run synthesis verification suite")
    
    # 5. SCIG-RSI Verification
    scig_parser = subparsers.add_parser("scig-test", help="Run specific SCIG-RSI integration test")
    synth_parser.add_argument("--quick", action="store_true", help="Reduce search effort for fast smoke runs")
    synth_parser.add_argument("--max-seconds", type=float, default=None, help="Hard cap runtime in seconds")
    synth_parser.add_argument("--tasks", type=str, default=None, help="Comma-separated list of tasks to run")
    synth_parser.add_argument("--guided", type=int, choices=[0, 1], default=0, help="Enable guided search")

    # 5. A/B Compare
    ab_parser = subparsers.add_parser("ab-compare", help="Run guided vs unguided A/B comparison")
    ab_parser.add_argument("--seeds", type=int, default=5, help="Number of seeds to compare")
    ab_parser.add_argument("--max-seconds", type=float, default=None, help="Hard cap runtime in seconds")
    ab_parser.add_argument("--quick", action="store_true", help="Reduce search effort for fast smoke runs")
    ab_parser.add_argument("--tasks", type=str, default=None, help="Comma-separated list of tasks to run")

    # 6. User-Injected Component Test
    user_test_parser = subparsers.add_parser("user-test", help="Run user-injected tests")

    # Default behavior if no args: Run safe smoke test instead of full benchmark
    if len(sys.argv) == 1:
        print("[Systemtest] No arguments provided. Defaulting to 'orchestrator-smoke'.")
        sys.argv.append("orchestrator-smoke")

    args = parser.parse_args()

    # Apply hygiene
    set_seed(args.seed)
    
    if args.allow_net:
        os.environ["SYSTEMTEST_ALLOW_NET"] = "1"
        print("[Systemtest] Network access ENABLED via flag.")
    else:
        # Explicitly disable any potential network usage
        os.environ["SYSTEMTEST_ALLOW_NET"] = "0" 
        
    # Dispatch
    if args.command == "benchmark":
        orchestrator_benchmark_main(args)
    elif args.command == "orchestrator-smoke":
        orchestrator_main()
    elif args.command == "hrm-life":
        run_hrm_life_v2()
    elif args.command == "synthesis":
        task_list = None
        if args.tasks:
            task_list = [t.strip() for t in args.tasks.split(",") if t.strip()]
        run_synthesis_verification_suite(
            quick=args.quick,
            max_seconds=args.max_seconds,
            tasks=task_list,
            guided=bool(args.guided),
        )
    elif args.command == "ab-compare":
        task_list = None
        if args.tasks:
            task_list = [t.strip() for t in args.tasks.split(",") if t.strip()]
        run_ab_compare(
            seeds=args.seeds,
            max_seconds=args.max_seconds,
            quick=args.quick,
            tasks=task_list,
        )
    elif args.command == "scig-test":
        run_scig_test()
    elif args.command == "user-test":
        run_user_injected_test()
    else:
        parser.print_help()

        parser.print_help()

def run_scig_test():
    """Specific test for SCIG-RSI integration logic."""
    print("=== SCIG-RSI INTEGRATION TEST ===")
    
    if not HAS_SCIG:
        print("❌ SCIG-RSI module not found. Cannot run test.")
        return

    try:
        print("[1] Initializing MetaBrain...")
        brain = scig_rsi.MetaBrain()
        print("✅ MetaBrain initialized successfully.")
        
        print("\n[2] Simulating Cognitive Stagnation...")
        print("    Feeding error signals to trigger adaptation...")
        
        initial_strategy = brain.get_structural_strategy()
        print(f"    Initial Strategy: {initial_strategy}")
        
        # Simulate 5 steps of high error (stagnation)
        for i in range(1, 6):
            # Percept: High loss, increasing stagnation counter
            brain.perceive(gain=0.1, stagnation_inc=1)
            new_strategy = brain.get_structural_strategy()
            
            # Calculate shift
            shift = sum(abs(initial_strategy[k] - new_strategy[k]) for k in initial_strategy)
            print(f"    Step {i}: Strategy Shift = {shift:.4f} -> {new_strategy}")
            
        print("\n[3] Testing Emergency Reset...")
        brain.emergency_reset()
        reset_strategy = brain.get_structural_strategy()
        print(f"    Post-Reset Strategy: {reset_strategy}")
        
        print("\n=== TEST PASSED: SCIG-RSI Logic is Active ===")
        
    except Exception as e:
        print(f"❌ TEST FAILED with error: {e}")
        import traceback
        traceback.print_exc()

if __name__ == "__main__":
    main()

