# ═══════════════════════════════════════════════════════════════
#  GLOBAL CONSTANTS — FIXED, NEVER TUNED MID-EXPERIMENT
# ═══════════════════════════════════════════════════════════════

SEED = 42
MAX_STACK = 64          # Stack depth limit
MAX_STEPS = 200         # Execution step limit (halting enforcement)
MAX_PROGRAM_LEN = 60    # Max bytecode length
MAX_ENCAPSULATED = 30   # Max new opcodes from encapsulation
