# ═══════════════════════════════════════════════════════════════
#  INSTRUCTION SET — THE MINIMAL TURING-COMPLETE BASIS
#  No math operators. No sin/cos/exp. Just structure.
# ═══════════════════════════════════════════════════════════════

# Core opcodes (the ONLY bootstrap — everything else must be discovered)
# These are the absolute minimum for Turing completeness on a stack machine.
OPCODES_CORE = {
    0:  "PUSH_0",      # Push 0
    1:  "PUSH_1",      # Push 1
    2:  "DUP",         # Duplicate top
    3:  "SWAP",        # Swap top two
    4:  "DROP",        # Discard top
    5:  "NAND",        # Bitwise NAND (universal boolean gate)
    6:  "INC",         # Increment top by 1
    7:  "DEC",         # Decrement top by 1
    8:  "IF_ZERO",     # Skip next instruction if top != 0
    9:  "LOOP_START",  # Begin loop (top = iteration count, max 20)
    10: "LOOP_END",    # End loop
    11: "READ_INPUT",  # Push next input value
    12: "WRITE_OUTPUT",# Pop top to output
    13: "NOP",         # No operation
    14: "ROT",         # Rotate top 3: a b c → b c a
    15: "OVER",        # Copy second element: a b → a b a
}

N_CORE_OPCODES = len(OPCODES_CORE)

# ═══════════════════════════════════════════════════════════════
#  ENCAPSULATION REGISTRY — dynamically growing basis
# ═══════════════════════════════════════════════════════════════

@dataclass
class EncapsulatedOp:
    """A discovered sub-sequence frozen into a new atomic opcode."""
    opcode_id: int          # Unique ID (N_CORE_OPCODES + index)
    name: str               # Human-readable name
    bytecode: List[int]     # The frozen instruction sequence
    gen_discovered: int     # Generation when encapsulated
    parent_fitness: float   # Fitness of the program it came from
    usage_count: int = 0    # How many times used in population
    avg_fitness_delta: float = 0.0  # Average fitness improvement when present

class BasisRegistry:
    """Manages the dynamically expanding instruction set."""

    def __init__(self):
        self.encapsulated: List[EncapsulatedOp] = []
        self.total_opcodes = N_CORE_OPCODES
        self.discovery_log: List[dict] = []
        self.rejection_log: List[dict] = []
        self._seen_hashes: Set[str] = set()

    def n_opcodes(self) -> int:
        return self.total_opcodes

    def try_encapsulate(self, subseq: List[int], gen: int, fitness: float) -> Optional[int]:
        """Attempt to freeze a sub-sequence as a new opcode."""
        if len(self.encapsulated) >= MAX_ENCAPSULATED:
            self.rejection_log.append({
                "gen": gen, "reason": "MAX_ENCAPSULATED_REACHED",
                "seq_len": len(subseq)
            })
            return None

        # Reject trivial sequences
        if len(subseq) < 3 or len(subseq) > 15:
            return None

        # Reject if only NOPs or single repeated instruction
        unique = set(subseq)
        if len(unique) <= 1:
            return None

        # Reject duplicates
        h = hashlib.md5(bytes(subseq)).hexdigest()
        if h in self._seen_hashes:
            return None
        self._seen_hashes.add(h)

        # Reject if contains other encapsulated ops (prevent nesting explosion)
        if any(op >= N_CORE_OPCODES for op in subseq):
            self.rejection_log.append({
                "gen": gen, "reason": "NESTED_ENCAPSULATION_BLOCKED",
                "seq_len": len(subseq)
            })
            return None

        new_id = self.total_opcodes
        name = f"ENCAP_{len(self.encapsulated)}_{gen}"
        op = EncapsulatedOp(
            opcode_id=new_id,
            name=name,
            bytecode=list(subseq),
            gen_discovered=gen,
            parent_fitness=fitness,
        )
        self.encapsulated.append(op)
        self.total_opcodes += 1

        self.discovery_log.append({
            "gen": gen,
            "opcode_id": new_id,
            "name": name,
            "bytecode": subseq,
            "bytecode_len": len(subseq),
            "parent_fitness": round(fitness, 6),
        })

        return new_id

    def get_encapsulated(self, opcode_id: int) -> Optional[EncapsulatedOp]:
        idx = opcode_id - N_CORE_OPCODES
        if 0 <= idx < len(self.encapsulated):
            return self.encapsulated[idx]
        return None

    def report(self) -> dict:
        return {
            "total_opcodes": self.total_opcodes,
            "n_encapsulated": len(self.encapsulated),
            "discoveries": self.discovery_log,
            "rejections_sample": self.rejection_log[:20],
            "encapsulated_ops": [
                {
                    "id": e.opcode_id, "name": e.name,
                    "bytecode": e.bytecode, "gen": e.gen_discovered,
                    "uses": e.usage_count,
                    "avg_delta": round(e.avg_fitness_delta, 6),
                }
                for e in self.encapsulated
            ],
        }


# ═══════════════════════════════════════════════════════════════
#  STACK MACHINE VM — executes bytecode programs
# ═══════════════════════════════════════════════════════════════

@dataclass
class VMState:
    stack: List[float] = field(default_factory=list)
    inputs: List[float] = field(default_factory=list)
    outputs: List[float] = field(default_factory=list)
    input_ptr: int = 0
    steps: int = 0
    crashed: bool = False
    crash_reason: str = ""

def execute(program: List[int], inputs: List[float],
            registry: BasisRegistry) -> VMState:
    """Execute a bytecode program on the stack machine.
    All crashes are logged, not discarded. [C4] enforced."""

    vm = VMState(inputs=list(inputs))
    pc = 0
    code = program

    # Pre-scan for loop structure
    loop_stack_addr = []  # stack of (loop_start_pc, remaining_iters)
    loop_map = {}  # LOOP_END_pc -> LOOP_START_pc

    i = 0
    temp_stack = []
    for i, op in enumerate(code):
        if op == 9:  # LOOP_START
            temp_stack.append(i)
        elif op == 10:  # LOOP_END
            if temp_stack:
                start = temp_stack.pop()
                loop_map[i] = start

    while pc < len(code) and vm.steps < MAX_STEPS:
        vm.steps += 1
        op = code[pc]

        # === CORE OPCODES ===
        if op == 0:  # PUSH_0
            if len(vm.stack) < MAX_STACK:
                vm.stack.append(0.0)
        elif op == 1:  # PUSH_1
            if len(vm.stack) < MAX_STACK:
                vm.stack.append(1.0)
        elif op == 2:  # DUP
            if vm.stack and len(vm.stack) < MAX_STACK:
                vm.stack.append(vm.stack[-1])
        elif op == 3:  # SWAP
            if len(vm.stack) >= 2:
                vm.stack[-1], vm.stack[-2] = vm.stack[-2], vm.stack[-1]
        elif op == 4:  # DROP
            if vm.stack:
                vm.stack.pop()
        elif op == 5:  # NAND
            if len(vm.stack) >= 2:
                b = vm.stack.pop()
                a = vm.stack.pop()
                # Treat as integer NAND, clamp to reasonable range
                ai = int(max(-1e6, min(1e6, a)))
                bi = int(max(-1e6, min(1e6, b)))
                result = ~(ai & bi) & 0xFFFF  # 16-bit NAND
                vm.stack.append(float(result))
        elif op == 6:  # INC
            if vm.stack:
                v = vm.stack[-1]
                if math.isfinite(v) and abs(v) < 1e8:
                    vm.stack[-1] = v + 1.0
                else:
                    vm.stack[-1] = float('nan')
        elif op == 7:  # DEC
            if vm.stack:
                v = vm.stack[-1]
                if math.isfinite(v) and abs(v) < 1e8:
                    vm.stack[-1] = v - 1.0
                else:
                    vm.stack[-1] = float('nan')
        elif op == 8:  # IF_ZERO (skip next if top != 0)
            if vm.stack:
                val = vm.stack.pop()
                if val != 0.0:
                    pc += 1  # Skip next instruction
        elif op == 9:  # LOOP_START
            if vm.stack:
                count = vm.stack.pop()
                count = max(0, min(20, int(count)))
                loop_stack_addr.append((pc, count))
            else:
                loop_stack_addr.append((pc, 0))
        elif op == 10:  # LOOP_END
            if loop_stack_addr:
                start_pc, remaining = loop_stack_addr[-1]
                remaining -= 1
                if remaining > 0:
                    loop_stack_addr[-1] = (start_pc, remaining)
                    pc = start_pc  # Jump back to loop start
                else:
                    loop_stack_addr.pop()
        elif op == 11:  # READ_INPUT
            if vm.input_ptr < len(vm.inputs) and len(vm.stack) < MAX_STACK:
                vm.stack.append(vm.inputs[vm.input_ptr])
                vm.input_ptr += 1
            elif len(vm.stack) < MAX_STACK:
                vm.stack.append(0.0)  # Default if no more inputs
        elif op == 12:  # WRITE_OUTPUT
            if vm.stack:
                vm.outputs.append(vm.stack.pop())
        elif op == 13:  # NOP
            pass
        elif op == 14:  # ROT
            if len(vm.stack) >= 3:
                c = vm.stack.pop()
                b = vm.stack.pop()
                a = vm.stack.pop()
                vm.stack.extend([b, c, a])
        elif op == 15:  # OVER
            if len(vm.stack) >= 2 and len(vm.stack) < MAX_STACK:
                vm.stack.append(vm.stack[-2])

        # === ENCAPSULATED OPCODES ===
        elif op >= N_CORE_OPCODES:
            enc = registry.get_encapsulated(op)
            if enc is not None:
                enc.usage_count += 1
                # Inline expansion: execute the frozen bytecode
                saved_pc = pc
                saved_code = code
                code = enc.bytecode
                pc = -1  # Will be incremented to 0
                # Execute inline (limited steps)
                inner_steps = 0
                while pc + 1 < len(code) and vm.steps < MAX_STEPS:
                    pc += 1
                    inner_op = code[pc]
                    vm.steps += 1
                    inner_steps += 1
                    if inner_steps > 50:
                        break  # Prevent encapsulated op from hogging execution
                    # Recursive expansion NOT allowed (encapsulated ops
                    # cannot contain other encapsulated ops — enforced at
                    # registration time)
                    if inner_op < N_CORE_OPCODES:
                        # Re-execute core op (duplicated logic, but keeps it simple)
                        # This is intentionally flat — no recursion
                        if inner_op == 0 and len(vm.stack) < MAX_STACK:
                            vm.stack.append(0.0)
                        elif inner_op == 1 and len(vm.stack) < MAX_STACK:
                            vm.stack.append(1.0)
                        elif inner_op == 2 and vm.stack and len(vm.stack) < MAX_STACK:
                            vm.stack.append(vm.stack[-1])
                        elif inner_op == 3 and len(vm.stack) >= 2:
                            vm.stack[-1], vm.stack[-2] = vm.stack[-2], vm.stack[-1]
                        elif inner_op == 4 and vm.stack:
                            vm.stack.pop()
                        elif inner_op == 5 and len(vm.stack) >= 2:
                            ib = vm.stack.pop(); ia = vm.stack.pop()
                            vm.stack.append(float(~(int(max(-1e6,min(1e6,ia))) & int(max(-1e6,min(1e6,ib)))) & 0xFFFF))
                        elif inner_op == 6 and vm.stack:
                            v = vm.stack[-1]
                            vm.stack[-1] = v + 1.0 if math.isfinite(v) and abs(v)<1e8 else float('nan')
                        elif inner_op == 7 and vm.stack:
                            v = vm.stack[-1]
                            vm.stack[-1] = v - 1.0 if math.isfinite(v) and abs(v)<1e8 else float('nan')
                        elif inner_op == 8 and vm.stack:
                            val = vm.stack.pop()
                            if val != 0.0: pc += 1
                        elif inner_op == 11:
                            if vm.input_ptr < len(vm.inputs) and len(vm.stack) < MAX_STACK:
                                vm.stack.append(vm.inputs[vm.input_ptr])
                                vm.input_ptr += 1
                            elif len(vm.stack) < MAX_STACK:
                                vm.stack.append(0.0)
                        elif inner_op == 12 and vm.stack:
                            vm.outputs.append(vm.stack.pop())
                        elif inner_op == 14 and len(vm.stack) >= 3:
                            c=vm.stack.pop(); b=vm.stack.pop(); a=vm.stack.pop()
                            vm.stack.extend([b,c,a])
                        elif inner_op == 15 and len(vm.stack)>=2 and len(vm.stack)<MAX_STACK:
                            vm.stack.append(vm.stack[-2])
                        # 9,10 (loops) inside encapsulated ops: skip (too complex)
                        # 13 (NOP): skip
                code = saved_code
                pc = saved_pc

        pc += 1

    # Check for NaN contamination
    for i, v in enumerate(vm.outputs):
        if not math.isfinite(v):
            vm.crashed = True
            vm.crash_reason = f"NaN_in_output_{i}"
            break

    if not vm.outputs:
        vm.crashed = True
        vm.crash_reason = "NO_OUTPUT"

    return vm


# ═══════════════════════════════════════════════════════════════
#  ENVIRONMENT — co-evolving problem generators
# ═══════════════════════════════════════════════════════════════

@dataclass
class Environment:
    """An environment is a set of (input, expected_output) test cases.
    Environments co-evolve: easy ones die, impossibly hard ones die,
    only calibrated-difficulty environments survive."""

    cases: List[Tuple[List[float], List[float]]]  # [(inputs, expected_outputs)]
    gen_created: int = 0
    n_solvers: int = 0      # How many programs solve this
    difficulty: float = 0.0 # Fraction that fail

    def complexity(self) -> float:
        """Rough complexity measure of the test cases."""
        total = 0.0
        for inputs, outputs in self.cases:
            for v in inputs + outputs:
                total += abs(v) if math.isfinite(v) else 100.0
        return total / max(1, len(self.cases))


def make_random_env(gen: int, rng: random.Random) -> Environment:
    """Generate a random environment with diverse test patterns."""
    pattern = rng.randint(0, 5)
    cases = []

    for _ in range(N_EVAL_CASES):
        if pattern == 0:
            # Identity: output = input
            x = rng.uniform(-10, 10)
            cases.append(([x], [x]))
        elif pattern == 1:
            # Doubling: output = input * 2
            x = rng.uniform(-5, 5)
            cases.append(([x], [x * 2.0]))
        elif pattern == 2:
            # Negation: output = -input
            x = rng.uniform(-10, 10)
            cases.append(([x], [-x]))
        elif pattern == 3:
            # Constant: output = k regardless of input
            k = rng.uniform(-5, 5)
            x = rng.uniform(-10, 10)
            cases.append(([x], [k]))
        elif pattern == 4:
            # Sum of two inputs
            a = rng.uniform(-5, 5)
            b = rng.uniform(-5, 5)
            cases.append(([a, b], [a + b]))
        elif pattern == 5:
            # Max of two inputs
            a = rng.uniform(-5, 5)
            b = rng.uniform(-5, 5)
            cases.append(([a, b], [max(a, b)]))

    return Environment(cases=cases, gen_created=gen)


def mutate_env(env: Environment, gen: int, rng: random.Random) -> Environment:
    """Mutate an environment by perturbing test cases."""
    new_cases = []
    for inputs, outputs in env.cases:
        new_in = list(inputs)
        new_out = list(outputs)
        if rng.random() < 0.3:
            # Perturb an input
            if new_in:
                idx = rng.randint(0, len(new_in) - 1)
                new_in[idx] += rng.gauss(0, 1.0)
        if rng.random() < 0.2:
            # Recompute expected output with slight shift
            if new_out:
                idx = rng.randint(0, len(new_out) - 1)
                new_out[idx] += rng.gauss(0, 0.5)
        new_cases.append((new_in, new_out))

    # Occasionally add a new case
    if rng.random() < 0.2 and len(new_cases) < N_EVAL_CASES + 4:
        x = rng.uniform(-10, 10)
        new_cases.append(([x], [x * rng.uniform(-3, 3)]))

    return Environment(cases=new_cases[:N_EVAL_CASES], gen_created=gen)


# ═══════════════════════════════════════════════════════════════
#  SELF-REFERENTIAL MUTATION — mutators ARE programs
# ═══════════════════════════════════════════════════════════════

def apply_mutator_program(solution: List[int], mutator: List[int],
                          registry: BasisRegistry,
                          rng: random.Random) -> List[int]:
    """Apply a mutator program to a solution's bytecode.

    The mutator receives the solution bytecode as input values,
    and its output values become the mutated solution.
    This is the SELF-REFERENTIAL core: mutators and solutions
    share the same instruction set.

    If the mutator crashes or produces garbage, the mutation is
    a no-op (but logged). [C4]: we don't discard the crash."""

    # Feed solution bytecode as float inputs to the mutator
    inputs = [float(op) for op in solution[:30]]  # Truncate to prevent huge inputs

    vm = execute(mutator, inputs, registry)

    if vm.crashed or not vm.outputs:
        # Mutator failed — fall back to minimal structural mutation
        # This is NOT a violation of self-reference: it's the "ground state"
        # mutation that prevents total population death
        return _fallback_mutate(solution, registry, rng)

    # Interpret outputs as new bytecode
    n_ops = registry.n_opcodes()
    new_code = []
    for v in vm.outputs[:MAX_PROGRAM_LEN]:
        if math.isfinite(v):
            op = int(round(v)) % n_ops
            if op < 0:
                op = abs(op) % n_ops
            new_code.append(op)

    if not new_code:
        return _fallback_mutate(solution, registry, rng)

    return new_code[:MAX_PROGRAM_LEN]


def _fallback_mutate(program: List[int], registry: BasisRegistry,
                     rng: random.Random) -> List[int]:
    """Minimal structural mutation. Used ONLY when self-referential
    mutation completely fails (mutator crash). This is the irreducible
    bootstrap — analogous to cosmic ray bit-flips."""

    p = list(program)
    if not p:
        return [rng.randint(0, registry.n_opcodes() - 1)
                for _ in range(rng.randint(5, 15))]

    n_ops = registry.n_opcodes()
    r = rng.random()

    if r < 0.25:
        # Point mutation: change one instruction
        idx = rng.randint(0, len(p) - 1)
        p[idx] = rng.randint(0, n_ops - 1)
    elif r < 0.5:
        # Insertion
        idx = rng.randint(0, len(p))
        p.insert(idx, rng.randint(0, n_ops - 1))
    elif r < 0.75:
        # Deletion
        if len(p) > 3:
            idx = rng.randint(0, len(p) - 1)
            p.pop(idx)
    else:
        # Block swap
        if len(p) >= 4:
            a = rng.randint(0, len(p) - 2)
            b = rng.randint(a + 1, min(a + 5, len(p)))
            c = rng.randint(0, len(p) - 1)
            block = p[a:b]
            p = p[:a] + p[b:]
            p = p[:c] + block + p[c:]

    return p[:MAX_PROGRAM_LEN]


# ═══════════════════════════════════════════════════════════════
#  FITNESS EVALUATION — black box, terminal state only [C1][C3]
# ═══════════════════════════════════════════════════════════════

def evaluate(program: List[int], env: Environment,
             registry: BasisRegistry) -> Tuple[float, dict]:
    """Evaluate a program against an environment.
    Returns (fitness, diagnostics).
    Fitness = -mean_absolute_error. Higher is better. 0.0 = perfect.
    All crashes scored as -100.0. [C4] enforced."""

    total_error = 0.0
    n_valid = 0
    n_crash = 0
    crash_reasons = []

    for inputs, expected_outputs in env.cases:
        vm = execute(program, inputs, registry)

        if vm.crashed:
            total_error += 100.0
            n_crash += 1
            crash_reasons.append(vm.crash_reason)
            continue

        # Compare outputs
        err = 0.0
        for i, expected in enumerate(expected_outputs):
            if i < len(vm.outputs):
                actual = vm.outputs[i]
                if math.isfinite(actual) and math.isfinite(expected):
                    err += abs(actual - expected)
                else:
                    err += 100.0
            else:
                err += 100.0  # Missing output

        total_error += err
        n_valid += 1

    n_cases = len(env.cases)
    fitness = -(total_error / max(1, n_cases))

    diag = {
        "n_cases": n_cases,
        "n_valid": n_valid,
        "n_crash": n_crash,
        "crash_reasons": crash_reasons[:3],
        "mean_error": round(total_error / max(1, n_cases), 6),
    }

    return fitness, diag


# ═══════════════════════════════════════════════════════════════
#  BEHAVIORAL CHARACTERIZATION — for diversity maintenance
# ═══════════════════════════════════════════════════════════════

def behavioral_hash(program: List[int], probe_inputs: List[List[float]],
                    registry: BasisRegistry) -> str:
    """Create a behavioral fingerprint by running program on probe inputs."""
    sig = []
    for inputs in probe_inputs:
        vm = execute(program, inputs, registry)
        if vm.outputs:
            # Discretize first output
            v = vm.outputs[0]
            if math.isfinite(v):
                bucket = int(max(-DIVERSITY_BINS, min(DIVERSITY_BINS,
                                                      round(v * 2))))
            else:
                bucket = 999  # NaN bucket
        else:
            bucket = -999  # No output bucket
        sig.append(bucket)
    return str(sig)


# ═══════════════════════════════════════════════════════════════
#  ENCAPSULATION ENGINE — discovers and freezes sub-sequences
# ═══════════════════════════════════════════════════════════════

def discover_encapsulations(population: List[Tuple[List[int], float]],
                            registry: BasisRegistry,
                            gen: int,
                            rng: random.Random) -> int:
    """Scan top programs for common high-value sub-sequences.
    Freeze them as new opcodes. Returns number of new opcodes created."""

    # Only look at top 30% of population
    sorted_pop = sorted(population, key=lambda x: x[1], reverse=True)
    top = sorted_pop[:max(3, len(sorted_pop) // 3)]

    # Extract all sub-sequences of length 3-10 from top programs
    subseq_counts: Counter = Counter()
    subseq_fitness: Dict[str, List[float]] = defaultdict(list)

    for prog, fitness in top:
        if fitness < ENCAP_THRESHOLD * (sorted_pop[0][1] if sorted_pop[0][1] != 0 else 1):
            continue

        for length in range(3, min(11, len(prog))):
            for start in range(len(prog) - length + 1):
                subseq = tuple(prog[start:start + length])
                # Only consider sub-sequences made of core ops
                if all(op < N_CORE_OPCODES for op in subseq):
                    key = str(subseq)
                    subseq_counts[key] += 1
                    subseq_fitness[key].append(fitness)

    # Encapsulate sub-sequences that appear frequently in top programs
    n_new = 0
    for key, count in subseq_counts.most_common(5):
        if count < ENCAP_MIN_USES:
            continue

        subseq = eval(key)  # Recover tuple
        avg_fit = sum(subseq_fitness[key]) / len(subseq_fitness[key])

        new_id = registry.try_encapsulate(list(subseq), gen, avg_fit)
        if new_id is not None:
            n_new += 1

    return n_new


# ═══════════════════════════════════════════════════════════════
#  MAIN EVOLUTION LOOP
# ═══════════════════════════════════════════════════════════════

def run_experiment():
    """Main experiment: co-evolve solutions, mutators, and environments."""

    master_rng = random.Random(SEED)
    registry = BasisRegistry()

    # ─── Initialize populations ───
    # Solutions: random bytecode
    solutions = []
    for _ in range(POP_SIZE):
        length = master_rng.randint(5, 25)
        prog = [master_rng.randint(0, N_CORE_OPCODES - 1) for _ in range(length)]
        solutions.append(prog)

    # Mutators: random bytecode (same substrate!)
    mutators = []
    for _ in range(MUT_POP_SIZE):
        length = master_rng.randint(8, 30)
        prog = [master_rng.randint(0, N_CORE_OPCODES - 1) for _ in range(length)]
        mutators.append(prog)

    # Environments: random test cases
    environments = [make_random_env(0, master_rng) for _ in range(ENV_POP_SIZE)]

    # Probe inputs for behavioral characterization
    probes = [[master_rng.uniform(-5, 5)] for _ in range(6)]

    # ─── Logging ───
    gen_log = []
    basis_sizes = []
    diversity_log = []
    mutator_success_log = []
    crash_log = []
    encap_timeline = []

    best_ever_fitness = -1e10
    best_ever_program = []
    best_ever_gen = 0
    stagnation_counter = 0

    total_self_ref_mutations = 0
    total_fallback_mutations = 0

    print("=" * 72)
    print("  OPEN-ENDED SELF-REFERENTIAL EVOLUTION (OESRE)")
    print("  Basis: 16 core opcodes (stack ops + NAND + INC/DEC)")
    print("  Self-referential: mutators = programs in same substrate")
    print("  Co-evolutionary: environments evolve with solutions")
    print("  Encapsulation: discovered patterns become new opcodes")
    print(f"  Pop: {POP_SIZE} solutions, {MUT_POP_SIZE} mutators, "
          f"{ENV_POP_SIZE} environments")
    print(f"  Generations: {N_GENERATIONS}")
    print("=" * 72)

    t0 = time.time()

    for gen in range(N_GENERATIONS):
        gen_t0 = time.time()

        # ─── Step 1: Evaluate all solutions against all environments ───
        fitness_matrix = []  # [solution_idx][env_idx] = fitness
        sol_fitnesses = []   # Aggregate fitness per solution
        sol_diags = []

        for si, sol in enumerate(solutions):
            row = []
            total_fit = 0.0
            for ei, env in enumerate(environments):
                fit, diag = evaluate(sol, env, registry)
                row.append(fit)
                total_fit += fit
            fitness_matrix.append(row)
            avg_fit = total_fit / len(environments)
            sol_fitnesses.append(avg_fit)
            sol_diags.append({"avg_fitness": round(avg_fit, 6),
                              "prog_len": len(sol)})

        # ─── Step 2: Update environment difficulty ───
        for ei, env in enumerate(environments):
            n_solved = sum(1 for si in range(len(solutions))
                          if fitness_matrix[si][ei] > -1.0)
            env.n_solvers = n_solved
            env.difficulty = 1.0 - (n_solved / max(1, len(solutions)))

        # ─── Step 3: Behavioral diversity ───
        behaviors = set()
        for sol in solutions:
            bh = behavioral_hash(sol, probes, registry)
            behaviors.add(bh)
        diversity = len(behaviors) / max(1, len(solutions))

        # ─── Step 4: Encapsulation check (every 20 generations) ───
        n_new_ops = 0
        if gen > 0 and gen % 20 == 0:
            pop_with_fit = list(zip(solutions, sol_fitnesses))
            n_new_ops = discover_encapsulations(pop_with_fit, registry, gen,
                                                 master_rng)
            if n_new_ops > 0:
                encap_timeline.append({
                    "gen": gen,
                    "n_new": n_new_ops,
                    "total_basis": registry.n_opcodes(),
                })

        basis_sizes.append(registry.n_opcodes())

        # ─── Step 5: Selection ───
        # Tournament selection for reproduction
        sorted_indices = sorted(range(len(solutions)),
                                key=lambda i: sol_fitnesses[i], reverse=True)
        elite_size = max(3, POP_SIZE // 5)
        elites = [list(solutions[i]) for i in sorted_indices[:elite_size]]

        # Track best
        gen_best_fitness = sol_fitnesses[sorted_indices[0]]
        gen_best_program = list(solutions[sorted_indices[0]])

        if gen_best_fitness > best_ever_fitness:
            best_ever_fitness = gen_best_fitness
            best_ever_program = list(gen_best_program)
            best_ever_gen = gen
            stagnation_counter = 0
        else:
            stagnation_counter += 1

        # ─── Step 6: Self-referential mutation to create offspring ───
        new_solutions = list(elites)
        gen_self_ref = 0
        gen_fallback = 0

        while len(new_solutions) < POP_SIZE:
            parent_idx = master_rng.choice(sorted_indices[:elite_size * 2])
            parent = solutions[parent_idx]
            mutator = master_rng.choice(mutators)

            # Attempt self-referential mutation
            child = apply_mutator_program(parent, mutator, registry, master_rng)

            # Check if it was self-referential or fallback
            # We detect this by checking if the child is structurally
            # different from what fallback would produce
            # (Actually, we track inside apply_mutator_program)
            # For now, approximate: if output length matches mutator output potential
            vm_test = execute(mutator, [float(op) for op in parent[:30]], registry)
            if vm_test.crashed or not vm_test.outputs:
                gen_fallback += 1
                total_fallback_mutations += 1
            else:
                gen_self_ref += 1
                total_self_ref_mutations += 1

            new_solutions.append(child[:MAX_PROGRAM_LEN])

        solutions = new_solutions[:POP_SIZE]

        # ─── Step 7: Evolve mutators ───
        # Mutators are scored by the fitness improvement they produce
        mutator_scores = []
        for mi, mut in enumerate(mutators):
            # Test this mutator on a few random parents
            score = 0.0
            for _ in range(3):
                pidx = master_rng.choice(sorted_indices[:elite_size * 2])
                parent = solutions[pidx] if pidx < len(solutions) else elites[0]
                parent_fit = sol_fitnesses[pidx] if pidx < len(sol_fitnesses) else -100

                child = apply_mutator_program(parent, mut, registry, master_rng)
                # Quick eval on first environment
                child_fit, _ = evaluate(child, environments[0], registry)
                score += (child_fit - parent_fit)
            mutator_scores.append(score / 3.0)

        # Select and mutate top mutators
        mut_sorted = sorted(range(len(mutators)),
                            key=lambda i: mutator_scores[i], reverse=True)
        mut_elites = [list(mutators[i]) for i in mut_sorted[:max(2, MUT_POP_SIZE // 4)]]
