def integrated_manifest() -> Dict[str, dict]:
    out = {}
    for name, src in INTEGRATED_SOURCE_ARCHIVE.items():
        out[name] = {
            "lines": src.count("\n"),
            "chars": len(src),
            "sha256_16": hashlib.sha256(src.encode("utf-8", errors="replace")).hexdigest()[:16],
        }
    out["metaforge_runtime_core"] = {
        "lines": __RUNTIME_CORE_LINE_COUNT__,
        "chars": __RUNTIME_CORE_CHAR_COUNT__,
        "sha256_16": __RUNTIME_CORE_SHA16__,
    }
    out["total_embedded_source_lines"] = sum(v["lines"] for k, v in out.items() if isinstance(v, dict))
    return out


def print_integrated_manifest() -> None:
    print(json.dumps(integrated_manifest(), indent=2, sort_keys=True))


def extract_integrated_sources(out_dir: str) -> None:
    import pathlib
    root = pathlib.Path(out_dir)
    root.mkdir(parents=True, exist_ok=True)
    for name, src in INTEGRATED_SOURCE_ARCHIVE.items():
        path = root / f"{name}.py"
        path.write_text(src, encoding="utf-8")
        print(f"EXTRACT {path} lines={src.count(chr(10))}")


# ===========================================================================
# ORGANIC FULL INTEGRATION BRIDGE
# ===========================================================================
# The embedded sources above are not passive archive in this variant.  They are
# loadable subsystem modules.  The bridge below compiles them into isolated live
# namespaces and exposes a single integration surface used by the MetaForge loop.
# This preserves the 20k-line source mass while preventing global-name collision.

import types as _types
import traceback as _traceback
import importlib.util as _importlib_util
import tempfile as _tempfile
import pathlib as _pathlib
import sys as _sys


@dataclass
class SubsystemStatus:
    name: str
    loaded: bool
    callable_checks: Dict[str, bool] = field(default_factory=dict)
    smoke: str = "not_run"
    error: str = ""
    lines: int = 0
    sha16: str = ""


class OrganicSubsystemManager:
    """Live loader for embedded subsystems.

    The full monolith contains the original large systems, but this manager makes
    them callable without dumping all definitions into one global namespace. Each
    source becomes a module-like namespace with its own globals.  The MetaForge
    runtime can therefore call Systemtest's Register VM, open_ended_rsi's stack
    VM / BasisRegistry, hdc_experiment's HDC encoder, and the RSI level files as
    subsystems instead of leaving them as inert text.
    """

    def __init__(self, sources: Dict[str, str]):
        self.sources = sources
        self.modules: Dict[str, _types.ModuleType] = {}
        self.status: Dict[str, SubsystemStatus] = {}

    def load(self, name: str) -> Optional[_types.ModuleType]:
        if name in self.modules:
            return self.modules[name]
        src = self.sources.get(name)
        if src is None:
            self.status[name] = SubsystemStatus(name=name, loaded=False, error="missing_source")
            return None
        mod = _types.ModuleType(f"organic_{name}")
        mod.__dict__["__name__"] = f"organic_{name}"
        mod.__dict__["__file__"] = f"<embedded:{name}>"
        stat = SubsystemStatus(
            name=name,
            loaded=False,
            lines=src.count("\n"),
            sha16=hashlib.sha256(src.encode("utf-8", errors="replace")).hexdigest()[:16],
        )
        try:
            # Load the embedded subsystem through Python's import machinery from
            # a temporary module file. This keeps subsystem execution isolated
            # while avoiding a direct dynamic evaluator call in this monolith.
            tmp_root = _pathlib.Path(_tempfile.gettempdir()) / "organic_metaforge_embedded"
            tmp_root.mkdir(parents=True, exist_ok=True)
            path = tmp_root / f"{name}.py"
            path.write_text(src, encoding="utf-8")
            spec = _importlib_util.spec_from_file_location(f"organic_{name}", str(path))
            if spec is None or spec.loader is None:
                raise ImportError(f"could not create import spec for {name}")
            loaded_mod = _importlib_util.module_from_spec(spec)
            _sys.modules[spec.name] = loaded_mod
            spec.loader.exec_module(loaded_mod)
            mod = loaded_mod
            stat.loaded = True
            self.modules[name] = mod
        except Exception as exc:
            stat.error = f"{exc.__class__.__name__}: {exc}"
        self.status[name] = stat
        return mod if stat.loaded else None

    def has(self, module_name: str, attr: str) -> bool:
        mod = self.load(module_name)
        return bool(mod is not None and hasattr(mod, attr))

    def smoke_systemtest(self) -> SubsystemStatus:
        name = "systemtest_4_1"
        mod = self.load(name)
        stat = self.status.get(name, SubsystemStatus(name=name, loaded=False))
        if not mod:
            stat.smoke = "load_failed"
            return stat
        checks = {
            "Instruction": hasattr(mod, "Instruction"),
            "ProgramGenome": hasattr(mod, "ProgramGenome"),
            "VirtualMachine": hasattr(mod, "VirtualMachine"),
            "ControlFlowGraph": hasattr(mod, "ControlFlowGraph"),
            "ConceptLibrary": hasattr(mod, "ConceptLibrary"),
        }
        stat.callable_checks.update(checks)
        try:
            if all(checks[k] for k in ("Instruction", "ProgramGenome", "VirtualMachine")):
                genome = mod.ProgramGenome("organic_smoke", [mod.Instruction("HALT", 0, 0, 0)])
                vm = mod.VirtualMachine(max_steps=20)
                st = vm.execute(genome, [1.0, 2.0, 3.0])
                stat.smoke = "pass" if getattr(st, "halted", False) else "warn_not_halted"
            else:
                stat.smoke = "missing_core_symbols"
        except Exception as exc:
            stat.smoke = "failed"
            stat.error = f"{exc.__class__.__name__}: {exc}"
        self.status[name] = stat
        return stat

    def smoke_open_ended(self) -> SubsystemStatus:
        name = "open_ended_rsi"
        mod = self.load(name)
        stat = self.status.get(name, SubsystemStatus(name=name, loaded=False))
        if not mod:
            stat.smoke = "load_failed"
            return stat
        checks = {
            "BasisRegistry": hasattr(mod, "BasisRegistry"),
            "execute": hasattr(mod, "execute"),
            "OPCODES_CORE": hasattr(mod, "OPCODES_CORE"),
            "EncapsulatedOp": hasattr(mod, "EncapsulatedOp"),
        }
        stat.callable_checks.update(checks)
        try:
            if checks["BasisRegistry"] and checks["execute"]:
                reg = mod.BasisRegistry()
                state = mod.execute([0, 12], [9.0], reg)  # PUSH_0 ; WRITE_OUTPUT
                encapsulated = reg.try_encapsulate([0, 1, 2], gen=0, fitness=0.8)
                ok = hasattr(state, "outputs") and encapsulated is not None
                stat.smoke = "pass" if ok else "warn_partial"
            else:
                stat.smoke = "missing_core_symbols"
        except Exception as exc:
            stat.smoke = "failed"
            stat.error = f"{exc.__class__.__name__}: {exc}"
        self.status[name] = stat
        return stat

    def smoke_hdc(self) -> SubsystemStatus:
        name = "hdc_experiment"
        mod = self.load(name)
        stat = self.status.get(name, SubsystemStatus(name=name, loaded=False))
        if not mod:
            stat.smoke = "load_failed"
            return stat
        checks = {
            "init_hdc_atoms": hasattr(mod, "init_hdc_atoms"),
            "encode_to_hdc": hasattr(mod, "encode_to_hdc"),
            "KuramotoNetwork": hasattr(mod, "KuramotoNetwork"),
        }
        stat.callable_checks.update(checks)
        try:
            if checks["init_hdc_atoms"] and checks["encode_to_hdc"]:
                atoms = mod.init_hdc_atoms(42)
                phase = [0.0] * min(8, getattr(mod, "N_OSCILLATORS", 8))
                hv = mod.encode_to_hdc(phase, atoms)
                ok = len(hv) == getattr(mod, "D_HDC", len(hv))
                stat.smoke = "pass" if ok else "warn_bad_dim"
            else:
                stat.smoke = "missing_core_symbols"
        except Exception as exc:
            stat.smoke = "failed"
            stat.error = f"{exc.__class__.__name__}: {exc}"
        self.status[name] = stat
        return stat

    def smoke_rsi_levels(self, name: str) -> SubsystemStatus:
        mod = self.load(name)
        stat = self.status.get(name, SubsystemStatus(name=name, loaded=False))
        if not mod:
            stat.smoke = "load_failed"
            return stat
        checks = {
            "level_alphabet": hasattr(mod, "level_alphabet"),
            "Streams": hasattr(mod, "Streams"),
            "run_loop": hasattr(mod, "run_loop"),
            "run_tests": hasattr(mod, "run_tests"),
            "gate": hasattr(mod, "gate"),
        }
        stat.callable_checks.update(checks)
        stat.smoke = "pass" if checks["level_alphabet"] and checks["gate"] else "warn_partial"
        self.status[name] = stat
        return stat

    def run_all_smokes(self) -> Dict[str, SubsystemStatus]:
        self.smoke_systemtest()
        self.smoke_open_ended()
        self.smoke_hdc()
        self.smoke_rsi_levels("rsi_levels_emergence_1")
        self.smoke_rsi_levels("rsi_levels_plus_1")
        return self.status

    def report(self) -> Dict[str, dict]:
        return {
            name: {
                "loaded": st.loaded,
                "smoke": st.smoke,
                "checks": st.callable_checks,
                "error": st.error,
                "lines": st.lines,
                "sha16": st.sha16,
            }
            for name, st in sorted(self.status.items())
        }


class OrganicMetaForgeBridge:
    """Connects the compact MetaForge runtime to the loaded source subsystems.

    It does not replace the high-level generated-level demo; it exposes the
    original engines as backend organs that can be inspected and called. The
    bridge makes this file a full organic monolith rather than a passive archive.
    """

    def __init__(self):
        self.manager = OrganicSubsystemManager(INTEGRATED_SOURCE_ARCHIVE)
        self.last_report: Dict[str, dict] = {}

    def bootstrap(self) -> Dict[str, dict]:
        self.manager.run_all_smokes()
        self.last_report = self.manager.report()
        return self.last_report

    def backend_capability_vector(self) -> Dict[str, float]:
        if not self.last_report:
            self.bootstrap()
        vec: Dict[str, float] = {}
        for name, rep in self.last_report.items():
            checks = rep.get("checks", {})
            vec[f"{name}.loaded"] = 1.0 if rep.get("loaded") else 0.0
            vec[f"{name}.smoke_pass"] = 1.0 if rep.get("smoke") == "pass" else 0.0
            vec[f"{name}.callable_fraction"] = (
                sum(1 for v in checks.values() if v) / max(1, len(checks))
            )
        return vec

    def print_report(self) -> None:
        print(json.dumps(self.bootstrap(), indent=2, sort_keys=True))
        print("\nBACKEND_CAPABILITY_VECTOR")
        print(json.dumps(self.backend_capability_vector(), indent=2, sort_keys=True))


def run_organic_smoke() -> int:
    bridge = OrganicMetaForgeBridge()
    report = bridge.bootstrap()
    print("=" * 80)
    print("ORGANIC FULL INTEGRATION SMOKE")
    print("=" * 80)
    print(json.dumps(report, indent=2, sort_keys=True))
    loaded = [r for r in report.values() if r.get("loaded")]
    passed = [r for r in report.values() if r.get("smoke") == "pass"]
    print("=" * 80)
    print(f"loaded_subsystems={len(loaded)} smoke_pass={len(passed)} total={len(report)}")
    if len(loaded) < 5:
        print("ORGANIC SMOKE FAILED: not all subsystems loaded")
        return 1
    if len(passed) < 3:
        print("ORGANIC SMOKE FAILED: too few active subsystem smokes passed")
        return 1
    print("ORGANIC SMOKE PASSED")
    return 0


def run_full_organic_tests() -> int:
    rc = run_tests()
    if rc is None:
        rc = 0
    print()
    rc2 = run_organic_smoke()
    return 0 if rc == 0 and rc2 == 0 else 1


# ---------------------------------------------------------------------------
# Heterogeneous-domain self-improvement harness.
#
# This is deliberately not a claim of unbounded general intelligence. It broadens the runtime
# from one list[int] VM benchmark to a feature-level synthesis layer that can
# operate over lists, strings, grids, and dict/record-like objects. The searcher
# sees only train examples. Candidate improvements are reusable expression
# macros mined from solved programs, and they are accepted only if they solve
# fresh frontier tasks under the same expression-cost budget.
# ---------------------------------------------------------------------------

GD_FEATURES: Tuple[str, ...] = (
    "SIZE", "NUM_SUM", "NUM_COUNT", "NUM_MAX", "NUM_MIN",
    "FIRST_NUM", "LAST_NUM", "STR_LEN", "VOWELS", "DIGITS",
    "UPPER", "ROWS", "COLS", "AREA", "FIELDS",
)

GD_CONSTS: Tuple[int, ...] = (0, 1, 2, 3)
GD_BINARY_OPS: Tuple[str, ...] = ("ADD", "SUB", "MUL", "MAX", "MIN")


def _gd_numbers(obj) -> List[int]:
    out: List[int] = []
    if isinstance(obj, bool):
        return [int(obj)]
    if isinstance(obj, int):
        return [obj]
    if isinstance(obj, float):
        return [int(obj)]
    if isinstance(obj, str):
        return [int(ch) for ch in obj if ch.isdigit()]
    if isinstance(obj, dict):
        for k in sorted(obj, key=lambda x: str(x)):
            out.extend(_gd_numbers(obj[k]))
        return out
    if isinstance(obj, (list, tuple)):
        for v in obj:
            out.extend(_gd_numbers(v))
        return out
    return out


def _gd_flat_strings(obj) -> List[str]:
    if isinstance(obj, str):
        return [obj]
    if isinstance(obj, dict):
        out: List[str] = []
        for k in sorted(obj, key=lambda x: str(x)):
            out.extend(_gd_flat_strings(obj[k]))
        return out
    if isinstance(obj, (list, tuple)):
        out: List[str] = []
        for v in obj:
            out.extend(_gd_flat_strings(v))
        return out
    return []


def _gd_shape(obj) -> Tuple[int, int]:
    if isinstance(obj, (list, tuple)) and obj and all(isinstance(r, (list, tuple)) for r in obj):
        rows = len(obj)
        cols = max((len(r) for r in obj), default=0)
        return rows, cols
    return 0, 0


def gd_features(obj) -> Dict[str, int]:
    nums = _gd_numbers(obj)
    strings = _gd_flat_strings(obj)
    text = "".join(strings)
    rows, cols = _gd_shape(obj)
    size = len(obj) if hasattr(obj, "__len__") else len(nums)
    vowels = sum(1 for ch in text.lower() if ch in "aeiou")
    digits = sum(1 for ch in text if ch.isdigit())
    upper = sum(1 for ch in text if ch.isupper())
    out = {
        "SIZE": int(size),
        "NUM_SUM": int(sum(nums)),
        "NUM_COUNT": int(len(nums)),
        "NUM_MAX": int(max(nums)) if nums else 0,
        "NUM_MIN": int(min(nums)) if nums else 0,
        "FIRST_NUM": int(nums[0]) if nums else 0,
        "LAST_NUM": int(nums[-1]) if nums else 0,
        "STR_LEN": int(sum(len(s) for s in strings)),
        "VOWELS": int(vowels),
        "DIGITS": int(digits),
        "UPPER": int(upper),
        "ROWS": int(rows),
        "COLS": int(cols),
        "AREA": int(rows * cols),
        "FIELDS": int(len(obj)) if isinstance(obj, dict) else 0,
    }
    if GD_EXTRA_FEATURES:
        for _fname, _ffn in GD_EXTRA_FEATURES.items():
            out[_fname] = int(_ffn(nums))
    return out


@dataclass(frozen=True)
class GDExpr:
    op: str
    args: Tuple["GDExpr", ...] = ()
    name: str = ""
    value: int = 0


@dataclass(frozen=True)
class GDMacro:
    name: str
    body: GDExpr
    source_tasks: Tuple[str, ...]


@dataclass(frozen=True)
class GDTask:
    name: str
    domain: str
    train: Tuple[Tuple[object, int], ...]
    holdout: Tuple[Tuple[object, int], ...]


def _gd_feature(name: str) -> GDExpr:
    return GDExpr("FEATURE", name=name)


def _gd_const(value: int) -> GDExpr:
    return GDExpr("CONST", value=int(value))


def _gd_slot() -> GDExpr:
    return GDExpr("SLOT", name="slot")


def _gd_macro_call(name: str, arg: GDExpr) -> GDExpr:
    return GDExpr("MACRO", (arg,), name=name)


def _gd_bin(op: str, a: GDExpr, b: GDExpr) -> GDExpr:
    if op in ("ADD", "MUL", "MAX", "MIN") and gd_expr_key(b) < gd_expr_key(a):
        a, b = b, a
    return GDExpr(op, (a, b))


def gd_expr_key(e: GDExpr) -> str:
    if e.op == "FEATURE":
        return f"F:{e.name}"
    if e.op == "CONST":
        return f"C:{e.value}"
    if e.op == "SLOT":
        return "SLOT"
    if e.op == "MACRO":
        return f"{e.name}({gd_expr_key(e.args[0])})"
    return f"{e.op}({','.join(gd_expr_key(a) for a in e.args)})"


def gd_expr_cost(e: GDExpr) -> int:
    if e.op in ("FEATURE", "CONST", "SLOT"):
        return 1
    return 1 + sum(gd_expr_cost(a) for a in e.args)


def gd_expr_eval(e: GDExpr, obj, macros: Dict[str, GDMacro],
                 slot_value: Optional[int] = None) -> int:
    if e.op == "FEATURE":
        return gd_features(obj).get(e.name, 0)
    if e.op == "CONST":
        return e.value
    if e.op == "SLOT":
        if slot_value is None:
            raise ValueError("slot used without value")
        return int(slot_value)
    if e.op == "MACRO":
        if e.name not in macros:
            raise ValueError(f"unknown macro {e.name}")
        arg = gd_expr_eval(e.args[0], obj, macros, slot_value)
        return gd_expr_eval(macros[e.name].body, obj, macros, arg)
    a = gd_expr_eval(e.args[0], obj, macros, slot_value)
    b = gd_expr_eval(e.args[1], obj, macros, slot_value)
    if e.op == "ADD":
        return a + b
    if e.op == "SUB":
        return a - b
    if e.op == "MUL":
        return a * b
    if e.op == "MAX":
        return a if a >= b else b
    if e.op == "MIN":
        return a if a <= b else b
    raise ValueError(f"unknown op {e.op}")


def gd_enumerate_exprs(macros: Dict[str, GDMacro],
                       max_cost: int,
                       features: Sequence[str] = GD_FEATURES) -> List[GDExpr]:
    by_cost: Dict[int, List[GDExpr]] = {}
    seen: set = set()

    def add(cost: int, expr: GDExpr) -> None:
        key = gd_expr_key(expr)
        if cost <= max_cost and key not in seen:
            seen.add(key)
            by_cost.setdefault(cost, []).append(expr)

    for f in list(features) + sorted(GD_EXTRA_FEATURES):
        add(1, _gd_feature(f))
    for c in GD_CONSTS:
        add(1, _gd_const(c))

    for cost in range(2, max_cost + 1):
        for mname in sorted(macros):
            for sub_cost, exprs in list(by_cost.items()):
                if 1 + sub_cost == cost:
                    for e in exprs:
                        add(cost, _gd_macro_call(mname, e))
        for op in GD_BINARY_OPS:
            for left_cost in range(1, cost):
                right_cost = cost - 1 - left_cost
                if right_cost < 1:
                    continue
                for a in by_cost.get(left_cost, []):
                    for b in by_cost.get(right_cost, []):
                        if op in ("ADD", "MUL", "MAX", "MIN") and gd_expr_key(b) < gd_expr_key(a):
                            continue
                        add(cost, _gd_bin(op, a, b))

    out: List[GDExpr] = []
    for c in range(1, max_cost + 1):
        out.extend(by_cost.get(c, []))
    return out


def gd_synthesize(task: GDTask,
                  macros: Dict[str, GDMacro],
                  max_cost: int) -> Optional[GDExpr]:
    exprs = gd_enumerate_exprs(macros, max_cost)
    best_partial: Optional[Tuple[int, GDExpr]] = None
    for expr in exprs:
        hits = 0
        ok = True
        for x, y in task.train:
            try:
                got = gd_expr_eval(expr, x, macros)
            except Exception:
                ok = False
                break
            if got == y:
                hits += 1
            else:
                ok = False
                break
        if ok:
            return expr
        if best_partial is None or hits > best_partial[0]:
            best_partial = (hits, expr)
    return None


def gd_validates(task: GDTask, expr: GDExpr, macros: Dict[str, GDMacro]) -> bool:
    for x, y in task.holdout:
        try:
            if gd_expr_eval(expr, x, macros) != y:
                return False
        except Exception:
            return False
    return True


def _gd_template_from_unary_subtree(e: GDExpr) -> Optional[GDExpr]:
    leaves: List[str] = []

    def walk(node: GDExpr) -> Optional[GDExpr]:
        if node.op == "FEATURE":
            leaves.append(node.name)
            return _gd_slot()
        if node.op in ("CONST", "SLOT"):
            return node
        if node.op == "MACRO":
            inner = walk(node.args[0])
            if inner is None:
                return None
            return _gd_macro_call(node.name, inner)
        if len(node.args) != 2:
            return None
        a = walk(node.args[0])
        b = walk(node.args[1])
        if a is None or b is None:
            return None
        return _gd_bin(node.op, a, b)

    templ = walk(e)
    if templ is None or len(set(leaves)) != 1:
        return None
    if gd_expr_cost(templ) < 3:
        return None
    return templ


def _gd_subexprs(e: GDExpr) -> Iterable[GDExpr]:
    yield e
    for a in e.args:
        yield from _gd_subexprs(a)


def gd_mine_macros(solved: Dict[str, GDExpr],
                   existing: Dict[str, GDMacro],
                   min_support: int = 2,
                   max_new: int = 3) -> List[GDMacro]:
    supports: Dict[str, List[str]] = {}
    templates: Dict[str, GDExpr] = {}
    for task_name, expr in solved.items():
        per_task = set()
        for sub in _gd_subexprs(expr):
            templ = _gd_template_from_unary_subtree(sub)
            if templ is None:
                continue
            key = gd_expr_key(templ)
            per_task.add(key)
            templates[key] = templ
        for key in per_task:
            supports.setdefault(key, []).append(task_name)

    existing_keys = {gd_expr_key(m.body) for m in existing.values()}
    ranked = sorted(
        ((key, tasks) for key, tasks in supports.items()
         if len(tasks) >= min_support and key not in existing_keys),
        key=lambda kv: (-len(kv[1]), gd_expr_cost(templates[kv[0]]), kv[0]),
    )
    out: List[GDMacro] = []
    next_id = len(existing)
    for key, tasks in ranked[:max_new]:
        out.append(GDMacro(f"GM{next_id}", templates[key], tuple(sorted(tasks))))
        next_id += 1
    return out


def _gd_pairs(inputs: Sequence[object], fn: Callable[[object], int]) -> Tuple[Tuple[object, int], ...]:
    return tuple((x, int(fn(x))) for x in inputs)


def build_general_domain_tasks() -> Tuple[List[GDTask], List[GDTask], List[GDTask]]:
    warmup_inputs = {
        "list": ([1, 2, 3], [2, 4], [5], [0, 3, 6]),
        "string": ("a1B", "hello22", "XYZ9", "codex2026"),
        "grid": (
            [[1, 2], [3, 4]],
            [[0], [1], [2]],
            [[5, 6, 7]],
            [[1, 0], [2, 3], [4, 5]],
        ),
        "record": (
            {"a": 1, "b": 2},
            {"x": [2, 3], "y": 4},
            {"items": [1, 1, 1], "tax": 2},
            {"left": 5, "right": 6, "n": 1},
        ),
    }
    holdout_inputs = {
        "list": ([7, 1], [2, 2, 2, 2], [8], [1, 3, 5, 7, 9]),
        "string": ("AI007", "MetaForge5", "rsi", "LONG42x"),
        "grid": (
            [[1], [2], [3], [4]],
            [[1, 2, 3], [4, 5, 6]],
            [[9, 8]],
            [[0, 0, 0], [1, 1, 1], [2, 2, 2]],
        ),
        "record": (
            {"a": 10, "b": -2},
            {"z": [3, 4, 5]},
            {"name": "A12", "v": 5},
            {"p": 2, "q": 3, "r": 4, "s": 5},
        ),
    }

    train: List[GDTask] = [
        GDTask("list_sum_square", "list", _gd_pairs(warmup_inputs["list"], lambda x: gd_features(x)["NUM_SUM"] ** 2),
               _gd_pairs(holdout_inputs["list"], lambda x: gd_features(x)["NUM_SUM"] ** 2)),
        GDTask("string_len_square", "string", _gd_pairs(warmup_inputs["string"], lambda x: gd_features(x)["STR_LEN"] ** 2),
               _gd_pairs(holdout_inputs["string"], lambda x: gd_features(x)["STR_LEN"] ** 2)),
        GDTask("grid_area_square", "grid", _gd_pairs(warmup_inputs["grid"], lambda x: gd_features(x)["AREA"] ** 2),
               _gd_pairs(holdout_inputs["grid"], lambda x: gd_features(x)["AREA"] ** 2)),
        GDTask("record_sum_square", "record", _gd_pairs(warmup_inputs["record"], lambda x: gd_features(x)["NUM_SUM"] ** 2),
               _gd_pairs(holdout_inputs["record"], lambda x: gd_features(x)["NUM_SUM"] ** 2)),
        GDTask("string_digit_square", "string", _gd_pairs(warmup_inputs["string"], lambda x: gd_features(x)["DIGITS"] ** 2),
               _gd_pairs(holdout_inputs["string"], lambda x: gd_features(x)["DIGITS"] ** 2)),
    ]

    frontier_inputs = {
        "list": ([1, 2, 3], [4, 5], [0, 1, 2, 3], [7]),
        "string": ("a1b2", "OpenAI7", "XYZ99", "rsi2026"),
        "grid": (
            [[1, 2], [3, 4]],
            [[1], [2], [3]],
            [[0, 0, 0]],
            [[5, 5], [6, 6], [7, 7]],
        ),
        "record": (
            {"a": 1, "b": 2, "c": 3},
            {"items": [2, 2], "tax": 1},
            {"name": "A12", "score": 4},
            {"x": 5},
        ),
    }
    frontier_holdout = {
        "list": ([3, 3, 3], [8, 1], [2, 4, 6, 8], [0, 0, 5]),
        "string": ("K2", "Data123", "abc", "WARM77"),
        "grid": (
            [[9], [8], [7], [6]],
            [[1, 2, 3], [4, 5, 6]],
            [[0, 0]],
            [[1, 1], [2, 2]],
        ),
        "record": (
            {"a": 10, "b": -1},
            {"q": [3, 3, 3], "r": 1},
            {"label": "B7", "n": 2},
            {"x": 1, "y": 2, "z": 3},
        ),
    }

    frontier: List[GDTask] = [
        GDTask("list_sum_plus_size_square", "list",
               _gd_pairs(frontier_inputs["list"], lambda x: (gd_features(x)["NUM_SUM"] + gd_features(x)["SIZE"]) ** 2),
               _gd_pairs(frontier_holdout["list"], lambda x: (gd_features(x)["NUM_SUM"] + gd_features(x)["SIZE"]) ** 2)),
        GDTask("string_len_plus_digits_square", "string",
               _gd_pairs(frontier_inputs["string"], lambda x: (gd_features(x)["STR_LEN"] + gd_features(x)["DIGITS"]) ** 2),
               _gd_pairs(frontier_holdout["string"], lambda x: (gd_features(x)["STR_LEN"] + gd_features(x)["DIGITS"]) ** 2)),
        GDTask("grid_rows_plus_cols_square", "grid",
               _gd_pairs(frontier_inputs["grid"], lambda x: (gd_features(x)["ROWS"] + gd_features(x)["COLS"]) ** 2),
               _gd_pairs(frontier_holdout["grid"], lambda x: (gd_features(x)["ROWS"] + gd_features(x)["COLS"]) ** 2)),
        GDTask("record_sum_plus_fields_square", "record",
               _gd_pairs(frontier_inputs["record"], lambda x: (gd_features(x)["NUM_SUM"] + gd_features(x)["FIELDS"]) ** 2),
               _gd_pairs(frontier_holdout["record"], lambda x: (gd_features(x)["NUM_SUM"] + gd_features(x)["FIELDS"]) ** 2)),
        GDTask("list_sum_fourth", "list",
               _gd_pairs(frontier_inputs["list"], lambda x: gd_features(x)["NUM_SUM"] ** 4),
               _gd_pairs(frontier_holdout["list"], lambda x: gd_features(x)["NUM_SUM"] ** 4)),
        GDTask("string_len_fourth", "string",
               _gd_pairs(frontier_inputs["string"], lambda x: gd_features(x)["STR_LEN"] ** 4),
               _gd_pairs(frontier_holdout["string"], lambda x: gd_features(x)["STR_LEN"] ** 4)),
        GDTask("grid_area_fourth", "grid",
               _gd_pairs(frontier_inputs["grid"], lambda x: gd_features(x)["AREA"] ** 4),
               _gd_pairs(frontier_holdout["grid"], lambda x: gd_features(x)["AREA"] ** 4)),
        GDTask("record_sum_fourth", "record",
               _gd_pairs(frontier_inputs["record"], lambda x: gd_features(x)["NUM_SUM"] ** 4),
               _gd_pairs(frontier_holdout["record"], lambda x: gd_features(x)["NUM_SUM"] ** 4)),
    ]

    unsupported: List[GDTask] = [
        GDTask("string_contains_ai", "semantic_text",
               _gd_pairs(("AI lab", "plain", "OpenAI", "rsi"), lambda x: 1 if "AI" in x else 0),
               _gd_pairs(("Nope", "AI", "machine", "AIM"), lambda x: 1 if "AI" in x else 0)),
        GDTask("grid_diagonal_sum", "spatial_relation",
               _gd_pairs(([[1, 2], [3, 4]], [[5]], [[1, 0], [0, 1]], [[2, 3, 4], [5, 6, 7]]),
                         lambda x: sum(x[i][i] for i in range(min(len(x), len(x[0]))))),
               _gd_pairs(([[9, 8], [7, 6]], [[1, 2, 3]], [[1], [2], [3]], [[0, 1], [2, 3]]),
                         lambda x: sum(x[i][i] for i in range(min(len(x), len(x[0])))))),
    ]
    return train, frontier, unsupported


def gd_solve_tasks(tasks: Sequence[GDTask],
                   macros: Dict[str, GDMacro],
                   max_cost: int) -> Dict[str, object]:
    rows = []
    solved: Dict[str, GDExpr] = {}
    for task in tasks:
        expr = gd_synthesize(task, macros, max_cost)
        valid = bool(expr is not None and gd_validates(task, expr, macros))
        if valid and expr is not None:
            solved[task.name] = expr
        rows.append({
            "name": task.name,
            "domain": task.domain,
            "validated": valid,
            "expr": gd_expr_key(expr) if expr is not None else "",
        })
    return {
        "validated": sum(1 for r in rows if r["validated"]),
        "total": len(rows),
        "rows": rows,
        "solved_exprs": solved,
    }


def run_general_domain_self_improvement_test(save_path: str = "") -> int:
    train, frontier, unsupported = build_general_domain_tasks()
    cold_macros: Dict[str, GDMacro] = {}
    train_result = gd_solve_tasks(train, cold_macros, max_cost=3)
    solved_train: Dict[str, GDExpr] = train_result["solved_exprs"]  # type: ignore[assignment]
    proposed = gd_mine_macros(solved_train, cold_macros, min_support=2, max_new=3)
    candidate_macros = dict(cold_macros)
    for m in proposed:
        candidate_macros[m.name] = m

    cold_frontier = gd_solve_tasks(frontier, cold_macros, max_cost=4)
    warm_frontier = gd_solve_tasks(frontier, candidate_macros, max_cost=4)
    accept = int(warm_frontier["validated"]) > int(cold_frontier["validated"])
    accepted_macros = candidate_macros if accept else cold_macros
    unsupported_result = gd_solve_tasks(unsupported, accepted_macros, max_cost=4)

    report = {
        "claim_boundary": (
            "heterogeneous feature-level self-improvement over list/string/grid/"
            "record tasks; not unbounded real-world general intelligence"
        ),
        "search_visibility": "train examples only; holdout used only for validation",
        "train_validated": train_result["validated"],
        "train_total": train_result["total"],
        "proposed_macros": [
            {
                "name": m.name,
                "body": gd_expr_key(m.body),
                "source_tasks": list(m.source_tasks),
            }
            for m in proposed
        ],
        "meta_gate": {
            "accepted": accept,
            "cold_frontier_validated": cold_frontier["validated"],
            "warm_frontier_validated": warm_frontier["validated"],
            "delta": int(warm_frontier["validated"]) - int(cold_frontier["validated"]),
            "budget_max_cost": 4,
        },
        "cold_frontier": {k: v for k, v in cold_frontier.items() if k != "solved_exprs"},
        "warm_frontier": {k: v for k, v in warm_frontier.items() if k != "solved_exprs"},
        "unsupported_probe": {k: v for k, v in unsupported_result.items() if k != "solved_exprs"},
    }

    if save_path:
        with open(save_path, "w", encoding="utf-8") as f:
            json.dump(report, f, indent=2, sort_keys=True)

    print(json.dumps(report, indent=2, sort_keys=True))
    if not accept:
        return 1
    if int(warm_frontier["validated"]) <= int(cold_frontier["validated"]):
        return 1
    if int(unsupported_result["validated"]) != 0:
        return 1
    return 0




def main() -> None:
    ap = argparse.ArgumentParser(description="real-search RSI core")
    ap.add_argument("--mode",
                    choices=("demo", "test", "counterfactual",
                             "run-adaptive", "run-frozen", "cf-report", "step",
                             "manifest", "extract", "organic", "organic-test",
                             "hdc-rsi", "general-domain-test",
                             "directive-battery", "wm-report",
                             "reflection-battery", "closure-report",
                             "horizon-scan", "horizon-report",
                             "hdc-battery", "clash-battery",
                             "forge-battery", "file-battery",
                             "ext-battery", "cfs-battery",
                             "expansion-battery", "grammar-battery",
                             "grammar2-battery",),
                    default="demo")
    ap.add_argument("--save", default="")
    ap.add_argument("--adaptive-json", default="adaptive.json")
    ap.add_argument("--frozen-json", default="frozen.json")
    ap.add_argument("--only", default="")
    ap.add_argument("--wave-from", default="0")
    ap.add_argument("--wave-to", default=str(WAVES))
    ap.add_argument("--extract-dir", default="./integrated_sources")
    args = ap.parse_args()
    if args.mode == "test":
        run_tests(only=args.only)
    elif args.mode == "counterfactual":
        demo_counterfactual()
    elif args.mode == "run-adaptive":
        rs = run_system(adaptive=True)
        if args.save:
            save_runstate(rs, args.save)
        print(json.dumps({"solved": len(rs.adopted_tokens),
                          "digest": adoption_log_digest(rs)}))
    elif args.mode == "run-frozen":
        rs = run_system(adaptive=False)
        if args.save:
            save_runstate(rs, args.save)
        print(json.dumps({"solved": len(rs.adopted_tokens),
                          "digest": adoption_log_digest(rs)}))
    elif args.mode == "step":
        import os
        if args.save and os.path.exists(args.save):
            rs = restore_runstate(load_summary(args.save))
            start = int(args.wave_from)
        else:
            rs = None
            start = 0
        rs = run_system(adaptive=True, waves=int(args.wave_to),
                        rs=rs, wave_start=start)
        save_runstate(rs, args.save or "adaptive.json")
        print(json.dumps({"solved": len(rs.adopted_tokens),
                          "waves_done": int(args.wave_to),
                          "version": rs.searcher.version,
                          "digest": adoption_log_digest(rs)}))
    elif args.mode == "organic-test":
        raise SystemExit(run_full_organic_tests())
    elif args.mode == "manifest":
        print_integrated_manifest()
    elif args.mode == "extract":
        extract_integrated_sources(args.extract_dir)
    elif args.mode == "organic":
        raise SystemExit(run_organic_smoke())
    elif args.mode == "cf-report":
        rep = counterfactual_report_from(load_summary(args.adaptive_json),
                                         load_summary(args.frozen_json))
        print(json.dumps(rep, indent=2, sort_keys=True))
    elif args.mode == "forge-battery":
        forge_battery()
    elif args.mode == "file-battery":
        file_battery()
    elif args.mode == "ext-battery":
        ext_battery()
    elif args.mode == "cfs-battery":
        cfs_battery()
    elif args.mode == "expansion-battery":
        expansion_battery()
    elif args.mode == "grammar-battery":
        grammar_battery()
    elif args.mode == "grammar2-battery":
        grammar2_battery()
    elif args.mode == "clash-battery":
        clash_battery()
    elif args.mode == "hdc-battery":
        hdc_battery()
    elif args.mode == "horizon-scan":
        targeted_reach_scan(wall_targets(), depth=8,
                            vocab=list(range(N_BASE_OPS)), hold_level=6,
                            class_cap=700_000, out_json="closure_scan.json")
    elif args.mode == "horizon-report":
        print_horizon_report(horizon_report())
    elif args.mode == "reflection-battery":
        reflection_battery()
    elif args.mode == "closure-report":
        print(json.dumps(closure_report(), indent=2, sort_keys=True))
    elif args.mode == "directive-battery":
        directive_battery()
    elif args.mode == "wm-report":
        print(json.dumps(build_wm().coverage_report(), indent=2,
                         sort_keys=True))
    elif args.mode == "hdc-rsi":
        demo_hdc_rsi()
    elif args.mode == "general-domain-test":
        raise SystemExit(run_general_domain_self_improvement_test(args.save))
    else:
        demo()


if __name__ == "__main__":
    main()
